-- Curated HEALTHY FOODS ("Sélection santé") — server-side mirror of
-- src/data/healthyFoods.ts. ~120 diabetes-friendly Moroccan dishes with
-- meal-time folders (moments), ingredients and preparation, so the AI and
-- scanner read PRE-STORED values instead of recomputing.
--
-- AUTO-GENERATED by scripts/gen-healthy-foods-sql.mjs — do not edit by hand.
-- Read-only for clients (RLS select-only).

create table if not exists public.healthy_foods (
  id text primary key,
  name_fr text not null,
  name_ar text not null,
  name_en text not null,
  category text not null,
  moments text[] not null default '{}',
  emoji text not null default '🍽️',
  serving text not null,
  grams numeric not null,
  calories numeric not null,
  carbs numeric not null,
  sugar numeric not null default 0,
  protein numeric not null default 0,
  fat numeric not null default 0,
  fiber numeric not null default 0,
  gi numeric,
  why_fr text,
  why_ar text,
  ingredients_fr jsonb not null default '[]',
  ingredients_ar jsonb not null default '[]',
  steps_fr jsonb not null default '[]',
  steps_ar jsonb not null default '[]',
  image_url text,
  aliases text[] default '{}',
  created_at timestamptz not null default now()
);

alter table public.healthy_foods enable row level security;

drop policy if exists "healthy_foods_read" on public.healthy_foods;
create policy "healthy_foods_read" on public.healthy_foods
  for select using (true);

create index if not exists healthy_foods_name_fr_idx
  on public.healthy_foods using gin (to_tsvector('french', name_fr));
create index if not exists healthy_foods_moments_idx
  on public.healthy_foods using gin (moments);

insert into public.healthy_foods
  (id, name_fr, name_ar, name_en, category, moments, emoji, serving, grams,
   calories, carbs, sugar, protein, fat, fiber, gi, why_fr, why_ar,
   ingredients_fr, ingredients_ar, steps_fr, steps_ar, image_url, aliases)
values
  ('oeufs-avocat', 'Œufs durs & avocat', 'بيض مسلوق مع الأفوكادو', 'Boiled eggs & avocado', 'breakfast', ARRAY['ftour']::text[], '🥑', '2 œufs + ½ avocat (180 g)', 180, 300, 7, 1, 15, 24, 5, 15, 'Presque zéro sucre : la glycémie reste stable toute la matinée. Les bonnes graisses de l''avocat et les protéines des œufs coupent la faim et évitent le grignotage.', 'تقريباً بلا سكر: السكر فالدم كيبقى مستقر الصباح كامل. الدهون الصحية ديال الأفوكادو والبروتين ديال البيض كيشبعو وكيمنعو التسناك.', '["2 pièces d''œufs de poule frais","1/2 pièce d''avocat mûr (environ 90 g)","1 cuillère à café d''huile d''olive extra vierge (5 ml)","1/4 cuillère à café de cumin moulu (1.25 g)","1/4 cuillère à café de paprika doux (1.25 g)","Une pincée de sel fin (environ 1 g)","Une pincée de poivre noir fraîchement moulu (environ 0.5 g)","Quelques feuilles de coriandre fraîche ciselée (pour la garniture)"]'::jsonb, '["2 بيضات دجاج طازجة","نص حبة أفوكادو طايبة (حوالي 90 غرام)","1 معلقة صغيرة زيت الزيتون البكر الممتاز (5 مل)","ربع معلقة صغيرة كامون مطحون (1.25 غرام)","ربع معلقة صغيرة تحميرة حلوة (1.25 غرام)","رشيشة ملح رقيق (حوالي 1 غرام)","رشيشة إبزار كحل مطحون طري (حوالي 0.5 غرام)","شوية قزبر طري مقطع رقيق (للتزيين)"]'::jsonb, '["1. Commencez par faire cuire les œufs. Plongez délicatement les 2 œufs dans une petite casserole d''eau froide. Portez à ébullition sur feu moyen-vif. Dès que l''eau bout franchement, réduisez le feu à moyen et laissez cuire pendant exactement 9 minutes pour obtenir des œufs durs parfaits, avec un jaune bien ferme.","2. Pendant la cuisson des œufs, préparez l''avocat. Coupez la demi-pièce d''avocat en deux dans le sens de la longueur, retirez le noyau et, à l''aide d''une cuillère, prélevez la chair verte et crémeuse. Déposez-la dans un petit bol.","3. Écrasez grossièrement la chair de l''avocat à l''aide d''une fourchette. Vous pouvez laisser quelques petits morceaux pour une texture plus intéressante. Ne la réduisez pas en purée lisse.","4. Assaisonnez l''avocat écrasé. Ajoutez 1/4 de cuillère à café de cumin moulu, 1/4 de cuillère à café de paprika doux, une pincée de sel fin et une pincée de poivre noir fraîchement moulu. Arrosez d''1 cuillère à café d''huile d''olive extra vierge. Mélangez délicatement pour bien incorporer les saveurs.","5. Une fois les œufs cuits, retirez-les de l''eau bouillante et plongez-les immédiatement dans un bain d''eau glacée pendant 2-3 minutes. Cela arrêtera la cuisson et facilitera l''écalage.","6. Écalez les œufs délicatement sous l''eau froide courante pour éviter que des petits morceaux de coquille ne restent collés. Coupez chaque œuf dur en deux dans le sens de la longueur.","7. Dressez votre assiette. Disposez les moitiés d''œufs durs et l''avocat assaisonné. Saupoudrez de quelques feuilles de coriandre fraîche ciselée pour une touche de fraîcheur et de couleur. Servez immédiatement. Ce plat est idéal pour un petit-déjeuner nourrissant et équilibré.","💡 Astuce diabète : Pour maintenir une glycémie stable, savourez ce plat en début de repas. L''avocat (90g) et les œufs (2 pièces) apportent des graisses saines et des protéines qui ralentissent l''absorption des glucides si vous l''accompagnez d''une petite tranche de pain complet (max 30g, IG bas). Évitez les jus de fruits ou les sucres ajoutés."]'::jsonb, '["1. بداو طيبو البيض. حطو 2 بيضات بشوية فكاسرونة صغيرة فيها ماء بارد. حطوها فوق نار متوسطة حتى تغلى مزيان. ملي تبدا تغلى، نقصو النار لمتوسطة وخليوها طيب بالضبط 9 دقايق باش يجي البيض مسلوق مزيان والصفر قاصح.","2. فاش يكون البيض كيطيب، وجدو الأفوكادو. قسمو نص حبة الأفوكادو على جوج بالطول، حيدو العظم، وبمعلقة حيدو اللب الأخضر الرطب. حطوه فزلافة صغيرة.","3. معسو الأفوكادو غير بشوية بالفرشيطة. خليو شي طريفات صغار باش تكون فيه قوام زوين. ماتمعسوهش حتى يولي بحال البوري.","4. نكهو الأفوكادو اللي معستو. زيدو ربع معلقة صغيرة كامون مطحون، ربع معلقة صغيرة تحميرة حلوة، رشيشة ملح رقيق ورشيشة إبزار كحل مطحون طري. رشو عليه 1 معلقة صغيرة زيت الزيتون البكر الممتاز. خلطو بشوية باش يتجانسو النكهات.","5. ملي يطيب البيض، حيدوه من الماء السخون وديروه دغيا فماء بارد فيه الثلج لمدة 2-3 دقايق. هادشي كيوقف الطياب وكيخلي القشرة تحيد بسهولة.","6. قشرو البيض بشوية تحت الماء البارد الجاري باش ماتبقاش شي قشور لاصقة. قسمو كل بيضة مسلوقة على جوج بالطول.","7. قدمو الطبق ديالكم. حطو نصاص البيض المسلوق والأفوكادو المنكه. رشو عليه شوية قزبر طري مقطع رقيق باش يعطي لمسة ديال الطراوة واللون. قدموه دغيا. هاد الطبق مثالي لفطور مغذي ومتوازن.","💡 نصيحة للسكري: باش تحافظو على مستوى السكر فالدم مستقر، كولو هاد الطبق فبداية الوجبة. الأفوكادو (90 غرام) والبيض (2 بيضات) كيعطيو دهون صحية وبروتينات اللي كيبطئو امتصاص الكربوهيدرات إذا رافقتوه بشريحة صغيرة ديال خبز كامل (أقصى 30 غرام، مؤشر سكري منخفض). تجنبو عصير الفواكه أو السكريات المضافة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3a/Brooke_Lark_2017-03-27_%28Unsplash%29.jpg/1280px-Brooke_Lark_2017-03-27_%28Unsplash%29.jpg', ARRAY['oeuf avocat', 'بيض أفوكادو']::text[]),
  ('flocons-avoine', 'Flocons d''avoine au lait', 'الشوفان بالحليب', 'Oatmeal with milk', 'breakfast', ARRAY['ftour']::text[], '🥣', '1 bol (250 g)', 250, 220, 32, 6, 9, 6, 5, 50, 'L''avoine libère ses glucides LENTEMENT (IG 50) : pas de pic de glycémie comme le pain blanc. Ses fibres bêta-glucane aident aussi à baisser le cholestérol.', 'الشوفان كيطلق السكريات بشوية بشوية (IG 50): ما كيديرش الطلعة السريعة ديال السكر بحال الخبز الأبيض. الألياف ديالو كينقصو حتى الكوليسترول.', '["40 g de flocons d''avoine entiers (grandes feuilles)","200 ml de lait demi-écrémé","5 g de graines de chia","3 g de cannelle en poudre","1 pincée de sel","1 c. à café de noix concassées (amandes, noix de Grenoble)","1/2 pièce de datte Medjool (environ 6-7 g), dénoyautée et coupée en petits dés"]'::jsonb, '["40 غرام شوفان كامل (حبوب كبيرة)","200 مل حليب نص دسم","5 غرام زريعة الشيا","3 غرام قرفة مطحونة","1 قبيصة ملح","1 معلقة صغيرة كركاع مهرمش (لوز، كركاع)","1/2 حبة تمر مجدول (تقريبا 6-7 غرام)، محيد العظم ومقطع طريفات صغار"]'::jsonb, '["Dans une petite casserole, versez les 200 ml de lait demi-écrémé. Ajoutez la pincée de sel et portez à frémissement sur feu moyen.","Dès que le lait commence à frémir, ajoutez les 40 g de flocons d''avoine entiers. Mélangez bien avec une cuillère en bois pour éviter que les flocons ne collent au fond.","Réduisez le feu à doux et laissez mijoter pendant 5 à 7 minutes, en remuant de temps en temps. L''avoine doit absorber le lait et devenir crémeuse, mais encore légèrement liquide.","Après 5-7 minutes, retirez la casserole du feu. Incorporez les 5 g de graines de chia et la moitié de la cannelle en poudre (environ 1.5 g). Mélangez bien. Les graines de chia vont épaissir le mélange en refroidissant.","Versez le الشوفان بالحليب chaud dans un bol de 250 g. Laissez reposer 2-3 minutes pour que les graines de chia fassent leur effet et que le mélange épaississe légèrement.","Garnissez le dessus avec les 1.5 g de cannelle restante, les 1 c. à café de noix concassées et les petits dés de 1/2 datte Medjool. Servez immédiatement.","💡 Astuce diabète : Pour un contrôle optimal de la glycémie, consommez ce bol de 250 g (environ 220 kcal, 32 g de glucides, IG 50) comme petit-déjeuner équilibré. Évitez d''ajouter du sucre ou du miel. Si vous souhaitez une touche sucrée supplémentaire, utilisez une petite quantité de fruits rouges frais à faible IG au lieu de la datte."]'::jsonb, '["فواحد الكاسرونة صغيرة، خوي 200 مل ديال الحليب نص دسم. زيد قبيصة الملحة وخليه يسخن فوق عافية متوسطة حتى يبدا يغلى.","فاش يبدا الحليب يغلى، زيد 40 غرام ديال الشوفان الكامل. خلط مزيان بمعلقة خشبية باش ما يلصقش الشوفان فالقاع.","نقص العافية لمهيلة وخليه يطيب لمدة 5 حتى 7 دقايق، وحرك مرة مرة. الشوفان خاصو يشرب الحليب ويولي كريمي، ولكن يبقى شوية سائل.","من بعد 5-7 دقايق، حيد الكاسرونة من فوق العافية. زيد 5 غرام ديال زريعة الشيا ونص القرفة مطحونة (تقريبا 1.5 غرام). خلط مزيان. زريعة الشيا غتخلي الخليط يتقال فاش يبرد.","خوي الشوفان بالحليب سخون فزلافة ديال 250 غرام. خليه يرتاح 2-3 دقايق باش زريعة الشيا تخدم خدمتها والخليط يتقال شوية.","زين الفوق بالقرفة اللي بقات، ومعلقة صغيرة ديال الكركاع مهرمش، وطريفات صغار ديال نص تمرة مجدول. قدمو بالصحة والراحة.","💡 نصيحة للسكري: باش تحافظ على مستوى السكر فالدم مزيان، تناول هاد الزلافة ديال 250 غرام (تقريبا 220 سعرة حرارية، 32 غرام كربوهيدرات، مؤشر سكري 50) كفطور صحي ومتوازن. تجنب تزيد السكر أو العسل. إلا بغيتي شي حاجة حلوة إضافية، استعمل كمية قليلة من الفواكه الحمراء الطازجة اللي المؤشر السكري ديالها منخفض بلاصة التمر."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/48/Cooked_oatmeal_in_bowl_3.jpg/1280px-Cooked_oatmeal_in_bowl_3.jpg', ARRAY['avoine', 'oats', 'شوفان']::text[]),
  ('yaourt-noix', 'Yaourt nature aux noix', 'دانون طبيعي بالكركاع', 'Plain yogurt with walnuts', 'breakfast', ARRAY['ftour', 'snack']::text[], '🥛', '1 yaourt + 5 noix (160 g)', 160, 210, 10, 8, 9, 15, 2, 30, 'Yaourt NATURE (pas aromatisé !) : 3× moins de sucre qu''un yaourt aux fruits. Les noix apportent des oméga-3 qui protègent le cœur — essentiel pour un diabétique.', 'دانون طبيعي (ماشي معطر!): فيه 3 مرات أقل من السكر من دانون بالفواكه. الكركاع فيه أوميغا 3 اللي كيحمي القلب — مهم بزاف للسكري.', '["125 g de yaourt nature entier (non sucré)","20 g de noix (environ 5 cerneaux entiers)","1/2 cuillère à café de cannelle moulue","1/4 cuillère à café de graines de chia","1 cuillère à café de miel d''oranger pur (facultatif, pour une touche de douceur naturelle)"]'::jsonb, '["125 غرام دانون طبيعي كامل الدسم (مسوس)","20 غرام كركاع (تقريباً 5 حبات كاملين)","1/2 معلقة صغيرة قرفة مطحونة","1/4 معلقة صغيرة زريعة الشيا","1 معلقة صغيرة عسل الليمون حر (اختياري، لشويا د الحلاوة الطبيعية)"]'::jsonb, '["Commencez par mesurer précisément 125 g de yaourt nature entier. Assurez-vous qu''il soit bien frais et sans aucun ajout de sucre ou d''arômes. Versez le yaourt dans un bol de taille moyenne.","Pesez ensuite 20 g de noix. Cela correspond généralement à environ 5 cerneaux entiers. Si les noix sont très grandes, vous pourriez en utiliser un peu moins. Hachez grossièrement les noix à l''aide d''un couteau, en veillant à ne pas les réduire en poudre. Les morceaux doivent rester perceptibles pour apporter du croquant.","Ajoutez les noix hachées au yaourt dans le bol. Mélangez délicatement avec une cuillère pour bien les incorporer.","Saupoudrez ensuite 1/2 cuillère à café de cannelle moulue sur le mélange. La cannelle est non seulement délicieuse, mais elle est aussi connue pour ses propriétés bénéfiques pour la régulation de la glycémie.","Incorporez 1/4 cuillère à café de graines de chia. Ces petites graines sont riches en fibres et contribuent à augmenter la sensation de satiété, ce qui est très utile pour un petit-déjeuner équilibré.","Si vous souhaitez une légère touche de douceur naturelle, ajoutez 1 cuillère à café de miel d''oranger pur. Mélangez bien pour que le miel soit uniformément réparti. Cette étape est facultative et peut être omise si vous préférez un goût entièrement non sucré.","Servez immédiatement pour profiter de la texture crémeuse du yaourt et du croquant des noix. Ce petit-déjeuner est idéal pour commencer la journée avec énergie et sans pic de glycémie.","💡 Astuce diabète : Pour un contrôle optimal de la glycémie, consommez ce yaourt nature aux noix en début de repas. La portion de 160 g (125 g de yaourt + 20 g de noix + ajouts) est parfaitement adaptée. Évitez d''ajouter du sucre raffiné et privilégiez le yaourt nature sans matières grasses si vous surveillez également votre apport en lipides."]'::jsonb, '["أول حاجة، عبر 125 غرام ديال دانون طبيعي كامل الدسم بالضبط. تأكد يكون بارد ومفيهش سكر ولا نكهات. خوي دانون فزلافة متوسطة.","من بعد، وزن 20 غرام ديال الكركاع. هادي كتعادل تقريباً 5 حبات كاملين. إلا كان الكركاع كبير بزاف، تقدر تستعمل قل شوية. قطع الكركاع طريفات كبار بالموس، رد البال متطحنوش بزاف. خاص يبقاو طراف باينين باش يعطيو القرمشة.","زيد الكركاع اللي قطعتي على دانون فالزلافة. خلط غير بشوية بالمعلقة باش يتخلط مزيان.","رش من الفوق 1/2 معلقة صغيرة ديال القرفة مطحونة. القرفة ماشي غير بنينة، راها معروفة بالمنافع ديالها لتنظيم السكر فالدم.","زيد 1/4 معلقة صغيرة ديال زريعة الشيا. هاد الحبيبات الصغار غنيين بالألياف وكيساعدو باش تحس بالشبع، وهادشي مهم بزاف لفطور صحي.","إلا بغيتي شوية د الحلاوة الطبيعية، زيد 1 معلقة صغيرة ديال عسل الليمون الحر. خلط مزيان باش يتوزع العسل بالتساوي. هاد الخطوة اختيارية وتقدر تستغنى عليها إلا كنتي كتبغي المذاق مسوس تماماً.","قدمو بالصحة والراحة دغيا باش تستمتع بالمذاق الكريمي ديال دانون والقرمشة ديال الكركاع. هاد الفطور مثالي باش تبدا نهارك بالطاقة وبلا ما يطلع ليك السكر.","💡 نصيحة للسكري: باش تحكم فمستوى السكر فالدم مزيان، كول هاد دانون طبيعي بالكركاع فبداية الوجبة. الكمية ديال 160 غرام (125 غرام دانون + 20 غرام كركاع + الإضافات) مناسبة تماماً. تجنب تزيد السكر المصنع وفضل دانون طبيعي بلا دهون إلا كنتي كترد البال حتى للدهون."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e1/Liat_Portal_for_Foodie_Disorder_-_Yogurt_Bowl_with_Figs%2C_Nuts%2C_Chia_Seeds%2C_and_Seaweed.jpg/1280px-Liat_Portal_for_Foodie_Disorder_-_Yogurt_Bowl_with_Figs%2C_Nuts%2C_Chia_Seeds%2C_and_Seaweed.jpg', ARRAY['yaourt', 'danone', 'دانون']::text[]),
  ('pain-complet-olive', 'Pain complet & huile d''olive', 'خبز كامل بزيت الزيتون', 'Whole-grain bread & olive oil', 'breakfast', ARRAY['ftour']::text[], '🫒', '¼ pain complet + 1 c.s. (95 g)', 95, 260, 30, 2, 6, 14, 5, 55, 'Le pain COMPLET (d''orge ou de blé entier) a 2× plus de fibres que le pain blanc : le sucre monte moins vite. L''huile d''olive ralentit encore l''absorption.', 'الخبز الكامل (ديال الشعير ولا القمح الكامل) فيه ضعف الألياف ديال الخبز الأبيض: السكر كيطلع بشوية. زيت الزيتون كتبطئ الامتصاص أكثر.', '["50 g de farine d''orge complète (ou blé entier)","25 ml d''eau tiède","2 g de levure boulangère fraîche","1 g de sel fin","5 ml d''huile d''olive extra vierge","1 pincée de graines de nigelle (facultatif)"]'::jsonb, '["50 غرام دقيق الشعير الكامل (أو القمح الكامل)","25 مل ماء دافئ","2 غرام خميرة الخبز الطرية","1 غرام ملح رقيق","5 مل زيت الزيتون البكر الممتاز","رشة حبة البركة (سانوج) (اختياري)"]'::jsonb, '["Dans un petit bol, mélanger l''eau tiède et la levure boulangère. Laisser reposer 5 minutes jusqu''à ce que la levure soit activée et forme une légère mousse à la surface.","Dans un grand saladier, mélanger la farine d''orge complète et le sel. Faire un puits au centre et y verser le mélange levure-eau.","Pétrir la pâte pendant environ 8 à 10 minutes sur un plan de travail légèrement fariné, jusqu''à obtenir une pâte souple et élastique. Si la pâte est trop collante, ajouter un tout petit peu de farine ; si elle est trop sèche, ajouter quelques gouttes d''eau.","Former une boule avec la pâte, la placer dans le saladier légèrement huilé, couvrir d''un linge propre et laisser lever dans un endroit chaud pendant environ 1 heure à 1 heure 30, ou jusqu''à ce qu''elle double de volume.","Dégazer délicatement la pâte en la pressant doucement. Sur un plan de travail légèrement fariné, étaler la pâte en un cercle d''environ 1 cm d''épaisseur. Saupoudrer de graines de nigelle si désiré.","Préchauffer le four à 200°C (Thermostat 6-7). Cuire le pain sur une plaque de cuisson recouverte de papier sulfurisé pendant 15 à 20 minutes, ou jusqu''à ce qu''il soit doré et sonne creux quand on le tapote par dessous.","💡 Astuce diabète : Pour cette portion de 95g (¼ du pain préparé + 1 c.s. d''huile d''olive), le pain complet aide à maintenir un indice glycémique bas (GI 55). Consommez-le avec des protéines ou des légumes pour ralentir davantage l''absorption du sucre. Évitez de le servir avec des confitures sucrées ou du miel."]'::jsonb, '["فزلافة صغيرة، خلط الماء الدافئ مع خميرة الخبز. خليها ترتاح 5 دقايق حتى تتفاعل الخميرة وتطلع رغوة خفيفة على الوجه.","فبانيو كبير، خلط دقيق الشعير الكامل والملح. دير حفرة فالوسط وخوي فيها خليط الخميرة والماء.","دلك العجينة لمدة 8 حتى 10 دقايق على سطح مرشوش بالدقيق، حتى تولي رطبة ومطاطية. إذا كانت العجينة كتلصق بزاف، زيد شوية دقيق؛ وإذا كانت ناشفة، زيد قطرات ماء.","جمع العجينة على شكل كرة، حطها فالبانيو مدهون شوية بالزيت، غطيها بفوطة نقية وخليها تخمر فمكان دافئ لمدة ساعة حتى ساعة ونص، أو حتى يتضاعف الحجم ديالها.","خرج الهواء من العجينة غير بشوية. على سطح مرشوش بالدقيق، بسط العجينة على شكل دائرة بسمك 1 سم تقريبا. رش عليها حبة البركة (السانوج) إذا بغيتي.","سخن الفران على 200 درجة مئوية. طيب الخبز فصينية عليها ورق الطهي لمدة 15 حتى 20 دقيقة، أو حتى يولي ذهبي ويخرج صوت أجوف ملي تخبط عليه من التحت.","💡 نصيحة للسكري: بالنسبة لهاد الحصة ديال 95 غرام (ربع الخبزة اللي وجدتي + معلقة كبيرة زيت الزيتون)، الخبز الكامل كيساعد باش تحافظ على مؤشر سكري منخفض (GI 55). كولها مع البروتينات أو الخضروات باش تبطأ امتصاص السكر أكثر. تجنب تقدمها مع المربى الحلو أو العسل."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/53/Roman_Army_Bread_-_Ingredients_%2812119594175%29.jpg/1280px-Roman_Army_Bread_-_Ingredients_%2812119594175%29.jpg', ARRAY['khobz chair', 'pain orge', 'خبز الشعير']::text[]),
  ('fromage-concombre', 'Fromage frais & concombre', 'جبن طري مع الخيار', 'Fresh cheese & cucumber', 'breakfast', ARRAY['ftour']::text[], '🧀', '100 g fromage + ½ concombre', 200, 160, 8, 6, 12, 9, 1, 20, 'Petit-déjeuner salé quasi sans glucides : idéal quand la glycémie du matin est déjà haute. Protéines rassasiantes, fraîcheur du concombre.', 'فطور مالح تقريباً بلا نشويات: مثالي ملي كيكون السكر ديال الصباح مرتفع. البروتين كيشبع والخيار منعش.', '["100 g de fromage frais nature (type جبن طري)","½ concombre (environ 200 g)","1 cuillère à café d''huile d''olive extra vierge","½ cuillère à café de menthe fraîche hachée finement","¼ cuillère à café de cumin moulu","Une pincée de sel de mer","Une pincée de poivre noir fraîchement moulu"]'::jsonb, '["100 غرام جبن طري طبيعي","نصف خيارة (حوالي 200 غرام)","1 ملعقة صغيرة زيت الزيتون البكر الممتاز","نصف ملعقة صغيرة نعناع طري مفروم رقيق","ربع ملعقة صغيرة كمون مطحون","رشة ملح بحري","رشة إبزار أسود مطحون طري"]'::jsonb, '["1. Lavez soigneusement le demi-concombre sous l''eau froide. Il n''est pas nécessaire de le peler si la peau est fine et bio, car elle contient des fibres bénéfiques. Coupez les extrémités.","2. À l''aide d''un couteau bien aiguisé ou d''une mandoline, coupez le concombre en fines rondelles ou en petits dés, selon votre préférence. Pour une texture plus croquante, les dés sont idéaux.","3. Dans un petit bol, déposez les 100 g de fromage frais nature. Assurez-vous qu''il soit à température ambiante pour une meilleure incorporation des saveurs, sortez-le 10 minutes avant.","4. Ajoutez au fromage frais la ½ cuillère à café de menthe fraîche finement hachée, le ¼ cuillère à café de cumin moulu, la pincée de sel de mer et la pincée de poivre noir fraîchement moulu. Mélangez délicatement avec une petite cuillère jusqu''à ce que les épices soient bien réparties.","5. Incorporez les dés ou les rondelles de concombre coupés dans le bol avec le fromage épicé. Mélangez doucement pour ne pas écraser le concombre, juste assez pour qu''il soit enrobé de fromage.","6. Versez la 1 cuillère à café d''huile d''olive extra vierge sur le mélange juste avant de servir. Cela ajoute une touche de saveur et de bons gras essentiels.","7. Servez immédiatement dans une petite assiette. Ce plat est idéal pour le petit-déjeuner. Vous pouvez l''accompagner d''une petite tranche de pain complet grillé (environ 30g) si votre glycémie le permet. Ne pas dépasser la portion recommandée pour maintenir un bon contrôle glycémique.","💡 Astuce diabète : Pour un contrôle optimal de la glycémie, consommez d''abord le fromage frais et le concombre. Les protéines et les fibres aideront à ralentir l''absorption des glucides si vous ajoutez une petite portion de pain complet. La portion recommandée est de 100g de fromage et ½ concombre (200g), pour un apport d''environ 8g de glucides et un IG très bas de 20."]'::jsonb, '["1. غسل نصف الخيارة مزيان تحت الماء البارد. ماشي ضروري تقشرها إذا كانت القشرة رقيقة وعضوية، حيت فيها ألياف مفيدة. قطع الأطراف.","2. باستعمال موس ماضي مزيان أو آلة تقطيع، قطع الخيار دوائر رقاق أو مكعبات صغار، على حسب شنو كتفضل. باش تكون القرمشة أكثر، المكعبات هما الأفضل.","3. في زلافة صغيرة، حط 100 غرام ديال الجبن الطري الطبيعي. تأكد أنه يكون بدرجة حرارة الغرفة باش يتخلطو النكهات مزيان، خرجه 10 دقائق قبل.","4. ضف للجبن الطري نصف ملعقة صغيرة ديال النعناع الطري مقطع رقيق، ربع ملعقة صغيرة ديال الكمون مطحون، رشة ملح بحري ورشة إبزار أسود مطحون طري. خلط بلطف بملعقة صغيرة حتى يتوزعوا التوابل مزيان.","5. خلط مكعبات أو دوائر الخيار المقطعة مع الجبن المتبل في الزلافة. خلط غير بشوية باش ما يتفرش الخيار، غير القياس باش يتغطى بالجبن.","6. صب ملعقة صغيرة ديال زيت الزيتون البكر الممتاز فوق الخليط قبل التقديم مباشرة. هادشي كيزيد لمسة ديال المذاق ودهون صحية ضرورية.","7. قدم الطبق مباشرة في طبق صغير. هاد الطبق مثالي للفطور. ممكن ترافقه بقطعة صغيرة ديال الخبز الكامل محمر (حوالي 30 غرام) إذا كانت نسبة السكر في الدم ديالك كتسمح. ما تفوتش الكمية الموصى بها باش تحافظ على تحكم جيد في نسبة السكر.","💡 نصيحة للسكري: باش تتحكم مزيان في نسبة السكر في الدم، كل الجبن الطري والخيار هو الأول. البروتينات والألياف غيعاونو باش يتباطأ امتصاص الكربوهيدرات إذا زدتي كمية صغيرة ديال الخبز الكامل. الكمية الموصى بها هي 100 غرام جبن ونصف خيارة (200 غرام)، باش يكون المدخول حوالي 8 غرام كربوهيدرات ومؤشر سكري منخفض جداً (20)."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5a/Liat_Portal_for_Foodie_Disorder_-_Cottage_cheese_and_vegetables_on_rice_cakes.jpg/1280px-Liat_Portal_for_Foodie_Disorder_-_Cottage_cheese_and_vegetables_on_rice_cakes.jpg', ARRAY['jben', 'جبن']::text[]),
  ('msemen-complet-light', 'Msemen à la farine complète (léger)', 'مسمن بالدقيق الكامل (خفيف)', 'Whole-wheat msemen (light)', 'breakfast', ARRAY['ftour', 'snack']::text[], '🫓', '1 pièce fine (70 g)', 70, 170, 22, 1, 5, 7, 3, 55, 'La version complète et FINE du msemen : moitié moins de gras, fibres doublées. Un plaisir marocain qui reste possible — une seule pièce, sans miel.', 'النسخة الكاملة والرقيقة ديال المسمن: نص الدهون وضعف الألياف. متعة مغربية ممكنة — وحدة برك، وبلا عسل.', '["50 g de farine de blé complète (T150)","20 g de semoule de blé fine complète","1/4 c. à café de levure boulangère sèche","1 pincée de sel","40 ml d''eau tiède (environ)","1 c. à café d''huile d''olive","1/2 c. à café de semoule de blé fine pour le façonnage"]'::jsonb, '["50 غرام دقيق القمح الكامل (T150)","20 غرام سميدة رقيقة كاملة","1/4 ملعقة صغيرة خميرة الخبز الجافة","قبيصة ملح","40 مل ماء دافئ (تقريبا)","1 ملعقة صغيرة زيت الزيتون","1/2 ملعقة صغيرة سميدة رقيقة للتوريق"]'::jsonb, '["Dans un grand bol, mélangez 50 g de farine de blé complète, 20 g de semoule de blé fine complète, 1/4 c. à café de levure boulangère sèche et une pincée de sel. Faites un puits au centre.","Versez progressivement 40 ml d''eau tiède dans le puits et commencez à pétrir. Continuez de pétrir pendant 5 à 7 minutes jusqu''à obtenir une pâte souple et homogène. Si la pâte est trop sèche, ajoutez un filet d''eau ; si elle est trop collante, ajoutez une pincée de farine.","Badigeonnez la pâte avec 1 c. à café d''huile d''olive, couvrez le bol d''un film alimentaire ou d''un torchon propre et laissez reposer pendant 30 minutes à température ambiante. Cela permet à la pâte de se détendre.","Sur un plan de travail légèrement huilé, divisez la pâte en une seule petite boule d''environ 70 g. Étalez cette boule très finement avec la paume de votre main et le bout des doigts pour former un cercle presque transparent. Plus la pâte est fine, plus le msemen sera léger.","Saupoudrez légèrement la surface de la pâte étalée avec 1/2 c. à café de semoule de blé fine. Pliez la pâte en trois, comme une lettre : ramenez un côté vers le centre, puis l''autre côté par-dessus. Ensuite, pliez les deux extrémités vers le centre pour former un carré.","Faites chauffer une poêle antiadhésive à feu moyen. Une fois chaude, déposez délicatement le msemen plié. Laissez cuire 2 à 3 minutes de chaque côté, jusqu''à ce qu''il soit doré et gonflé. Retournez-le plusieurs fois pour une cuisson uniforme.","Servez le msemen chaud. 💡 Astuce diabète : Pour contrôler votre glycémie, consommez une seule pièce de ce msemen (70 g, environ 170 kcal, 22 g de glucides, GI 55) et accompagnez-le de légumes frais ou d''une source de protéines maigres (comme un œuf brouillé) plutôt que de miel ou de confiture. Mangez les fibres et les protéines en premier."]'::jsonb, '["فواحد الإناء كبير، خلط 50 غرام دقيق القمح الكامل، 20 غرام سميدة رقيقة كاملة، 1/4 ملعقة صغيرة خميرة الخبز الجافة وقبيصة ملح. دير حفرة فالوسط.","صب بشوية 40 مل ماء دافئ فالحفرة وبدا تدلك. كمل الدليك لمدة 5 حتى 7 دقايق حتى تولي العجينة رطبة ومتجانسة. إذا كانت العجينة ناشفة بزاف، زيد شوية ماء؛ وإذا كانت كتلصق بزاف، زيد قبيصة دقيق.","دهن العجينة بـ 1 ملعقة صغيرة زيت الزيتون، غطي الإناء ببلاستيك غذائي أو منديل نقي وخليه يرتاح لمدة 30 دقيقة فدرجة حرارة الغرفة. هادشي كيخلي العجينة ترخف.","فوق سطح عمل مدهون شوية بالزيت، قسم العجينة لكويرة صغيرة وحدة وزنها حوالي 70 غرام. بسط هاد الكويرة رقيقة بزاف براحة يدك ورؤوس الأصابع باش تشكل دائرة شبه شفافة. كلما كانت العجينة رقيقة، كلما كان المسمن خفيف.","رش شوية على سطح العجينة المبسوطة بـ 1/2 ملعقة صغيرة سميدة رقيقة. طوي العجينة على ثلاثة، بحال شي رسالة: جيب طرف للوسط، عاد الطرف الآخر فوقو. من بعد، طوي الأطراف بجوج للوسط باش تشكل مربع.","سخن مقلاة ماكتلصقش على نار متوسطة. ملي تسخن، حط المسمن المطوي بشوية. خليه يطيب 2 حتى 3 دقايق من كل جهة، حتى يتحمر ويتنفخ. قلبو عدة مرات باش يطيب مزيان من كل الجوانب.","قدم المسمن سخون. 💡 نصيحة للسكري: باش تحافظ على مستوى السكر في الدم، كل قطعة وحدة من هاد المسمن (70 غرام، تقريبا 170 سعرة حرارية، 22 غرام كربوهيدرات، مؤشر سكري 55) ورافقها بخضراوات طازجة أو مصدر بروتين قليل الدهن (بحال بيضة مخفوقة) بلا عسل أو كونفيتور. كل الألياف والبروتينات هي الأولى."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/98/Msemmen-Ghrayef.jpg/1280px-Msemmen-Ghrayef.jpg', ARRAY['msemen sain']::text[]),
  ('harcha-avoine', 'Harcha à l''avoine', 'حرشة بالشوفان', 'Oat harcha', 'breakfast', ARRAY['ftour', 'snack']::text[], '🌕', '1 pièce (80 g)', 80, 190, 24, 2, 6, 8, 4, 50, 'La harcha revisitée : moitié semoule, moitié flocons d''avoine. Même goût du bled, mais l''IG chute de 65 à 50 et les fibres doublent. Avec jben, pas avec miel.', 'الحرشة بطريقة جديدة: نص سميدة ونص شوفان. نفس ذوق البلاد، ولكن المؤشر كيهبط من 65 ل50 والألياف كتضاعف. مع الجبن، ماشي مع العسل.', '["40 g de semoule de blé dur fine","40 g de flocons d''avoine fins","1/4 c. à café de sel","1/4 c. à café de levure chimique","15 ml d''huile d''olive extra vierge","50 ml d''eau tiède (environ)","5 g de beurre (pour la cuisson, facultatif)"]'::jsonb, '["40 غرام سميدة رقيقة","40 غرام شوفان رقيق","ربع معلقة صغيرة ملح","ربع معلقة صغيرة خميرة الحلوى","15 مل زيت الزيتون بكر ممتاز","50 مل ماء دافئ (تقريبا)","5 غرام زبدة (للطياب، اختياري)"]'::jsonb, '["Dans un grand bol, mélangez la semoule de blé dur fine, les flocons d''avoine, le sel et la levure chimique. Assurez-vous que les ingrédients secs sont bien combinés.","Ajoutez l''huile d''olive aux ingrédients secs. Frottez le mélange entre vos paumes pendant 2-3 minutes jusqu''à ce que l''huile soit uniformément répartie et que le mélange ressemble à du sable mouillé. Cette étape est cruciale pour une harcha tendre.","Incorporez progressivement l''eau tiède, cuillère par cuillère, en mélangeant délicatement avec le bout des doigts. N''ajoutez pas toute l''eau d''un coup. La pâte doit être molle et légèrement collante, mais pas liquide. Laissez-la reposer 5 minutes pour que l''avoine et la semoule absorbent l''eau.","Pendant que la pâte repose, préchauffez une poêle antiadhésive à feu moyen. Si vous utilisez du beurre, faites-le fondre et étalez-le légèrement dans la poêle.","Farinez légèrement vos mains avec un peu de semoule fine ou de flocons d''avoine. Prélevez toute la pâte (pour une portion de 80g) et formez une boule. Aplatissez-la délicatement entre vos paumes pour obtenir un disque d''environ 1 cm d''épaisseur et 10-12 cm de diamètre.","Déposez la harcha dans la poêle chaude. Laissez cuire à feu moyen-doux pendant 6-8 minutes de chaque côté, ou jusqu''à ce qu''elle soit dorée et bien cuite. Surveillez attentivement pour éviter qu''elle ne brûle.","💡 Astuce diabète : Servez votre harcha à l''avoine (1 pièce de 80g) tiède, accompagnée de jben (fromage frais marocain) ou d''avocat. Évitez absolument le miel ou la confiture. Pour une meilleure gestion de la glycémie, consommez d''abord une source de protéines et de fibres (comme le jben) avant de manger la harcha."]'::jsonb, '["فزلافة كبيرة، خلطو السميدة الرقيقة، الشوفان الرقيق، الملحة وخميرة الحلوى. تأكدو بلي المكونات الجافة تخلطو مزيان.","زيدو زيت الزيتون على المكونات الجافة. حكو الخليط بين يديكم لمدة 2-3 دقايق حتى يتوزع الزيت بالتساوي ويولي الخليط بحال الرملة فازكة. هاد الخطوة مهمة باش تجي الحرشة رطبة.","زيدو الماء دافئ شوية بشوية، معلقة بمعلقة، وخلطو غير برؤوس الأصابع. ماتزيدوش الماء كامل فدقة وحدة. العجينة خاصها تكون رطبة وتلصق شوية، ولكن ماشي جارية. خليوها ترتاح 5 دقايق باش الشوفان والسميدة يشربو الماء.","فالوقت اللي العجينة كترتاح، سخنو مقلة ماكتلصقش على نار متوسطة. إلا كنتو غتستعملو الزبدة، ذوبوها ودهنو بيها المقلاة خفيف.","رشو يديكم بشوية سميدة رقيقة أو شوفان. خدو العجينة كاملة (للقياس ديال 80 غرام) وشكلوها كرة. بسطوها بلطف بين يديكم باش تحصلو على قرص بسمك 1 سم تقريبا وقطر 10-12 سم.","حطو الحرشة فالمقلة السخونة. خليوها طيب على نار متوسطة-مهيلة لمدة 6-8 دقايق من كل جهة، أو حتى تولي ذهبية ومطيبة مزيان. ردو البال باش ماتحرقش.","💡 نصيحة للسكري: قدمو الحرشة ديال الشوفان (قطعة وحدة 80 غرام) دافية، مع الجبن البلدي أو لافوكا. تجنبو تماما العسل أو الكونفيتير. باش تحكمو فمستوى السكر فالدم أحسن، كولو أولا مصدر ديال البروتين والألياف (بحال الجبن) قبل ماتكلو الحرشة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/aa/Harcha_%28Homemade%29.jpg/1280px-Harcha_%28Homemade%29.jpg', ARRAY['harcha', 'حرشة صحية']::text[]),
  ('batbout-complet', 'Batbout complet (mini)', 'بطبوط بالقمح الكامل (صغير)', 'Whole-wheat mini batbout', 'breakfast', ARRAY['ftour', 'snack']::text[], '🫓', '1 mini (50 g)', 50, 120, 22, 1, 4, 1.5, 3, 55, 'Le batbout cuit à la poêle (sans friture) en version farine complète et format MINI : le plaisir du pain marocain chaud, en portion qui ne fait pas exploser la glycémie.', 'البطبوط مطيب فالمقلة (بلا قلي) بالدقيق الكامل وبحجم صغير: متعة الخبز المغربي السخون، بكمية ما كتفجرش السكر.', '["25 g de farine de blé complet (T150)","25 g de semoule de blé extra-fine (finot)","2 g de levure boulangère fraîche","1 g de sel fin","30 ml d''eau tiède (environ)","1/2 c. à café d''huile d''olive (pour le pétrissage/façonnage)"]'::jsonb, '["25 غرام دقيق القمح الكامل (T150)","25 غرام سميدة رقيقة بزاف (فينو)","2 غرام خميرة الخبز طرية","1 غرام ملح رقيق","30 ملل ماء دافئ (تقريبا)","1/2 ملعقة صغيرة زيت الزيتون (للعجن والتشكيل)"]'::jsonb, '["1. Dans un grand bol, mélangez la farine de blé complet, la semoule extra-fine et le sel. Émiettez la levure fraîche dans un petit creux au centre.","2. Ajoutez progressivement l''eau tiède (environ 30 ml) en pétrissant. La pâte doit être souple et légèrement collante. Pétrissez pendant 5 à 7 minutes jusqu''à obtenir une pâte homogène et élastique. Vous pouvez ajouter une goutte d''huile d''olive pour faciliter le pétrissage si nécessaire.","3. Couvrez le bol d''un linge propre et laissez la pâte lever dans un endroit chaud pendant environ 45 minutes à 1 heure, ou jusqu''à ce qu''elle double de volume.","4. Dégazez délicatement la pâte en la pressant légèrement. Sur un plan de travail légèrement fariné avec de la semoule extra-fine, étalez la pâte sur une épaisseur d''environ 0,5 cm.","5. À l''aide d''un emporte-pièce rond (environ 5-6 cm de diamètre) ou d''un verre, découpez des mini batbouts. Ramassez les chutes, pétrissez-les légèrement et ré-étalez pour découper d''autres batbouts.","6. Disposez les mini batbouts sur un linge propre fariné et couvrez-les. Laissez-les lever une seconde fois pendant 15 à 20 minutes, ils doivent gonfler légèrement.","7. Faites chauffer une poêle antiadhésive à feu moyen. Une fois chaude, déposez délicatement les mini batbouts sans ajouter de matière grasse. Laissez cuire 2 à 3 minutes de chaque côté, jusqu''à ce qu''ils soient dorés et gonflés. Retournez-les plusieurs fois pour une cuisson uniforme.","8. Servez les batbouts chauds. Ils peuvent être garnis de légumes grillés ou d''une petite quantité de fromage frais allégé.","💡 Astuce diabète : Ce batbout complet mini (50g) a un IG de 55. Pour maintenir une glycémie stable, consommez-le avec des protéines (œuf, fromage frais) et des fibres (légumes frais) pour ralentir l''absorption des glucides. Évitez de le tremper dans de l''huile ou de le garnir de confiture."]'::jsonb, '["1. فشي زلافة كبيرة، خلط الدقيق الكامل، السميدة الرقيقة بزاف والملح. فرتت خميرة الخبز الطرية فواحد الحفرة صغيرة فالوسط.","2. زيد الماء دافئ بشوية بشوية (تقريبا 30 ملل) وانت كتعجن. العجينة خاصها تكون رطبة وتلصق شوية. عجن لمدة 5 حتى ل 7 دقايق حتى تولي العجينة متجانسة ومطاطية. تقدر تزيد قطرة زيت الزيتون باش تسهل العجينة إذا لزم الأمر.","3. غطي الزلافة بشي منديل نقي وخلي العجينة تخمر فمكان دافئ لمدة 45 دقيقة حتى لساعة، ولا حتى يتضاعف الحجم ديالها.","4. حيد الهواء من العجينة غير بشوية بالضغط الخفيف. فوق سطح العمل مرشوش بالسميدة الرقيقة بزاف، سرح العجينة بسمك تقريبا 0.5 سم.","5. باستعمال قطاعة دائرية (قطرها تقريبا 5-6 سم) أو كاس، قطع البطبوط الصغير. جمع البقايا، عجنها شوية وعاود سرحها باش تقطع بطبوطات آخرين.","6. حط البطبوط الصغير فوق منديل نقي مرشوش بالسميدة وغطيه. خليه يخمر مرة ثانية لمدة 15 حتى ل 20 دقيقة، خاصو يتنفخ شوية.","7. سخن مقلة ماكتلصقش على نار متوسطة. ملي تسخن، حط البطبوط الصغير غير بشوية بلا ماتزيد الزيت. خليه يطيب 2 حتى ل 3 دقايق من كل جهة، حتى يتحمر ويتنفخ. قلبو عدة مرات باش يطيب بالتساوي.","8. قدم البطبوط سخون. تقدر تعمرو بخضرة مشوية أو بكمية قليلة من الفرماج الطري اللايت.","💡 نصيحة للسكري: هاد البطبوط الكامل الصغير (50 غرام) عندو مؤشر سكري 55. باش تحافظ على سكر الدم مستقر، كولوه مع البروتينات (بيض، فرماج طري) والألياف (خضروات طرية) باش تبطئ امتصاص الكربوهيدرات. تجنب تغماسو فالزيت أو تعمرو بالكونفيتير."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/13/Mini_batbout.jpg/1280px-Mini_batbout.jpg', ARRAY['batbout', 'بطبوط']::text[]),
  ('baghrir-amlou', 'Baghrir complet à l''amlou', 'بغرير كامل بأملو', 'Whole-wheat baghrir with amlou', 'breakfast', ARRAY['ftour']::text[], '🥞', '2 pièces + amlou (110 g)', 110, 230, 30, 4, 7, 9, 4, 55, 'Le baghrir en farine complète garde ses mille trous mais double ses fibres. Remplacez le miel (IG 58, sucre pur) par 1 c.c. d''amlou : bonnes graisses d''argan et d''amande qui aplatissent la glycémie.', 'البغرير بالدقيق الكامل كيحتفظ بألف ثقب ديالو وكيضاعف الألياف. عوض العسل (سكر صافي) بمعلقة صغيرة ديال أملو: دهون صحية ديال أركان واللوز كتهدن السكر.', '["100 g de semoule de blé complet fine","10 g de farine de blé complet","125 ml d''eau tiède","2 g de levure de boulanger sèche","1 pincée de sel","1/4 c. à café de levure chimique","1 c. à café d''amlou (environ 15 g)"]'::jsonb, '["100 غرام سميدة رقيقة كاملة","10 غرام دقيق القمح الكامل","125 ملل ماء دافئ","2 غرام خميرة خبز جافة","1 قبيصة ملح","1/4 ملعقة صغيرة خميرة حلويات","1 ملعقة صغيرة أملو (حوالي 15 غرام)"]'::jsonb, '["1. Dans un grand bol, mélangez la semoule de blé complet fine, la farine de blé complet, la levure de boulanger sèche et le sel.","2. Ajoutez progressivement l''eau tiède tout en mélangeant avec un fouet pour éviter les grumeaux. La pâte doit être lisse et légèrement liquide.","3. Incorporez la levure chimique et mélangez bien. Couvrez le bol d''un torchon propre et laissez reposer la pâte dans un endroit chaud pendant environ 30 à 45 minutes, jusqu''à ce qu''elle double de volume et que de petites bulles apparaissent à la surface.","4. Une fois la pâte levée, mélangez-la délicatement une dernière fois. Faites chauffer une poêle antiadhésive à feu moyen. Ne graissez pas la poêle pour le premier baghrir.","5. Versez une petite louche de pâte (environ 50 ml) au centre de la poêle chaude. La pâte va s''étaler d''elle-même. Des milliers de petits trous vont apparaître à la surface du baghrir.","6. Laissez cuire le baghrir sur un seul côté, sans le retourner, jusqu''à ce que toute la surface soit sèche et que les bords soient légèrement dorés (environ 2 à 3 minutes). Retirez le baghrir de la poêle et déposez-le sur un torchon propre pour qu''il refroidisse sans coller.","7. Répétez l''opération avec le reste de la pâte. Servez 2 pièces de baghrir tièdes avec 1 c. à café d''amlou. 💡 Astuce diabète : Pour une meilleure gestion de votre glycémie, consommez d''abord l''amlou riche en bonnes graisses et fibres, puis le baghrir. Le baghrir complet a un IG de 55, mais la portion de 110g (2 pièces) est contrôlée. Évitez de le servir avec du miel ou du sucre."]'::jsonb, '["1. في إناء كبير، خلطو السميدة الرقيقة الكاملة، دقيق القمح الكامل، خميرة الخبز الجافة والملح.","2. زيدو الماء الدافئ شوية بشوية ونتوما كتخلطو بالطراب باش ما يتكونوش كويرات. العجينة خاصها تكون رطبة وسائل شوية.","3. ضيفو خميرة الحلويات وخلطو مزيان. غطيو الإناء بفوطة نقية وخليو العجينة ترتاح فمكان دافئ لمدة 30 حتى 45 دقيقة تقريبا، حتى يتضاعف الحجم ديالها ويبانو فقاعات صغار على السطح.","4. منين تخمر العجينة، خلطوها غير بشوية مرة أخيرة. سخنو مقلة ما كتلصقش على نار متوسطة. ما دهنوش المقلة لأول بغريرة.","5. خويو مغرفة صغيرة من العجينة (حوالي 50 ملل) فوسط المقلة السخونة. العجينة غادا تسرح بوحدها. غادين يبانو آلاف الثقوب الصغار على سطح البغرير.","6. خليو البغرير يطيب على جهة وحدة، بلا ما تقلبوه، حتى ينشف السطح كامل ويوليو الجناب مذهبين شوية (حوالي 2 حتى 3 دقائق). حيدو البغرير من المقلة وحطوه فوق فوطة نقية باش يبرد بلا ما يلصق.","7. كملو بنفس الطريقة مع باقي العجينة. قدمو 2 حبات بغرير دافيين مع 1 ملعقة صغيرة أملو. 💡 نصيحة للسكري: باش تحكمو فمستوى السكر فالدم ديالكم بشكل أفضل، كولو الأملو الغني بالدهون الصحية والألياف هو الأول، عاد البغرير. البغرير الكامل عندو مؤشر سكري 55، ولكن الحصة ديال 110 غرام (2 حبات) مضبوطة. تجنبو تقدموه مع العسل أو السكر."]'::jsonb, null, ARRAY['baghrir', 'beghrir', 'بغرير']::text[]),
  ('byd-maticha', 'Œufs à la tomate (bid o maticha)', 'بيض بالمطيشة', 'Eggs with tomato (bid o maticha)', 'breakfast', ARRAY['ftour', '3cha']::text[], '🍳', '2 œufs + tomate (220 g)', 220, 240, 9, 6, 16, 15, 3, 20, 'Le déjeuner marocain classique de la khonza, version saine : tomates fondues, épices, 2 œufs. Protéines et lycopène, presque pas de glucides — un ftour qui tient jusqu’au déjeuner.', 'فطور مغربي كلاسيكي، بالنسخة الصحية: مطيشة ذايبة، عطرية، وجوج بيضات. بروتين وليكوبين، وتقريباً بلا نشويات — فطور كيشبع حتى للغدا.', '["220 g de tomates fraîches mûres (environ 2 tomates moyennes)","2 œufs de poule frais","1 c. à soupe d''huile d''olive extra vierge","1/4 c. à café de cumin moulu","1/4 c. à café de paprika doux","Une pincée de sel de mer","Une pincée de poivre noir fraîchement moulu","1 gousse d''ail (petite), hachée finement","1 c. à soupe de persil frais, haché"]'::jsonb, '["220 غرام مطيشة طايبة (حوالي 2 مطيشات متوسطين)","2 بيضات بلديين","1 معلقة كبيرة زيت الزيتون البكر الممتاز","1/4 معلقة صغيرة كمون مطحون","1/4 معلقة صغيرة تحميرة حلوة","قبيصة ملح البحر","قبيصة إبزار مطحون جديد","1 فص ثوم (صغير)، مفروم رقيق","1 معلقة كبيرة معدنوس طري، مقطع"]'::jsonb, '["Lavez les tomates et coupez-les en petits dés. Épluchez et hachez finement la gousse d''ail.","Dans une petite poêle antiadhésive (environ 20 cm de diamètre), versez 1 c. à soupe d''huile d''olive et faites chauffer à feu moyen pendant 30 secondes.","Ajoutez les dés de tomates et l''ail haché dans la poêle. Laissez mijoter à feu doux pendant environ 8-10 minutes, en remuant de temps en temps, jusqu''à ce que les tomates ramollissent et libèrent leur jus, formant une sauce épaisse.","Incorporez 1/4 c. à café de cumin, 1/4 c. à café de paprika, une pincée de sel et une pincée de poivre noir. Mélangez bien et laissez cuire encore 2 minutes pour que les épices libèrent leurs arômes.","À l''aide d''une cuillère, créez deux petits puits dans la sauce tomate. Cassez délicatement un œuf dans chaque puits.","Couvrez la poêle et laissez cuire à feu très doux pendant 4 à 6 minutes, ou jusqu''à ce que les blancs soient pris et les jaunes encore coulants (ou à votre convenance). Surveillez attentivement pour éviter de trop cuire les œufs.","Retirez du feu, parsemez de 1 c. à soupe de persil frais haché et servez immédiatement.","💡 Astuce diabète : Pour cette portion de 220 g, le plat est naturellement faible en glucides (environ 9 g) et riche en protéines. Mangez lentement et savourez chaque bouchée. Accompagnez-le d''une petite portion de pain complet (pas plus de 30 g) ou de crudités pour augmenter l''apport en fibres sans impacter la glycémie."]'::jsonb, '["غسل مطيشة وقطعها مكعبات صغار. قشر الثومة وقطعها رقيقة بزاف.","فمقلاة صغيرة ما كاتلصقش (قطرها حوالي 20 سم)، دير 1 معلقة كبيرة زيت الزيتون وسخنها على نار متوسطة لمدة 30 ثانية.","زيد مكعبات مطيشة والثومة المقطعة فالمقلاة. خليها طيب على نار مهيلة لمدة 8-10 دقايق، وحرك مرة مرة، حتى ترطاب مطيشة وتطلق الماء ديالها، وتولي صوص خاترة.","زيد 1/4 معلقة صغيرة كمون، 1/4 معلقة صغيرة تحميرة، قبيصة ملح وقبيصة إبزار. خلط مزيان وخليها طيب جوج دقايق آخرين باش تطلق العطرية البنة ديالها.","باستعمال معلقة، دير جوج حفيرات صغار فالصوص ديال مطيشة. هرّس بيضة فكل حفرة غير بشوية.","غطي المقلاة وخليها طيب على نار مهيلة بزاف لمدة 4 حتى 6 دقايق، أو حتى يطيب البيض الأبيض ويبقى الأصفر جاري (أو على حسب الرغبة ديالك). راقبها مزيان باش ما يطيبش البيض بزاف.","حيدها من فوق النار، رش عليها 1 معلقة كبيرة معدنوس مقطع وقدمها سخونة فالحين.","💡 نصيحة للسكري: هاد الطبق ديال 220 غرام قليل الكربوهيدرات (حوالي 9 غرام) وغني بالبروتينات. كل بشوية وتمتع بكل لقمة. ممكن تاكل معاه شوية خبز كامل (ماشي كثر من 30 غرام) أو خضرة خضرا باش تزيد الألياف بلا ما تأثر على السكر فالدم."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/18/Shakshuka_by_Calliopejen1.jpg/1280px-Shakshuka_by_Calliopejen1.jpg', ARRAY['oeufs tomate', 'chakchouka', 'بيض مطيشة']::text[]),
  ('chia-lben', 'Pudding de chia au lben', 'بودينغ الشيا باللبن', 'Chia pudding with lben', 'breakfast', ARRAY['ftour', 'snack']::text[], '🥣', '1 bol (200 g)', 200, 180, 16, 8, 8, 9, 8, 30, 'Les graines de chia gonflent et forment un gel de fibres solubles qui freine l’absorption du sucre. Préparé avec du lben marocain et quelques fruits rouges, un ftour rassasiant et frais.', 'حبوب الشيا كتنتفخ وكتكون جيل ديال الألياف اللي كيبطئ امتصاص السكر. محضر باللبن المغربي وشوية توت، فطور كيشبع ومنعش.', '["30 g de graines de chia","150 ml de lben (babeurre marocain)","50 g de fruits rouges frais (framboises, myrtilles)","1/2 c. à café d''extrait de vanille naturelle","1 pincée de cannelle en poudre","5 g d''amandes effilées grillées (facultatif)"]'::jsonb, '["30 غرام من بذور الشيا","150 مل من اللبن المغربي","50 غرام من الفواكه الحمراء الطازجة (توت العليق، توت أزرق)","1/2 ملعقة صغيرة من خلاصة الفانيليا الطبيعية","1 قبيصة قرفة مطحونة","5 غرام من اللوز إيفيلي محمر (اختياري)"]'::jsonb, '["1. Dans un bol de taille moyenne, versez les 30 g de graines de chia.","2. Ajoutez les 150 ml de lben marocain. Le lben doit être bien frais pour une meilleure texture.","3. Incorporez la 1/2 c. à café d''extrait de vanille naturelle et la pincée de cannelle en poudre. Mélangez bien le tout à l''aide d''une cuillère ou d''un fouet pour éviter la formation de grumeaux de chia.","4. Couvrez le bol et placez-le au réfrigérateur pendant au moins 4 heures, ou idéalement toute une nuit. Les graines de chia vont gonfler et absorber le lben pour former un gel épais et crémeux.","5. Le lendemain matin (ou après 4 heures), sortez le pudding du réfrigérateur. Mélangez-le à nouveau pour vérifier la consistance. Si le pudding est trop épais, vous pouvez ajouter une petite quantité de lben (environ 10-15 ml) et mélanger.","6. Versez le pudding de chia dans un bol de service individuel (environ 200 g). Disposez délicatement les 50 g de fruits rouges frais sur le dessus. Si vous le souhaitez, parsemez les 5 g d''amandes effilées grillées pour ajouter un peu de croquant.","7. Servez immédiatement pour le petit-déjeuner. Ce pudding est meilleur frais. 💡 Astuce diabète : Consommez ce pudding de chia (portion de 200g, GI 30) comme un petit-déjeuner complet. Les fibres des graines de chia et des fruits rouges ralentissent l''absorption du sucre. Évitez d''ajouter du miel ou du sucre, les fruits rouges apportent une douceur naturelle suffisante."]'::jsonb, '["1. فزلافة متوسطة الحجم، خوي 30 غرام ديال بذور الشيا.","2. زيد عليها 150 مل ديال اللبن المغربي. اللبن خاصو يكون بارد مزيان باش تجي القوام ديالو زوين.","3. ضيف 1/2 ملعقة صغيرة ديال خلاصة الفانيليا الطبيعية وقبيصة القرفة مطحونة. خلط كلشي مزيان بالمعلقة ولا بالطراب باش ماتكونش كويرات ديال الشيا.","4. غطي الزلافة ودخلها للثلاجة على الأقل 4 سوايع، ولا من الأحسن ليلة كاملة. بذور الشيا غادي تنفخ وتشرب اللبن وغادي تكون واحد الجيل غليظ وكريمي.","5. فالصباح الموالي (ولا من بعد 4 سوايع)، خرج البودينغ من الثلاجة. خلطو مرة أخرى باش تشوف القوام ديالو. إلا جاك البودينغ غليظ بزاف، تقدر تزيد شوية ديال اللبن (تقريبا 10-15 مل) وتخلط.","6. خوي البودينغ ديال الشيا فزلافة ديال التقديم فردية (تقريبا 200 غرام). حط الفواكه الحمراء الطازجة (50 غرام) فوق منو بشوية. إلا بغيتي، رش 5 غرام ديال اللوز إيفيلي محمر باش تزيد شوية ديال القرمشة.","7. قدمو مباشرة للفطور. هاد البودينغ كيجي بنين وهو بارد. 💡 نصيحة للسكري: تناول بودينغ الشيا هذا (حصة 200 غرام، مؤشر جلايسيمي 30) كفطور كامل. الألياف اللي فبذور الشيا والفواكه الحمراء كاتباطئ امتصاص السكر. تجنب إضافة العسل أو السكر، الفواكه الحمراء كافية باش تعطي الحلاوة الطبيعية."]'::jsonb, null, ARRAY['chia', 'شيا']::text[]),
  ('avocat-toast-complet', 'Toast complet à l’avocat', 'خبز كامل بالأفوكادو', 'Whole-grain avocado toast', 'breakfast', ARRAY['ftour', 'snack']::text[], '🥑', '1 tranche + ½ avocat (120 g)', 120, 230, 20, 2, 7, 14, 6, 45, 'Une tranche de pain complet (IG bas), ½ avocat écrasé et un œuf : fibres + bonnes graisses + protéines, le trio qui garde la glycémie plate. Bien mieux que pain blanc + confiture.', 'شريحة خبز كامل (مؤشر منخفض)، نص أفوكادو مهروس وبيضة: ألياف + دهون صحية + بروتين، الثلاثي اللي كيخلي السكر مستقر. أحسن بزاف من خبز أبيض + كونفيتور.', '["1 tranche (40 g) de pain complet au levain","½ avocat mûr (120 g)","1 œuf de poule (60 g)","1 c. à café d''huile d''olive extra vierge","1 pincée de sel fin","1 pincée de poivre noir fraîchement moulu","Quelques feuilles de coriandre fraîche (pour la garniture)"]'::jsonb, '["1 طريف (40 غ) ديال خبز كامل بالخميرة البلدية","½ أفوكا طايبة (120 غ)","1 بيضة (60 غ)","1 معلقة صغيرة ديال زيت الزيتون البكر الممتاز","1 قبيصة ديال الملحة الرقيقة","1 قبيصة ديال البزار مطحون جديد","شوية ديال القزبور طري (للتزيين)"]'::jsonb, '["1. Préparez l''avocat : Coupez le demi-avocat en deux, retirez le noyau et prélevez la chair à l''aide d''une cuillère. Dans un petit bol, écrasez la chair d''avocat à la fourchette jusqu''à obtenir une consistance crémeuse mais avec quelques morceaux. Salez et poivrez légèrement (environ ¼ de pincée de chaque).","2. Préparez l''œuf poché : Remplissez une petite casserole d''eau et portez à frémissement (pas à gros bouillons) sur feu moyen. Cassez l''œuf dans un petit ramequin. À l''aide d''une cuillère, créez un léger tourbillon dans l''eau frémissante et déposez délicatement l''œuf au centre. Laissez cuire pendant 3 à 4 minutes pour un jaune coulant, ou plus longtemps si vous préférez un jaune plus ferme. Retirez l''œuf avec une écumoire et égouttez-le sur du papier absorbant.","3. Toastez le pain : Pendant que l''œuf cuit, faites griller la tranche de pain complet au grille-pain ou dans une poêle sèche sur feu moyen pendant 2 à 3 minutes de chaque côté, jusqu''à ce qu''elle soit dorée et croustillante.","4. Assemblez le toast : Sur la tranche de pain grillée, étalez généreusement l''avocat écrasé.","5. Ajoutez l''œuf : Déposez délicatement l''œuf poché sur l''avocat.","6. Finition et assaisonnement : Arrosez l''œuf et l''avocat d''une cuillère à café d''huile d''olive extra vierge. Salez et poivrez le tout avec le reste des pincées de sel et de poivre.","7. Garnissez et servez : Ciselez quelques feuilles de coriandre fraîche et parsemez-les sur le toast. Servez immédiatement.","💡 Astuce diabète : Pour maintenir une glycémie stable, savourez ce toast complet à l''avocat et à l''œuf en commençant par l''œuf et l''avocat riches en protéines et bonnes graisses. La portion est de 1 tranche de pain (40g) et ½ avocat (120g) pour un IG bas de 45. Évitez d''ajouter des sauces sucrées ou des confitures."]'::jsonb, '["1. وجد الأفوكا: قسم نص أفوكا على جوج، حيد العظم، وخرج اللب بالمعلقة. فزلافة صغيرة، معس اللب بالفرشيطة حتى يولي كريمي ولكن يبقى فيه شوية ديال الطراف. زيد عليه شوية ديال الملحة والبزار (تقريبا ربع قبيصة من كل واحد).","2. وجد البيضة بوشي: عمر كاسرونة صغيرة بالماء وخليها تسخن حتى تبدا تغلي بشوية (ماشي بزاف) على نار متوسطة. هرّس البيضة فزلافة صغيرة. بالمعلقة، دير دوامة صغيرة فالماء اللي كيغلي وحط البيضة غير بشوية فالوسط. خليها طيب من 3 حتى لـ 4 دقايق باش يبقى الصفر جاري، ولا كثر إلا كنتي كتبغيه قاصح. حيد البيضة بالشبكة وصفيها فوق ورق النشاف.","3. حمر الخبز: فاش تكون البيضة كطيب، حمر طريف الخبز الكامل فالمحمصة (grille-pain) ولا فمقلاة ناشفة على نار متوسطة لمدة 2 حتى لـ 3 دقايق من كل جهة، حتى يولي مذهب ومقرمش.","4. جمع الطوست: فوق طريف الخبز المحمر، دهن الأفوكا اللي معستي مزيان.","5. زيد البيضة: حط البيضة بوشي غير بشوية فوق الأفوكا.","6. اللمسة الأخيرة والتتبيل: رش البيضة والأفوكا بمعلقة صغيرة ديال زيت الزيتون البكر الممتاز. زيد عليهم اللي بقى من الملحة والبزار.","7. زين وقدم: قطع شوية ديال القزبور طري ورشو فوق الطوست. قدمو مباشرة.","💡 نصيحة للسكري: باش تحافظ على مستوى السكر في الدم مستقر، استمتع بهذا الطوست الكامل بالأفوكادو والبيض ببدء الأكل بالبيض والأفوكادو الغنيين بالبروتين والدهون الصحية. الحصة هي 1 طريف خبز (40 غ) و ½ أفوكا (120 غ) لمؤشر سكري منخفض (GI 45). تجنب إضافة الصلصات الحلوة أو المربى."]'::jsonb, null, ARRAY['avocado toast', 'توست أفوكادو']::text[]),
  ('zaalouk', 'Zaalouk d''aubergines', 'زعلوك الدنجال', 'Eggplant zaalouk', 'salad', ARRAY['ghda', '3cha']::text[], '🍆', '1 portion (200 g)', 200, 120, 12, 6, 3, 7, 5, 30, 'Star marocaine anti-diabète : IG très bas, riche en fibres qui freinent le sucre. L''aubergine est l''un des légumes les plus recommandés aux diabétiques.', 'النجم المغربي ضد السكري: مؤشر جلايسيمي منخفض بزاف، عامر بالألياف اللي كتوقف السكر. الدنجال من أحسن الخضرة للسكري.', '["200 g d''aubergine (environ 1 petite)","1 tomate moyenne (environ 100 g)","1/2 poivron vert (environ 50 g)","1 gousse d''ail","1 c. à soupe d''huile d''olive extra vierge","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","Une pincée de sel de mer","Une pincée de poivre noir"]'::jsonb, '["200 غرام دنجال (حبة صغيرة تقريبا)","1 مطيشة متوسطة (تقريبا 100 غرام)","1/2 فلفلة خضرا (تقريبا 50 غرام)","1 فص ثومة","1 م.ك زيت الزيتون البكر الممتاز","1/2 م.ص كامون مطحون","1/4 م.ص تحميرة حلوة","قبيصة ملح البحر","قبيصة إبزار كحل"]'::jsonb, '["1. Préchauffez le four à 200°C (Thermostat 6-7). Lavez l''aubergine, la tomate et le poivron. Coupez l''aubergine en deux dans le sens de la longueur, puis faites des incisions en croisillons sur la chair sans percer la peau. Badigeonnez légèrement avec 1/2 c. à café d''huile d''olive.","2. Placez l''aubergine coupée, la tomate entière et le poivron entier sur une plaque de cuisson recouverte de papier sulfurisé. Enfournez pour 25-30 minutes, ou jusqu''à ce que les légumes soient tendres et légèrement rôtis. La peau de l''aubergine doit être fripée et la chair très molle.","3. Une fois les légumes rôtis, sortez-les du four. Laissez-les tiédir quelques minutes. Pelez délicatement la peau de l''aubergine, de la tomate et du poivron. Jetez les graines du poivron et de la tomate.","4. Hachez finement la chair de l''aubergine, de la tomate et du poivron. Écrasez la gousse d''ail. Vous pouvez utiliser une fourchette pour écraser les légumes afin d''obtenir une texture rustique.","5. Dans une petite casserole ou une poêle à bords hauts, versez le reste de l''huile d''olive (1/2 c. à café). Ajoutez l''ail écrasé et faites-le revenir à feu doux pendant 30 secondes, juste pour qu''il libère son parfum sans brûler.","6. Ajoutez les légumes hachés dans la casserole. Incorporez le cumin, le paprika, le sel et le poivre. Mélangez bien et laissez mijoter à feu doux pendant 5-7 minutes, en remuant de temps en temps, jusqu''à ce que l''eau des légumes s''évapore et que le zaalouk épaississe légèrement.","7. Servez le zaalouk tiède ou froid. Il peut être garni d''un filet d''huile d''olive fraîche et de persil frais haché (facultatif).","💡 Astuce diabète : Cette portion de 200 g de Zaalouk est parfaite pour un diabétique (IG 30). Consommez-la en entrée ou en accompagnement d''une protéine maigre (poulet grillé, poisson) et de céréales complètes (quinoa, boulgour) en quantité contrôlée. Évitez de le servir avec du pain blanc ; préférez une petite quantité de pain complet ou des crudités pour tremper."]'::jsonb, '["1. سخّن الفران على 200 درجة مئوية. غسل الدنجال، مطيشة والفلفلة. قطع الدنجال على جوج بالطول، ودير فيه فليحات على شكل مربعات بالسكين بلا ما تقطع القشرة. دهنو بشوية زيت الزيتون (1/2 م.ص).","2. حط الدنجال مقطع، مطيشة صاينة والفلفلة صاينة فصينية ديال الفران مفرشة بورق الطبخ. دخلهم للفران لمدة 25-30 دقيقة، ولا حتى يولي الخضرة رطبة ومحمّرة شوية. خاص قشرة الدنجال تكون مجعدة والداخل ديالو رطب بزاف.","3. ملي طيب الخضرة، خرجها من الفران. خليها تبرد شوية. قشر الدنجال، مطيشة والفلفلة بعناية. حيد الزريعة من الفلفلة ومطيشة.","4. قطع اللب ديال الدنجال، مطيشة والفلفلة رقيق. هرّس فص الثومة. تقدر تستعمل فرشيطة باش تهرس الخضرة باش تجيك المذاق بلدي.","5. فكاسرونة صغيرة ولا مقلة عندها الجناب طالعين، دير زيت الزيتون اللي بقى (1/2 م.ص). زيد الثومة مهرسة وخليها تقلى على نار مهيلة لمدة 30 ثانية، غير باش تطلق ريحتها بلا ما تحرق.","6. زيد الخضرة مقطعة ف الكاسرونة. زيد الكامون، التحميرة، الملحة والإبزار. خلط مزيان وخليها طيب على نار مهيلة لمدة 5-7 دقائق، وحرك مرة مرة، حتى ينشف الماء ديال الخضرة ويتقال الزعلوك شوية.","7. قدم الزعلوك دافئ ولا بارد. تقدر تزينو بشوية زيت الزيتون جديدة ومعدنوس مقطع رقيق (اختياري).","💡 نصيحة للسكري: هاد الكمية ديال 200 غرام ديال الزعلوك مثالية لمرضى السكري (المؤشر الجلايسيمي 30). كولها كمقبلة ولا مع بروتين قليل الدهون (دجاج مشوي، حوت) وحبوب كاملة (كينوا، برغل) بكمية مضبوطة. تجنب تقدمها مع الخبز الأبيض؛ من الأفضل كمية قليلة من الخبز الكامل أو خضروات طازجة للغمس."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/1b/Zaalouk-01.JPG/1280px-Zaalouk-01.JPG', ARRAY['زعلوك', 'zaalouk aubergine']::text[]),
  ('salade-marocaine', 'Salade marocaine (tomate-concombre)', 'شلاضة مغربية', 'Moroccan tomato-cucumber salad', 'salad', ARRAY['ghda', '3cha']::text[], '🥗', '1 assiette (200 g)', 200, 90, 10, 6, 2, 5, 3, 25, 'À VOLONTÉ : presque pas de glucides. Commencez chaque repas par cette salade — les fibres mangées en premier réduisent le pic de glycémie du plat qui suit.', 'كول منها بلا حساب: تقريباً بلا نشويات. بدا كل ماكلة بهاد الشلاضة — الألياف اللي كتاكل الأول كتنقص طلعة السكر ديال الماكلة اللي موراها.', '["150 g de tomates mûres (environ 1 tomate moyenne)","50 g de concombre (environ 1/4 de concombre moyen)","1/4 d''oignon rouge très finement émincé (environ 15 g)","1 cuillère à soupe de persil frais haché (environ 5 g)","1 cuillère à soupe de coriandre fraîche hachée (environ 5 g)","1 cuillère à café d''huile d''olive extra vierge (5 ml)","1 cuillère à soupe de jus de citron frais (15 ml)","1 pincée de sel fin","1 pincée de cumin moulu"]'::jsonb, '["150 غرام مطيشة طايبة (حبة مطيشة متوسطة)","50 غرام خيار (ربع خيارة متوسطة)","ربع بصلة حمراء مشلضة رقيقة بزاف (تقريبا 15 غرام)","1 معلقة كبيرة معدنوس مقطع رقيق (تقريبا 5 غرام)","1 معلقة كبيرة قزبور مقطع رقيق (تقريبا 5 غرام)","1 معلقة صغيرة زيت الزيتون البكر الممتاز (5 مل)","1 معلقة كبيرة عصير الحامض طري (15 مل)","رشيشة ملح رقيق","رشيشة كامون مطحون"]'::jsonb, '["Lavez soigneusement les 150 g de tomates et les 50 g de concombre sous l''eau froide. Séchez-les avec un torchon propre.","Coupez les tomates en petits dés d''environ 1 cm. Pour une meilleure texture, vous pouvez retirer les graines si vous le souhaitez, mais ce n''est pas obligatoire. Placez les dés de tomates dans un saladier.","Épluchez le concombre si la peau est épaisse ou amère, sinon laissez-la pour les fibres. Coupez le concombre en petits dés de taille similaire aux tomates (environ 1 cm) et ajoutez-les au saladier.","Émincez très finement le quart d''oignon rouge. Plus il est fin, plus sa saveur sera douce et se mélangera bien. Ajoutez l''oignon émincé aux légumes dans le saladier.","Hachez finement la cuillère à soupe de persil frais et la cuillère à soupe de coriandre fraîche. Incorporez les herbes hachées aux légumes.","Dans un petit bol, mélangez la cuillère à café d''huile d''olive extra vierge, la cuillère à soupe de jus de citron frais, la pincée de sel fin et la pincée de cumin moulu pour créer la vinaigrette.","Versez la vinaigrette sur les légumes coupés et mélangez délicatement avec une cuillère en bois ou une spatule jusqu''à ce que tous les ingrédients soient bien enrobés. Servez immédiatement pour profiter de la fraîcheur. Cette salade de 200 g est une portion idéale.","💡 Astuce diabète : Cette salade (environ 200 g, 90 kcal, 10 g de glucides, GI 25) est excellente à consommer à volonté. Commencez chaque repas par une grande portion de cette salade riche en fibres. Les fibres consommées en début de repas aident à ralentir l''absorption des glucides du plat principal qui suit, réduisant ainsi le pic de glycémie post-prandial."]'::jsonb, '["غسل 150 غرام ديال مطيشة و 50 غرام ديال الخيار مزيان تحت الماء بارد. نشفهم بفوطة نقية.","قطع مطيشة مكعبات صغار قياس 1 سنتيمتر تقريبا. باش تكون المذاق أحسن، تقدر تحيد الزريعة إلى بغيتي، ولكن ماشي ضروري. حط مكعبات مطيشة في زلافة كبيرة.","قشر الخيار إلى كانت القشرة غليظة أو مرة، وإلا خليها باش تستافد من الألياف. قطع الخيار مكعبات صغار بحال مطيشة (قياس 1 سنتيمتر تقريبا) وزيدهم على الزلافة.","شلط ربع بصلة حمراء رقيقة بزاف. كلما كانت رقيقة، كلما كان المذاق ديالها خفيف وكيتخلط مزيان. زيد البصلة المشلضة على الخضرة في الزلافة.","قطع معلقة كبيرة ديال المعدنوس طري ومعلقة كبيرة ديال القزبور طري رقيق. خلط الربيع المقطع مع الخضرة.","في زلافة صغيرة، خلط معلقة صغيرة ديال زيت الزيتون البكر الممتاز، معلقة كبيرة ديال عصير الحامض طري، رشيشة ملح رقيق ورشيشة كامون مطحون باش تصاوب لاصوص.","خوي لاصوص فوق الخضرة المقطعة وخلط بشوية بمعلقة خشبية أو سباتول حتى يتلبسو جميع المكونات مزيان. قدمها مباشرة باش تستمتع بالطراوة ديالها. هاد الشلاضة ديال 200 غرام هي حصة مثالية.","💡 نصيحة للسكري: هاد الشلاضة (تقريبا 200 غرام، 90 سعرة حرارية، 10 غرام كربوهيدرات، مؤشر سكري 25) ممتازة تاكلها بلا حساب. ابدأ كل وجبة بكمية كبيرة من هاد الشلاضة الغنية بالألياف. الألياف اللي كتاكلها في الأول كتساعد باش تبطئ امتصاص الكربوهيدرات من الطبق الرئيسي اللي كيجي من بعد، وهكدا كتقلل من ارتفاع السكر في الدم بعد الأكل."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/20/Moroccan_salad_1.jpg/1280px-Moroccan_salad_1.jpg', ARRAY['chlada', 'شلاضة']::text[]),
  ('taktouka', 'Taktouka (poivrons-tomates)', 'تكتوكة', 'Taktouka (peppers & tomatoes)', 'salad', ARRAY['ghda', '3cha']::text[], '🫑', '1 portion (200 g)', 200, 110, 11, 7, 2, 7, 4, 30, 'Poivrons grillés + tomates : vitamine C, fibres, très peu de calories. Parfaite en entrée ou en accompagnement à la place des frites ou du riz blanc.', 'فلفلة مشوية مع الطماطم: فيتامين C، ألياف، وكالوري قليلة. مثالية كمقبلات ولا بلاصة الفريت والروز الأبيض.', '["200 g de tomates mûres","150 g de poivrons (1 rouge, 1 vert)","1 gousse d''ail (environ 5 g)","1 cuillère à soupe d''huile d''olive extra vierge (15 ml)","1/2 cuillère à café de cumin moulu (2 g)","1/4 cuillère à café de paprika doux (1 g)","Une pincée de sel (2 g)","Une pincée de poivre noir (1 g)","Quelques brins de coriandre fraîche (5 g)"]'::jsonb, '["200 غرام مطيشة طايبة","150 غرام فلفلة (1 حمرة، 1 خضرة)","1 ضرس ثومة (حوالي 5 غرام)","1 معلقة كبيرة زيت الزيتون بكر ممتاز (15 مل)","1/2 معلقة صغيرة كامون مطحون (2 غرام)","1/4 معلقة صغيرة تحميرة حلوة (1 غرام)","رشيشة ملح (2 غرام)","رشيشة إبزار كحل (1 غرام)","شوية قزبر طري (5 غرام)"]'::jsonb, '["1. Commencez par griller les poivrons : lavez les 150 g de poivrons (rouge et vert), puis placez-les entiers sur une plaque de cuisson recouverte de papier sulfurisé. Faites-les griller au four préchauffé à 200°C (thermostat 6-7) pendant environ 20-25 minutes, en les retournant à mi-cuisson, jusqu''à ce que la peau soit noircie et boursouflée. Vous pouvez aussi les griller directement sur le feu vif d''une gazinière.","2. Une fois grillés, retirez les poivrons du four et placez-les immédiatement dans un sac en plastique fermé ou un bol couvert pendant 10 minutes. Cela facilitera l''épluchage. Après 10 minutes, retirez la peau noircie, les graines et les membranes blanches. Coupez la chair des poivrons en petits dés d''environ 1 cm.","3. Pendant que les poivrons refroidissent, préparez les tomates : lavez les 200 g de tomates mûres. Incisez-les en croix sur le dessus et plongez-les 30 secondes dans de l''eau bouillante, puis immédiatement dans de l''eau froide. Épluchez-les, retirez les graines et coupez la chair en petits dés.","4. Préparez l''ail et la coriandre : pelez la gousse d''ail (5 g) et hachez-la finement. Lavez et ciselez finement les brins de coriandre fraîche (5 g).","5. Dans une poêle antiadhésive, sur feu moyen, versez la cuillère à soupe d''huile d''olive (15 ml). Ajoutez l''ail haché et faites-le revenir pendant 30 secondes sans le laisser dorer.","6. Ajoutez les dés de tomates dans la poêle. Laissez mijoter sur feu doux pendant environ 10-12 minutes, en remuant de temps en temps, jusqu''à ce que les tomates soient bien réduites et aient formé une sauce épaisse. Écrasez-les légèrement avec une cuillère en bois.","7. Incorporez les dés de poivrons grillés, la 1/2 cuillère à café de cumin moulu (2 g), la 1/4 cuillère à café de paprika doux (1 g), la pincée de sel (2 g) et la pincée de poivre noir (1 g). Mélangez bien et laissez mijoter encore 5 minutes sur feu doux pour que les saveurs se mélangent.","8. Retirez du feu et ajoutez la coriandre fraîche ciselée. Mélangez une dernière fois. Servez la taktouka tiède ou froide.","💡 Astuce diabète : Cette taktouka est une excellente option pour les personnes atteintes de diabète de type 2. Une portion de 200 g (environ 110 kcal, 11 g de glucides, GI 30) est idéale en entrée ou en accompagnement. Pour un meilleur contrôle de la glycémie, consommez-la en début de repas, avant les plats plus riches en glucides. Évitez de la servir avec du pain blanc ; préférez-la avec une petite portion de pain complet ou comme accompagnement d''une protéine maigre."]'::jsonb, '["1. بداو تشويو الفلفلة: غسلو 150 غرام ديال الفلفلة (الحمرة والخضرة)، وحطوها كاملة فوق لاطة ديال الفران مفرشة بورق الطهي. دخلوها للفران مسخن على 200 درجة مئوية (الدرجة 6-7) لمدة 20-25 دقيقة تقريبا، وقلبوها في النص ديال الطياب، حتى تشوفو القشرة ديالها كحالت وتنفخات. تقدرو تشويوها مباشرة فوق البوطة على نار مجهدة.","2. منين تشوى الفلفلة، خرجوها من الفران وحطوها مباشرة فميكة مسدودة أو زلافة مغطية لمدة 10 دقايق. هادشي كيسهل التقشير ديالها. من بعد 10 دقايق، حيدو ليها القشرة الكحلة والزريعة والخيوط البيضين. قطعو اللب ديال الفلفلة مكعبات صغار ديال حوالي 1 سنتيمتر.","3. فاش تكون الفلفلة كتبرد، وجدو مطيشة: غسلو 200 غرام ديال مطيشة طايبة. فلحوها على شكل زائد من الفوق وغطسوها 30 ثانية فما طايب، ومن بعد مباشرة فما بارد. قشروها، حيدو ليها الزريعة وقطعو اللب ديالها مكعبات صغار.","4. وجدو الثومة والقزبر: قشرو ضرس الثومة (5 غرام) وقطعوه رقيق بزاف. غسلو وقطعو رقيق بزاف القزبر الطري (5 غرام).","5. فمقلاة ما كتلصقش، على نار متوسطة، ديرو معلقة كبيرة ديال زيت الزيتون (15 مل). زيدو الثومة مقطعة وشحروها لمدة 30 ثانية بلا ما تخليوها تتحمر.","6. زيدو مكعبات مطيشة للمقلاة. خليوها طيب على نار مهيلة لمدة 10-12 دقيقة تقريبا، وحركو مرة مرة، حتى تشوفو مطيشة تجمعات ولات صوص خاتر. معسوها شوية بالمعلقة ديال الخشب.","7. زيدو مكعبات الفلفلة المشوية، 1/2 معلقة صغيرة ديال الكامون مطحون (2 غرام)، 1/4 معلقة صغيرة ديال التحميرة الحلوة (1 غرام)، رشيشة ديال الملح (2 غرام) ورشيشة ديال الإبزار الكحل (1 غرام). خلطو مزيان وخليوها طيب 5 دقايق أخرى على نار مهيلة باش تندمج النكهات.","8. حيدوها من فوق النار وزيدو القزبر الطري مقطع. خلطو آخر مرة. قدمو التكتوكة دافية أو باردة.","💡 نصيحة للسكري: هاد التكتوكة اختيار ممتاز للناس اللي عندهم السكري من النوع 2. حصة ديال 200 غرام (حوالي 110 سعرة حرارية، 11 غرام كربوهيدرات، مؤشر سكري 30) مثالية كمقبلات أو مرافق للأكل. باش تحكمو بشكل أفضل في مستوى السكر في الدم، كولوها في بداية الوجبة، قبل الأطباق اللي فيها كربوهيدرات بزاف. تجنبو تقدموها مع الخبز الأبيض؛ فضلوها مع كمية قليلة من الخبز الكامل أو كمرافق لبروتين خالي من الدهون."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f7/2008_04_23_-_Laurel_-_Sauce.JPG/1280px-2008_04_23_-_Laurel_-_Sauce.JPG', ARRAY['تكتوكة']::text[]),
  ('salade-carottes', 'Salade de carottes au cumin', 'شلاضة الخيزو بالكامون', 'Carrot salad with cumin', 'salad', ARRAY['ghda', '3cha']::text[], '🥕', '1 portion (180 g)', 180, 95, 14, 8, 2, 4, 5, 35, 'Les carottes CUITES puis refroidies ont un IG plus bas qu’on ne croit (35). Beta-carotène pour les yeux — les diabétiques doivent protéger leur rétine.', 'الخيزو المطيب والمبرد عندو مؤشر جلايسيمي منخفض (35). فيه بيتا كاروتين اللي كيحمي العينين — السكري خاصو يحافظ على الشبكية ديالو.', '["200 g de carottes fraîches (environ 2 carottes moyennes)","1/2 gousse d''ail, hachée finement","1/2 cuillère à café de cumin moulu","1/4 cuillère à café de paprika doux","1/4 cuillère à café de sel fin","1 pincée de poivre noir fraîchement moulu","1 cuillère à soupe de jus de citron fraîchement pressé","1 cuillère à café d''huile d''olive extra vierge","1 cuillère à café de persil frais ciselé"]'::jsonb, '["200 غرام خيزو طري (تقريبا 2 خيزوات متوسطين)","1/2 فص ثوم، مفروم رقيق","1/2 ملعقة صغيرة كامون مطحون","1/4 ملعقة صغيرة تحميرة حلوة","1/4 ملعقة صغيرة ملح رقيق","1 قبيصة إبزار أسود مطحون جديد","1 ملعقة كبيرة عصير حامض طري","1 ملعقة صغيرة زيت الزيتون البكر الممتاز","1 ملعقة صغيرة معدنوس طري مقطع رقيق"]'::jsonb, '["1. Lavez et épluchez soigneusement les 200 g de carottes. Coupez-les en rondelles d''environ 0,5 cm d''épaisseur. Si les carottes sont très larges, coupez les rondelles en deux ou en quatre pour obtenir des morceaux de taille similaire.","2. Dans une casserole moyenne, portez à ébullition un volume d''eau suffisant pour couvrir les carottes. Plongez les rondelles de carottes dans l''eau bouillante et laissez-les cuire pendant 10 à 12 minutes à feu moyen. Les carottes doivent être tendres mais encore légèrement fermes (al dente), pas pâteuses.","3. Égouttez immédiatement les carottes cuites et rincez-les sous l''eau froide pendant 1 minute pour arrêter la cuisson et les refroidir rapidement. Laissez-les égoutter complètement dans une passoire pendant au moins 5 minutes pour éliminer l''excès d''eau.","4. Pendant que les carottes refroidissent, préparez la vinaigrette. Dans un petit bol, mélangez la 1/2 gousse d''ail hachée, la 1/2 cuillère à café de cumin moulu, la 1/4 cuillère à café de paprika doux, la 1/4 cuillère à café de sel et la pincée de poivre noir.","5. Ajoutez 1 cuillère à soupe de jus de citron frais et 1 cuillère à café d''huile d''olive extra vierge aux épices. Mélangez bien tous les ingrédients de la vinaigrette jusqu''à obtenir une émulsion homogène.","6. Dans un saladier, versez les carottes refroidies et égouttées. Ajoutez la vinaigrette préparée et la 1 cuillère à café de persil frais ciselé. Mélangez délicatement pour enrober toutes les carottes de la vinaigrette. Goûtez et ajustez l''assaisonnement si nécessaire.","7. Laissez la salade reposer au réfrigérateur pendant au moins 30 minutes avant de servir pour que les saveurs se développent. Servez 1 portion de 180 g. 💡 Astuce diabète : Consommez cette salade de carottes, dont l''IG est de 35 après cuisson et refroidissement, en début de repas. Sa richesse en fibres et en bêta-carotène est bénéfique. Évitez de la réchauffer pour maintenir son IG bas."]'::jsonb, '["1. غسلوا ونقيو 200 غرام ديال خيزو مزيان. قطعوه دوائر بسمك 0.5 سم تقريبا. إذا كان خيزو غليظ بزاف، قطعوا الدوائر على جوج أو على أربعة باش يجيوا القطع بنفس الحجم.","2. فكاسرونة متوسطة، غليو كمية كافية ديال الماء باش تغطيو خيزو. حطوا دوائر خيزو فالماء المغلي وخليوهم يطيبوا لمدة 10 حتى 12 دقيقة على نار متوسطة. خاص خيزو يجي رطب ولكن باقي شاد فراسو شوية (ماشي معجن).","3. صفيو خيزو المطبوخ مباشرة وشللوه تحت الماء بارد لمدة دقيقة باش توقفوا الطياب ويبرد دغيا. خليوه يتصفى مزيان فشبكة لمدة 5 دقائق على الأقل باش يحيد منو الماء الزايد.","4. فاش يكون خيزو كيبرد، وجدوا لاصوص. فزلافة صغيرة، خلطوا 1/2 فص ثوم مفروم، 1/2 ملعقة صغيرة كامون مطحون، 1/4 ملعقة صغيرة تحميرة حلوة، 1/4 ملعقة صغيرة ملح وقبيصة إبزار أسود.","5. زيدوا 1 ملعقة كبيرة عصير حامض طري و 1 ملعقة صغيرة زيت الزيتون البكر الممتاز على العطرية. خلطوا جميع المكونات ديال لاصوص مزيان حتى يتجانسوا.","6. فإناء ديال الشلاضة، حطوا خيزو البارد والمصفى. زيدوا عليه لاصوص اللي وجدتو و 1 ملعقة صغيرة معدنوس طري مقطع رقيق. خلطوا بلطف باش يتغطى خيزو كامل بلاصوص. ذوقوا وعدلوا الملح والإبزار إذا كان خاص.","7. خليو الشلاضة ترتاح فالثلاجة لمدة 30 دقيقة على الأقل قبل التقديم باش تطلق النكهات. قدموا 1 حصة ديال 180 غرام. 💡 نصيحة للسكري: تناولوا شلاضة خيزو هادي، اللي المؤشر الكلايسيمي ديالها 35 من بعد الطياب والتبريد، فبداية الوجبة. غنية بالألياف والبيتا كاروتين ومفيدة. تجنبوا تسخينها باش تحافظوا على المؤشر الكلايسيمي المنخفض ديالها."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/49/Nest_of_Carrot_Salad%2C_by_LadyofProcrastination.jpg/1280px-Nest_of_Carrot_Salad%2C_by_LadyofProcrastination.jpg', ARRAY['khizou', 'خيزو']::text[]),
  ('salade-lentilles', 'Salade de lentilles froide', 'شلاضة العدس الباردة', 'Cold lentil salad', 'salad', ARRAY['ghda', '3cha']::text[], '🥙', '1 assiette (250 g)', 250, 230, 30, 3, 14, 6, 9, 25, 'Les lentilles refroidies développent de l’amidon résistant : IG encore plus bas (25). Protéines végétales + fibres = repas complet qui ne fait pas monter le sucre.', 'العدس المبرد كيطور نشا مقاوم: المؤشر الجلايسيمي كينقص أكثر (25). بروتين نباتي مع الألياف = ماكلة كاملة ما كتطلعش السكر.', '["80 g de lentilles vertes sèches","1/2 oignon rouge (environ 40 g), finement haché","1/2 tomate (environ 60 g), coupée en petits dés","1/4 de concombre (environ 30 g), coupé en petits dés","1 c. à soupe de persil frais, ciselé","1 c. à soupe de coriandre fraîche, ciselée","1 c. à soupe d''huile d''olive extra vierge","1 c. à café de vinaigre de cidre","Une pincée de cumin moulu, sel et poivre noir"]'::jsonb, '["80 غرام عدس أخضر ناشف","1/2 بصلة حمراء (حوالي 40 غرام)، مفرومة رقيقة","1/2 مطيشة (حوالي 60 غرام)، مقطعة مكعبات صغار","1/4 خيارة (حوالي 30 غرام)، مقطعة مكعبات صغار","1 م. كبيرة معدنوس طري، مقطع رقيق","1 م. كبيرة قزبر طري، مقطع رقيق","1 م. كبيرة زيت الزيتون البكر الممتاز","1 م. صغيرة خل التفاح","رشيشة كامون مطحون، ملح وإبزار كحل"]'::jsonb, '["1. Rincez soigneusement les 80 g de lentilles vertes sous l''eau froide. Mettez-les dans une casserole avec environ 300 ml d''eau froide (trois fois leur volume). Portez à ébullition sur feu vif, puis réduisez à feu doux et laissez mijoter pendant 20 à 25 minutes, ou jusqu''à ce qu''elles soient tendres mais encore légèrement fermes (al dente).","2. Pendant que les lentilles cuisent, préparez les légumes : hachez finement la 1/2 oignon rouge, coupez la 1/2 tomate et le 1/4 de concombre en petits dés réguliers. Ciselez le persil et la coriandre frais.","3. Une fois les lentilles cuites, égouttez-les immédiatement dans une passoire fine. Rincez-les brièvement à l''eau froide pour stopper la cuisson et les refroidir rapidement. Laissez-les égoutter complètement pendant au moins 5 minutes.","4. Transférez les lentilles refroidies dans un grand saladier. Ajoutez l''oignon rouge haché, les dés de tomate et de concombre, le persil et la coriandre ciselés.","5. Dans un petit bol, préparez la vinaigrette : mélangez la 1 c. à soupe d''huile d''olive extra vierge, la 1 c. à café de vinaigre de cidre, une pincée de cumin moulu, le sel et le poivre noir selon votre goût.","6. Versez la vinaigrette sur la salade de lentilles et mélangez délicatement pour bien enrober tous les ingrédients. Assurez-vous que les lentilles sont uniformément assaisonnées.","7. Couvrez le saladier et placez la salade au réfrigérateur pendant au moins 30 minutes, idéalement 1 à 2 heures, pour que les saveurs se développent et que les lentilles soient bien froides. Servez une portion de 250 g dans une assiette.","💡 Astuce diabète : Cette salade de lentilles (250 g) est un excellent choix avec un IG très bas (25) grâce à l''amidon résistant formé au refroidissement. Pour optimiser le contrôle de la glycémie, mangez-la en début de repas. Évitez de l''accompagner de pain blanc ou de féculents raffinés ; préférez une petite portion de légumes verts crus ou cuits à la vapeur."]'::jsonb, '["1. غسلوا 80 غرام ديال العدس الأخضر مزيان تحت الماء بارد. ديروه فكاسرونة مع تقريبا 300 ملل ديال الماء بارد (ثلاثة أضعاف الكمية ديالو). خليوه يغلى فوق نار مجهدة، من بعد نقصوا النار لمهيلة وخليوه يطيب على خاطر خاطرو لمدة 20 حتى 25 دقيقة، ولا حتى يولي رطب ولكن باقي شاد فراسو شوية (ماشي طايب بزاف).","2. فاش يكون العدس كيطيب، وجدوا الخضرة: قطعوا 1/2 بصلة حمراء رقيقة بزاف، وقطعوا 1/2 مطيشة و 1/4 خيارة مكعبات صغار ومقادين. قطعوا المعدنوس والقزبر طريين رقاق.","3. ملي يطيب العدس، صفّيوه مباشرة فشبكة رقيقة. شلّلوه دغيا بالماء بارد باش يحبس الطياب ويبرد بالزربة. خليوه يتصفى مزيان لمدة 5 دقائق على الأقل.","4. حطوا العدس اللي برد فزلافة كبيرة. زيدوا عليه البصلة الحمراء مقطعة، مكعبات المطيشة والخيار، والمعدنوس والقزبر مقطعين.","5. فزلافة صغيرة، وجدوا لاصوص: خلطوا 1 م. كبيرة زيت الزيتون البكر الممتاز، 1 م. صغيرة خل التفاح، رشيشة كامون مطحون، الملح والإبزار الكحل على حسب الذوق ديالكم.","6. خويو لاصوص فوق شلاضة العدس وخلطوا غير بشوية باش يتلبسوا جميع المكونات مزيان. تأكدوا أن العدس تشرّب لاصوص بالتساوي.","7. غطّيو الزلافة وديروا الشلاضة فالثلاجة لمدة 30 دقيقة على الأقل، والأحسن من ساعة حتى لساعتين، باش النكهات يتخلطوا مزيان والعدس يبرد تمامًا. قدموا حصة ديال 250 غرام فطبسيل.","💡 نصيحة للسكري: هاد شلاضة العدس (250 غرام) اختيار ممتاز بنسبة سكر منخفضة بزاف (25) بفضل النشا المقاوم اللي كيتكون فاش كيبرد. باش تحكموا فالسكري بشكل أحسن، كولوها فبداية الوجبة. تجنبوا تاكلوها مع الخبز الأبيض أو النشويات المكررة؛ من الأفضل تاكلو معاها كمية قليلة من الخضروات الخضراء الطازجة أو المطبوخة على البخار."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9f/Lentil_salad_%2829308018298%29.jpg/1280px-Lentil_salad_%2829308018298%29.jpg', ARRAY['lentilles froides']::text[]),
  ('salade-avocat-thon', 'Salade avocat-thon', 'شلاضة الأفوكادو بالطون', 'Avocado tuna salad', 'salad', ARRAY['ghda', '3cha']::text[], '🥑', '1 assiette (250 g)', 250, 320, 9, 3, 24, 22, 7, 15, 'Repas complet quasi sans glucides : parfait le soir quand la glycémie de la journée était haute. Rassasie longtemps grâce aux protéines du thon et aux fibres de l’avocat.', 'ماكلة كاملة تقريباً بلا نشويات: مثالية فالليل ملي كيكون السكر ديال النهار مرتفع. كتشبع مدة طويلة بفضل بروتين الطون وألياف الأفوكادو.', '["120 g d''avocat mûr (environ 1/2 avocat moyen)","80 g de thon à l''eau égoutté","1/4 de tomate moyenne (environ 30 g)","1/4 d''oignon rouge (environ 15 g), finement émincé","1 c. à soupe de jus de citron frais","1 c. à café d''huile d''olive extra vierge","Quelques brins de coriandre fraîche, ciselée","Une pincée de sel","Une pincée de poivre noir moulu"]'::jsonb, '["120 غرام أفوكادو طايب (نص حبة متوسطة تقريبا)","80 غرام طون بالماء مصفي","ربع مطيشة متوسطة (تقريبا 30 غرام)","ربع بصلة حمراء (تقريبا 15 غرام)، مقطعة رقيقة بزاف","1 معلقة كبيرة عصير حامض طري","1 معلقة صغيرة زيت الزيتون البكر الممتاز","شوية قزبر طري مقطع رقيق","رشيشة ملح","رشيشة إبزار مطحون"]'::jsonb, '["1. Commencez par préparer l''avocat : coupez l''avocat mûr en deux, retirez le noyau et la peau. Coupez la chair en petits dés d''environ 1 cm de côté. Mettez les dés d''avocat dans un saladier.","2. Égouttez soigneusement le thon en conserve pour éliminer l''excès d''eau. Émiettez le thon à l''aide d''une fourchette et ajoutez-le aux dés d''avocat dans le saladier.","3. Lavez la tomate et coupez-la en petits dés, de taille similaire à ceux de l''avocat. Ajoutez les dés de tomate au mélange avocat-thon.","4. Pelez et émincez très finement l''oignon rouge. Si l''oignon est trop fort, vous pouvez le rincer rapidement à l''eau froide et bien l''égoutter avant de l''ajouter au saladier.","5. Ciselez finement la coriandre fraîche. Ajoutez la coriandre ciselée au reste des ingrédients dans le saladier.","6. Dans un petit bol, mélangez le jus de citron frais, l''huile d''olive extra vierge, la pincée de sel et la pincée de poivre noir. Versez cette vinaigrette sur la salade.","7. Mélangez délicatement tous les ingrédients de la salade avec une cuillère en bois ou une spatule pour ne pas écraser l''avocat. Servez immédiatement dans une assiette.","💡 Astuce diabète : Cette salade est un excellent choix pour un repas léger et nutritif. Pour un contrôle optimal de la glycémie, respectez la portion de 250 g. L''avocat et le thon apportent des graisses saines et des protéines qui ralentissent l''absorption des glucides. Mangez cette salade seule ou accompagnée d''une petite portion de crudités non amylacées."]'::jsonb, '["1. أول حاجة، وجد الأفوكادو: قسم الأفوكادو طايب على جوج، حيد العظم والجلدة. قطع اللب ديالو مربعات صغار تقريبا 1 سنتيم. حط مربعات الأفوكادو في زلافة كبيرة.","2. صفي الطون المعلب مزيان باش تحيد منو الماء الزايد. فرتت الطون بالفرشيطة وزيدو على مربعات الأفوكادو في الزلافة.","3. غسل مطيشة وقطعها مربعات صغار، بحال حجم مربعات الأفوكادو. زيد مربعات مطيشة على خليط الأفوكادو والطون.","4. قشر البصلة الحمراء وقطعها رقيقة بزاف. إلا كانت البصلة حارة بزاف، تقدر تشللها بالماء بارد دغيا وتصفيها مزيان قبل ما تزيدها للزلافة.","5. قطع القزبر طري رقيق. زيد القزبر مقطع على باقي المكونات في الزلافة.","6. في زلافة صغيرة، خلط عصير الحامض طري، زيت الزيتون البكر الممتاز، رشيشة الملح ورشيشة الإبزار. خوي هاد لاصوص فوق الشلاضة.","7. خلط جميع مكونات الشلاضة غير بشوية بمعلقة خشبية أو سباتولا باش ما تهرسش الأفوكادو. قدمها مباشرة في طبق.","💡 نصيحة للسكري: هاد الشلاضة اختيار ممتاز لوجبة خفيفة ومغذية. باش تحافظ على مستوى السكر في الدم مزيان، التزم بالكمية ديال 250 غرام. الأفوكادو والطون كيعطيو دهون صحية وبروتينات اللي كيبطئوا امتصاص الكربوهيدرات. كل هاد الشلاضة بوحدها أو مع كمية قليلة من الخضروات الطازجة غير النشوية."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/dc/Avocado_and_tuna_salad_%289902653876%29.jpg/1280px-Avocado_and_tuna_salad_%289902653876%29.jpg', ARRAY['thon avocat']::text[]),
  ('bakoula', 'Bakoula (mauve sautée)', 'البقولة', 'Bakoula (sautéed mallow)', 'salad', ARRAY['ghda', '3cha']::text[], '🌿', '1 portion (200 g)', 200, 110, 9, 2, 4, 7, 6, 20, 'Le trésor vert des grands-mères : quasi zéro glucide, bourrée de fibres, fer et vitamines. Un des plats marocains les PLUS adaptés au diabète — mangez-en souvent.', 'الكنز الأخضر ديال الجدات: تقريباً بلا نشويات، عامرة بالألياف والحديد والفيتامينات. من أحسن الماكلات المغربية للسكري — كول منها بزاف.', '["200 g de mauve fraîche (bakoula)","1 c. à soupe de coriandre fraîche hachée","1 c. à soupe de persil frais haché","1 gousse d''ail écrasée","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","1 pincée de piment doux (facultatif)","1 c. à soupe de jus de citron frais","1 c. à café d''huile d''olive extra vierge","2 olives violettes (pour la garniture)"]'::jsonb, '["200 غرام ديال الخبازي طري (البقولة)","1 معلقة كبيرة ديال القزبور طري مقطع رقيق","1 معلقة كبيرة ديال المعدنوس طري مقطع رقيق","1 فص ديال الثومة مدقوق","1/2 معلقة صغيرة ديال الكامون مطحون","1/4 معلقة صغيرة ديال التحميرة الحلوة","1 قريصة ديال السودانية الحلوة (اختياري)","1 معلقة كبيرة ديال عصير الحامض طري","1 معلقة صغيرة ديال زيت الزيتون البكر الممتاز","2 زيتونات كحلين (للتزيين)"]'::jsonb, '["1. Lavez soigneusement les feuilles de mauve (bakoula) sous l''eau froide. Égouttez-les bien et hachez-les grossièrement.","2. Dans le panier d''un cuit-vapeur, placez la mauve hachée. Faites cuire à la vapeur pendant environ 20 à 25 minutes, ou jusqu''à ce que les feuilles soient tendres et aient changé de couleur (elles deviennent plus foncées).","3. Pendant que la mauve cuit, préparez la chermoula. Dans un petit bol, mélangez la coriandre hachée, le persil haché, l''ail écrasé, le cumin moulu, le paprika doux et le piment doux (si utilisé).","4. Une fois la mauve cuite, retirez-la du cuit-vapeur et pressez-la légèrement pour éliminer l''excès d''eau. Hachez-la finement si elle n''est pas déjà assez fine.","5. Dans une poêle antiadhésive, sur feu doux, ajoutez la mauve cuite et la chermoula préparée. Mélangez bien pour que la mauve s''imprègne des saveurs.","6. Laissez mijoter doucement pendant 5 à 7 minutes, en remuant de temps en temps, jusqu''à ce que les arômes se développent et que le mélange soit bien homogène. Retirez du feu.","7. Incorporez le jus de citron frais et l''huile d''olive extra vierge. Mélangez une dernière fois. Servez tiède ou froid, garni des deux olives violettes.","💡 Astuce diabète : Cette portion de 200 g de bakoula est idéale pour un diabétique (environ 110 kcal, 9 g de glucides, GI 20). Mangez-la en entrée pour ralentir l''absorption des glucides du plat principal, ou comme accompagnement léger. Évitez de l''accompagner de pain blanc ; préférez une petite portion de pain complet si nécessaire, ou des crudités."]'::jsonb, '["1. غسلوا أوراق البقولة مزيان تحت الماء البارد. قطرّوهم مزيان و قطعوهم غلاظ شوية.","2. حطوا البقولة المقطعة في الكسكاس ديال البرمة. فوروها لمدة 20 حتى ل 25 دقيقة تقريبا، ولا حتى تولي الأوراق رطبة و يتغير اللون ديالها (تولي غامقة).","3. فاش تكون البقولة كتفور، وجدوا الشرمولة. في زلافة صغيرة، خلطوا القزبور مقطع، المعدنوس مقطع، الثومة مدقوقة، الكامون مطحون، التحميرة الحلوة و السودانية الحلوة (إلى استعملتوها).","4. ملي طيب البقولة، حيدوها من الكسكاس و عصروها شوية باش تحيدوا الماء الزائد. قطعوها رقيقة إلى ما كانتش رقيقة بما فيه الكفاية.","5. في مقلة ما كتلصقش، على نار مهيلة، زيدوا البقولة طايبة و الشرمولة اللي وجدتوها. خلطوا مزيان باش البقولة تشرب النكهات.","6. خليوها تشحر على نار مهيلة لمدة 5 حتى 7 دقائق، مع التحريك مرة مرة، حتى تطلع الروائح و يتجانس الخليط مزيان. حيدوها من فوق النار.","7. زيدوا عصير الحامض طري و زيت الزيتون البكر الممتاز. خلطوا آخر مرة. قدموها دافية أو باردة، مزينة بالزيتونات الكحلين.","💡 نصيحة للسكري: هاد الكمية ديال 200 غرام ديال البقولة مثالية لمريض السكري (تقريبا 110 سعرة حرارية، 9 غرامات ديال الكربوهيدرات، مؤشر سكري 20). كولوها كمقبلة باش تبطئوا امتصاص الكربوهيدرات ديال الطبق الرئيسي، أو كطبق جانبي خفيف. تجنبوا تاكلوها مع الخبز الأبيض؛ فضّلوا كمية صغيرة ديال الخبز الكامل إلى كان ضروري، أو خضر طازجة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/03/Ary_beqqola.JPG/1280px-Ary_beqqola.JPG', ARRAY['khoubiza', 'بقولة', 'خبيزة']::text[]),
  ('foul-cumin', 'Fèves bouillies au cumin (foul)', 'الفول المسلوق بالكامون', 'Boiled fava beans with cumin', 'salad', ARRAY['ftour', 'ghda', 'snack']::text[], '🫛', '1 bol (200 g)', 200, 180, 24, 3, 12, 4, 8, 30, 'Le foul du souk, version santé : protéines végétales, IG bas, ultra rassasiant. En plat ou en entrée — avec cumin et huile d’olive, sans pain blanc à côté.', 'الفول ديال السوق، بالنسخة الصحية: بروتين نباتي، مؤشر منخفض، وكيشبع بزاف. طبق ولا مقبلات — بالكامون وزيت الزيتون، بلا خبز أبيض معاه.', '["200 g de fèves fraîches (ou surgelées)","1/2 cuillère à café de cumin moulu","1/4 cuillère à café de paprika doux","1 pincée de sel de mer","1 pincée de poivre noir fraîchement moulu","1 cuillère à café d''huile d''olive extra vierge","1/2 gousse d''ail, finement hachée (facultatif)","Quelques brins de coriandre fraîche, ciselée (pour la garniture)"]'::jsonb, '["200 غرام من الفول الطري (أو المجمد)","1/2 ملعقة صغيرة من الكامون مطحون","1/4 ملعقة صغيرة من التحميرة (بابريكا حلوة)","رشة ملح بحري","رشة إبزار أسود مطحون طري","1 ملعقة صغيرة من زيت الزيتون البكر الممتاز","1/2 فص ثوم، مفروم ناعم (اختياري)","بعض وريقات القزبور طري، مقطع رقيق (للتزيين)"]'::jsonb, '["1. Rincer soigneusement 200 g de fèves fraîches. Si vous utilisez des fèves surgelées, ne les décongelez pas au préalable.","2. Dans une petite casserole, porter à ébullition un volume d''eau suffisant pour couvrir les fèves. Ajouter une pincée de sel à l''eau.","3. Plonger les fèves dans l''eau bouillante et laisser cuire à feu moyen pendant environ 10 à 15 minutes, ou jusqu''à ce qu''elles soient tendres mais encore légèrement fermes (al dente). Le temps de cuisson peut varier selon la taille et la fraîcheur des fèves.","4. Égoutter les fèves immédiatement après cuisson. Pour préserver leur couleur verte vive, vous pouvez les passer rapidement sous l''eau froide après les avoir égouttées, puis les égoutter à nouveau très soigneusement.","5. Dans un petit bol, mélanger 1/2 cuillère à café de cumin moulu, 1/4 cuillère à café de paprika doux, une pincée de sel et une pincée de poivre noir. Si vous utilisez de l''ail, ajoutez 1/2 gousse d''ail finement hachée à ce mélange d''épices.","6. Transférer les fèves égouttées dans un plat de service. Arroser avec 1 cuillère à café d''huile d''olive extra vierge et saupoudrer généreusement avec le mélange d''épices préparé. Mélanger délicatement pour bien enrober toutes les fèves.","7. Garnir avec quelques brins de coriandre fraîche ciselée avant de servir. Ce plat peut être dégusté tiède ou froid.","💡 Astuce diabète : Savourez ce bol de 200 g de fèves bouillies comme une entrée ou un plat léger. Son indice glycémique bas (environ 30) et sa richesse en fibres et protéines végétales en font un excellent choix. Mangez-le lentement et évitez de l''accompagner de pain blanc pour maintenir une glycémie stable."]'::jsonb, '["1. غسل 200 غرام من الفول الطري بعناية. إذا كنت تستخدم الفول المجمد، فلا تذوبه مسبقًا.","2. في كسرونة صغيرة، غلي كمية كافية من الماء لتغطية الفول. أضف رشة ملح إلى الماء.","3. ضع الفول في الماء المغلي واتركه يطهى على نار متوسطة لمدة تتراوح بين 10 إلى 15 دقيقة، أو حتى يصبح طريًا ولكن لا يزال متماسكًا قليلاً (al dente). قد يختلف وقت الطهي حسب حجم الفول وطراوته.","4. صفي الفول فورًا بعد الطهي. للحفاظ على لونه الأخضر الزاهي، يمكنك شطفه بسرعة تحت الماء البارد بعد تصفيته، ثم صفيه مرة أخرى بعناية فائقة.","5. في زلافة صغيرة، اخلط 1/2 ملعقة صغيرة من الكامون مطحون، 1/4 ملعقة صغيرة من التحميرة (بابريكا حلوة)، رشة ملح ورشة إبزار أسود. إذا كنت تستخدم الثوم، أضف 1/2 فص ثوم مفروم ناعم إلى خليط التوابل هذا.","6. انقل الفول المصفى إلى طبق التقديم. رشه بـ 1 ملعقة صغيرة من زيت الزيتون البكر الممتاز ورشه بسخاء بخليط التوابل المحضر. اخلط برفق لتغطية جميع حبات الفول جيدًا.","7. زين الطبق ببعض وريقات القزبور الطري المقطع رقيق قبل التقديم. يمكن الاستمتاع بهذا الطبق دافئًا أو باردًا.","💡 نصيحة للسكري: استمتع بهذا الزلافة (200 غرام) من الفول المسلوق كطبق مقبلات أو وجبة خفيفة. مؤشره الجلايسيمي المنخفض (حوالي 30) وغناه بالألياف والبروتينات النباتية يجعله خيارًا ممتازًا. تناوله ببطء وتجنب تقديمه مع الخبز الأبيض للحفاظ على مستوى سكر الدم مستقرًا."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/e/e5/Ful_medames.jpg', ARRAY['foul', 'fèves', 'الفول']::text[]),
  ('loubia-khadra-ail', 'Haricots verts sautés à l''ail', 'اللوبيا الخضراء المقلية بالثوم', 'Garlic green beans', 'salad', ARRAY['ghda', '3cha']::text[], '🫛', '1 portion (200 g)', 200, 90, 10, 4, 4, 5, 5, 20, 'L''accompagnement marocain parfait : remplace frites, riz et pâtes à côté de n''importe quel tajine ou grillade. Quasi zéro impact sur la glycémie.', 'المرافق المغربي المثالي: كيعوض الفريت والروز والمعكرونة مع أي طاجين ولا مشوي. تقريباً بلا تأثير على السكر.', '["200 g de haricots verts frais, parés","2 gousses d''ail moyennes, hachées finement","1 c. à soupe d''huile d''olive extra vierge","1/4 c. à café de cumin moulu","1/8 c. à café de paprika doux","1 pincée de piment fort (facultatif)","Jus d''1/4 de citron frais","Sel de mer et poivre noir fraîchement moulu, au goût","1 c. à soupe de coriandre fraîche hachée"]'::jsonb, '["200 غرام من اللوبيا الخضراء الطازجة، مقطعة الأطراف","2 فصوص ثوم متوسطة، مفرومة ناعمًا","1 ملعقة كبيرة زيت زيتون بكر ممتاز","1/4 ملعقة صغيرة كمون مطحون","1/8 ملعقة صغيرة فلفل أحمر حلو (تحميرة)","رشة فلفل حار (اختياري)","عصير 1/4 ليمونة طازجة","ملح بحري وفلفل أسود مطحون طازج، حسب الذوق","1 ملعقة كبيرة قزبر طازج مفروم"]'::jsonb, '["Lavez soigneusement les haricots verts. Dans une grande casserole d''eau bouillante légèrement salée, faites-les cuire pendant 5 à 7 minutes, jusqu''à ce qu''ils soient tendres mais encore légèrement croquants (al dente). Égouttez-les immédiatement et plongez-les dans un bain d''eau glacée pour arrêter la cuisson et préserver leur couleur vive. Égouttez-les à nouveau très soigneusement.","Dans une poêle antiadhésive, faites chauffer 1 c. à soupe d''huile d''olive à feu moyen-doux.","Ajoutez les 2 gousses d''ail hachées et faites-les revenir pendant 30 secondes à 1 minute, juste jusqu''à ce qu''elles soient parfumées et légèrement dorées, en veillant à ne pas les brûler.","Incorporez 1/4 c. à café de cumin moulu, 1/8 c. à café de paprika doux et la pincée de piment fort (si utilisé). Mélangez bien les épices avec l''ail pendant 15 secondes pour libérer leurs arômes.","Ajoutez les haricots verts égouttés dans la poêle. Faites-les sauter pendant 3 à 5 minutes à feu moyen, en remuant fréquemment, jusqu''à ce qu''ils soient bien enrobés des épices et de l''ail et qu''ils aient légèrement réchauffé.","Retirez la poêle du feu. Arrosez les haricots verts avec le jus d''1/4 de citron frais. Salez et poivrez au goût. Ajoutez 1 c. à soupe de coriandre fraîche hachée et mélangez délicatement.","Servez immédiatement comme accompagnement chaud ou tiède. Cette portion de 200 g est parfaite pour un repas équilibré.","💡 Astuce diabète : Cette portion de 200 g de haricots verts sautés à l''ail a un indice glycémique très bas (GI 20) et seulement 10 g de glucides. C''est un excellent substitut aux accompagnements riches en glucides comme les frites, le riz ou les pâtes. Pour une meilleure gestion de la glycémie, consommez-les en début de repas, avant les protéines et les glucides plus complexes."]'::jsonb, '["اغسل اللوبيا الخضراء جيدًا. في قدر كبير من الماء المغلي المملح قليلًا، اسلقها لمدة 5 إلى 7 دقائق، حتى تصبح طرية ولكن لا تزال مقرمشة قليلًا (ال دنتي). صفيها فورًا وضعها في حمام ماء مثلج لوقف الطهي والحفاظ على لونها الزاهي. صفيها مرة أخرى بعناية فائقة.","في مقلاة غير لاصقة، سخّن 1 ملعقة كبيرة من زيت الزيتون على نار متوسطة-هادئة.","أضف فصي الثوم المفرومين وقلبهما لمدة 30 ثانية إلى دقيقة واحدة، فقط حتى يصبحا عطريين ومذهبين قليلًا، مع الحرص على عدم حرقهما.","أضف 1/4 ملعقة صغيرة من الكمون المطحون، 1/8 ملعقة صغيرة من الفلفل الأحمر الحلو (تحميرة) ورشة الفلفل الحار (إذا كنت تستخدمه). اخلط التوابل جيدًا مع الثوم لمدة 15 ثانية لإطلاق نكهاتها.","أضف اللوبيا الخضراء المصفاة إلى المقلاة. قلبها لمدة 3 إلى 5 دقائق على نار متوسطة، مع التحريك المتكرر، حتى تتغطى جيدًا بالتوابل والثوم وتسخن قليلًا.","أبعد المقلاة عن النار. رش اللوبيا الخضراء بعصير 1/4 ليمونة طازجة. تبّلها بالملح والفلفل حسب الذوق. أضف 1 ملعقة كبيرة من القزبر الطازج المفروم واخلط بلطف.","قدم الطبق فورًا كطبق جانبي ساخن أو دافئ. هذه الحصة التي تزن 200 غرام مثالية لوجبة متوازنة.","💡 نصيحة للسكري: هذه الحصة التي تزن 200 غرام من اللوبيا الخضراء المقلية بالثوم لها مؤشر سكري منخفض جدًا (GI 20) وتحتوي على 10 غرامات فقط من الكربوهيدرات. إنها بديل ممتاز للأطباق الجانبية الغنية بالكربوهيدرات مثل البطاطس المقلية أو الأرز أو المعكرونة. لتحكم أفضل في نسبة السكر في الدم، تناولها في بداية الوجبة، قبل البروتينات والكربوهيدرات الأكثر تعقيدًا."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/fb/Sauteed_Garlic_Green_Beans_1_2017-02-22.jpg/1280px-Sauteed_Garlic_Green_Beans_1_2017-02-22.jpg', ARRAY['haricots verts', 'لوبيا خضرا']::text[]),
  ('salade-betterave', 'Salade de betterave (barba)', 'شلاضة البربة', 'Beetroot salad', 'salad', ARRAY['ghda', '3cha']::text[], '🟣', '1 portion (180 g)', 180, 90, 15, 11, 3, 3, 4, 40, 'La betterave a un IG modéré mais une charge glycémique faible grâce à ses fibres. Ses nitrates aident la circulation — utile quand le diabète fatigue les vaisseaux. En petite portion, en entrée.', 'البربة عندها مؤشر معتدل ولكن حمولة سكرية ضعيفة بفضل الألياف. النترات ديالها كتعاون الدورة الدموية — مفيدة ملي السكري كيتعب الشرايين. بكمية صغيرة، كمقبلات.', '["180 g de betteraves crues (environ 2 petites)","1 c. à soupe de jus de citron frais (environ 15 ml)","1 c. à café d''huile d''olive extra vierge (environ 5 ml)","1/4 c. à café de cumin moulu","1 pincée de sel de mer","1 pincée de poivre noir fraîchement moulu","1 c. à soupe de persil frais ciselé (environ 5 g)"]'::jsonb, '["180 غرام ديال الباربا خضرا (تقريبا 2 صغار)","1 معلقة كبيرة ديال عصير الحامض طري (تقريبا 15 مل)","1 معلقة صغيرة ديال زيت الزيتون البكر الممتاز (تقريبا 5 مل)","1 ربع معلقة صغيرة ديال الكامون مطحون","1 قبيصة ديال الملحة البحرية","1 قبيصة ديال البزار كحل مطحون جديد","1 معلقة كبيرة ديال المعدنوس مقطع رقيق (تقريبا 5 غرام)"]'::jsonb, '["1. Lavez soigneusement les betteraves crues. Ne les épluchez pas pour l''instant.","2. Placez les betteraves entières, avec leur peau, dans une casserole d''eau froide. Portez à ébullition sur feu moyen, puis réduisez le feu et laissez mijoter pendant 30 à 45 minutes, ou jusqu''à ce qu''elles soient tendres (vous pouvez les piquer facilement avec la pointe d''un couteau).","3. Une fois cuites, retirez les betteraves de l''eau et laissez-les refroidir complètement. Une fois froides, la peau s''enlèvera très facilement en frottant avec les doigts ou un petit couteau.","4. Coupez les betteraves épluchées en petits dés d''environ 1 cm. Placez les dés dans un bol de taille moyenne.","5. Dans un petit récipient séparé, préparez la vinaigrette : mélangez 1 c. à soupe de jus de citron frais, 1 c. à café d''huile d''olive extra vierge, 1/4 c. à café de cumin moulu, 1 pincée de sel de mer et 1 pincée de poivre noir fraîchement moulu. Fouettez bien pour émulsionner.","6. Versez la vinaigrette sur les dés de betterave et mélangez délicatement pour bien enrober tous les morceaux. Ajoutez 1 c. à soupe de persil frais ciselé et mélangez à nouveau.","7. Laissez la salade reposer au réfrigérateur pendant au moins 30 minutes avant de servir pour que les saveurs se mélangent bien. Servez frais en entrée.","💡 Astuce diabète : Cette salade de betterave est une excellente entrée. Mangez votre portion de 180 g avant le plat principal pour profiter de ses fibres qui ralentiront l''absorption des glucides du repas. Son IG modéré (40) est compensé par une faible charge glycémique grâce aux fibres. Évitez d''ajouter du sucre ou du miel."]'::jsonb, '["1. غسلوا الباربا الخضرا مزيان. ما تقشروهاش دابا.","2. حطوا الباربا كاملة، بالقشرة ديالها، فكاسرونة فيها ماء بارد. خليوها تغلى على نار متوسطة، من بعد نقصوا العافية وخليوها طيب على خاطرها لمدة 30 حتى 45 دقيقة، ولا حتى تولي رطبة (تقدروا تدخلوا فيها الموس بسهولة).","3. ملي طيب، حيدوا الباربا من الماء وخليوها تبرد تماما. ملي تبرد، القشرة غادي تحيد بسهولة غير بالحكان باليدين أو بموس صغير.","4. قطعوا الباربا اللي قشرتوها مكعبات صغار قياس 1 سم تقريبا. حطوا المكعبات فزلافة متوسطة.","5. فزلافة صغيرة بوحدها، وجدوا لاصوص: خلطوا 1 معلقة كبيرة ديال عصير الحامض طري، 1 معلقة صغيرة ديال زيت الزيتون البكر الممتاز، 1 ربع معلقة صغيرة ديال الكامون مطحون، 1 قبيصة ديال الملحة البحرية و 1 قبيصة ديال البزار كحل مطحون جديد. خلطوا مزيان باش يتجانسوا.","6. خويو لاصوص فوق مكعبات الباربا وخلطوا بلطف باش يتلبسوا جميع القطع. زيدوا 1 معلقة كبيرة ديال المعدنوس مقطع رقيق وخلطوا مرة أخرى.","7. خليو الشلاضة ترتاح فالثلاجة لمدة 30 دقيقة على الأقل قبل التقديم باش تندمج النكهات مزيان. قدموها باردة كمقبلات.","💡 نصيحة للسكري: شلاضة الباربا هادي مقبلة ممتازة. كولو الحصة ديالكم اللي هي 180 غرام قبل الطبق الرئيسي باش تستافدوا من الألياف ديالها اللي غادي تبطئ امتصاص الكربوهيدرات من الوجبة. المؤشر الغلايسيمي ديالها متوسط (40) ولكن الحمل الغلايسيمي ديالها منخفض بفضل الألياف. تجنبوا تزيدوا السكر أو العسل."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/1/1e/Beetroot_Salad_%283862315693%29.jpg', ARRAY['barba', 'betterave', 'بربة']::text[]),
  ('khyar-lben', 'Concombre au lben & menthe', 'خيار باللبن والنعناع', 'Cucumber with lben & mint', 'salad', ARRAY['ghda', '3cha', 'snack']::text[], '🥒', '1 bol (200 g)', 200, 80, 9, 7, 5, 2, 2, 20, 'Fraîcheur d’été à IG très bas : concombre + lben marocain + menthe. Presque pas de sucre, hydratant, parfait par temps chaud ou en entrée légère avant le tajine.', 'انتعاش الصيف بمؤشر منخفض بزاف: خيار + لبن مغربي + نعناع. تقريباً بلا سكر، كيرطب، مثالي فالسخانة ولا كمقبلات خفيفة قبل الطاجين.', '["150 g de concombre frais","50 ml de lben (babeurre marocain)","1 c. à soupe de menthe fraîche ciselée","1/4 c. à café de sel fin","1 pincée de poivre noir moulu","1/2 c. à café d''huile d''olive extra vierge"]'::jsonb, '["150 غرام خيار طري","50 مل لبن مغربي","1 م.ك نعناع طري مقطع رقيق","1/4 م.ص ملح رقيق","1 قبيصة إبزار كحل مطحون","1/2 م.ص زيت الزيتون البكر الممتاز"]'::jsonb, '["1. Lavez soigneusement le concombre sous l''eau froide. Pour une texture plus douce et une meilleure digestion, vous pouvez peler une bande sur deux de la peau du concombre, ou le peler entièrement si vous préférez. Coupez ensuite le concombre en très petits dés d''environ 0.5 cm de côté.","2. Dans un petit bol, placez les dés de concombre. Ajoutez le sel fin et le poivre noir moulu. Mélangez délicatement pour bien enrober les dés de concombre avec les assaisonnements.","3. Lavez la menthe fraîche et séchez-la bien. Ciselez finement les feuilles de menthe pour obtenir environ 1 cuillère à soupe de menthe ciselée. Ajoutez la menthe ciselée au concombre assaisonné.","4. Versez les 50 ml de lben marocain sur le mélange de concombre et de menthe. Le lben doit être bien frais pour un goût optimal.","5. Mélangez délicatement tous les ingrédients à l''aide d''une cuillère jusqu''à ce que le concombre soit uniformément enrobé de lben et de menthe.","6. Juste avant de servir, arrosez le tout d''une demi-cuillère à café d''huile d''olive extra vierge. Cela ajoute une touche de saveur et de bons gras sans altérer le profil nutritionnel.","7. Servez immédiatement dans un petit bol de 200 g. Ce plat est idéal en entrée rafraîchissante ou en accompagnement léger. Il est important de le consommer frais. \n💡 Astuce diabète : Cette salade est excellente pour les diabétiques grâce à son IG très bas (environ 20) et sa richesse en eau. La portion recommandée est de 200 g. Consommez-la en début de repas pour aider à stabiliser la glycémie avant d''autres plats plus riches en glucides, comme un tajine de légumes."]'::jsonb, '["1. غسل الخيار مزيان تحت الماء البارد. باش يجي رطب و ساهل في الهضم، ممكن تقشري قشرة اه و قشرة لا، أو تقشريه كامل إلا بغيتي. من بعد، قطعي الخيار مكعبات صغار بزاف، تقريبا 0.5 سم.","2. في زلافة صغيرة، حطي مكعبات الخيار. زيدي الملح الرقيق و الإبزار الكحل مطحون. خلطي غير بشوية باش يتلبس الخيار مزيان بالتوابل.","3. غسلي النعناع الطري و نشفيه مزيان. قطعيه رقيق بزاف باش تحصلي على تقريبا 1 معلقة كبيرة ديال النعناع مقطع. زيدي النعناع المقطع على الخيار اللي فيه التوابل.","4. خوي 50 مل ديال اللبن المغربي على خليط الخيار و النعناع. اللبن خاصو يكون بارد مزيان باش يعطي مذاق رائع.","5. خلطي جميع المكونات غير بشوية بالمعلقة حتى يتلبس الخيار كله باللبن و النعناع.","6. قبل ما تقدمي الطبق مباشرة، رشي عليه نص معلقة صغيرة ديال زيت الزيتون البكر الممتاز. هادشي كيزيد لمسة ديال المذاق و دهون صحية بلا ما يأثر على القيمة الغذائية.","7. قدميه مباشرة في زلافة صغيرة ديال 200 غرام. هاد الطبق مثالي كمقبلة منعشة أو مرافق خفيف. مهم يتكال بارد. \n💡 نصيحة للسكري: هاد الشلاضة ممتازة لمرضى السكري حيت المؤشر الجلايسيمي ديالها منخفض بزاف (تقريبا 20) و غنية بالماء. الكمية الموصى بها هي 200 غرام. تناولوها في بداية الوجبة باش تساعد على تثبيت مستوى السكر في الدم قبل الأطباق الأخرى اللي فيها كربوهيدرات أكثر، بحال الطاجين بالخضرة."]'::jsonb, null, ARRAY['concombre lben', 'خيار لبن']::text[]),
  ('harira-legere', 'Harira légère (sans vermicelles)', 'حريرة خفيفة (بلا شعرية)', 'Light harira (no vermicelli)', 'soup', ARRAY['3cha', 'snack']::text[], '🍲', '1 bol (300 ml)', 300, 160, 22, 4, 8, 4, 6, 40, 'La harira SANS vermicelles ni farine garde tout le bon (lentilles, pois chiches, tomates) et perd ce qui fait grimper la glycémie. Jamais avec dattes + chebakia.', 'الحريرة بلا شعرية وبلا دقيق كتحتفظ بكل ما هو مزيان (عدس، حمص، طماطم) وكتخسر اللي كيطلع السكر. عمرها مع التمر والشباكية.', '["100 g de tomates fraîches mûres (environ 1 petite tomate)","30 g de lentilles corail (non trempées)","30 g de pois chiches cuits (en conserve, rincés et égouttés)","10 g de céleri branche (environ 1/2 petite branche)","5 g de coriandre fraîche (environ 1 c. à soupe hachée)","5 g de persil frais (environ 1 c. à soupe haché)","1/4 d''oignon moyen (environ 20 g)","200 ml d''eau","1/2 c. à café de concentré de tomate","1/4 c. à café de curcuma"]'::jsonb, '["100 غرام مطيشة طايبة (حبة صغيرة تقريبا)","30 غرام عدس أحمر (بلا ما يترقد)","30 غرام حمص طايب (معلب، مغسول ومقطر)","10 غرام كرافس (نص عود صغير تقريبا)","5 غرام قزبور طري (معلقة كبيرة مقطعة تقريبا)","5 غرام معدنوس طري (معلقة كبيرة مقطعة تقريبا)","ربع بصلة متوسطة (20 غرام تقريبا)","200 ملل ماء","نص معلقة صغيرة مطيشة الحك","ربع معلقة صغيرة خرقوم بلدي"]'::jsonb, '["1. Lavez les tomates. Incisez-les légèrement en croix et plongez-les 30 secondes dans de l''eau bouillante. Pelez-les, épépinez-les et mixez-les pour obtenir une purée fine. Réservez.","2. Hachez finement l''oignon, le céleri, la coriandre et le persil. Dans une petite marmite ou casserole, faites chauffer 1/2 c. à café d''huile d''olive à feu doux. Ajoutez l''oignon haché et faites-le revenir pendant 2 minutes jusqu''à ce qu''il devienne translucide.","3. Ajoutez le céleri haché, le curcuma, le gingembre et le poivre noir. Mélangez bien et laissez mijoter 1 minute à feu doux pour libérer les arômes.","4. Incorporez la purée de tomates et le concentré de tomate. Ajoutez les lentilles corail rincées et les pois chiches cuits rincés. Versez les 200 ml d''eau.","5. Portez à ébullition à feu moyen, puis réduisez le feu à doux. Couvrez et laissez mijoter pendant environ 15-20 minutes, ou jusqu''à ce que les lentilles soient tendres et que la soupe ait légèrement épaissi. Remuez de temps en temps pour éviter que les lentilles n''accrochent au fond.","6. Juste avant de servir, ajoutez la coriandre et le persil hachés restants. Salez selon votre goût. Mélangez et laissez reposer 1 minute hors du feu pour que les arômes des herbes fraîches se diffusent.","7. Servez la harira légère chaude dans un bol de 300 ml (environ 300 g). Elle doit avoir une consistance légèrement épaisse mais fluide. Ne la servez jamais avec des dattes ou de la chebakia. 💡 Astuce diabète : Pour une meilleure gestion de la glycémie, consommez cette harira (1 bol de 300g, GI 40) comme plat principal léger. Évitez absolument les accompagnements sucrés comme les dattes ou la chebakia, qui feraient grimper votre glycémie. Privilégiez un verre d''eau avant le repas."]'::jsonb, '["1. غسلوا مطيشة. فلحوها شوية على شكل زائد وديروها فماء طايب لمدة 30 ثانية. قشروها، حيدو ليها الزريعة وطحنوها باش تحصلوا على بيوري رقيق. خليوها على جنب.","2. قطعوا البصلة، الكرافس، القزبور والمعدنوس رقيق بزاف. فكوكوط صغيرة أو طنجرة، سخنوا نص معلقة صغيرة زيت الزيتون على نار مهيلة. زيدوا البصلة المقطعة وخليوها تشحر لمدة 2 دقائق حتى تولي شفافة.","3. زيدوا الكرافس مقطع، الخرقوم، سكينجبير والإبزار. خلطوا مزيان وخليوها طيب على نار مهيلة لمدة دقيقة باش تطلق النكهات ديالها.","4. زيدوا بيوري مطيشة ومطيشة الحك. زيدوا العدس الأحمر مغسول والحمص طايب مغسول. خويوا 200 ملل ديال الماء.","5. خليوها حتى تغلى على نار متوسطة، من بعد نقصوا النار لمهيلة. غطيوها وخليوها طيب لمدة 15-20 دقيقة تقريبا، أو حتى يطيب العدس وتختار الشوربة شوية. حركوها مرة مرة باش ما يلصقش العدس فالقاع.","6. قبل ما تقدموها مباشرة، زيدوا القزبور والمعدنوس المقطعين اللي بقاو. زيدوا الملح حسب الذوق ديالكم. خلطوا وخليوها ترتاح دقيقة وحدة بعيد على النار باش تطلق النكهات ديال الأعشاب الطرية.","7. قدموا الحريرة الخفيفة سخونة فزلافة ديال 300 ملل (300 غرام تقريبا). خاص تكون القوام ديالها شوية خاتر ولكن سائل. ما تقدموهاش أبدا مع التمر أو الشباكية. 💡 نصيحة للسكري: باش تحافظوا على مستوى السكر فالدم، تناولوا هاد الحريرة (زلافة وحدة 300غ، GI 40) كوجبة رئيسية خفيفة. تجنبوا تماما المرافقة ديالها بحوايج حلوة بحال التمر أو الشباكية، اللي غادي تطلع ليكم السكر. شربوا كاس ديال الماء قبل الماكلة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/0d/Harira..JPG/1280px-Harira..JPG', ARRAY['hrira', 'حريرة صحية']::text[]),
  ('bissara-legere', 'Bissara (portion raisonnable)', 'بيصارة (كمية معقولة)', 'Bissara (moderate portion)', 'soup', ARRAY['ftour', 'ghda', '3cha']::text[], '🫘', '1 bol (250 ml)', 250, 210, 28, 2, 12, 5, 8, 40, 'Fèves = protéines végétales + fibres, IG modéré. Le piège c''est le PAIN qu''on trempe dedans : limitez-vous à ¼ de pain d''orge et 1 filet d''huile d''olive.', 'الفول = بروتين نباتي وألياف، مؤشر معتدل. الفخ هو الخبز اللي كنغمسو فيها: اكتفي بربع خبزة شعير وخيط ديال زيت الزيتون.', '["125 g de fèves séchées décortiquées (environ 1/2 tasse)","500 ml d''eau (2 tasses)","1 gousse d''ail, écrasée","1/4 c. à café de cumin en poudre","1/8 c. à café de paprika doux","1 pincée de sel","1 pincée de poivre noir","1 c. à café d''huile d''olive extra vierge","1/4 de pain d''orge (environ 30g)"]'::jsonb, '["125 غرام ديال الفول اليابس منقي (تقريبا نص كاس)","500 مللتر ديال الماء (2 كيسان)","1 فص ديال الثومة، مدقوق","1/4 معلقة صغيرة ديال الكامون مطحون","1/8 معلقة صغيرة ديال التحميرة الحلوة","1 قبيصة ديال الملحة","1 قبيصة ديال البزار الكحل","1 معلقة صغيرة ديال زيت الزيتون البكر الممتاز","1/4 خبزة ديال الشعير (تقريبا 30 غرام)"]'::jsonb, '["1. Rincez soigneusement 125 g de fèves séchées décortiquées à l''eau froide. Il n''est pas nécessaire de les faire tremper si vous utilisez une cocotte-minute, sinon trempez-les pendant au moins 4 heures.","2. Dans une cocotte-minute ou une casserole à fond épais, mettez les fèves rincées, 500 ml d''eau, la gousse d''ail écrasée, 1 pincée de sel et 1 pincée de poivre noir.","3. Si vous utilisez une cocotte-minute, fermez-la et laissez cuire à feu moyen pendant environ 20-25 minutes après le sifflement. Si vous utilisez une casserole normale, couvrez et laissez mijoter à feu doux pendant 1h30 à 2 heures, ou jusqu''à ce que les fèves soient très tendres et se désintègrent facilement.","4. Une fois les fèves bien cuites, retirez la casserole du feu. À l''aide d''un mixeur plongeant ou d''un presse-purée, réduisez les fèves en purée jusqu''à obtenir une consistance lisse et homogène. Si la Bissara est trop épaisse, ajoutez un peu d''eau chaude (environ 50 ml) pour ajuster la consistance désirée.","5. Remettez la purée sur feu doux. Ajoutez 1/4 c. à café de cumin en poudre et 1/8 c. à café de paprika doux. Mélangez bien et laissez mijoter encore 5 minutes, en remuant de temps en temps pour éviter que la Bissara n''attache au fond de la casserole.","6. Servez la Bissara chaude dans un bol de 250 ml. Juste avant de déguster, arrosez d''un filet d''1 c. à café d''huile d''olive extra vierge et saupoudrez d''une petite pincée de cumin supplémentaire si désiré.","7. Accompagnez votre bol de Bissara avec 1/4 de pain d''orge (environ 30g).","💡 Astuce diabète : La Bissara a un IG modéré. Pour contrôler votre glycémie, limitez votre portion à 250g (un bol) et ne dépassez pas 1/4 de pain d''orge (environ 30g) pour tremper. Privilégiez le pain d''orge qui a un IG plus bas que le pain blanc. Mangez lentement et savourez chaque bouchée."]'::jsonb, '["1. غسلوا مزيان 125 غرام ديال الفول اليابس المنقي بالماء البارد. ما تحتاجوش ترقدوه إذا كنتوا غتستعملوا طنجرة الضغط، وإلا رقدوه على الأقل 4 ساعات.","2. في طنجرة الضغط أو كاسرونة ثقيلة، حطوا الفول المغسول، 500 مللتر ديال الماء، فص الثومة المدقوق، قبيصة ديال الملحة وقبيصة ديال البزار الكحل.","3. إذا كنتوا كتستعملوا طنجرة الضغط، سدوها وخليوها طيب على نار متوسطة لمدة 20-25 دقيقة تقريبا من بعد ما تصفر. إذا كنتوا كتستعملوا كاسرونة عادية، غطيوها وخليوها طيب على نار مهيلة من ساعة ونص حتى لساعتين، أو حتى يولي الفول رطب بزاف وكيتهرس بسهولة.","4. ملي يطيب الفول مزيان، حيدوا الكاسرونة من فوق النار. استعملوا خلاط يدوي أو معس الفول باش طحنوا الفول حتى يولي أملس ومتجانس. إذا كانت البيصارة ثقيلة بزاف، زيدوا شوية ديال الماء سخون (تقريبا 50 مللتر) باش تعدلوا القوام اللي بغيتوا.","5. رجعوا البيصارة المطحونة فوق نار مهيلة. زيدوا 1/4 معلقة صغيرة ديال الكامون مطحون و 1/8 معلقة صغيرة ديال التحميرة الحلوة. خلطوا مزيان وخليوها طيب 5 دقائق أخرى، مع التحريك مرة مرة باش ما تلصقش البيصارة في قاع الكاسرونة.","6. قدموا البيصارة سخونة في زلافة ديال 250 مللتر. قبل ما تاكلوا، ديروا عليها خط ديال 1 معلقة صغيرة ديال زيت الزيتون البكر الممتاز ورشوا عليها شوية ديال الكامون إضافي إذا بغيتوا.","7. رافقوا الزلافة ديال البيصارة ديالكم مع 1/4 خبزة ديال الشعير (تقريبا 30 غرام).","💡 نصيحة للسكري: البيصارة عندها مؤشر سكري متوسط. باش تحكموا في مستوى السكر في الدم ديالكم، حددوا الكمية ديالكم في 250 غرام (زلافة وحدة) وما تفوتوش 1/4 خبزة ديال الشعير (تقريبا 30 غرام) باش تغمسوا. فضلوا خبز الشعير اللي عندو مؤشر سكري أقل من الخبز الأبيض. كلوا ببطء واستمتعوا بكل لقمة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/19/Bissara_%28Moroccan_Dip%29.JPG/1280px-Bissara_%28Moroccan_Dip%29.JPG', ARRAY['bessara', 'بيصارة']::text[]),
  ('soupe-legumes', 'Soupe de légumes maison', 'صوبة الخضرة ديال الدار', 'Homemade vegetable soup', 'soup', ARRAY['3cha']::text[], '🥕', '1 bol (300 ml)', 300, 110, 16, 6, 4, 3, 5, 30, 'Le dîner parfait quand la journée a été trop sucrée : chaude, rassasiante, presque sans glucides. Évitez les pommes de terre, gardez courgettes-carottes-poireaux.', 'العشا المثالي ملي يكون النهار عامر بالسكر: سخونة، كتشبع، وتقريباً بلا نشويات. تجنب البطاطا، خلي القرعة والخيزو والبورو.', '["150 g de courgettes (environ 1 petite)","50 g de carottes (environ 1/2 moyenne)","50 g de poireaux (environ 1/4 de tige)","100 ml d''eau filtrée","1/2 c. à café d''huile d''olive extra vierge","1 petite pincée de sel de mer","1 petite pincée de cumin moulu","1 petite pincée de gingembre moulu","Quelques brins de coriandre fraîche pour la garniture"]'::jsonb, '["150 غرام قرعة خضرا (حبة صغيرة تقريبا)","50 غرام خيزو (نص حبة متوسطة تقريبا)","50 غرام بورو (ربع عود تقريبا)","100 مللتر ماء مفلتر","نص معلقة صغيرة زيت الزيتون البكر الممتاز","رشيشة صغيرة ملح البحر","رشيشة صغيرة كامون مطحون","رشيشة صغيرة سكينجبير مطحون","شوية قزبر طري للتزيين"]'::jsonb, '["1. Lavez soigneusement tous les légumes. Épluchez la carotte et coupez-la en petits dés. Coupez la courgette (non épluchée) et le poireau en rondelles fines.","2. Dans une petite casserole à fond épais, faites chauffer 1/2 c. à café d''huile d''olive à feu doux. Ajoutez les dés de carotte et les rondelles de poireau. Faites-les revenir doucement pendant 3 à 4 minutes, jusqu''à ce qu''ils commencent à s''attendrir, sans les laisser dorer.","3. Incorporez les rondelles de courgette dans la casserole. Remuez bien et laissez cuire encore 2 minutes.","4. Versez 100 ml d''eau filtrée. Ajoutez la pincée de sel, de cumin et de gingembre. Mélangez délicatement.","5. Portez à ébullition, puis réduisez le feu à doux. Couvrez la casserole et laissez mijoter pendant 15 à 20 minutes, ou jusqu''à ce que tous les légumes soient très tendres. Vérifiez la cuisson avec la pointe d''un couteau.","6. Retirez la casserole du feu. À l''aide d''un mixeur plongeant, mixez la soupe directement dans la casserole jusqu''à obtenir une consistance lisse et homogène. Si vous préférez une texture plus rustique, mixez moins longtemps en laissant quelques petits morceaux.","7. Servez la soupe chaude dans un bol de 300 ml. Garnissez avec quelques brins de coriandre fraîche ciselée. Dégustez immédiatement. \n💡 Astuce diabète : Cette soupe est un excellent choix pour un dîner léger. Pour un contrôle optimal de la glycémie, consommez votre bol de 300g (environ 110 kcal, 16g de glucides) en début de repas, avant d''éventuels autres aliments. Évitez d''ajouter des pommes de terre ou des pâtes pour maintenir un indice glycémique bas (GI 30).","8. Pour une version plus consistante sans augmenter significativement les glucides, vous pouvez ajouter 30g de lentilles corail (bien rincées) en même temps que l''eau et les épices à l''étape 4. Cela augmentera légèrement les protéines et les fibres."]'::jsonb, '["1. غسلوا الخضرة مزيان. قشروا خيزو وقطعوه مكعبات صغار. قطعوا القرعة الخضرا (بلا ما تقشروها) والبورو دوائر رقاق.","2. فكاسرونة صغيرة وثقيلة، سخنوا نص معلقة صغيرة ديال زيت الزيتون على نار مهيلة. زيدوا مكعبات خيزو ودوائر البورو. خليوهم يتشحروا بشوية لمدة 3 حتى 4 دقايق، حتى يبداو يرطابو بلا ما يتحمروا.","3. زيدوا دوائر القرعة الخضرا فالكاسرونة. خلطوا مزيان وخليوهم يطيبوا جوج دقايق آخرين.","4. خويوا 100 مللتر ديال الماء المفلتر. زيدوا رشيشة الملحة، الكامون، وسكينجبير. خلطوا بلطف.","5. خليوها حتى تغلى، من بعد نقصوا العافية لمهيلة. غطيو الكاسرونة وخليوها طيب على خاطرها لمدة 15 حتى 20 دقيقة، ولا حتى تولي الخضرة كلها رطبة بزاف. تأكدوا من الطياب برأس الموس.","6. حيدوا الكاسرونة من فوق العافية. باستعمال الخلاط اليدوي (mixeur plongeant)، طحنوا الشوربة مباشرة فالكاسرونة حتى تولي ملساء ومتجانسة. إلا كنتوا كتفضلوا قوام حرش شوية، طحنوا غير شوية وخليو شي طريفات صغار.","7. قدموا الشوربة سخونة فزلافة ديال 300 مللتر. زينوها بشوية ديال القزبر الطري مقطع. بالصحة والراحة. \n💡 نصيحة للسكري: هاد الشوربة اختيار ممتاز لعشاء خفيف. باش تحافظوا على مستوى السكر فالدم مزيان، كولوا الزلافة ديالكم (300 غرام، تقريبا 110 سعرة حرارية، 16 غرام كربوهيدرات) فبداية الوجبة، قبل أي أكل آخر. تجنبوا تزيدوا البطاطا أو المعجنات باش تحافظوا على مؤشر سكري منخفض (GI 30).","8. لنسخة أكثر إشباعًا دون زيادة كبيرة في الكربوهيدرات، يمكنكم إضافة 30 غرامًا من العدس الأحمر (مغسول جيدًا) في نفس الوقت مع الماء والتوابل في الخطوة 4. هذا سيزيد قليلاً من البروتينات والألياف."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f6/Vegetable_soup_9.jpg/1280px-Vegetable_soup_9.jpg', ARRAY['soupe khodra']::text[]),
  ('chorba-poisson', 'Chorba de poisson', 'شوربة الحوت', 'Fish chorba', 'soup', ARRAY['3cha', 'ghda']::text[], '🐠', '1 bol (300 ml)', 300, 170, 12, 4, 18, 6, 3, 25, 'Protéines de la mer + légumes, presque pas de glucides. Le poisson 2×/semaine est prouvé bénéfique pour le cœur des diabétiques.', 'بروتين البحر مع الخضرة، تقريباً بلا نشويات. الحوت جوج مرات فالسيمانة مثبت علمياً أنه مفيد لقلب السكري.', '["150 g de filet de poisson blanc (merlan, cabillaud)","75 ml d''eau","50 g de tomates concassées (sans sucre ajouté)","30 g de carottes, coupées en petits dés","30 g de courgettes, coupées en petits dés","15 g de céleri branche, haché finement","1 c. à soupe d''huile d''olive extra vierge","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","Une pincée de sel de mer"]'::jsonb, '["150 غرام من فيليه السمك الأبيض (الميرلان، الكود)","75 ملل من الماء","50 غرام من مطيشة محكوكة (بدون سكر مضاف)","30 غرام من خيزو، مقطع مكعبات صغيرة","30 غرام من القرعة الخضراء، مقطعة مكعبات صغيرة","15 غرام من الكرافس، مقطع رقيق","1 ملعقة كبيرة من زيت الزيتون البكر الممتاز","1/2 ملعقة صغيرة من الكمون مطحون","1/4 ملعقة صغيرة من التحميرة الحلوة","قبيصة ملح البحر"]'::jsonb, '["Dans une casserole moyenne, faites chauffer 1 c. à soupe d''huile d''olive à feu moyen. Ajoutez les dés de carottes, de courgettes et le céleri haché. Faites revenir pendant 5 minutes en remuant de temps en temps, jusqu''à ce que les légumes commencent à s''attendrir.","Ajoutez les 50 g de tomates concassées, le 1/2 c. à café de cumin et le 1/4 c. à café de paprika. Mélangez bien et laissez mijoter pendant 3 minutes pour que les saveurs se développent.","Versez les 75 ml d''eau dans la casserole. Portez à ébullition, puis réduisez le feu à doux et laissez mijoter à couvert pendant 10 minutes, jusqu''à ce que les légumes soient tendres mais encore légèrement croquants.","Pendant ce temps, coupez le filet de poisson blanc en morceaux de taille moyenne (environ 2-3 cm).","Ajoutez délicatement les morceaux de poisson dans la soupe. Salez et poivrez selon votre goût (une pincée de chaque).","Laissez cuire à feu doux pendant 5 à 7 minutes, ou jusqu''à ce que le poisson soit opaque et se défasse facilement à la fourchette. Ne sur-cuisez pas le poisson pour qu''il reste moelleux.","Servez la chorba de poisson chaude dans un bol de 300 ml. Vous pouvez garnir d''un peu de persil frais haché si désiré (non inclus dans le calcul nutritionnel).","💡 Astuce diabète : Cette chorba est excellente pour stabiliser la glycémie. Consommez un bol de 300 g (environ 170 kcal, 12 g de glucides, GI 25) en début de repas. Évitez de l''accompagner de pain blanc ou de semoule, préférez une petite portion de pain complet ou une salade verte pour un apport en fibres supplémentaire."]'::jsonb, '["فوق نار متوسطة، سخّن 1 ملعقة كبيرة من زيت الزيتون في كاسرونة متوسطة. ضف مكعبات خيزو، القرعة الخضراء والكرافس المقطع. شحرهم لمدة 5 دقائق مع التحريك مرة مرة حتى يبداو الخضراوات يترخاو شوية.","ضف 50 غرام من مطيشة محكوكة، 1/2 ملعقة صغيرة من الكمون و 1/4 ملعقة صغيرة من التحميرة. خلط مزيان وخليهم يتشحرو لمدة 3 دقائق باش تطلق النكهات.","صب 75 ملل من الماء في الكاسرونة. خليه يغلى، من بعد نقص النار لمهيلة وخليه يطيب مغطي لمدة 10 دقائق، حتى يطيبو الخضراوات ولكن يبقاو قاصحين شوية.","في هاد الوقت، قطع فيليه السمك الأبيض لقطع متوسطة (تقريبا 2-3 سم).","ضف قطع السمك بلطف للشوربة. ضف الملح والإبزار حسب الذوق ديالك (قبيصة من كل واحد).","خليه يطيب فوق نار مهيلة لمدة 5 حتى 7 دقائق، أو حتى يولي السمك أبيض ومايبقاش شفاف ويتفتت بسهولة بالفرشيطة. ماتطيبش السمك بزاف باش يبقى رطب.","قدم شوربة الحوت سخونة في زلافة ديال 300 ملل. تقدر تزينها بشوية ديال المعدنوس مقطع طري إذا بغيتي (ماشي داخل في الحساب الغذائي).","💡 نصيحة للسكري: هاد الشوربة ممتازة لتثبيت مستوى السكر في الدم. تناول زلافة ديال 300 غرام (تقريبا 170 سعرة حرارية، 12 غرام كربوهيدرات، مؤشر سكري 25) في بداية الوجبة. تجنب تاكلها مع الخبز الأبيض أو السميدة، من الأفضل تاكل معاها كمية صغيرة من الخبز الكامل أو سلطة خضراء باش تزيد من الألياف."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/98/Sliced_fish_soup%2C_Pek_Kio_Market_%26_Food_Centre_%2825065937730%29.jpg/1280px-Sliced_fish_soup%2C_Pek_Kio_Market_%26_Food_Centre_%2825065937730%29.jpg', ARRAY['soupe poisson', 'شوربة']::text[]),
  ('tchicha-belboula', 'Tchicha (soupe d''orge)', 'التشيشة (حساء الشعير)', 'Tchicha (barley soup)', 'soup', ARRAY['ftour', '3cha']::text[], '🌾', '1 bol (300 ml)', 300, 170, 28, 3, 6, 4, 6, 45, 'L''orge est la céréale marocaine à l''IG le plus bas : bien meilleure que la semoule de blé. La tchicha du matin ou du soir cale sans faire grimper le sucre.', 'الشعير هو الحبوب المغربية بأقل مؤشر جلايسيمي: أحسن بكثير من سميدة القمح. تشيشة الصباح ولا العشية كتشبع بلا ما تطلع السكر.', '["50 g d''orge concassée (tchicha)","300 ml d''eau","100 ml de lait demi-écrémé","1/4 oignon moyen (environ 30 g), finement haché","1/2 gousse d''ail, écrasée","1/4 c. à café de sel","Une pincée de poivre noir","1/2 c. à café d''huile d''olive extra vierge","Une pincée de cumin en poudre (facultatif)"]'::jsonb, '["50 غرام تشيشة (شعير مهرس)","300 مل ماء","100 مل حليب نصف دسم","1/4 بصلة متوسطة (حوالي 30 غرام)، مفرومة رقيق","1/2 فص ثوم، مدقوق","1/4 ملعقة صغيرة ملح","رشة فلفل أسود","1/2 ملعقة صغيرة زيت زيتون بكر ممتاز","رشة كمون مطحون (اختياري)"]'::jsonb, '["1. Rincez soigneusement les 50 g d''orge concassée (tchicha) sous l''eau froide jusqu''à ce que l''eau soit claire. Égouttez bien.","2. Dans une petite casserole à fond épais, faites chauffer 1/2 c. à café d''huile d''olive à feu moyen. Ajoutez l''oignon finement haché et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide. Ajoutez l''ail écrasé et faites revenir 1 minute de plus, en veillant à ne pas le brûler.","3. Incorporez l''orge rincée et égouttée dans la casserole. Remuez pendant 1 minute pour bien enrober l''orge avec l''oignon et l''ail.","4. Versez les 300 ml d''eau. Portez à ébullition, puis réduisez le feu à doux. Couvrez et laissez mijoter pendant 20 minutes, en remuant de temps en temps pour éviter que l''orge ne colle au fond. L''orge doit commencer à gonfler et à s''attendrir.","5. Après 20 minutes, ajoutez les 100 ml de lait demi-écrémé, 1/4 c. à café de sel et une pincée de poivre noir. Mélangez bien.","6. Poursuivez la cuisson à feu doux, à découvert, pendant encore 10-15 minutes, ou jusqu''à ce que la tchicha ait atteint la consistance désirée (elle doit être crémeuse mais encore légèrement texturée). Si vous souhaitez une consistance plus liquide, vous pouvez ajouter un peu plus d''eau chaude ou de lait. Goûtez et ajustez l''assaisonnement si nécessaire, ajoutez la pincée de cumin si désiré.","7. Servez immédiatement dans un bol de 300 ml. 💡 Astuce diabète : Cette portion de 300 g (environ 170 kcal, 28 g de glucides, IG 45) est idéale pour un repas léger ou une collation. Pour stabiliser davantage la glycémie, consommez-la avec une source de protéines maigres (ex: œuf dur, un petit morceau de fromage frais) ou des légumes verts pour augmenter l''apport en fibres."]'::jsonb, '["1. غسلوا التشيشة (50 غرام) مزيان بالماء بارد حتى يولي الماء نقي. صفّيوها مزيان.","2. فكاسرونة صغيرة وثقيلة، سخّنوا 1/2 ملعقة صغيرة زيت زيتون على نار متوسطة. زيدوا البصلة مفرومة رقيق وخليوها تشحر 3-4 دقايق حتى تولي شفافة. زيدوا الثومة مدقوقة وخليوها تشحر دقيقة أخرى، ردوا البال ماتحرقش.","3. زيدوا التشيشة مغسولة ومصفية للكاسرونة. حركوا دقيقة باش التشيشة تتغلف مزيان بالبصلة والثومة.","4. خويوا 300 مل ماء. خليوه يغلى، من بعد نقصوا النار لمهيلة. غطيوها وخليوها طيب على خاطرها 20 دقيقة، وحركوا مرة مرة باش ماتلصقش التشيشة فالقاع. التشيشة خاصها تبدا تنفخ وتطرى.","5. من بعد 20 دقيقة، زيدوا 100 مل حليب نصف دسم، 1/4 ملعقة صغيرة ملح ورشة فلفل أسود. خلطوا مزيان.","6. كملوا الطياب على نار مهيلة، بلا غطا، لمدة 10-15 دقيقة أخرى، أو حتى توصل التشيشة للقوام اللي بغيتوا (خاصها تكون كريمية ولكن فيها شوية ديال القوام). إلا بغيتوها جارية أكثر، ممكن تزيدوا شوية ماء سخون أو حليب. ذوقوا وقادوا الملح إلا خاص، وزيدوا رشة الكمون إلا بغيتوا.","7. قدموها سخونة فزلافة ديال 300 مل. 💡 نصيحة للسكري: هاد الكمية ديال 300 غرام (حوالي 170 سعرة حرارية، 28 غرام كربوهيدرات، مؤشر سكري 45) مثالية لوجبة خفيفة أو كاسكروط. باش تحافظوا على مستوى السكر فدم مستقر أكثر، كلوها مع مصدر بروتين قليل الدهن (مثلا: بيضة مسلوقة، طريف صغير ديال فرماج طري) أو خضروات خضراء باش تزيدوا من الألياف."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/73/Mmm..._Beef_n_Barley_Soup_%285086768393%29.jpg/1280px-Mmm..._Beef_n_Barley_Soup_%285086768393%29.jpg', ARRAY['belboula', 'dchicha', 'تشيشة', 'بلبولة']::text[]),
  ('soupe-potiron-gingembre', 'Velouté de potiron au gingembre', 'صوبة القرع الأحمر بالسكينجبير', 'Pumpkin ginger soup', 'soup', ARRAY['3cha']::text[], '🎃', '1 bol (300 ml)', 300, 120, 18, 8, 3, 4, 4, 40, 'Le potiron (graa hamra) est peu calorique et rassasiant. Le gingembre réchauffe et soutient la digestion. Un dîner doux et réconfortant, sans pomme de terre ni crème.', 'القرع الأحمر قليل الكالوري وكيشبع. السكينجبير كيسخن وكيعاون على الهضم. عشا حلو ومريح، بلا بطاطا وبلا كريمة.', '["300 g de potiron (graa hamra) épluché et coupé en dés","1/2 pièce d''oignon rouge (environ 50 g), haché finement","1 gousse d''ail, écrasée","1 c. à café de gingembre frais râpé","200 ml d''eau filtrée ou de bouillon de légumes léger (sans sel ajouté)","1/4 c. à café de cumin moulu","1/4 c. à café de curcuma moulu","1 c. à café d''huile d''olive extra vierge","Sel et poivre noir fraîchement moulu au goût (très peu de sel)"]'::jsonb, '["300 غرام من القرع الأحمر (كراعة حمرا) مقشر ومقطع مكعبات","1/2 حبة بصل أحمر (حوالي 50 غرام)، مفروم رقيق","1 فص ثوم، مدقوق","1 ملعقة صغيرة زنجبيل طازج مبشور","200 مل ماء مفلتر أو مرق خضروات خفيف (بدون ملح مضاف)","1/4 ملعقة صغيرة كمون مطحون","1/4 ملعقة صغيرة كركم مطحون","1 ملعقة صغيرة زيت زيتون بكر ممتاز","ملح وفلفل أسود مطحون طازج حسب الذوق (قليل جدا من الملح)"]'::jsonb, '["Dans une casserole à fond épais, faites chauffer 1 c. à café d''huile d''olive à feu doux. Ajoutez l''oignon rouge haché et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide, sans le laisser dorer. Remuez régulièrement.","Ajoutez la gousse d''ail écrasée et le gingembre frais râpé. Faites revenir pendant 1 minute supplémentaire en remuant constamment pour libérer les arômes.","Incorporez les dés de potiron, le cumin moulu et le curcuma moulu. Mélangez bien pour enrober tous les morceaux de potiron avec les épices. Laissez cuire 2 minutes à feu doux, en remuant de temps en temps.","Versez les 200 ml d''eau filtrée ou de bouillon de légumes léger. Portez à ébullition, puis réduisez le feu à doux, couvrez et laissez mijoter pendant 15-20 minutes, ou jusqu''à ce que le potiron soit très tendre et puisse être facilement écrasé à la fourchette.","Retirez la casserole du feu. À l''aide d''un mixeur plongeant, mixez la soupe directement dans la casserole jusqu''à obtenir une texture très lisse et homogène. Si la soupe est trop épaisse, vous pouvez ajouter une petite quantité d''eau chaude (10-20 ml) pour ajuster la consistance désirée.","Remettez la casserole sur feu doux juste pour réchauffer. Salez et poivrez très légèrement au goût. Goûtez et ajustez l''assaisonnement si nécessaire, en privilégiant les épices plutôt que le sel.","💡 Astuce diabète : Cette portion de 300 g (1 bol) est idéale pour un dîner léger. Son faible indice glycémique (GI 40) aide à maintenir une glycémie stable. Pour un repas équilibré, accompagnez-la d''une petite salade verte sans féculents et d''une source de protéines maigres (par exemple, 50-70g de poulet grillé). Évitez le pain ou les croûtons pour ne pas augmenter l''apport en glucides."]'::jsonb, '["فوق نار مهيلة، سخني 1 ملعقة صغيرة زيت زيتون في طنجرة ثقيلة. ضيفي البصل الأحمر المفروم وخليه يتشحر لمدة 3-4 دقائق حتى يولي شفاف، بلا ما يتحمر. حركي مرة مرة.","ضيفي فص الثوم المدقوق والزنجبيل الطازج المبشور. خليهم يتشحروا دقيقة أخرى مع التحريك المستمر باش تطلق الروائح ديالهم.","زيدي مكعبات القرع الأحمر، الكمون المطحون والكركم المطحون. خلطي مزيان باش يتغطاو جميع طريفات القرع بالعطرية. خليه يطيب 2 دقائق فوق نار مهيلة، مع التحريك مرة مرة.","صبي 200 مل من الماء المفلتر أو مرق الخضروات الخفيف. خليه يغلى، من بعد نقصي النار لمهيلة، غطي الطنجرة وخليه يطيب لمدة 15-20 دقيقة، أو حتى يولي القرع رطب بزاف وتقدري تهرسيه بسهولة بالفرشيطة.","حيدي الطنجرة من فوق النار. باستعمال الخلاط اليدوي (mixeur plongeant)، طحني الشوربة مباشرة في الطنجرة حتى تولي ملساء ومتجانسة. إذا كانت الشوربة ثقيلة بزاف، تقدري تزيدي شوية ماء سخون (10-20 مل) باش تعدلي القوام اللي بغيتي.","رجعي الطنجرة فوق نار مهيلة غير باش تسخن. زيدي شوية ملح وفلفل أسود حسب الذوق. ذوقي وعدلي التوابل إذا لزم الأمر، مع التركيز على العطرية أكثر من الملح.","💡 نصيحة للسكري: هاد الكمية ديال 300 غرام (1 زلافة) مثالية لعشاء خفيف. المؤشر الجلايسيمي المنخفض ديالها (GI 40) كيساعد باش يبقى السكر في الدم مستقر. لوجبة متوازنة، قدميها مع سلطة خضراء صغيرة بدون نشويات ومصدر بروتين قليل الدهون (مثلا، 50-70 غرام دجاج مشوي). تجنبي الخبز أو الخبز المحمص باش ما تزيدي نسبة الكربوهيدرات."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/2/23/Pumpkin_soup_with_ginger_and_roasted_pumpkin_seeds.jpg', ARRAY['potiron', 'graa hamra', 'قرع']::text[]),
  ('chorba-adas-khodra', 'Chorba lentilles & légumes', 'شوربة العدس بالخضرة', 'Lentil & vegetable chorba', 'soup', ARRAY['3cha', 'ghda']::text[], '🥣', '1 bol (320 ml)', 320, 200, 28, 5, 12, 4, 9, 30, 'Lentilles + légumes = un dîner complet à IG bas qui stabilise la glycémie toute la nuit. Les fibres et les protéines végétales rassasient sans faire grimper le sucre.', 'العدس + الخضرة = عشا كامل بمؤشر منخفض كيثبت السكر الليل كامل. الألياف والبروتين النباتي كيشبعو بلا ما يطلعو السكر.', '["60 g lentilles corail (rouges)","1/2 pièce oignon rouge (environ 40 g)","1/2 pièce carotte (environ 30 g)","1/4 pièce courgette (environ 25 g)","1/2 gousse ail","1/2 c. à café cumin moulu","1/4 c. à café curcuma moulu","1/2 c. à soupe huile d''olive extra vierge","250 ml eau ou bouillon de légumes faible en sel"]'::jsonb, '["60 غرام عدس أحمر (عدس بلدي)","نص بصلة حمراء (تقريبا 40 غرام)","نص خيزوة (تقريبا 30 غرام)","ربع قرعة خضرا (تقريبا 25 غرام)","نص ضرس ثومة","نص معلقة صغيرة كامون مطحون","ربع معلقة صغيرة خرقوم بلدي مطحون","نص معلقة كبيرة زيت الزيتون البكر الممتاز","250 مل ماء أو مرق خضروات قليل الملح"]'::jsonb, '["1. Rincez soigneusement les 60 g de lentilles corail sous l''eau froide jusqu''à ce que l''eau soit claire. Égouttez et réservez.","2. Préparez les légumes : hachez finement la 1/2 pièce d''oignon rouge, la 1/2 gousse d''ail. Coupez la 1/2 pièce de carotte et la 1/4 pièce de courgette en petits dés de 0,5 cm.","3. Dans une petite casserole à fond épais, faites chauffer la 1/2 c. à soupe d''huile d''olive à feu moyen. Ajoutez l''oignon haché et faites-le revenir pendant 3 minutes jusqu''à ce qu''il devienne translucide. Ajoutez l''ail haché et faites cuire 1 minute de plus sans le laisser dorer.","4. Incorporez les dés de carotte et de courgette. Faites-les revenir pendant 5 minutes en remuant de temps en temps, jusqu''à ce qu''ils commencent à s''attendrir légèrement.","5. Ajoutez les lentilles corail rincées, la 1/2 c. à café de cumin moulu et la 1/4 c. à café de curcuma moulu. Mélangez bien pendant 1 minute pour enrober les lentilles et les légumes des épices.","6. Versez les 250 ml d''eau ou de bouillon de légumes. Portez à ébullition, puis réduisez le feu à doux, couvrez et laissez mijoter pendant 15-20 minutes, ou jusqu''à ce que les lentilles soient tendres et que la soupe ait épaissi. Remuez occasionnellement pour éviter que les lentilles n''attachent au fond.","7. Servez immédiatement dans un bol de 320 ml. Vous pouvez ajouter un filet de jus de citron frais avant de déguster pour rehausser les saveurs.","💡 Astuce diabète : Cette chorba est un repas complet à IG bas. Pour maintenir une glycémie stable, consommez votre bol de 320 g lentement. N''ajoutez pas de pain blanc; si vous souhaitez accompagner, optez pour une petite tranche de pain complet aux céréales (max 30g) ou une salade verte sans vinaigrette sucrée."]'::jsonb, '["1. غسلوا 60 غرام ديال العدس الأحمر مزيان تحت الماء بارد حتى يولي الماء نقي. صفيوه وخليوه على جنب.","2. وجدوا الخضرة: قطعوا نص بصلة حمراء رقيقة بزاف، ونص ضرس ثومة حتى هو رقيق. قطعوا نص خيزوة وربع قرعة خضرا مكعبات صغار بزاف (0.5 سم).","3. فكاسرونة صغيرة وثقيلة، سخنوا نص معلقة كبيرة ديال زيت الزيتون على نار متوسطة. زيدوا البصلة المقطعة وشحروها لمدة 3 دقايق حتى تولي شفافة. زيدوا الثومة المقطعة وطيبوها دقيقة أخرى بلا ما تخليوها تتحمر.","4. زيدوا مكعبات خيزو والقرعة الخضرا. شحروهم لمدة 5 دقايق مع التحريك مرة مرة، حتى يبداو يرطابوا شوية.","5. زيدوا العدس الأحمر اللي غسلتوه، نص معلقة صغيرة ديال الكامون مطحون وربع معلقة صغيرة ديال الخرقوم البلدي مطحون. خلطوا مزيان لمدة دقيقة باش يتلبس العدس والخضرة بالعطرية.","6. خويوا 250 مل ديال الماء أو مرق الخضروات. خليوه يغلى، من بعد نقصوا النار لمهيلة، غطيوا الكاسرونة وخليوها طيب لمدة 15-20 دقيقة، أو حتى يطيب العدس ويرطاب وتختار الشوربة. حركوا مرة مرة باش ما يلصقش العدس فالقاع.","7. قدموا الشوربة سخونة فزلافة ديال 320 مل. تقدروا تزيدوا شوية ديال عصير الحامض الطري قبل ما تاكلوا باش تزيدوا البنة.","💡 نصيحة للسكري: هاد الشوربة وجبة كاملة ومؤشرها الكلايسيمي منخفض. باش تحافظوا على مستوى السكر مستقر، كولوا الزلافة ديالكم (320 غرام) بشوية. ما تزيدوش الخبز الأبيض؛ إلا بغيتوا شي حاجة معها، اختاروا طريف صغير ديال الخبز الكامل بالحبوب (أقصى حد 30 غرام) أو سلطة خضرا بلا صلصة حلوة."]'::jsonb, null, ARRAY['chorba adas', 'شوربة عدس']::text[]),
  ('tajine-poulet-legumes', 'Tajine de poulet aux légumes', 'طاجين الدجاج بالخضرة', 'Chicken & vegetable tagine', 'main', ARRAY['ghda', '3cha']::text[], '🍗', '1 assiette (350 g)', 350, 330, 15, 6, 34, 15, 5, 35, 'LE plat marocain idéal pour un diabétique : protéines du poulet, légumes à IG bas, cuisson douce. Le secret : beaucoup de légumes, peu d''huile, et ¼ de pain seulement.', 'الطاجين المغربي المثالي للسكري: بروتين الدجاج، خضرة بمؤشر منخفض، وطيب هادئ. السر: خضرة بزاف، زيت قليلة، وربع خبزة برك.', '["150 g de blanc de poulet (sans peau ni os)","100 g de légumes variés (carottes, courgettes, haricots verts, petits pois)","1/2 oignon (environ 50 g)","1/2 tomate (environ 40 g)","1 c. à soupe d''huile d''olive (15 ml)","1/2 c. à café de curcuma","1/2 c. à café de gingembre moulu","1/4 c. à café de poivre noir","Quelques brins de coriandre fraîche et persil (environ 5 g)"]'::jsonb, '["150 غرام صدر دجاج (بلا جلد وعظم)","100 غرام خضرة مشكلة (خيزو، كرعة، لوبيا خضرا، جلبانة)","نص بصلة (تقريبا 50 غرام)","نص مطيشة (تقريبا 40 غرام)","1 معلقة كبيرة زيت الزيتون (15 مل)","نص معلقة صغيرة خرقوم بلدي","نص معلقة صغيرة سكينجبير","ربع معلقة صغيرة إبزار","شوية قزبر ومعدنوس طري (تقريبا 5 غرام)"]'::jsonb, '["1. Coupez le blanc de poulet en morceaux de taille moyenne. Dans un bol, mélangez le poulet avec le curcuma, le gingembre, le poivre noir, et une pincée de sel. Laissez mariner pendant au moins 15 minutes.","2. Lavez et coupez les légumes : les carottes et courgettes en rondelles épaisses, les haricots verts en tronçons, et émincez finement l''oignon et la tomate.","3. Dans un tajine ou une cocotte à fond épais, versez 1 c. à soupe d''huile d''olive. Faites chauffer à feu moyen. Ajoutez l''oignon émincé et faites-le revenir jusqu''à ce qu''il soit translucide (environ 3-4 minutes).","4. Ajoutez les morceaux de poulet marinés et faites-les dorer de tous les côtés pendant environ 5 minutes. Le poulet doit être légèrement coloré.","5. Incorporez la tomate émincée et les légumes (carottes, courgettes, haricots verts, petits pois) par-dessus le poulet. Ajoutez un petit verre d''eau (environ 50 ml) pour éviter que le tajine ne colle.","6. Couvrez le tajine et laissez mijoter à feu très doux pendant environ 45-50 minutes, ou jusqu''à ce que le poulet soit tendre et les légumes cuits mais encore légèrement croquants. Vérifiez de temps en temps et ajoutez un filet d''eau si nécessaire.","7. Avant de servir, parsemez de coriandre et persil frais hachés. Servez chaud. 💡 Astuce diabète : Pour une portion de 350 g, ce tajine est idéal. Accompagnez-le d''un quart de pain complet (environ 30g) et commencez toujours par manger les légumes pour stabiliser votre glycémie."]'::jsonb, '["1. قطع صدر الدجاج طريفات متوسطين. فزلافة، خلط الدجاج مع الخرقوم، سكينجبير، إبزار، وشوية ملح. خليه يترقد على الأقل 15 دقيقة.","2. غسل وقطع الخضرة: خيزو والكرعة دوائر غلاظ، اللوبيا الخضرا طريفات، وقطع البصلة ومطيشة رقاق بزاف.","3. ف طاجين أو كوكوط ثقيلة، دير 1 معلقة كبيرة زيت الزيتون. سخنها على نار متوسطة. زيد البصلة مقطعة وخليها تشحر حتى تولي شفافة (تقريبا 3-4 دقايق).","4. زيد طريفات الدجاج اللي ترقدو وخليهم يتحمرو من جميع الجوانب لمدة 5 دقايق تقريبا. الدجاج خاصو ياخد لون خفيف.","5. زيد مطيشة مقطعة والخضرة (خيزو، كرعة، لوبيا خضرا، جلبانة) فوق الدجاج. زيد كاس صغير ديال الماء (تقريبا 50 مل) باش الطاجين ما يلصقش.","6. غطي الطاجين وخليه يطيب على نار مهيلة بزاف لمدة 45-50 دقيقة، أو حتى يولي الدجاج رطب والخضرة طايبة ولكن باقا شوية شادة فراسها. مرة مرة قلب وزيد شوية ماء إذا لزم الأمر.","7. قبل ما تقدم، رش عليه القزبر والمعدنوس مقطعين. قدمو سخون. 💡 نصيحة للسكري: هاد الطاجين مثالي لطبق ديال 350 غرام. كولو مع ربع خبز كامل (تقريبا 30 غرام) وبدا ديما بالخضرة باش تحافظ على مستوى السكر في الدم."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/TAGINE_COOKED_CHICKEN_AND_VEGETABLES_WITH_MINT_TEA_IN_JEMAA_EL_FNA_SQUARE_MARRAKECH_MOROCCO_APRIL_2013_%288704488002%29.jpg/1280px-TAGINE_COOKED_CHICKEN_AND_VEGETABLES_WITH_MINT_TEA_IN_JEMAA_EL_FNA_SQUARE_MARRAKECH_MOROCCO_APRIL_2013_%288704488002%29.jpg', ARRAY['tajine djaj', 'طاجين دجاج']::text[]),
  ('poisson-four', 'Poisson au four aux légumes', 'حوت فالفرن بالخضرة', 'Oven-baked fish with vegetables', 'main', ARRAY['ghda', '3cha']::text[], '🐟', '1 portion (350 g)', 350, 310, 14, 5, 38, 12, 4, 20, 'Zéro glucide dans le poisson, cuisson au four sans friture. La chermoula marocaine (coriandre, ail, cumin, citron) donne le goût sans une calorie de trop.', 'الحوت بلا نشويات، وطيب فالفرن بلا قلي. الشرمولة المغربية (قزبر، ثوم، كامون، حامض) كتعطي الذوق بلا كالوري زايدة.', '["150 g filet de poisson blanc (mérou, daurade, cabillaud)","1 c. à soupe d''huile d''olive extra vierge","50 g de tomates cerises coupées en deux","50 g de poivron vert coupé en lanières fines","50 g de courgette coupée en demi-rondelles fines","1 gousse d''ail hachée finement","1/4 c. à café de cumin moulu","1/4 c. à café de paprika doux","1 c. à soupe de coriandre fraîche ciselée","1/2 citron (jus et quelques rondelles fines)"]'::jsonb, '["150 غرام فيلي سمك أبيض (كربينة، دوراد، قادوس)","1 ملعقة كبيرة زيت الزيتون البكر الممتاز","50 غرام مطيشة صغيرة (طوماط سويز) مقطعة على جوج","50 غرام فلفلة خضرا مقطعة شرائح رقاق","50 غرام كرعة خضرا مقطعة نص دوائر رقاق","1 فص ثوم محكوك رقيق","1/4 ملعقة صغيرة كامون مطحون","1/4 ملعقة صغيرة تحميرة حلوة","1 ملعقة كبيرة قزبر طري مقطع رقيق","1/2 حامضة (عصير و شي دوائر رقاق)"]'::jsonb, '["1. Préchauffez votre four à 180°C (thermostat 6). Lavez et séchez délicatement le filet de poisson.","2. Dans un petit bol, préparez la chermoula : mélangez l''ail haché, le cumin, le paprika, la coriandre ciselée et le jus d''un quart de citron. Ajoutez une pincée de sel et de poivre noir.","3. Badigeonnez le filet de poisson avec la moitié de la chermoula, en vous assurant qu''il soit bien enrobé de tous les côtés.","4. Dans un plat allant au four, disposez les légumes coupés (tomates cerises, poivron vert, courgette). Arrosez-les avec la cuillère à soupe d''huile d''olive et le reste de la chermoula. Mélangez bien pour enrober les légumes.","5. Placez le filet de poisson assaisonné au centre des légumes dans le plat. Déposez quelques rondelles de citron sur le poisson pour plus de saveur.","6. Enfournez le plat pour 15 à 20 minutes. Le temps de cuisson peut varier selon l''épaisseur du poisson. Le poisson est cuit lorsqu''il s''effeuille facilement à la fourchette et que les légumes sont tendres mais encore légèrement croquants.","7. Servez immédiatement votre Poisson au four aux légumes. Accompagnez d''une salade verte simple si désiré, sans féculents ajoutés.","💡 Astuce diabète : Cette portion de 350 g est idéale pour un repas principal. Le faible indice glycémique (20) de ce plat est parfait. Pour une meilleure gestion de la glycémie, mangez d''abord les légumes et le poisson avant d''éventuels accompagnements riches en glucides (non recommandés ici)."]'::jsonb, '["1. سخّن الفران ديالك على درجة حرارة 180°C. غسل الحوت ونشفو مزيان.","2. فزلافة صغيرة، وجد الشرمولة: خلط الثومة محكوكة، الكامون، التحميرة، القزبر مقطع وعصير ربع حامضة. زيد شوية الملح والإبزار الكحل.","3. دهن فيلي الحوت بنص الشرمولة، تأكد بلي الحوت تغطى مزيان من جميع الجوانب.","4. فمول ديال الفران، ستف الخضرة مقطعة (مطيشة صغيرة، فلفلة خضرا، كرعة). خوي عليهم ملعقة كبيرة ديال زيت الزيتون وباقي الشرمولة. خلط مزيان باش الخضرة تشرب الشرمولة.","5. حط فيلي الحوت المشرمول فوسط الخضرة فالمول. حط شي دوائر ديال الحامض فوق الحوت باش يزيد البنة.","6. دخل المول للفران لمدة 15 حتى 20 دقيقة. وقت الطياب يقدر يختلف على حسب غلظ الحوت. الحوت كيكون طاب ملي كيتقطع بسهولة بالفرشيطة والخضرة كتكون طابت ولكن باقا شوية شادة فراسها.","7. قدم الحوت فالفران بالخضرة ديالك سخون مباشرة. تقدر ترافقو بشلاضة خضرا بسيطة إلى بغيتي، بلا ما تزيد نشويات.","💡 نصيحة للسكري: هاد الكمية ديال 350 غرام مثالية كوجبة رئيسية. المؤشر الكلايسيمي المنخفض (20) ديال هاد الطبق ممتاز. باش تحافظ على مستوى السكر فالدم، كل الخضرة والحوت هما اللولين قبل أي حاجة أخرى فيها الكربوهيدرات (ماشي منصوح بها هنا)."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/0a/Cajun_Grilled_Fish%2C_Savoury_Rice_and_Mixed_Baked_Vegetables_%2817459785061%29.jpg/1280px-Cajun_Grilled_Fish%2C_Savoury_Rice_and_Mixed_Baked_Vegetables_%2817459785061%29.jpg', ARRAY['hout four', 'حوت الفرن']::text[]),
  ('poulet-grille-salade', 'Poulet grillé & grande salade', 'دجاج مشوي مع شلاضة كبيرة', 'Grilled chicken & big salad', 'main', ARRAY['ghda', '3cha']::text[], '🥗', '150 g poulet + salade (350 g)', 350, 340, 10, 5, 40, 16, 4, 15, 'Le réflexe "glycémie haute ce midi" : protéines grillées + légumes crus, quasi zéro glucide. La glycémie redescend tranquillement dans l’après-midi.', 'الحل ملي يكون السكر طالع فالغدا: بروتين مشوي مع خضرة خضراء، تقريباً بلا نشويات. السكر كيهبط بشوية فالعشية.', '["150 g de blanc de poulet (sans peau)","2 c. à soupe de jus de citron frais","1 c. à café d''huile d''olive extra vierge","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","1/4 c. à café de sel fin","Une pincée de poivre noir moulu","100 g de laitue romaine (feuilles intérieures)","50 g de concombre (pelé et épépiné)","50 g de tomate (ferme)"]'::jsonb, '["150 غرام صدر دجاج (بلا جلد)","2 ملاعق كبيرة عصير حامض طازج","1 ملعقة صغيرة زيت زيتون بكر ممتاز","1/2 ملعقة صغيرة كمون مطحون","1/4 ملعقة صغيرة تحميرة (بابريكا حلوة)","1/4 ملعقة صغيرة ملح رقيق","رشة فلفل أسود مطحون","100 غرام خس روماني (الأوراق الداخلية)","50 غرام خيار (مقشر ومنزوع البذور)","50 غرام طماطم (قاصحة)"]'::jsonb, '["1. Préparez la marinade pour le poulet : Dans un bol, mélangez 1 c. à soupe de jus de citron, 1/2 c. à café d''huile d''olive, le cumin, le paprika, le sel et le poivre. Coupez le blanc de poulet en deux dans l''épaisseur pour obtenir deux escalopes plus fines. Badigeonnez le poulet avec la marinade et laissez reposer au moins 15 minutes à température ambiante, ou plus longtemps au réfrigérateur.","2. Pendant ce temps, préparez les légumes pour la salade. Lavez soigneusement la laitue, le concombre, la tomate, les radis et les herbes.","3. Coupez la laitue en fines lanières. Le concombre et la tomate en petits dés. Les radis en fines rondelles. Émincez l''oignon rouge très finement.","4. Dans un grand saladier, mélangez la laitue, le concombre, la tomate, les radis et l''oignon rouge. Ajoutez le persil et la coriandre ciselés.","5. Préparez la vinaigrette : Dans un petit bol, mélangez le reste du jus de citron (1 c. à soupe), le reste de l''huile d''olive (1/2 c. à café) et le vinaigre de cidre. Salez et poivrez légèrement si nécessaire.","6. Faites chauffer une poêle grill ou un grill électrique à feu moyen-vif. Une fois bien chaude, déposez les escalopes de poulet marinées. Faites griller 3 à 4 minutes de chaque côté, jusqu''à ce que le poulet soit bien doré et cuit à cœur (la chair doit être blanche et non rosée).","7. Pendant que le poulet grille, versez la vinaigrette sur la salade et mélangez délicatement pour bien enrober tous les légumes.","8. Servez immédiatement le poulet grillé chaud avec la grande salade fraîche. Assurez-vous que la portion de poulet est de 150 g et la salade de 350 g.","💡 Astuce diabète : Pour une meilleure gestion de la glycémie, commencez toujours votre repas par la salade. Les fibres des légumes ralentissent l''absorption des glucides (même s''il y en a peu dans ce plat) et aident à stabiliser la glycémie. Évitez d''ajouter du pain ou des féculents avec ce plat pour maintenir son faible indice glycémique."]'::jsonb, '["1. وجد الشرمولة ديال الدجاج: فزلافة، خلط 1 ملعقة كبيرة عصير حامض، 1/2 ملعقة صغيرة زيت الزيتون، الكمون، التحميرة، الملحة والفلفل الكحل. قطع صدر الدجاج على جوج من الوسط باش يولي عندك جوج طراف رقاق. دهن الدجاج بالشرمولة وخليه يرتاح على الأقل 15 دقيقة فحرارة الغرفة، أو كثر فالثلاجة.","2. فهاد الوقت، وجد الخضرة ديال الشلاضة. غسل الخس، الخيار، مطيشة، الفجل والربيع مزيان.","3. قطع الخس شرائح رقاق. الخيار ومطيشة مكعبات صغار. الفجل دوائر رقاق. قطع البصلة الحمراء رقيقة بزاف.","4. فزلافة كبيرة، خلط الخس، الخيار، مطيشة، الفجل والبصلة الحمراء. زيد المعدنوس والقزبر مقطعين.","5. وجد لاصوص ديال الشلاضة: فزلافة صغيرة، خلط عصير الحامض اللي بقى (1 ملعقة كبيرة)، زيت الزيتون اللي بقى (1/2 ملعقة صغيرة) وخل التفاح. زيد شوية ملح وفلفل كحل إذا كان خاص.","6. سخن مقلاة الشواء أو الشواية الكهربائية على نار متوسطة-مجهدة. ملي تسخن مزيان، حط طراف الدجاج المشملين. شويها 3 حتى 4 دقائق من كل جهة، حتى يولي الدجاج مذهب مزيان وطايب من الداخل (اللحم خاصو يكون أبيض ماشي وردي).","7. فاش يكون الدجاج كيتشوى، خوي لاصوص على الشلاضة وخلط بلطف باش يتغطاو جميع الخضر.","8. قدم الدجاج المشوي سخون مع الشلاضة الطرية الكبيرة مباشرة. تأكد أن حصة الدجاج 150 غرام والشلاضة 350 غرام.","💡 نصيحة للسكري: باش تحكم فمستوى السكر فالدم بشكل أحسن، ديما بدا الوجبة ديالك بالشلاضة. الألياف اللي فالخضر كاتباطئ امتصاص الكربوهيدرات (وخا قلال فهاد الطبق) وكايساعدو فاستقرار مستوى السكر. تجنب تزيد الخبز أو النشويات مع هاد الطبق باش تحافظ على مؤشر الكلايسيمي المنخفض ديالو."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/0b/Caesar_Salad_%26_Grilled_Chicken_%2830548011308%29.jpg/1280px-Caesar_Salad_%26_Grilled_Chicken_%2830548011308%29.jpg', ARRAY['poulet grillé']::text[]),
  ('loubia-light', 'Loubia à la marocaine (portion contrôlée)', 'لوبيا مغربية (كمية مضبوطة)', 'Moroccan white beans (controlled portion)', 'main', ARRAY['ghda', '3cha']::text[], '🫘', '1 petite assiette (250 g)', 250, 270, 36, 4, 13, 7, 10, 35, 'Les haricots blancs ont un IG bas (35) malgré leurs glucides : les fibres freinent tout. La règle : petite assiette, pas de pain avec (le plat EST le féculent).', 'اللوبيا عندها مؤشر منخفض (35) رغم النشويات: الألياف كتوقف كلشي. القاعدة: طبسيل صغير، وبلا خبز معاها (هي بوحدها النشويات).', '["120 g de haricots blancs secs (trempés la veille)","1 c. à soupe d''huile d''olive extra vierge","50 g d''oignon rouge, finement haché","1 gousse d''ail, écrasée","70 g de tomates fraîches, pelées, épépinées et concassées","1/2 c. à café de paprika doux","1/4 c. à café de cumin moulu","1 pincée de curcuma","150 ml d''eau ou de bouillon de légumes sans sel ajouté","Sel et poivre noir fraîchement moulu, au goût"]'::jsonb, '["120 غرام لوبيا بيضاء يابسة (مرطبة ليلة كاملة)","1 م.كبيرة زيت الزيتون البكر الممتاز","50 غرام بصل أحمر، مشلض رقيق","1 فص ثوم، مدقوق","70 غرام مطيشة طرية، مقشرة، محيدة الزريعة ومقطعة","1/2 م.صغيرة تحميرة حلوة","1/4 م.صغيرة كامون مطحون","1 قبيصة خرقوم بلدي","150 مل ماء أو مرقة خضرة بلا ملح","ملح وإبزار أسود مطحون طري، حسب الذوق"]'::jsonb, '["La veille, rincez soigneusement les 120 g de haricots blancs secs et faites-les tremper dans un grand volume d''eau froide pendant au moins 12 heures. Le lendemain, égouttez-les et rincez-les à nouveau.","Dans une cocotte-minute (ou une marmite à fond épais), faites chauffer 1 c. à soupe d''huile d''olive à feu moyen. Ajoutez les 50 g d''oignon rouge haché et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide.","Incorporez la gousse d''ail écrasée et faites revenir 1 minute de plus jusqu''à ce que l''odeur se dégage, en veillant à ne pas le brûler.","Ajoutez les 70 g de tomates concassées, la 1/2 c. à café de paprika, la 1/4 c. à café de cumin et la pincée de curcuma. Mélangez bien et laissez mijoter à feu doux pendant 5 minutes, jusqu''à ce que la sauce épaississe légèrement.","Ajoutez les haricots blancs égouttés et rincés dans la cocotte. Versez les 150 ml d''eau ou de bouillon de légumes. Salez et poivrez au goût. Mélangez délicatement.","Fermez la cocotte-minute et laissez cuire pendant 30-40 minutes après le sifflement, à feu moyen. Si vous utilisez une marmite normale, comptez 1h30 à 2h, ou jusqu''à ce que les haricots soient tendres. Vérifiez la cuisson et ajustez l''assaisonnement si nécessaire.","Servez la loubia chaude dans une petite assiette (environ 250 g) et garnissez de coriandre fraîche ciselée. 💡 Astuce diabète : Cette portion de 250 g de loubia est un plat complet et équilibré. Ne la servez PAS avec du pain, car les haricots sont déjà la source de glucides. Mangez lentement et savourez chaque bouchée pour une meilleure gestion de la glycémie."]'::jsonb, '["بالليل، غسلوا 120 غرام ديال اللوبيا البيضاء اليابسة مزيان ورطبوها فكمية كبيرة ديال الماء بارد لمدة 12 ساعة على الأقل. فالصباح، صفّيوها وعاودوا غسلوها.","فطنجرة الضغط (أو طنجرة عادية ثقيلة)، سخّنوا 1 م.كبيرة زيت الزيتون على نار متوسطة. زيدوا 50 غرام ديال البصل الأحمر مشلض وخليوه يتشحر لمدة 3-4 دقائق حتى يولي شفاف.","زيدوا فص الثوم المدقوق وخليوه يتشحر دقيقة أخرى حتى تطلع ريحتو، وردوا البال باش ما يتحرقش.","زيدوا 70 غرام ديال مطيشة مقطعة، 1/2 م.صغيرة تحميرة، 1/4 م.صغيرة كامون وقبيصة خرقوم. خلطوا مزيان وخليوها تشحر على نار مهيلة لمدة 5 دقائق، حتى تعقاد لاصوص شوية.","زيدوا اللوبيا البيضاء المصفاة والمغسولة فالطنجرة. خويوا 150 مل ديال الماء أو مرقة الخضرة. ملحوا وبزروا حسب الذوق. خلطوا غير بشوية.","سدوا طنجرة الضغط وخليوها طيب لمدة 30-40 دقيقة من بعد ما تصفر، على نار متوسطة. إلا كنتوا كتستعملوا طنجرة عادية، خليوها من ساعة ونص حتى لساعتين، أو حتى تولي اللوبيا رطبة. قلبوا الطياب وصححوا المذاق إلا كان خاص.","قدموا اللوبيا سخونة فطبسيل صغير (حوالي 250 غرام) وزينوها بالقزبر طري مقطع. 💡 نصيحة للسكري: هاد الكمية ديال 250 غرام ديال اللوبيا هي وجبة كاملة ومتوازنة. ما تقدموهاش مع الخبز، حيت اللوبيا هي مصدر الكربوهيدرات. كلوا بشوية وتمتعوا بكل لقمة باش تحافظوا على مستوى السكر فالدم."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/01Stewed_fried_milkfish_with_yardlong_beans%2C_taro%2C_and_white_radish_in_guava%2C_tomato_and_lemon_grass_broth_01.jpg/1280px-01Stewed_fried_milkfish_with_yardlong_beans%2C_taro%2C_and_white_radish_in_guava%2C_tomato_and_lemon_grass_broth_01.jpg', ARRAY['loubia', 'لوبيا']::text[]),
  ('adass-marocain', 'Lentilles à la marocaine', 'العدس المغربي', 'Moroccan lentils', 'main', ARRAY['ghda', '3cha']::text[], '🥣', '1 assiette (280 g)', 280, 280, 38, 4, 16, 5, 11, 30, 'IG 30 seulement : les lentilles sont LE féculent du diabétique. Fer, protéines, fibres — un plat complet qui stabilise la glycémie pendant des heures.', 'مؤشر 30 برك: العدس هو النشويات ديال السكري. حديد، بروتين، ألياف — ماكلة كاملة كتثبت السكر ساعات.', '["80 g de lentilles vertes du Puy (sèches)","1/4 d''oignon rouge (environ 30 g), haché finement","1/2 tomate moyenne (environ 60 g), râpée","1 petite gousse d''ail (environ 3 g), écrasée","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","1 pincée de curcuma moulu","1/4 c. à café de sel de mer","1/2 c. à soupe d''huile d''olive extra vierge","200 ml d''eau"]'::jsonb, '["80 غرام عدس أخضر (ناشف)","1/4 بصلة حمراء (حوالي 30 غرام)، مشلضة رقيقة","1/2 مطيشة متوسطة (حوالي 60 غرام)، محكوكة","1 فص صغير ديال الثومة (حوالي 3 غرام)، مدقوق","1/2 معلقة صغيرة ديال الكامون مطحون","1/4 معلقة صغيرة ديال التحميرة الحلوة","1 قريصة ديال الخرقوم البلدي مطحون","1/4 معلقة صغيرة ديال الملحة الحية","1/2 معلقة كبيرة ديال زيت الزيتون البكر الممتاز","200 ملل ديال الماء"]'::jsonb, '["1. Rincez soigneusement les 80 g de lentilles vertes sous l''eau froide. Il n''est pas nécessaire de les faire tremper pour cette variété.","2. Dans une petite casserole à fond épais, faites chauffer 1/2 c. à soupe d''huile d''olive à feu doux. Ajoutez l''oignon rouge haché et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide, sans le laisser dorer.","3. Incorporez la gousse d''ail écrasée et faites cuire pendant 30 secondes supplémentaires, juste assez pour libérer son arôme.","4. Ajoutez la tomate râpée, 1/2 c. à café de cumin, 1/4 c. à café de paprika, 1 pincée de curcuma et 1/4 c. à café de sel. Mélangez bien et laissez mijoter à feu doux pendant 5 minutes, jusqu''à ce que la sauce épaississe légèrement et que l''eau de la tomate s''évapore.","5. Versez les lentilles rincées dans la casserole et mélangez-les avec la sauce. Ajoutez ensuite 200 ml d''eau. Portez à ébullition à feu moyen.","6. Une fois que l''eau bout, réduisez le feu à doux, couvrez la casserole et laissez mijoter pendant 25 à 30 minutes, ou jusqu''à ce que les lentilles soient tendres mais conservent une légère tenue. Remuez occasionnellement pour éviter que les lentilles n''accrochent au fond. Si nécessaire, ajoutez un filet d''eau chaude pendant la cuisson.","7. Servez chaud dans une assiette. Les lentilles doivent avoir une consistance crémeuse mais non liquide. 💡 Astuce diabète : Consommez votre portion de 280 g de lentilles (IG 30) en début de repas. Évitez de les accompagner de pain blanc ou de féculents raffinés. Préférez une salade verte fraîche sans vinaigrette sucrée pour un repas équilibré et une glycémie stable."]'::jsonb, '["1. غسلوا 80 غرام ديال العدس الأخضر مزيان تحت الماء بارد. هاد النوع ديال العدس ما كيحتاجش يتفزك.","2. فكاسرونة صغيرة وثقيلة، سخنوا 1/2 معلقة كبيرة ديال زيت الزيتون على نار مهيلة. زيدوا البصلة الحمراء المشلضة وخليوها تشحر لمدة 3-4 دقايق حتى تولي شفافة، بلا ما تحمر.","3. زيدوا فص الثومة المدقوق وخليوه يطيب لمدة 30 ثانية أخرى، غير باش تطلق الريحة ديالها.","4. زيدوا مطيشة المحكوكة، 1/2 معلقة صغيرة ديال الكامون، 1/4 معلقة صغيرة ديال التحميرة، قريصة ديال الخرقوم البلدي و 1/4 معلقة صغيرة ديال الملحة. خلطوا مزيان وخليوه يتشحر على نار مهيلة لمدة 5 دقايق، حتى تعقاد لاصوص شوية وينشف الماء ديال مطيشة.","5. خويوا العدس اللي غسلتوا فالكاسرونة وخلطوه مع لاصوص. من بعد زيدوا 200 ملل ديال الماء. خليوه حتى يغلى على نار متوسطة.","6. ملي يبدا الماء يغلى، نقصوا النار لمهيلة، غطيو الكاسرونة وخليوه يطيب لمدة 25 حتى لـ 30 دقيقة، أو حتى يولي العدس رطب ولكن يبقى شاد فراسو شوية. حركوا مرة مرة باش ما يلصقش العدس فالقاع. إلا خاص الماء، زيدوا شوية ديال الماء سخون أثناء الطياب.","7. قدموه سخون فطبسيل. خاص العدس يكون خاتر ماشي جاري. 💡 نصيحة للسكري: كولوا الحصة ديالكم ديال 280 غرام ديال العدس (مؤشر سكري 30) فبداية الوجبة. تجنبوا تاكلوه مع الخبز الأبيض أو النشويات المكررة. من الأفضل تقدموه مع سلطة خضراء طازجة بلا صلصة حلوة لوجبة متوازنة ومستوى سكر مستقر."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/2/29/Vegan_French_lentil_soup_with_salad%2C_bread_and_tea.jpg', ARRAY['adass', '3ades', 'عدس']::text[]),
  ('tajine-kefta-dinde', 'Tajine de kefta de dinde (léger)', 'طاجين كفتة البيبي (خفيف)', 'Light turkey kefta tagine', 'main', ARRAY['ghda', '3cha']::text[], '🍳', '1 assiette (300 g)', 300, 320, 10, 5, 32, 18, 3, 25, 'La kefta de DINDE a 2× moins de gras saturé que le bœuf haché gras. Même plaisir, sauce tomate maison, un œuf — et le cœur vous dit merci.', 'كفتة البيبي فيها نص الدهون المشبعة ديال الكفتة الحمراء. نفس البنة، صلصة طماطم ديال الدار، وبيضة — والقلب كيشكرك.', '["150 g de viande hachée de dinde maigre","1 petite tomate (environ 80 g)","1/2 oignon moyen (environ 40 g)","1 gousse d''ail","1 c. à soupe d''huile d''olive extra vierge","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","Quelques brins de coriandre fraîche","1 œuf moyen"]'::jsonb, '["150 غرام كفتة بيبي رقيقة","1 مطيشة صغيرة (حوالي 80 غرام)","1/2 بصلة متوسطة (حوالي 40 غرام)","1 فص ثوم","1 م.كبيرة زيت الزيتون البكر الممتاز","1/2 م.صغيرة كمون مطحون","1/4 م.صغيرة تحميرة حلوة","شوية قزبر طري","1 بيضة متوسطة"]'::jsonb, '["Dans un bol, mélangez la viande hachée de dinde avec la moitié du cumin (1/4 c. à café), la moitié du paprika (1/8 c. à café), et la moitié de la coriandre fraîche ciselée. Salez et poivrez légèrement. Formez des petites boulettes de kefta d''environ 15 g chacune.","Râpez finement la tomate et l''oignon. Hachez l''ail. Dans un tajine ou une petite cocotte, faites chauffer 1 c. à soupe d''huile d''olive à feu doux.","Ajoutez l''oignon râpé et faites-le revenir doucement pendant 5 minutes jusqu''à ce qu''il devienne translucide. Ajoutez l''ail haché et faites revenir 1 minute de plus.","Incorporez la tomate râpée, le reste du cumin (1/4 c. à café), le reste du paprika (1/8 c. à café), et un peu de sel et de poivre. Laissez mijoter à feu très doux pendant 10-12 minutes, jusqu''à ce que la sauce épaississe légèrement.","Disposez délicatement les boulettes de kefta de dinde dans la sauce. Couvrez le tajine et laissez cuire à feu doux pendant 10 minutes, en retournant les boulettes à mi-cuisson pour qu''elles cuisent uniformément.","Cassez l''œuf directement sur les boulettes de kefta dans la sauce. Couvrez à nouveau et laissez cuire 3-5 minutes, ou jusqu''à ce que le blanc soit pris et le jaune encore coulant (ou à votre convenance).","Parsemez le reste de coriandre fraîche ciselée juste avant de servir. Servez immédiatement dans une assiette. 💡 Astuce diabète : Pour un contrôle optimal de la glycémie, mangez d''abord les protéines (kefta, œuf) et les légumes de la sauce. Accompagnez ce tajine d''une petite portion (50g cuit) de boulgour complet ou de quinoa pour un apport en glucides à faible indice glycémique."]'::jsonb, '["فزلافة، خلط الكفتة ديال البيبي مع نص الكمون (1/4 م.صغيرة)، نص التحميرة (1/8 م.صغيرة)، ونص القزبر مقطع رقيق. زيد شوية ملح وإبزار. صاوب كويرات صغار ديال الكفتة، كل وحدة فيها تقريبا 15 غرام.","حك مطيشة والبصلة رقيق. قطع الثومة رقيقة. فطاجين ولا كوكوط صغيرة، سخن 1 م.كبيرة زيت الزيتون على نار مهيلة.","زيد البصلة محكوكة وخليها تشحر بشوية لمدة 5 دقايق حتى تولي شفافة. زيد الثومة مقطعة وخليها تشحر دقيقة أخرى.","زيد مطيشة محكوكة، باقي الكمون (1/4 م.صغيرة)، باقي التحميرة (1/8 م.صغيرة)، وشوية ملح وإبزار. خليها طيب على نار مهيلة بزاف لمدة 10-12 دقيقة، حتى تتختر لاصوص شوية.","حط كويرات الكفتة ديال البيبي بلطف فالصوص. غطي الطاجين وخليه يطيب على نار مهيلة لمدة 10 دقايق، وقلب الكويرات فالنص باش يطيبو مزيان من كل جهة.","هرس البيضة مباشرة فوق كويرات الكفتة فالصوص. غطي تاني وخليه يطيب 3-5 دقايق، ولا حتى يطيب البيض الأبيض ويبقى الأصفر شوية جاري (ولا كيفما بغيتي).","رش باقي القزبر مقطع رقيق قبل ما تقدم الطبق مباشرة. قدمو فطبسيل. 💡 نصيحة للسكري: باش تحافظ على مستوى السكر فالدم مزيان، كول البروتينات (الكفتة، البيض) والخضرة ديال لاصوص هي اللولة. قدم هاد الطاجين مع كمية صغيرة (50 غرام طايب) ديال البرغل الكامل ولا الكينوا باش تاخد كربوهيدرات بمؤشر سكري منخفض."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/68/20151121_Morocco_2645%2B7_A%C3%AFt_Ben_Haddou_sRGB_%2824483612775%29.jpg/1280px-20151121_Morocco_2645%2B7_A%C3%AFt_Ben_Haddou_sRGB_%2824483612775%29.jpg', ARRAY['kefta dinde']::text[]),
  ('brochettes-poulet', 'Brochettes de poulet marinées', 'قطبان الدجاج المشرملين', 'Marinated chicken skewers', 'main', ARRAY['ghda', '3cha']::text[], '🍢', '3 brochettes (200 g)', 200, 280, 4, 2, 40, 12, 1, 10, 'Le grill = zéro friture. Protéines pures, presque pas de glucides. Accompagnez de salade ou légumes grillés — pas de frites.', 'الشوي = بلا قلي. بروتين صافي وتقريباً بلا نشويات. كول معاهم شلاضة ولا خضرة مشوية — ماشي فريت.', '["200 g de blanc de poulet, coupé en dés de 3 cm","1/2 oignon rouge, coupé en dés de 2 cm","1/2 poivron vert, coupé en dés de 2 cm","1 c. à soupe de persil frais haché","1 c. à soupe de coriandre fraîche hachée","1 c. à café de cumin moulu","1/2 c. à café de paprika doux","1/4 c. à café de curcuma moulu","1 c. à soupe d''huile d''olive extra vierge","Jus d''1/4 de citron (environ 1 c. à soupe)"]'::jsonb, '["200 غرام من صدر الدجاج، مقطع مكعبات 3 سم","1/2 بصلة حمراء، مقطعة مكعبات 2 سم","1/2 فلفلة خضراء، مقطعة مكعبات 2 سم","1 ملعقة كبيرة من المعدنوس الطري مفروم","1 ملعقة كبيرة من القزبور الطري مفروم","1 ملعقة صغيرة من الكامون مطحون","1/2 ملعقة صغيرة من التحميرة الحلوة","1/4 ملعقة صغيرة من الخرقوم البلدي مطحون","1 ملعقة كبيرة من زيت الزيتون البكر الممتاز","عصير 1/4 حامضة (حوالي 1 ملعقة كبيرة)"]'::jsonb, '["Dans un grand bol, mélangez le persil haché, la coriandre hachée, le cumin moulu, le paprika doux, le curcuma moulu, le sel et le poivre noir. Ajoutez l''huile d''olive et le jus de citron. Mélangez bien pour obtenir une marinade homogène.","Ajoutez les dés de poulet dans le bol avec la marinade. Assurez-vous que chaque morceau de poulet est bien enrobé. Couvrez le bol et laissez mariner au réfrigérateur pendant au moins 30 minutes, idéalement 2 heures pour un maximum de saveur.","Pendant que le poulet marine, préparez les brochettes. Si vous utilisez des brochettes en bois, faites-les tremper dans l''eau pendant au moins 20 minutes pour éviter qu''elles ne brûlent sur le grill.","Enfilez alternativement les dés de poulet, les dés d''oignon rouge et les dés de poivron vert sur les brochettes. Essayez de répartir les ingrédients de manière égale pour obtenir 3 brochettes bien garnies.","Préchauffez votre grill (charbon, gaz ou électrique) à feu moyen-vif. La température doit être suffisamment chaude pour saisir le poulet sans le brûler.","Placez les brochettes sur le grill chaud. Faites-les cuire pendant environ 4 à 6 minutes de chaque côté, en les retournant régulièrement, jusqu''à ce que le poulet soit bien doré à l''extérieur et entièrement cuit à l''intérieur (sans trace de rose). Le temps de cuisson total sera d''environ 16 à 24 minutes, selon l''épaisseur des morceaux et la chaleur du grill.","Servez immédiatement. 💡 Astuce diabète : Cette portion de 3 brochettes (environ 200 g) est parfaite pour un repas principal. Son indice glycémique est très bas (GI 10) grâce à l''absence de glucides raffinés. Accompagnez-la d''une grande salade verte fraîche ou de légumes grillés (aubergines, courgettes) sans féculents pour maintenir un contrôle optimal de la glycémie. Évitez les frites ou le pain blanc."]'::jsonb, '["فواحد الزلافة كبيرة، خلطو المعدنوس مفروم، القزبور مفروم، الكامون مطحون، التحميرة الحلوة، الخرقوم البلدي، الملح والإبزار الأسود. زيدو زيت الزيتون وعصير الحامض. خلطو مزيان باش تحصلو على تتبيلة متجانسة.","زيدو مكعبات الدجاج فالزلافة مع التتبيلة. تأكدو بلي كل طرف دجاج تغطى مزيان. غطيو الزلافة وخليوها ترتاح فالثلاجة على الأقل 30 دقيقة، ومن الأحسن ساعتين باش تشرب البنة مزيان.","فالوقت اللي الدجاج كيرقد، وجدو القطبان. إذا كنتو كتستعملو قطبان خشبية، رقدوهم فالماء على الأقل 20 دقيقة باش مايتحرقوش فالشواية.","ركبو بالتناوب مكعبات الدجاج، مكعبات البصل الأحمر ومكعبات الفلفلة الخضراء فالقطبان. حاولو توزعو المكونات بالتساوي باش تحصلو على 3 قطبان عامرين مزيان.","سخنو الشواية ديالكم (فحم، غاز أو كهربائية) على نار متوسطة إلى مجهدة. خاص تكون سخونة كافية باش تشوي الدجاج بلا ما يتحرق.","حطو القطبان فوق الشواية السخونة. خليوهم يتشواو تقريبا من 4 حتى لـ 6 دقائق لكل جهة، وقلبوهم بانتظام، حتى يولي الدجاج مذهب مزيان من برا ومطيب كامل من الداخل (بلا ما يبقى فيه أثر الوردية). وقت الطياب الإجمالي غيكون تقريبا من 16 حتى لـ 24 دقيقة، على حسب سمك الطراف وسخونية الشواية.","قدموهم مباشرة. 💡 نصيحة للسكري: هاد الحصة ديال 3 قطبان (حوالي 200 غرام) مثالية لوجبة رئيسية. المؤشر الكلايسيمي ديالها منخفض بزاف (GI 10) حيت مافيهاش كربوهيدرات مكررة. قدموها مع سلطة خضراء كبيرة طرية أو خضروات مشوية (دنجال، قرعة خضراء) بلا نشويات باش تحافظو على تحكم مثالي فمستوى السكر فالدم. تجنبو الفريت أو الخبز الأبيض."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a7/Skewer_with_marinated_chicken_wings_bbq_barbeque.jpg/1280px-Skewer_with_marinated_chicken_wings_bbq_barbeque.jpg', ARRAY['qotban', 'قطبان']::text[]),
  ('courgettes-farcies', 'Courgettes farcies à la viande maigre', 'قرعة معمرة باللحم المزوق', 'Zucchini stuffed with lean meat', 'main', ARRAY['ghda', '3cha']::text[], '🥒', '2 courgettes (350 g)', 350, 290, 14, 7, 28, 14, 4, 25, 'La courgette remplace le riz ou les pâtes comme "contenant" : mêmes saveurs, 4× moins de glucides. Le plat familial qui ne fait pas exploser la glycémie.', 'القرعة كتعوض الروز والمعكرونة: نفس البنة، بأربع مرات أقل نشويات. الماكلة العائلية اللي ما كتفجرش السكر.', '["350 g de courgettes moyennes (environ 2 pièces)","100 g de viande hachée maigre (bœuf ou dinde)","20 g de riz complet (non cuit)","50 g de tomates concassées (sans sucre ajouté)","1/2 oignon moyen (environ 50 g)","1 gousse d''ail","1 c. à soupe de persil frais ciselé","1 c. à café de coriandre fraîche ciselée","1 c. à café d''huile d''olive"]'::jsonb, '["350 غرام قرعة متوسطة (تقريبا 2 حبات)","100 غرام كفتة رقيقة (بقر أو دجاج)","20 غرام روز كامل (ما طايبش)","50 غرام مطيشة محكوكة (بلا سكر)","نص بصلة متوسطة (تقريبا 50 غرام)","1 فص ثوم","1 م.ك. معدنوس مقطع رقيق","1 م.ص. قزبور مقطع رقيق","1 م.ص. زيت الزيتون"]'::jsonb, '["1. Lavez les courgettes. Coupez-les en deux dans le sens de la longueur. À l''aide d''une petite cuillère ou d''un économe, retirez délicatement la chair des courgettes en laissant une paroi d''environ 0,5 cm d''épaisseur. Hachez finement la chair retirée et réservez.","2. Dans une poêle, faites chauffer 1 c. à café d''huile d''olive à feu moyen. Hachez finement l''oignon et l''ail. Faites-les revenir pendant 3-4 minutes jusqu''à ce qu''ils soient translucides.","3. Ajoutez la viande hachée maigre dans la poêle. Émiettez-la à l''aide d''une spatule et faites-la cuire pendant 5-7 minutes jusqu''à ce qu''elle soit dorée et qu''il n''y ait plus de liquide. Salez et poivrez légèrement.","4. Incorporez la chair de courgette hachée, le riz complet non cuit, les tomates concassées, le persil et la coriandre. Mélangez bien et laissez mijoter à feu doux pendant 5 minutes pour que les saveurs se mélangent.","5. Préchauffez votre four à 180°C (Thermostat 6). Farcissez généreusement les moitiés de courgettes avec la préparation à la viande et au riz. Ne les remplissez pas à ras bord car le riz va gonfler légèrement.","6. Disposez les courgettes farcies dans un plat allant au four. Ajoutez un fond d''eau (environ 100 ml) dans le plat pour créer de la vapeur et éviter que les courgettes ne sèchent. Couvrez le plat avec du papier aluminium.","7. Enfournez pour 30-40 minutes. Retirez le papier aluminium après 25 minutes et poursuivez la cuisson jusqu''à ce que les courgettes soient tendres et légèrement dorées sur le dessus. Servez chaud.","💡 Astuce diabète : Cette portion de 2 courgettes (350g) est idéale. Pour un meilleur contrôle de la glycémie, mangez d''abord les légumes et la viande, puis le riz. Évitez de servir avec du pain blanc ou des frites. Accompagnez plutôt d''une salade verte fraîche."]'::jsonb, '["1. غسل القرعة مزيان. قطعها على جوج بالطول. بمعلقة صغيرة أو موس، حيد اللب ديال القرعة بشوية وخلي الجناب ديالها بسمك 0.5 سم. قطع اللب اللي حيدتي رقيق وخليه على جنب.","2. في مقلة، سخن 1 م.ص. زيت الزيتون على نار متوسطة. قطع البصلة والثومة رقيق. شحرهم لمدة 3-4 دقائق حتى يوليو شفافين.","3. زيد الكفتة الرقيقة في المقلة. فرقها بالمعلقة وطيبها لمدة 5-7 دقائق حتى تتحمر وميبقاش فيها الماء. زيد شوية الملح والإبزار.","4. زيد اللب ديال القرعة المقطع، الروز الكامل اللي ما طايبش، مطيشة محكوكة، المعدنوس والقزبور. خلط كلشي مزيان وخليه يتشحر على نار مهيلة لمدة 5 دقائق باش يتخلطو النكهات.","5. سخن الفران على 180 درجة مئوية. عمر نصاص القرعة مزيان بالخليط ديال الكفتة والروز. ما تعمرهمش حتى الفم حيت الروز غادي يتنفخ شوية.","6. ستف القرعة المعمرة في لاطة ديال الفران. زيد شوية الماء (تقريبا 100 مل) في اللاطة باش يدير البخار وماتنشفش القرعة. غطي اللاطة بورق الألمنيوم.","7. دخلها للفران لمدة 30-40 دقيقة. حيد ورق الألمنيوم من بعد 25 دقيقة وكمل الطياب حتى تولي القرعة رطبة ومحمرة شوية من الفوق. قدمها سخونة.","💡 نصيحة للسكري: هاد الحصة ديال 2 قرعات (350غ) مثالية. باش تتحكم في السكر ديالك مزيان، كل الخضرة واللحم هما الأولين، عاد الروز. تجنب تقدمها مع الخبز الأبيض أو البطاطس المقلية. قدمها مع سلطة خضراء طازجة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d0/Kabak_%C3%A7i%C3%A7e%C4%9Fi_dolma.jpg/1280px-Kabak_%C3%A7i%C3%A7e%C4%9Fi_dolma.jpg', ARRAY['courgette farcie']::text[]),
  ('omelette-legumes', 'Omelette aux légumes', 'أومليت بالخضرة', 'Vegetable omelet', 'main', ARRAY['ftour', '3cha']::text[], '🍳', '3 œufs + légumes (250 g)', 250, 290, 8, 4, 21, 20, 3, 15, 'Dîner express (10 min) sans glucides : les œufs ne font PAS monter la glycémie. Poivrons, tomates et oignons pour les vitamines.', 'عشا سريع (10 دقايق) بلا نشويات: البيض ما كيطلعش السكر. الفلفلة والطماطم والبصلة للفيتامينات.', '["3 œufs de poule frais","120 g de poivron vert (environ 1 petit)","80 g de tomate (environ 1 petite)","50 g d''oignon (environ 1/4 d''oignon moyen)","1 c. à soupe d''huile d''olive extra vierge","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","Sel et poivre noir fraîchement moulu (au goût)"]'::jsonb, '["3 بيضات دجاج طازجة","120 غرام فلفلة خضرا (وحدة صغيرة تقريبا)","80 غرام مطيشة (وحدة صغيرة تقريبا)","50 غرام بصلة (ربع بصلة متوسطة تقريبا)","1 معلقة كبيرة زيت الزيتون البكر الممتاز","1/2 معلقة صغيرة كامون مطحون","1/4 معلقة صغيرة تحميرة حلوة","ملح و إبزار مطحون طري (حسب الذوق)"]'::jsonb, '["Lavez soigneusement le poivron et la tomate. Épépinez le poivron et coupez-le en petits dés d''environ 1 cm. Coupez la tomate en petits dés de taille similaire. Pelez l''oignon et hachez-le finement.","Dans une poêle antiadhésive de taille moyenne (environ 20 cm de diamètre), faites chauffer 1 cuillère à soupe d''huile d''olive à feu moyen. Ajoutez l''oignon haché et faites-le revenir pendant 3-4 minutes, jusqu''à ce qu''il devienne translucide et légèrement doré.","Ajoutez les dés de poivron vert dans la poêle. Laissez cuire pendant 5-7 minutes, en remuant de temps en temps, jusqu''à ce que les poivrons soient tendres mais conservent une légère fermeté (al dente).","Incorporez les dés de tomate. Saupoudrez avec 1/2 c. à café de cumin moulu et 1/4 c. à café de paprika doux. Salez et poivrez au goût. Mélangez bien et laissez cuire encore 2-3 minutes, juste le temps que les tomates ramollissent légèrement et que les saveurs se mélangent.","Pendant ce temps, dans un bol, cassez les 3 œufs. Battez-les légèrement à la fourchette pendant environ 30 secondes, juste assez pour mélanger le jaune et le blanc. Salez et poivrez les œufs battus.","Versez les œufs battus uniformément sur les légumes dans la poêle. Réduisez le feu à doux. Couvrez la poêle et laissez cuire pendant 5-7 minutes, ou jusqu''à ce que les bords de l''omelette soient pris et que le centre soit juste cuit mais encore moelleux. Ne pas trop cuire pour éviter une texture sèche.","Servez l''omelette aux légumes immédiatement. Vous pouvez la faire glisser délicatement de la poêle sur une assiette. Accompagnez-la d''une salade verte simple sans vinaigrette sucrée. 💡 Astuce diabète : Cette omelette est un excellent dîner sans glucides. Pour maintenir une glycémie stable, consommez cette portion de 250 g telle quelle. Évitez de l''accompagner de pain ou de frites. Privilégiez une grande salade de crudités assaisonnée d''huile d''olive et de vinaigre de cidre."]'::jsonb, '["غسلوا الفلفلة ومطيشة مزيان. حيدوا الزريعة من الفلفلة وقطعوها مربعات صغار تقريبا 1 سنتيمتر. قطعوا مطيشة مربعات بنفس الحجم. قشروا البصلة وقطعوها رقيقة بزاف.","فمقلاة ما كاتلصقش متوسطة الحجم (تقريبا 20 سنتيمتر فالقطر)، سخنوا 1 معلقة كبيرة ديال زيت الزيتون على نار متوسطة. زيدوا البصلة المقطعة وخليوها تشحر لمدة 3-4 دقايق، حتى تولي شفافة وذهبية شوية.","زيدوا مربعات الفلفلة الخضرا فالمقلاة. خليوها طيب لمدة 5-7 دقايق، وحركوا مرة مرة، حتى تولي الفلفلة رطبة ولكن باقا شادة فراسها شوية (ماشي طايبة بزاف).","زيدوا مربعات مطيشة. رشوا عليها 1/2 معلقة صغيرة كامون مطحون و 1/4 معلقة صغيرة تحميرة حلوة. ملحوا وبزروا حسب الذوق. خلطوا مزيان وخليوها طيب 2-3 دقايق أخرى، غير باش مطيشة ترطاب شوية وتندمج النكهات.","فهاذ الوقت، فزلافة، هرّسوا 3 البيضات. خفقوهم شوية بالفرشيطة لمدة 30 ثانية تقريبا، غير باش يتخلط الصفر مع البيض. ملحوا وبزروا البيض المخفوق.","خويوا البيض المخفوق بالتساوي فوق الخضرة فالمقلاة. نقصوا النار لمهيلة. غطوا المقلاة وخليوها طيب لمدة 5-7 دقايق، أو حتى يطيبوا الجناب ديال الأومليت ويبقى الوسط طايب ولكن باقي رطب. ما طيبوهاش بزاف باش ما تجيش ناشفة.","قدموا الأومليت بالخضرة مباشرة. تقدروا دوزوها غير بشوية من المقلاة للطبسيل. رافقوها بشلاضة خضرا بسيطة بلا صوص حلوة. 💡 نصيحة للسكري: هاد الأومليت عشاء ممتاز بلا كربوهيدرات. باش تحافظوا على مستوى السكر فالدم مستقر، تناولوا هاد الكمية ديال 250 غرام كيف ما هي. تجنبوا تاكلوها مع الخبز أو البطاطس المقلية. فضلوا شلاضة كبيرة ديال الخضرة الطازجة متبلة بزيت الزيتون وخل التفاح."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/47/Cha-om_omelette.jpg/1280px-Cha-om_omelette.jpg', ARRAY['omelette']::text[]),
  ('quinoa-legumes', 'Quinoa aux légumes (alternative au couscous)', 'الكينوا بالخضرة (بديل الكسكس)', 'Quinoa with vegetables (couscous alternative)', 'main', ARRAY['ghda', '3cha']::text[], '🌾', '1 assiette (300 g)', 300, 320, 42, 6, 12, 10, 7, 40, 'Le "couscous" nouvelle génération : IG 40 contre 65 pour la semoule. Mêmes légumes, même vapeur, mais une glycémie beaucoup plus douce le vendredi.', '"الكسكس" ديال الجيل الجديد: مؤشر 40 مقابل 65 ديال السميدة. نفس الخضرة ونفس البخار، ولكن سكر هادئ بزاف نهار الجمعة.', '["60 g quinoa non cuit","150 g légumes variés (courgette, carotte, navet, potiron)","50 g pois chiches cuits","1/2 tomate mûre","1/4 oignon","1 c. à café d''huile d''olive","1/2 c. à café de curcuma","1/4 c. à café de gingembre moulu","Sel et poivre noir au goût"]'::jsonb, '["60 غرام كينوا ناشفة","150 غرام خضرة مشكلة (قرعة خضرا، خيزو، لفت، قرعة حمرا)","50 غرام حمص طايب","1/2 مطيشة طايبة","1/4 بصلة","1 م. ص. زيت الزيتون","1/2 م. ص. خرقوم بلدي","1/4 م. ص. سكينجبير","ملح و إبزار حسب الذوق"]'::jsonb, '["1. Rincez soigneusement les 60 g de quinoa sous l''eau froide dans une passoire fine jusqu''à ce que l''eau soit claire. Égouttez bien.","2. Dans une petite casserole, portez à ébullition 120 ml d''eau. Ajoutez le quinoa rincé, couvrez et laissez mijoter à feu doux pendant 15 minutes, ou jusqu''à ce que toute l''eau soit absorbée et que le quinoa soit tendre. Laissez reposer couvert pendant 5 minutes, puis égrainez à la fourchette.","3. Pendant ce temps, préparez les légumes : coupez les 150 g de légumes (courgette, carotte, navet, potiron) en gros dés. Râpez la demi-tomate et hachez finement le quart d''oignon.","4. Dans une cocotte ou un faitout, faites chauffer 1 c. à café d''huile d''olive à feu moyen. Ajoutez l''oignon haché et faites-le revenir jusqu''à ce qu''il devienne translucide (environ 3-4 minutes).","5. Ajoutez la tomate râpée, le 1/2 c. à café de curcuma, le 1/4 c. à café de gingembre, le sel et le poivre. Laissez mijoter 2 minutes en remuant.","6. Incorporez les légumes coupés en dés et les 50 g de pois chiches cuits. Ajoutez environ 150 ml d''eau chaude (juste assez pour couvrir les légumes à moitié). Portez à ébullition, puis réduisez le feu à doux, couvrez et laissez cuire pendant 20-25 minutes, ou jusqu''à ce que les légumes soient tendres mais encore légèrement fermes.","7. Servez le quinoa chaud dans une assiette (environ 150 g de quinoa cuit), puis disposez généreusement les légumes et leur bouillon par-dessus. Mélangez délicatement avant de déguster.","💡 Astuce diabète : Cette portion de 300 g (150 g quinoa cuit + 150 g légumes) a un IG de 40. Pour une meilleure gestion de la glycémie, commencez toujours votre repas par les légumes et les fibres. Évitez d''ajouter des sucres ou des graisses saturées. Accompagnez d''une salade verte simple."]'::jsonb, '["1. غسل 60 غرام ديال الكينوا مزيان تحت الماء بارد فشي صفاية رقيقة حتى يولي الماء نقي. قطرها مزيان.","2. فكاسرونة صغيرة، غلي 120 مللتر ديال الماء. زيد الكينوا اللي غسلتي، غطيها وخليها طيب على نار مهيلة لمدة 15 دقيقة، ولا حتى تشرب الماء كامل وتولي رطبة. خليها ترتاح مغطية 5 دقايق، ومن بعد فرتها بالفرشيطة.","3. فهاد الوقت، وجد الخضرة: قطع 150 غرام ديال الخضرة (قرعة خضرا، خيزو، لفت، قرعة حمرا) مكعبات كبار. حك نص مطيشة وقطع ربع بصلة رقيقة بزاف.","4. فكوكوط ولا طنجرة، سخن 1 م. ص. ديال زيت الزيتون على نار متوسطة. زيد البصلة مقطعة وخليها تشحر حتى تولي شفافة (تقريبا 3-4 دقايق).","5. زيد مطيشة محكوكة، 1/2 م. ص. ديال الخرقوم، 1/4 م. ص. ديال سكينجبير، الملحة والإبزار. خليها طيب 2 دقايق وانت كتحرك.","6. زيد الخضرة مقطعة و 50 غرام ديال الحمص طايب. زيد تقريبا 150 مللتر ديال الماء سخون (غير القياس اللي يغطي نص الخضرة). خليها تغلى، ومن بعد نقص العافية لمهيلة، غطيها وخليها طيب 20-25 دقيقة، ولا حتى تولي الخضرة رطبة ولكن باقا شادة فراسها شوية.","7. حط الكينوا سخونة فطبسيل (تقريبا 150 غرام كينوا طايبة)، ومن بعد حط فوقها الخضرة والمرقة ديالها. خلط بشوية قبل ما تاكل.","💡 نصيحة للسكري: هاد الطبسيل ديال 300 غرام (150 غرام كينوا طايبة + 150 غرام خضرة) عندو مؤشر سكري ديال 40. باش تحافظ على مستوى السكر فدمك، ديما بدا الماكلة ديالك بالخضرة والألياف. تجنب تزيد السكر ولا الدهون المشبعة. قدمها مع شلاضة خضرا بسيطة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/41/Liat_Portal_for_Foodie_Disorder_-_Stuffed_Cabbage_with_Meat_and_Quinoa.jpg/1280px-Liat_Portal_for_Foodie_Disorder_-_Stuffed_Cabbage_with_Meat_and_Quinoa.jpg', ARRAY['quinoa']::text[]),
  ('steak-haricots-verts', 'Steak grillé & haricots verts', 'ستيك مشوي مع اللوبيا الخضراء', 'Grilled steak & green beans', 'main', ARRAY['ghda', '3cha']::text[], '🥩', '150 g steak + 200 g haricots', 350, 360, 9, 4, 42, 17, 5, 15, 'Viande rouge MAIGRE 1-2×/semaine, c’est permis : fer et B12. Les haricots verts sautés à l’ail remplacent parfaitement frites et purée.', 'اللحم الأحمر المزوق مرة ولا جوج فالسيمانة مسموح: حديد وB12. اللوبيا الخضراء المقلية بالثوم كتعوض الفريت والبطاطا.', '["150 g de steak de bœuf maigre (faux-filet ou rumsteck)","200 g de haricots verts frais","1 c. à soupe d''huile d''olive extra vierge","2 gousses d''ail","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","Une pincée de sel de mer","Une pincée de poivre noir fraîchement moulu","1 c. à soupe de persil frais haché"]'::jsonb, '["150 غرام ستيك لحم بقري بلا شحمة (فيليه أو رومستيك)","200 غرام لوبيا خضراء طرية","1 معلقة كبيرة زيت الزيتون البكر الممتاز","2 فصوص ثوم","1/2 معلقة صغيرة كمون مطحون","1/4 معلقة صغيرة تحميرة (بابريكا حلوة)","قبيصة ملح البحر","قبيصة إبزار أسود مطحون طري","1 معلقة كبيرة معدنوس طري مفروم"]'::jsonb, '["1. Préparez le steak : Assurez-vous que le steak est à température ambiante. Salez et poivrez généreusement les deux côtés du steak (environ 1/4 c. à café de chaque).","2. Préparez les haricots verts : Lavez et équeutez les haricots verts. Faites-les cuire à la vapeur pendant 5 à 7 minutes, jusqu''à ce qu''ils soient tendres mais encore croquants (al dente). Plongez-les immédiatement dans un bain d''eau glacée pour arrêter la cuisson et fixer leur couleur, puis égouttez-les bien.","3. Préparez la marinade rapide pour le steak : Dans un petit bol, mélangez 1/2 c. à café de cumin et 1/4 c. à café de paprika. Frottez ce mélange d''épices sur le steak.","4. Grillez le steak : Faites chauffer une poêle à griller ou un grill à feu vif. Une fois bien chaude, placez le steak. Pour une cuisson saignante, faites cuire 2-3 minutes de chaque côté. Pour une cuisson à point, 4-5 minutes de chaque côté. Laissez reposer le steak sur une planche à découper pendant 5 minutes avant de le trancher pour que les jus se redistribuent.","5. Préparez les haricots sautés : Pendant que le steak repose, hachez finement les 2 gousses d''ail. Dans une poêle antiadhésive, faites chauffer 1 c. à soupe d''huile d''olive à feu moyen. Ajoutez l''ail haché et faites-le revenir pendant 30 secondes jusqu''à ce qu''il soit parfumé, sans le laisser brunir.","6. Ajoutez les haricots verts égouttés à la poêle. Faites-les sauter pendant 2-3 minutes, en remuant constamment, jusqu''à ce qu''ils soient bien enrobés et légèrement réchauffés. Salez et poivrez si nécessaire, puis incorporez 1 c. à soupe de persil frais haché.","7. Servez : Tranchez le steak contre le grain en fines lamelles. Disposez les 150 g de steak tranché et les 200 g de haricots verts sautés sur une assiette. Servez immédiatement. 💡 Astuce diabète : Mangez d''abord les haricots verts riches en fibres pour aider à stabiliser la glycémie. La portion de 350 g (150 g steak + 200 g haricots) est idéale. Évitez les sauces sucrées ou les accompagnements à base de glucides raffinés."]'::jsonb, '["1. حضّر الستيك: تأكد أن الستيك في درجة حرارة الغرفة. رش الملح والإبزار بسخاء على الجهتين (تقريبا 1/4 معلقة صغيرة من كل واحد).","2. حضّر اللوبيا الخضراء: غسل اللوبيا ونقيها من الجوانب. فورها لمدة 5 إلى 7 دقائق، حتى تصبح طرية ولكن مازال فيها شوية القرمشة. مباشرة من بعد، حطها في ماء بارد جدا مع الثلج باش توقف الطياب وتحافظ على لونها، ثم صفيها مزيان.","3. حضّر التتبيلة السريعة للستيك: في زلافة صغيرة، خلط 1/2 معلقة صغيرة كمون و 1/4 معلقة صغيرة تحميرة. دهن الستيك بهذا الخليط ديال العطرية.","4. شوي الستيك: سخّن مقلاة الشواء أو الشواية على نار مجهدة. ملي تسخن مزيان، حط الستيك. باش يجي نص طيبة، شوي 2-3 دقائق من كل جهة. باش يجي طايب مزيان، 4-5 دقائق من كل جهة. خلي الستيك يرتاح فوق لوحة التقطيع لمدة 5 دقائق قبل ما تقطعو باش يتوزع العصير ديالو.","5. حضّر اللوبيا مشرملة: بينما الستيك كيرتاح، قطع 2 فصوص ثوم رقاق بزاف. في مقلاة ماكتلصقش، سخّن 1 معلقة كبيرة زيت الزيتون على نار متوسطة. ضف الثوم المقطع وقليه لمدة 30 ثانية حتى تطلع ريحتو، بلا ما يتحمر.","6. ضف اللوبيا الخضراء المصفاة للمقلاة. شحرها لمدة 2-3 دقائق، مع التحريك المستمر، حتى تتغطى بالزيت والثوم وتسخن مزيان. ضف الملح والإبزار إذا لزم الأمر، ثم خلط 1 معلقة كبيرة معدنوس طري مفروم.","7. قدّم الطبق: قطع الستيك ضد الألياف إلى شرائح رقيقة. حط 150 غرام من الستيك المقطع و 200 غرام من اللوبيا الخضراء مشرملة في طبق. قدّم الطبق مباشرة. 💡 نصيحة للسكري: كل اللوبيا الخضراء الغنية بالألياف أولا باش تساعد في استقرار نسبة السكر في الدم. الكمية ديال 350 غرام (150 غرام ستيك + 200 غرام لوبيا) مثالية. تجنب الصلصات الحلوة أو الأطباق الجانبية اللي فيها كربوهيدرات مكررة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8e/Steak_samples%2C_Oberm%C3%BChle%2C_Hennethal.jpg/1280px-Steak_samples%2C_Oberm%C3%BChle%2C_Hennethal.jpg', ARRAY['steak']::text[]),
  ('couscous-belboula', 'Couscous d''orge (belboula) aux légumes', 'كسكس بلبولة بالخضرة', 'Barley couscous with vegetables', 'main', ARRAY['ghda']::text[], '🥘', '1 assiette moyenne (300 g)', 300, 380, 55, 8, 13, 9, 9, 50, 'Le vendredi reste sacré ! La belboula (orge) a un IG bien plus bas que la semoule blanche (50 vs 65), et 2× plus de fibres. Assiette MOYENNE, beaucoup de légumes, peu de grains.', 'الجمعة كتبقى مقدسة! البلبولة (الشعير) عندها مؤشر أقل بكثير من السميدة البيضاء (50 مقابل 65)، وضعف الألياف. طبسيل متوسط، خضرة بزاف، وشوية ديال الكسكس.', '["100 g de couscous d''orge (belboula) moyenne","100 g de courge (khamssa) coupée en gros dés","80 g de carottes coupées en rondelles épaisses","80 g de navets coupés en quatre","50 g de chou blanc coupé en quartiers","1 tomate moyenne râpée","1/2 oignon moyen émincé","2 c. à soupe d''huile d''olive extra vierge","1/2 c. à café de curcuma","1/4 c. à café de gingembre moulu"]'::jsonb, '["100 غرام كسكس بلبولة متوسطة","100 غرام قرعة حمراء مقطعة مكعبات كبيرة","80 غرام خيزو مقطع دوائر غليظة","80 غرام لفت مقطع على أربعة","50 غرام كرنب (ليشو) مقطع أرباع","1 مطيشة متوسطة محكوكة","1/2 بصلة متوسطة مشلضة","2 م. كبار زيت الزيتون البكر الممتاز","1/2 م. صغيرة خرقوم بلدي","1/4 م. صغيرة سكينجبير مطحون"]'::jsonb, '["Dans le bas du couscoussier, faites chauffer 1 cuillère à soupe d''huile d''olive à feu moyen. Ajoutez l''oignon émincé et faites-le revenir jusqu''à ce qu''il devienne translucide, environ 3-4 minutes.","Ajoutez la tomate râpée, le curcuma, le gingembre, le safran (ou colorant), le sel et le poivre. Laissez mijoter 5 minutes à feu doux, en remuant de temps en temps, jusqu''à ce que la sauce épaississe légèrement.","Versez environ 500 ml d''eau chaude dans la marmite. Ajoutez les carottes et les navets. Portez à ébullition, puis réduisez le feu à doux et laissez cuire 10 minutes.","Pendant ce temps, préparez la belboula : dans un grand plat, mettez la belboula, arrosez-la d''1/2 verre d''eau froide et d''1 cuillère à soupe d''huile d''olive. Mélangez délicatement avec les mains pour bien séparer les grains. Laissez reposer 5 minutes.","Placez la belboula dans le haut du couscoussier (le keskas). Une fois que la vapeur commence à s''échapper du keskas (environ 15-20 minutes après avoir mis les légumes), comptez 20 minutes de cuisson à la vapeur. Retirez le keskas et versez la belboula dans le grand plat. Séparez les grains avec une fourchette, salez légèrement et arrosez d''1/2 verre d''eau froide. Laissez absorber 5 minutes.","Ajoutez la courge et le chou dans le bas du couscoussier avec les autres légumes. Remettez la belboula dans le keskas et faites-la cuire une deuxième fois à la vapeur pendant 20 minutes, jusqu''à ce qu''elle soit tendre et moelleuse. Vérifiez la cuisson des légumes : ils doivent être tendres mais pas en purée.","💡 Astuce diabète : Servez une assiette moyenne de 300 g. Commencez par manger les légumes pour bénéficier de leurs fibres qui ralentissent l''absorption des glucides. La belboula a un IG de 50, ce qui est bien meilleur que la semoule blanche. Évitez d''ajouter du sucre ou du smen (beurre rance) et privilégiez l''huile d''olive."]'::jsonb, '["فالبرمة ديال الكسكسو، سخّن 1 معلقة كبيرة ديال زيت الزيتون على نار متوسطة. زيد البصلة المشلضة وخليها تشحر حتى تولي شفافة، تقريبا 3-4 دقايق.","زيد مطيشة محكوكة، الخرقوم، سكينجبير، الزعفران (أو الملون)، الملحة والإبزار. خليها طيب على نار مهيلة 5 دقايق، وحرك مرة مرة، حتى تعقاد لاصوص شوية.","صب تقريبا 500 مل ديال الماء سخون فالبرمة. زيد خيزو واللفت. خليها تغلى، من بعد نقص النار لمهيلة وخليها طيب 10 دقايق.","فهاذ الوقت، وجد البلبولة: فقصعة كبيرة، حط البلبولة، رشها بنص كاس ديال الماء بارد و1 معلقة كبيرة ديال زيت الزيتون. خلطها غير بشوية بيديك باش تفك الحبات مزيان. خليها ترتاح 5 دقايق.","حط البلبولة فالكسكاس. ملي يبدا يطلع البخار من الكسكاس (تقريبا 15-20 دقيقة من بعد ما حطيتي الخضرة)، حسب 20 دقيقة ديال الطياب على البخار. حيد الكسكاس وخوي البلبولة فالقصعة. فك الحبات بالفرشيطة، رش شوية الملحة ورش نص كاس ديال الماء بارد. خليها تشرب 5 دقايق.","زيد القرعة والكرنب (ليشو) فالبرمة مع الخضرة الأخرى. رجع البلبولة للكسكاس وطيبها مرة ثانية على البخار لمدة 20 دقيقة، حتى تولي رطبة ومفروزة. تأكد من طياب الخضرة: خاصها تكون طايبة ولكن ماشي مهرية.","💡 نصيحة للسكري: قدم طبق متوسط ديال 300 غرام. ابدأ بأكل الخضرة باش تستافد من الألياف ديالها اللي كاتباطئ امتصاص الكربوهيدرات. البلبولة عندها مؤشر سكري 50، وهذا أحسن بزااف من السميدة البيضاء. تجنب إضافة السكر أو السمن البلدي واستعمل زيت الزيتون."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/8/82/Moroccan_cuisine-Couscous_with_vegetables.jpg', ARRAY['belboula', 'couscous orge', 'بلبولة']::text[]),
  ('kebda-mchermla', 'Foie mchermel (kebda)', 'الكبدة المشرملة', 'Chermoula liver (kebda)', 'main', ARRAY['ftour', 'ghda', '3cha']::text[], '🥩', '1 portion (150 g)', 150, 240, 6, 2, 32, 10, 1, 10, 'La kebda est une bombe de fer et de vitamine B12 — parfaite contre la fatigue du diabétique — avec quasi zéro glucide. Poêlée, pas frite, 1×/semaine.', 'الكبدة قنبلة ديال الحديد وفيتامين B12 — مثالية ضد التعب ديال السكري — وتقريباً بلا نشويات. فالمقلة، ماشي مقلية فالزيت، مرة فالسيمانة.', '["150 g de foie de bœuf (ou veau)","1 c. à soupe d''huile d''olive extra vierge","1 petite tomate (environ 80g), râpée","1/2 oignon rouge (environ 40g), finement haché","1 gousse d''ail, écrasée","1/2 c. à café de paprika doux","1/4 c. à café de cumin moulu","Une pincée de piment doux (facultatif)","2 c. à soupe de coriandre fraîche et persil plat, hachés","Jus de 1/4 de citron (environ 1 c. à soupe)"]'::jsonb, '["150 غرام كبدة بقري (أو عجل)","1 ملعقة كبيرة زيت زيتون بكر ممتاز","1 حبة طماطم صغيرة (حوالي 80 غرام)، محكوكة","1/2 بصلة حمراء صغيرة (حوالي 40 غرام)، مفرومة ناعم","1 فص ثوم، مدقوق","1/2 ملعقة صغيرة تحميرة (بابريكا حلوة)","1/4 ملعقة صغيرة كمون مطحون","رشة فلفل حار حلو (اختياري)","2 ملاعق كبيرة قزبر ومعدنوس طري، مفرومين","عصير 1/4 حامضة (حوالي 1 ملعقة كبيرة)"]'::jsonb, '["Coupez le foie en petits dés de 2-3 cm. Rincez-le rapidement et égouttez-le bien.","Dans une poêle antiadhésive, faites chauffer 1 cuillère à soupe d''huile d''olive à feu moyen. Ajoutez l''oignon haché et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide.","Ajoutez l''ail écrasé et la tomate râpée. Laissez mijoter à feu doux pendant 5 minutes, en remuant de temps en temps, jusqu''à ce que la sauce épaississe légèrement.","Incorporez le paprika, le cumin, le piment doux (si utilisé), le sel et le poivre. Mélangez bien et laissez cuire 1 minute pour que les épices libèrent leurs arômes.","Augmentez le feu à moyen-vif. Ajoutez les dés de foie dans la poêle. Faites-les sauter pendant 3-4 minutes, en remuant constamment, jusqu''à ce qu''ils soient juste dorés à l''extérieur et encore légèrement rosés à l''intérieur. Attention à ne pas trop cuire le foie pour qu''il reste tendre.","Retirez la poêle du feu. Incorporez la coriandre et le persil hachés, puis arrosez avec le jus de citron. Mélangez délicatement.","Servez immédiatement. 💡 Astuce diabète : Cette portion de 150g de foie mchermel est idéale. Pour un repas équilibré, accompagnez-la d''une grande salade verte sans féculents ou de légumes vapeur (brocoli, haricots verts) pour augmenter l''apport en fibres et stabiliser la glycémie. Évitez le pain blanc et privilégiez une petite portion de pain complet si nécessaire."]'::jsonb, '["قطعوا الكبدة إلى مكعبات صغيرة بحجم 2-3 سم. شللوها بسرعة وقطروها مزيان.","في مقلاة غير لاصقة، سخنوا 1 ملعقة كبيرة زيت زيتون على نار متوسطة. ضيفوا البصل المفروم وخليوه يتشحر لمدة 3-4 دقائق حتى يصبح شفاف.","ضيفوا الثوم المدقوق والطماطم المحكوكة. خليوهم يتشحروا على نار هادئة لمدة 5 دقائق، مع التحريك مرة مرة، حتى تخثار الصلصة شوية.","زيدوا التحميرة، الكمون، الفلفل الحار الحلو (إذا استعملتوه)، الملح والفلفل الأسود. خلطوا مزيان وخليوه يطيب دقيقة باش تطلق العطرية النكهة ديالها.","عليوا النار إلى متوسطة-عالية. ضيفوا مكعبات الكبدة للمقلاة. قلبوها لمدة 3-4 دقائق، مع التحريك المستمر، حتى تتحمر من برا وتبقى وردية شوية من الداخل. ردوا البال ماتطيبوش الكبدة بزاف باش تبقى رطبة.","حيدوا المقلاة من فوق النار. ضيفوا القزبر والمعدنوس المفرومين، ثم سقيوها بعصير الحامض. خلطوا بلطف.","قدموها مباشرة. 💡 نصيحة للسكري: هذه الحصة ديال 150 غرام من الكبدة مشرملة مثالية. لوجبة متوازنة، قدموها مع سلطة خضراء كبيرة بدون نشويات أو خضروات مبخرة (بروكلي، لوبيا خضراء) لزيادة الألياف وتثبيت مستوى السكر في الدم. تجنبوا الخبز الأبيض وفضلوا قطعة صغيرة من الخبز الكامل إذا لزم الأمر."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5f/Leber-9589371.jpg/1280px-Leber-9589371.jpg', ARRAY['kebda', 'foie', 'كبدة']::text[]),
  ('poulet-roti-four', 'Poulet rôti au four (sans peau)', 'دجاج محمر فالفرن (بلا جلدة)', 'Oven-roasted chicken (skinless)', 'main', ARRAY['ghda', '3cha']::text[], '🍗', '1 cuisse + légumes (300 g)', 300, 310, 9, 4, 38, 14, 3, 15, 'Le djaj m''hamer des fêtes, version santé : au four avec citron confit et olives, SANS la peau (là où se cache le gras). Le goût du Maroc, la glycémie en paix.', 'دجاج محمر ديال الأعراس، بالنسخة الصحية: فالفرن مع الحامض المصير والزيتون، بلا الجلدة (فين مخبية الدهون). ذوق المغرب، والسكر هاني.', '["1 cuisse de poulet sans peau (environ 150 g)","1/2 citron confit (pulpe et écorce, 15 g)","5 olives violettes (20 g)","1/2 oignon rouge (50 g)","1 petite tomate (80 g)","1/2 poivron vert (70 g)","1 c. à café de paprika doux","1/2 c. à café de cumin moulu","1 c. à soupe d''huile d''olive"]'::jsonb, '["1 فخد دجاج بلا جلدة (تقريبا 150 غ)","1/2 حامضة مصيرة (اللب والقشرة، 15 غ)","5 زيتونات كحلين (20 غ)","1/2 بصلة حمراء (50 غ)","1 مطيشة صغيرة (80 غ)","1/2 فلفلة خضرا (70 غ)","1 معلقة صغيرة تحميرة حلوة","1/2 معلقة صغيرة كامون مطحون","1 معلقة كبيرة زيت الزيتون"]'::jsonb, '["Préchauffez votre four à 180°C (Thermostat 6). Lavez la cuisse de poulet et assurez-vous qu''elle est bien sans peau. Salez et poivrez légèrement.","Dans un bol, mélangez 1/2 c. à café de paprika et 1/4 c. à café de cumin avec 1/2 c. à soupe d''huile d''olive. Badigeonnez la cuisse de poulet avec cette marinade. Laissez reposer 10 minutes.","Coupez l''oignon rouge en fines lamelles, la tomate en dés et le poivron vert en lanières. Hachez finement la pulpe et l''écorce du citron confit.","Dans un plat allant au four, disposez la cuisse de poulet. Autour, répartissez les légumes coupés (oignon, tomate, poivron). Ajoutez le citron confit haché et les olives violettes.","Arrosez les légumes avec le reste de l''huile d''olive (1/2 c. à soupe) et saupoudrez du reste de paprika (1/2 c. à café) et de cumin (1/4 c. à café). Mélangez délicatement les légumes pour bien les enrober.","Enfournez le plat pour environ 35 à 40 minutes. Le poulet doit être doré et bien cuit à cœur, et les légumes tendres mais encore légèrement croquants. Retournez la cuisse de poulet à mi-cuisson pour une cuisson uniforme.","💡 Astuce diabète : Cette portion de 300g (une cuisse + légumes) est idéale. Pour maintenir une glycémie stable, commencez votre repas par les légumes riches en fibres. Évitez de servir ce plat avec du pain blanc ou des frites ; préférez une petite portion de boulgour complet ou de quinoa si vous souhaitez un accompagnement féculent."]'::jsonb, '["سخن الفران ديالك على درجة حرارة 180°C (الدرجة 6). غسل فخد الدجاج وتأكد أنه بلا جلدة. رش عليه شوية ملح وبزار.","فزلافة، خلط 1/2 معلقة صغيرة تحميرة و 1/4 معلقة صغيرة كامون مع 1/2 معلقة كبيرة زيت الزيتون. دهن فخد الدجاج بهاد الشرمولة. خليه يرتاح 10 دقايق.","قطع البصلة الحمرا شرائح رقيقة، مطيشة مربعات صغار، والفلفلة الخضرا شرائح طويلة. قطع الحامض المصير (اللب والقشرة) رقيق بزاف.","فلاطة كتدخل للفران، حط فخد الدجاج. وزع الخضرة المقطعة (البصل، مطيشة، الفلفلة) داير بيه. زيد الحامض المصير مقطع والزيتون الكحل.","سقي الخضرة بالزيت الزيتون اللي بقى (1/2 معلقة كبيرة) ورش عليها باقي التحميرة (1/2 معلقة صغيرة) والكامون (1/4 معلقة صغيرة). خلط الخضرة غير بشوية باش تشرب العطرية مزيان.","دخل اللاطة للفران لمدة 35 حتى 40 دقيقة تقريبا. الدجاج خاصو يتحمر ويطيب مزيان من الداخل، والخضرة تولي رطبة ولكن باقا فيها شوية القرمشة. قلب فخد الدجاج فوسط الطياب باش يطيب من كل الجوانب.","💡 نصيحة للسكري: هاد الكمية ديال 300غ (فخد دجاج + خضرة) مثالية. باش تحافظ على سكر الدم مستقر، بدا الماكلة ديالك بالخضرة اللي غنية بالألياف. تجنب تقدم هاد الطبق مع الخبز الأبيض أو البطاطس المقلية؛ من الأفضل تقدم معاه كمية قليلة من البرغل الكامل أو الكينوا إذا بغيتي شي حاجة نشوية."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d2/Lemon_%26_Garlic_Roasted_Chicken_%288733072162%29.jpg/1280px-Lemon_%26_Garlic_Roasted_Chicken_%288733072162%29.jpg', ARRAY['djaj mhamer', 'دجاج محمر']::text[]),
  ('choufleur-mchermel', 'Chou-fleur rôti mchermel', 'الشيفلور المحمر المشرمل', 'Roasted chermoula cauliflower', 'main', ARRAY['ghda', '3cha']::text[], '🥦', '1 portion (250 g)', 250, 140, 12, 5, 5, 8, 6, 15, 'Rôti au four avec chermoula, le chou-fleur devient doré et savoureux — un "faux couscous" ou un accompagnement à volonté, avec 5× moins de glucides que le riz.', 'محمر فالفرن بالشرمولة، الشيفلور كيولي مذهب وبنين — "كسكس مزور" ولا مرافق بلا حساب، ب5 مرات أقل نشويات من الروز.', '["250 g de chou-fleur frais, coupé en bouquets","1 c. à soupe d''huile d''olive extra vierge","1/2 c. à café de paprika doux","1/4 c. à café de cumin moulu","1/4 c. à café de curcuma moulu","1 petite gousse d''ail, hachée finement","1 c. à café de persil frais, ciselé","1 c. à café de coriandre fraîche, ciselée","Une pincée de sel de mer"]'::jsonb, '["250 غرام من الشيفلور الطري، مقطع وردات","1 ملعقة كبيرة زيت الزيتون البكر الممتاز","1/2 ملعقة صغيرة تحميرة (بابريكا حلوة)","1/4 ملعقة صغيرة كمون مطحون","1/4 ملعقة صغيرة خرقوم بلدي (كركم مطحون)","1 فص ثوم صغير، مفروم رقيق","1 ملعقة صغيرة معدنوس طري، مقطع رقيق","1 ملعقة صغيرة قزبور طري، مقطع رقيق","رشة ملح بحري"]'::jsonb, '["Préchauffez votre four à 200°C (Thermostat 6-7). Tapissez une plaque de cuisson de papier sulfurisé.","Dans un grand bol, mélangez l''huile d''olive, le paprika, le cumin, le curcuma, l''ail haché, le persil ciselé, la coriandre ciselée et la pincée de sel pour créer la chermoula.","Ajoutez les bouquets de chou-fleur dans le bol et mélangez bien avec vos mains pour enrober chaque morceau de chermoula. Assurez-vous que le chou-fleur est uniformément couvert.","Disposez les bouquets de chou-fleur assaisonnés en une seule couche sur la plaque de cuisson préparée, en veillant à ne pas les superposer pour une cuisson homogène.","Faites rôtir au four préchauffé pendant 20 à 25 minutes, ou jusqu''à ce que le chou-fleur soit tendre et légèrement doré sur les bords. Retournez les bouquets à mi-cuisson (après environ 10-12 minutes) pour une dorure uniforme.","Vérifiez la cuisson en piquant un bouquet avec une fourchette : il doit être tendre mais encore légèrement ferme. Le chou-fleur doit avoir une belle couleur dorée et un parfum épicé.","💡 Astuce diabète : Cette portion de 250 g de chou-fleur rôti est idéale pour un plat principal léger. Pour maintenir une glycémie stable, servez-le avec une source de protéines maigres (poulet grillé, poisson) et une grande salade verte. Évitez de le servir avec du pain blanc ou des féculents raffinés. Le chou-fleur a un IG très bas (15), ce qui en fait un excellent choix."]'::jsonb, '["سخن الفران ديالك على درجة حرارة 200°C. فرّش لاطة الفران بورق الطهي.","فزلافة كبيرة، خلط زيت الزيتون، التحميرة، الكمون، الخرقوم البلدي، الثومة محكوكة، المعدنوس مقطع، القزبور مقطع ورشة الملح باش تصاوب الشرمولة.","زيد وردات الشيفلور فالزلافة وخلط مزيان بيديك باش تغلف كل قطعة بالشرمولة. تأكد أن الشيفلور تغطى كامل.","ستّف وردات الشيفلور المشملة فـ اللاطة اللي وجدتي، وحاول ما تحطهمش فوق بعضياتهم باش يطيبو مزيان ويتحمرو بالتساوي.","دخل الشيفلور يطيب فالفران السخون لمدة 20 حتى 25 دقيقة، ولا حتى يولي رطب ومحمر شوية من الجناب. قلب الوردات فـ نص الطياب (تقريبا من بعد 10-12 دقيقة) باش يتحمرو من جميع الجوانب.","تأكد من الطياب بأنك تغرز فرشيطة فـ شي وردة: خاصها تكون رطبة ولكن باقا شادة راسها شوية. الشيفلور خاصو يكون عندو لون ذهبي زوين وريحة بنينة ديال العطرية.","💡 نصيحة للسكري: هاد الكمية ديال 250 غرام من الشيفلور المحمر مناسبة كوجبة رئيسية خفيفة. باش تحافظ على مستوى السكر فالدم مستقر، قدمو مع مصدر بروتين قليل الدهن (دجاج مشوي، حوت) وسلطة خضراء كبيرة. تجنب تقدمو مع الخبز الأبيض أو النشويات المكررة. الشيفلور عندو مؤشر سكري منخفض بزاف (15)، وهذا كيجعلو اختيار ممتاز."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/16/Plated_roasted_cauliflower_10.jpg/1280px-Plated_roasted_cauliflower_10.jpg', ARRAY['choufleur', 'شيفلور']::text[]),
  ('tajine-legumes', 'Tajine de légumes (khodra)', 'طاجين الخضرة', 'Vegetable tagine', 'main', ARRAY['ghda', '3cha']::text[], '🥘', '1 assiette (350 g)', 350, 210, 26, 10, 7, 8, 8, 40, 'Tout le parfum du tajine, sans viande grasse : courgettes, carottes, navets, petits pois mijotés aux épices. Riche en fibres, léger, parfait le soir avec ¼ de pain seulement.', 'كل ريحة الطاجين، بلا لحم دسم: قرعة، خيزو، لفت وجلبانة مطيبين بالعطرية. غني بالألياف، خفيف، مثالي فالعشية مع ربع خبزة برك.', '["150 g de courgettes (environ 1 petite)","100 g de carottes (environ 1 moyenne)","50 g de navets (environ 1 petit)","30 g de petits pois frais ou surgelés","1/2 tomate moyenne (environ 60 g)","1/4 oignon moyen (environ 30 g)","1 c. à café d''huile d''olive (5 ml)","1/4 c. à café de curcuma","1/4 c. à café de gingembre moulu","1 pincée de cumin moulu"]'::jsonb, '["150 غرام من الكورجيط (حبة صغيرة تقريبا)","100 غرام من خيزو (حبة متوسطة تقريبا)","50 غرام من اللفت (حبة صغيرة تقريبا)","30 غرام من الجلبانة طرية أو مجمدة","نصف مطيشة متوسطة (حوالي 60 غرام)","ربع بصلة متوسطة (حوالي 30 غرام)","1 ملعقة صغيرة زيت الزيتون (5 مل)","ربع ملعقة صغيرة خرقوم بلدي","ربع ملعقة صغيرة سكينجبير مطحون","رشة كمون مطحون"]'::jsonb, '["1. Lavez et préparez tous les légumes. Coupez les courgettes, les carottes et les navets en gros morceaux ou en rondelles épaisses. Hachez finement l''oignon et coupez la tomate en petits dés.","2. Dans un tajine ou une cocotte à fond épais, versez 1 cuillère à café d''huile d''olive. Ajoutez l''oignon haché et faites-le revenir à feu doux pendant 3-4 minutes jusqu''à ce qu''il devienne translucide, en remuant de temps en temps.","3. Ajoutez les dés de tomate, le curcuma, le gingembre, le cumin, le paprika, le sel et le poivre. Mélangez bien et laissez mijoter 5 minutes à feu doux, jusqu''à ce que la tomate ramollisse et que les épices libèrent leur parfum.","4. Disposez les carottes et les navets au fond du tajine, car ils nécessitent un temps de cuisson plus long. Ajoutez environ 50 ml d''eau (environ 1/4 de verre) pour éviter que les légumes n''attachent.","5. Couvrez le tajine et laissez cuire à feu doux pendant 15-20 minutes. Vérifiez de temps en temps qu''il y a suffisamment de liquide et ajoutez une petite quantité d''eau si nécessaire.","6. Après 15-20 minutes, ajoutez les courgettes et les petits pois sur le dessus des autres légumes. Couvrez à nouveau et poursuivez la cuisson pendant 10-15 minutes, ou jusqu''à ce que tous les légumes soient tendres mais encore légèrement fermes (al dente).","7. Avant de servir, saupoudrez le tajine de coriandre fraîche hachée. Servez chaud directement du tajine. Ce plat est une portion individuelle de 350 g.","💡 Astuce diabète : Pour un contrôle optimal de la glycémie, consommez cette portion de 350 g de tajine de légumes riche en fibres. Accompagnez-le d''un quart de pain complet (environ 30-40 g) et mangez d''abord les légumes pour ralentir l''absorption des glucides."]'::jsonb, '["1. غسلوا ووجدوا جميع الخضروات. قطعوا الكورجيط، خيزو واللفت طراف كبار أو دوائر غليظة. قطعوا البصلة رقيقة بزاف و مطيشة مربعات صغار.","2. في الطاجين أو كوكوط تكون ثقيلة، ديروا 1 ملعقة صغيرة زيت الزيتون. زيدوا البصلة اللي قطعتوا رقيقة وخليوها تشحر على نار مهيلة لمدة 3-4 دقائق حتى تولي شفافة، مع التحريك مرة مرة.","3. زيدوا مطيشة مقطعة، الخرقوم، سكينجبير، الكمون، التحميرة، الملح والإبزار. خلطوا مزيان وخليوها طيب على نار مهيلة لمدة 5 دقائق، حتى ترطاب مطيشة وتطلق العطرية ريحتها.","4. ستفوا خيزو واللفت في قاع الطاجين، حيت كيحتاجوا وقت أطول باش يطيبوا. زيدوا حوالي 50 مل ديال الماء (تقريبا ربع كاس) باش ما تلصقش الخضرة.","5. غطيو الطاجين وخليوه يطيب على نار مهيلة لمدة 15-20 دقيقة. مرة مرة قلبوا واش كاين الماء الكافي وزيدوا شوية الماء إذا لزم الأمر.","6. من بعد 15-20 دقيقة، زيدوا الكورجيط والجلبانة فوق الخضرة الأخرى. غطيو عاوتاني وكملوا الطياب لمدة 10-15 دقيقة، أو حتى تولي الخضرة كلها طايبة ولكن باقا شادة راسها شوية (ال دنتي).","7. قبل ما تقدموا، رشوا الطاجين بالقزبر طري مقطع رقيق. قدموه سخون مباشرة من الطاجين. هاد الطبق هو وجبة فردية ديال 350 غرام.","💡 نصيحة للسكري: باش تحافظوا على مستوى السكر في الدم مزيان، كولوا هاد الكمية ديال 350 غرام من طاجين الخضرة الغني بالألياف. رافقوه بربع خبزة كاملة (حوالي 30-40 غرام) وكولوا الخضرة هي الأولى باش تبطئوا امتصاص الكربوهيدرات."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/87/Chicken_Veg_Tagine_Rabat_Nov25_A7CR_08908.jpg/1280px-Chicken_Veg_Tagine_Rabat_Nov25_A7CR_08908.jpg', ARRAY['tajine khodra', 'طاجين خضرة']::text[]),
  ('tajine-poulet-citron-olives', 'Tajine poulet citron confit & olives', 'طاجين الدجاج بالحامض المصير والزيتون', 'Chicken tagine with preserved lemon & olives', 'main', ARRAY['ghda', '3cha']::text[], '🍗', '1 assiette (320 g)', 320, 330, 8, 3, 36, 17, 2, 15, 'Le tajine mqualli classique, sans peau ni excès d’huile : poulet, citron confit et olives, presque zéro glucide. Un des meilleurs plats de fête possibles pour un diabétique.', 'طاجين مقلي كلاسيكي، بلا جلدة وبلا زيت زايد: دجاج، حامض مصير وزيتون، تقريباً بلا نشويات. من أحسن ماكلات العرس الممكنة للسكري.', '["150 g de blanc de poulet (sans peau ni os)","1/4 de citron confit (pulpe retirée, peau coupée en 4)","20 g d''olives vertes dénoyautées","1/2 oignon moyen (environ 50 g), haché finement","1 c. à café d''huile d''olive extra vierge","1/2 gousse d''ail, écrasée","1/4 c. à café de curcuma moulu","1/4 c. à café de gingembre moulu","Une pincée de safran (facultatif)"]'::jsonb, '["150 غرام صدر دجاج (بلا جلد وعظم)","1/4 حامضة مصيرة (اللب محيد، القشرة مقطعة على 4)","20 غرام زيتون أخضر بلا عظم","1/2 بصلة متوسطة (حوالي 50 غرام)، مشلضة رقيقة","1 ملعقة صغيرة زيت الزيتون البكر الممتاز","1/2 فص ثوم، مدقوق","1/4 ملعقة صغيرة خرقوم بلدي مطحون","1/4 ملعقة صغيرة سكينجبير مطحون","رشة زعفران شعرة (اختياري)"]'::jsonb, '["1. Dans un tajine ou une cocotte à fond épais, chauffez 1 c. à café d''huile d''olive à feu moyen. Ajoutez 1/2 oignon haché finement et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide, en remuant de temps en temps.","2. Ajoutez 1/2 gousse d''ail écrasée, 1/4 c. à café de curcuma, 1/4 c. à café de gingembre et une pincée de safran (si utilisé). Mélangez bien et laissez cuire 30 secondes en remuant pour libérer les arômes.","3. Coupez 150 g de blanc de poulet en morceaux de taille moyenne. Ajoutez le poulet au tajine et faites-le dorer de tous les côtés pendant environ 5 minutes, jusqu''à ce qu''il ne soit plus rosé.","4. Ajoutez environ 50 ml d''eau chaude (juste assez pour couvrir le fond du tajine) et la peau de 1/4 de citron confit coupée en 4. Portez à légère ébullition, puis réduisez le feu à doux, couvrez et laissez mijoter pendant 20 minutes.","5. Après 20 minutes, vérifiez la cuisson du poulet. Il doit être tendre. Si la sauce est trop liquide, retirez le couvercle et laissez mijoter à feu doux quelques minutes pour qu''elle épaississe légèrement.","6. Ajoutez 20 g d''olives vertes dénoyautées. Mélangez délicatement et laissez mijoter encore 5 minutes pour que les saveurs se mélangent bien et que les olives chauffent.","7. Servez le tajine chaud directement du plat. Le poulet doit être tendre et la sauce légèrement réduite. Assurez-vous que le citron confit est bien intégré au plat. Ce plat est conçu pour une portion de 320 g.","💡 Astuce diabète : Pour ce tajine, la portion recommandée est de 320 g. Commencez votre repas par une salade verte sans féculents pour améliorer la glycémie post-prandiale. Évitez de le servir avec du pain blanc ou du riz, préférez une petite portion de légumes verts cuits à la vapeur ou une salade."]'::jsonb, '["1. فواحد الطاجين ولا كوكوط ثقيلة، سخّن 1 ملعقة صغيرة زيت الزيتون على نار متوسطة. زيد 1/2 بصلة مشلضة رقيقة وشحرها لمدة 3-4 دقايق حتى تولي شفافة، مع التحريك مرة مرة.","2. زيد 1/2 فص ثوم مدقوق، 1/4 ملعقة صغيرة خرقوم، 1/4 ملعقة صغيرة سكينجبير ورشة زعفران (إذا استعملتيه). خلط مزيان وخليه يطيب 30 ثانية مع التحريك باش تطلق النكهات.","3. قطع 150 غرام صدر دجاج لقطع متوسطة. زيد الدجاج للطاجين وحمّرو من جميع الجوانب لمدة 5 دقايق تقريبا، حتى ميبقاش وردي.","4. زيد حوالي 50 ملل ماء سخون (غير القياس اللي يغطي قاع الطاجين) وقشرة 1/4 حامضة مصيرة مقطعة على 4. خليه يغلى شوية، من بعد نقص النار لمهيلة، غطي الطاجين وخليه يطيب على خاطرو لمدة 20 دقيقة.","5. من بعد 20 دقيقة، تأكد من طياب الدجاج. خاصو يكون رطب. إذا كانت المرقة جارية بزاف، حيد الغطا وخليه يتشحر على نار مهيلة شي دقايق باش تختار شوية.","6. زيد 20 غرام زيتون أخضر بلا عظم. خلط بلطف وخليه يتشحر 5 دقايق أخرى باش تتجانس النكهات ويسخن الزيتون.","7. قدم الطاجين سخون مباشرة من الطاجين. خاص الدجاج يكون رطب والمرقة خاثرة شوية. تأكد أن الحامض المصير مندمج مزيان مع الطبق. هاد الطبق مخصص لواحد الحصة ديال 320 غرام.","💡 نصيحة للسكري: لهاد الطاجين، الحصة الموصى بها هي 320 غرام. ابدأ وجبتك بسلطة خضراء بلا نشويات لتحسين مستوى السكر في الدم بعد الأكل. تجنب تقدمه مع الخبز الأبيض أو الأرز، وفضل تقدمه مع كمية قليلة من الخضروات الخضراء المطهوة على البخار أو سلطة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8a/Moroccan_food-Chicken_tagine_with_preserved_lemons_and_olives-01.jpg/1280px-Moroccan_food-Chicken_tagine_with_preserved_lemons_and_olives-01.jpg', ARRAY['tajine mqualli', 'طاجين مقلي']::text[]),
  ('tajine-poisson-chermoula', 'Tajine de poisson à la chermoula', 'طاجين الحوت بالشرمولة', 'Chermoula fish tagine', 'main', ARRAY['ghda', '3cha']::text[], '🐟', '1 assiette (350 g)', 350, 300, 14, 5, 34, 12, 4, 25, 'Poisson blanc, chermoula parfumée et légumes fondants : oméga-3, protéines et presque pas de glucides. Le tajine côtier idéal — plus léger que la viande, meilleur pour le cœur.', 'حوت أبيض، شرمولة معطرة وخضرة ذايبة: أوميغا 3، بروتين وتقريباً بلا نشويات. الطاجين الساحلي المثالي — أخف من اللحم وأحسن للقلب.', '["150 g filet de poisson blanc (mérou, cabillaud ou sole)","1 petite tomate (environ 70 g), coupée en rondelles fines","1/2 poivron vert (environ 40 g), coupé en lanières","1 petite carotte (environ 30 g), coupée en fines rondelles","1/4 citron confit (environ 10 g), rincé et haché","1 c. à soupe d''huile d''olive extra vierge","1 c. à café de paprika doux","1/2 c. à café de cumin moulu","1/4 c. à café de curcuma","1 petite gousse d''ail (environ 3 g), écrasée"]'::jsonb, '["150 غرام فيليه سمك أبيض (كربينة، قادوس أو سول)","1 مطيشة صغيرة (حوالي 70 غرام)، مقطعة دوائر رقاق","1/2 فلفلة خضرا (حوالي 40 غرام)، مقطعة شرائح طوال","1 خيزوة صغيرة (حوالي 30 غرام)، مقطعة دوائر رقاق","1/4 حامضة مصيرة (حوالي 10 غرام)، مشللة ومقطعة رقيقة","1 م. ك. زيت الزيتون البكر الممتاز","1 م. ص. تحميرة حلوة","1/2 م. ص. كامون مطحون","1/4 م. ص. خرقوم بلدي","1 ضرس ثومة صغير (حوالي 3 غرام)، مدقوق"]'::jsonb, '["1. Dans un petit bol, préparez la chermoula : mélangez l''ail écrasé, la coriandre hachée, le persil haché, le paprika, le cumin, le curcuma, le piment fort (si utilisé), la moitié de l''huile d''olive (1/2 c. à soupe), le sel et le poivre. Mélangez bien pour obtenir une pâte homogène.","2. Badigeonnez généreusement le filet de poisson blanc des deux côtés avec la chermoula préparée. Laissez mariner pendant au moins 15 minutes à température ambiante pour que les saveurs s''imprègnent bien.","3. Pendant ce temps, préparez le tajine. Dans un tajine en terre cuite ou une cocotte à fond épais, versez le reste de l''huile d''olive (1/2 c. à soupe) et disposez les rondelles de carottes en une seule couche au fond. Faites cuire à feu doux pendant 5 minutes pour les attendrir légèrement.","4. Ajoutez ensuite les lanières de poivron vert par-dessus les carottes, puis les rondelles de tomate. Salez et poivrez légèrement les légumes.","5. Déposez délicatement le filet de poisson mariné au centre des légumes. Ajoutez le citron confit haché autour du poisson.","6. Couvrez le tajine et laissez cuire à feu très doux pendant environ 15 à 20 minutes. Le poisson est cuit lorsqu''il s''effeuille facilement à la fourchette et que les légumes sont tendres. N''ajoutez pas d''eau, les légumes rendront leur propre jus.","7. Servez le tajine de poisson directement dans son plat de cuisson, bien chaud. Accompagnez-le d''une petite salade verte sans féculents. 💡 Astuce diabète : Pour un contrôle optimal de la glycémie, consommez d''abord les légumes et le poisson. La portion recommandée est de 350 g (une assiette) pour maintenir l''apport en glucides à 14 g et le GI bas (25)."]'::jsonb, '["1. فزلافة صغيرة، وجد الشرمولة: خلط الثومة مدقوقة، القزبور والمعدنوس مقطعين، التحميرة، الكامون، الخرقوم، الهريسة (إيلا استعملتيها)، نص زيت الزيتون (1/2 م. ك.)، الملح والإبزار. خلط مزيان باش تحصل على عجينة متجانسة.","2. دهن فيليه السمك الأبيض مزيان من الجيهات بجوج بالشرمولة اللي وجدتي. خليه يترقد على الأقل 15 دقيقة فحرارة الغرفة باش يتشرب النكهات مزيان.","3. فهاد الوقت، وجد الطاجين. فطاجين ديال الطين أو كوكوط تقيلة، خوي اللي بقى من زيت الزيتون (1/2 م. ك.) وستف دوائر خيزو طبقة وحدة فالقاع. طيبهم على نار مهيلة لمدة 5 دقائق باش يرطابو شوية.","4. من بعد، زيد شرائح الفلفلة الخضرا فوق خيزو، ومن بعد دوائر مطيشة. رش شوية الملح والإبزار على الخضرة.","5. حط فيليه السمك المرقد غير بشوية فالوسط ديال الخضرة. زيد الحامض المصير مقطع رقيق داير بالسمك.","6. غطي الطاجين وخليه يطيب على نار مهيلة بزاف لمدة 15 حتى 20 دقيقة تقريبا. السمك كيكون طاب ملي كيتقشر بسهولة بالفرشيطة والخضرة كتكون رطبة. ماتزيدش الماء، الخضرة غتطلق الماء ديالها.","7. قدم طاجين السمك مباشرة فسيرو ديالو، سخون. رافقه بسلطة خضرا صغيرة بلا نشويات. 💡 نصيحة للسكري: باش تحافظ على مستوى السكر فالدم مزيان، كول الخضرة والسمك هو الأول. الكمية الموصى بها هي 350 غرام (طبسيل واحد) باش تحافظ على الكربوهيدرات فـ 14 غرام ومؤشر السكر منخفض (25)."]'::jsonb, null, ARRAY['tajine hout', 'طاجين حوت']::text[]),
  ('rfissa-legere', 'Rfissa légère (msemen complet)', 'رفيسة خفيفة (مسمن كامل)', 'Light rfissa (whole-wheat msemen)', 'main', ARRAY['ghda', '3cha']::text[], '🍲', '1 assiette (350 g)', 350, 400, 40, 5, 30, 14, 7, 50, 'La rfissa réinventée : msemen en farine complète, beaucoup de lentilles et de fenugrec (helba, ami de la glycémie), peu de matière grasse. Portion contrôlée, riche en fibres.', 'الرفيسة بطريقة جديدة: مسمن بالدقيق الكامل، عدس بزاف والحلبة (صديقة السكر)، وشوية ديال الدهون. كمية مضبوطة وعامرة بالألياف.', '["100 g de farine de blé complet (pour le msemen)","50 g de lentilles vertes sèches","100 g de poulet fermier (blanc ou cuisse sans peau)","1 petite branche de persil frais","1 petite branche de coriandre fraîche","1/2 oignon moyen (environ 50g)","1/2 gousse d''ail","1/4 c. à café de curcuma moulu","1/4 c. à café de gingembre moulu","1/8 c. à café de poivre noir"]'::jsonb, '["100 غرام دقيق القمح الكامل (للمسمن)","50 غرام عدس أخضر ناشف","100 غرام دجاج بلدي (صدر أو فخذ بلا جلد)","عود صغير معدنوس طري","عود صغير قزبر طري","نص بصلة متوسطة (حوالي 50 غرام)","نص فص ثوم","ربع معلقة صغيرة خرقوم بلدي مطحون","ربع معلقة صغيرة سكينجبير مطحون","تمن معلقة صغيرة إبزار"]'::jsonb, '["1. Préparez le msemen complet : Dans un bol, mélangez la farine de blé complet avec une pincée de sel et environ 70 ml d''eau tiède. Pétrissez pendant 5-7 minutes jusqu''à obtenir une pâte souple et non collante. Laissez reposer 15 minutes, couverte, puis formez une petite boule. Étalez-la très finement sur un plan de travail légèrement huilé pour obtenir un carré. Faites cuire sur une poêle antiadhésive chaude (feu moyen) environ 1-2 minutes de chaque côté jusqu''à légère dorure. Réservez et coupez-le en petits morceaux une fois refroidi.","2. Rincez les lentilles vertes à l''eau froide et mettez-les de côté.","3. Dans une marmite ou une cocotte, faites chauffer 1 c. à café d''huile d''olive à feu moyen. Ajoutez le demi-oignon finement haché et la demi-gousse d''ail écrasée. Faites revenir pendant 3-4 minutes jusqu''à ce que l''oignon devienne translucide.","4. Ajoutez le morceau de poulet (100g) coupé en petits dés, le curcuma, le gingembre, le poivre noir et le safran (si utilisé). Faites dorer le poulet de tous les côtés pendant 5 minutes en remuant.","5. Incorporez les lentilles rincées, les graines de fenugrec, le persil et la coriandre hachés finement. Versez 200 ml d''eau chaude. Portez à ébullition, puis réduisez le feu à doux, couvrez et laissez mijoter pendant 25-30 minutes, ou jusqu''à ce que les lentilles soient tendres et le poulet bien cuit. La sauce doit être légèrement épaisse.","6. Goûtez et ajustez l''assaisonnement si nécessaire (une pincée de sel si besoin, mais attention à la teneur en sodium).","7. Pour servir, disposez les morceaux de msemen complet dans une assiette creuse (environ 100g de msemen). Versez généreusement la sauce aux lentilles et au poulet par-dessus (environ 250g de sauce avec lentilles et poulet). Servez immédiatement. 💡 Astuce diabète : Pour une meilleure gestion de la glycémie, commencez par manger les lentilles et le poulet riches en fibres et protéines avant le msemen. La portion totale de 350g est contrôlée pour un apport d''environ 40g de glucides, avec un IG modéré de 50 grâce au msemen complet et aux lentilles."]'::jsonb, '["1. وجد المسمن الكامل: فزلافة، خلط الدقيق الكامل مع شوية ملح وحوالي 70 ملل ماء دافئ. دلك العجينة لمدة 5-7 دقايق حتى تولي رطبة وماتلصقش. خليها ترتاح 15 دقيقة مغطية، من بعد شكل منها كويرة صغيرة. سرحها رقيقة بزاف فوق سطح عمل مدهون بشوية زيت باش تحصل على مربع. طيبها فمقلاة ماتلصقش وسخونة (عافية متوسطة) لمدة دقيقة حتى دقيقتين لكل جهة حتى تولي ذهبية شوية. حطها على جنب وقطعها طريفات صغار ملي تبرد.","2. غسل العدس الأخضر بالماء بارد وحطو على جنب.","3. فكوكوط أو طنجرة، سخن معلقة صغيرة زيت الزيتون على عافية متوسطة. زيد نص بصلة مشلضة رقيقة ونص فص ثوم مدقوق. شحرهم لمدة 3-4 دقايق حتى تولي البصلة شفافة.","4. زيد طريف الدجاج (100 غرام) مقطع مكعبات صغار، الخرقوم، سكينجبير، الإبزار والزعفران (إلى استعملتيه). حمر الدجاج من جميع الجوانب لمدة 5 دقايق وانت كتحرك.","5. ضيف العدس المغسول، حبوب الحلبة، المعدنوس والقزبر مقطعين رقاق. صب 200 ملل ماء سخون. خليها تغلى، من بعد نقص العافية لمهيلة، غطي الطنجرة وخليها طيب لمدة 25-30 دقيقة، أو حتى يطيب العدس والدجاج مزيان. خاص المرقة تكون خاترة شوية.","6. ذوق وقاد الملح إلى خاص (شويه ملح إلى احتاجت، ولكن رد البال لمستوى الصوديوم).","7. للتقديم، حط طريفات المسمن الكامل فطبسيل غارق (حوالي 100 غرام مسمن). صب فوقهم المرقة ديال العدس والدجاج بسخاء (حوالي 250 غرام مرقة مع العدس والدجاج). قدمها سخونة. 💡 نصيحة للسكري: باش تحافظ على مستوى السكر فالدم، بدا تاكل العدس والدجاج اللي غني بالألياف والبروتينات قبل المسمن. الكمية الإجمالية ديال 350 غرام مضبوطة باش تعطي حوالي 40 غرام كربوهيدرات، مع مؤشر سكري متوسط (50) بفضل المسمن الكامل والعدس."]'::jsonb, null, ARRAY['rfissa', 'رفيسة']::text[]),
  ('boulettes-dinde-maticha', 'Boulettes de dinde à la tomate', 'كريات البيبي بالمطيشة', 'Turkey meatballs in tomato', 'main', ARRAY['ghda', '3cha']::text[], '🍅', '1 assiette (300 g)', 300, 290, 12, 7, 30, 14, 3, 25, 'Boulettes de dinde maigre mijotées dans une sauce tomate maison : protéines, lycopène, presque pas de glucides. Un plat familial réconfortant sans faire grimper le sucre.', 'كريات البيبي المزوق مطيبين فصلصة مطيشة ديال الدار: بروتين، ليكوبين، وتقريباً بلا نشويات. ماكلة عائلية مريحة بلا ما تطلع السكر.', '["150 g de viande de dinde hachée maigre","1 petite tomate mûre (environ 80 g)","1/4 d''oignon rouge (environ 20 g)","1 gousse d''ail (environ 3 g)","1/2 bouquet de coriandre fraîche (environ 5 g)","1/2 c. à café de paprika doux","1/4 c. à café de cumin moulu","1 c. à soupe d''huile d''olive extra vierge","50 ml d''eau"]'::jsonb, '["150 غرام من كفتة الديك الرومي الهبرة","1 مطيشة صغيرة طايبة (حوالي 80 غرام)","1/4 بصلة حمراء (حوالي 20 غرام)","1 فص ثوم (حوالي 3 غرام)","1/2 ربطة قزبر طري (حوالي 5 غرام)","1/2 معلقة صغيرة ديال التحميرة الحلوة","1/4 معلقة صغيرة ديال الكامون مطحون","1 معلقة كبيرة ديال زيت الزيتون البكر الممتاز","50 مللتر ديال الماء"]'::jsonb, '["Dans un bol, mélangez la dinde hachée avec la moitié de la coriandre hachée finement, 1/4 c. à café de paprika et 1/8 c. à café de cumin. Salez et poivrez légèrement. Formez environ 8 petites boulettes de taille égale.","Râpez la tomate et hachez finement l''oignon et la gousse d''ail. Réservez.","Dans une petite casserole à fond épais, faites chauffer l''huile d''olive à feu moyen. Ajoutez l''oignon haché et faites-le revenir pendant 3 minutes jusqu''à ce qu''il devienne translucide.","Ajoutez l''ail haché et la tomate râpée. Incorporez le reste du paprika (1/4 c. à café) et du cumin (1/8 c. à café). Laissez mijoter la sauce à feu doux pendant 5 minutes, en remuant de temps en temps, jusqu''à ce qu''elle épaississe légèrement.","Versez les 50 ml d''eau dans la sauce et portez à frémissement. Déposez délicatement les boulettes de dinde dans la sauce. Couvrez la casserole et laissez cuire à feu doux pendant 15 minutes.","Après 15 minutes, vérifiez la cuisson des boulettes (elles doivent être fermes et ne plus être roses à l''intérieur). La sauce doit avoir réduit et enrobé les boulettes. Goûtez et ajustez l''assaisonnement si nécessaire.","Servez immédiatement, parsemé du reste de coriandre fraîche hachée. 💡 Astuce diabète : Pour une portion contrôlée, visez 300g de ce plat. Accompagnez-le d''une grande salade verte sans féculents pour augmenter l''apport en fibres et favoriser une meilleure gestion de la glycémie."]'::jsonb, '["فواحد الزلافة، خلط الكفتة ديال الديك الرومي مع نص القزبر مقطع رقيق، 1/4 معلقة صغيرة ديال التحميرة و 1/8 معلقة صغيرة ديال الكامون. دير شوية الملح و الإبزار. شكل حوالي 8 كويرات صغار قد قد.","حك مطيشة و قطع البصلة و الثومة رقيق بزاف. خليهم على جنب.","فواحد الكاسرونة صغيرة ثقيلة، سخّن زيت الزيتون على نار متوسطة. زيد البصلة مقطعة و خليها تشحر لمدة 3 دقايق حتى تولي شفافة.","زيد الثومة مقطعة و مطيشة محكوكة. خلط معاهم باقي التحميرة (1/4 معلقة صغيرة) و الكامون (1/8 معلقة صغيرة). خلي لاصوص طيب على نار مهيلة لمدة 5 دقايق، و حرك مرة مرة، حتى تعقاد شوية.","خوي 50 مللتر ديال الماء فلاصوص و خليها تبدا تغلي. حط الكويرات ديال الكفتة غير بشوية فلاصوص. غطي الكاسرونة و خليها طيب على نار مهيلة لمدة 15 دقيقة.","من بعد 15 دقيقة، تأكد من طياب الكويرات (خاصهم يكونو قاصحين و مايبقاوش حمرين من الداخل). لاصوص خاصها تكون نقصات و غطات الكويرات. ذوق و قاد المذاق إذا خاص.","قدم الطبق فالحين، رش عليه باقي القزبر طري مقطع. 💡 نصيحة للسكري: باش تكون عندك حصة مضبوطة، كول 300 غرام من هاد الطبق. رافقو بسلاطة خضرا كبيرة بلا نشويات باش تزيد الألياف و تساعد على تحكم أفضل فمستوى السكر فالدم."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4f/Penne_and_turkey_meatballs_-_Jan_2022_-_Sarah_Stierch.jpg/1280px-Penne_and_turkey_meatballs_-_Jan_2022_-_Sarah_Stierch.jpg', ARRAY['kefta dinde tomate', 'كريات بيبي']::text[]),
  ('hommos-sbanekh', 'Pois chiches aux épinards', 'الحمص بالسبانخ', 'Chickpeas with spinach', 'main', ARRAY['ghda', '3cha']::text[], '🥬', '1 assiette (300 g)', 300, 300, 34, 5, 15, 10, 11, 30, 'Pois chiches (IG 30) + épinards riches en fer : un plat végétarien complet, rassasiant et à glycémie plate. Les fibres et les protéines végétales remplacent la viande sans manque.', 'الحمص (مؤشر 30) + السبانخ العامر بالحديد: طبق نباتي كامل، كيشبع والسكر مستقر. الألياف والبروتين النباتي كيعوضو اللحم بلا نقصان.', '["150 g de pois chiches cuits (en conserve, rincés et égouttés)","150 g d''épinards frais (environ 2 tasses tassées)","1 petite tomate (environ 60 g), pelée, épépinée et coupée en petits dés","1/4 d''oignon rouge (environ 20 g), finement haché","1 petite gousse d''ail (environ 3 g), écrasée","1 cuillère à café d''huile d''olive extra vierge","1/2 cuillère à café de cumin moulu","1/4 cuillère à café de paprika doux","Une pincée de sel de mer et de poivre noir fraîchement moulu"]'::jsonb, '["150 غرام حمص طايب (معلب، مغسول ومقطر)","150 غرام سبانخ طرية (تقريبا 2 كيسان مضغوطين)","1 مطيشة صغيرة (تقريبا 60 غرام)، مقشرة، محيد ليها الزريعة ومقطعة مكعبات صغار","1/4 بصلة حمراء صغيرة (تقريبا 20 غرام)، مشلضة رقيقة","1 فص ثوم صغير (تقريبا 3 غرام)، مدقوق","1 ملعقة صغيرة زيت الزيتون البكر الممتاز","1/2 ملعقة صغيرة كمون مطحون","1/4 ملعقة صغيرة تحميرة حلوة","قبيصة ملح بحري وإبزار أسود مطحون طري"]'::jsonb, '["Dans une casserole à fond épais ou une marmite, faites chauffer 1 cuillère à café d''huile d''olive à feu moyen. Ajoutez 1/4 d''oignon rouge finement haché et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide et légèrement doré.","Ajoutez 1 petite gousse d''ail écrasée et faites cuire pendant 1 minute supplémentaire, en remuant constamment pour éviter qu''il ne brûle.","Incorporez 1 petite tomate pelée, épépinée et coupée en petits dés. Laissez mijoter à feu doux pendant 5-7 minutes, en écrasant légèrement la tomate avec le dos d''une cuillère pour former une sauce épaisse et parfumée.","Ajoutez 1/2 cuillère à café de cumin moulu et 1/4 de cuillère à café de paprika doux. Mélangez bien et laissez cuire pendant 1 minute pour libérer les arômes des épices.","Incorporez 150 g de pois chiches cuits, rincés et égouttés. Mélangez délicatement pour bien les enrober de la sauce. Laissez mijoter pendant 2-3 minutes pour que les saveurs se mélangent.","Ajoutez 150 g d''épinards frais. Couvrez la casserole et laissez cuire à feu doux pendant 3-5 minutes, ou jusqu''à ce que les épinards soient flétris et tendres. Remuez une dernière fois. Salez et poivrez selon votre goût.","Servez immédiatement dans une assiette. Ce plat peut être dégusté seul ou accompagné d''une petite portion de pain complet (max 30g).","💡 Astuce diabète : Cette portion de 300g de pois chiches aux épinards est un plat complet et équilibré avec un IG bas (environ 30). Pour une meilleure gestion de la glycémie, mangez les légumes et les pois chiches en premier. Évitez de le servir avec du pain blanc ou des féculents raffinés."]'::jsonb, '["فطنجرة ثقيلة أو كوكوط، سخني 1 ملعقة صغيرة زيت الزيتون على نار متوسطة. ضيفي 1/4 بصلة حمراء مشلضة رقيقة وشحريها لمدة 3-4 دقائق حتى تولي شفافة وذهبية شوية.","ضيفي 1 فص ثوم صغير مدقوق وطيبيه لمدة دقيقة إضافية، مع التحريك المستمر باش ما يتحرقش.","زيدي 1 مطيشة صغيرة مقشرة، محيد ليها الزريعة ومقطعة مكعبات صغار. خليها طيب على نار مهيلة لمدة 5-7 دقائق، مع الضغط الخفيف على مطيشة بظهر الملعقة باش تولي صوص خاتر وبنين.","ضيفي 1/2 ملعقة صغيرة كمون مطحون و 1/4 ملعقة صغيرة تحميرة حلوة. خلطي مزيان وخليه يطيب لمدة دقيقة باش تطلق النكهات ديال العطرية.","زيدي 150 غرام حمص طايب، مغسول ومقطر. خلطي بلطف باش يتغطى مزيان بالصوص. خليه يطيب على نار مهيلة لمدة 2-3 دقائق باش تندمج النكهات.","ضيفي 150 غرام سبانخ طرية. غطي الطنجرة وخليها طيب على نار مهيلة لمدة 3-5 دقائق، أو حتى تذبال السبانخ وتولي رطبة. حركي آخر مرة. زيدي الملح والإبزار حسب الذوق.","قدمي الطبق سخون مباشرة فطبسيل. ممكن يتكال بوحدو أو مع قطعة صغيرة ديال خبز كامل (أقصى حد 30 غرام).","💡 نصيحة للسكري: هاد الحصة ديال 300 غرام حمص بالسبانخ طبق كامل ومتوازن بمؤشر سكري منخفض (حوالي 30). لتحكم أفضل فمستوى السكر، كولي الخضرة والحمص هو الأول. تجنبي تقدميه مع الخبز الأبيض أو النشويات المكررة."]'::jsonb, null, ARRAY['hummus spinach', 'حمص سبانخ']::text[]),
  ('batbout-farci-poulet', 'Batbout complet farci au poulet', 'بطبوط كامل معمر بالدجاج', 'Whole-wheat batbout stuffed with chicken', 'main', ARRAY['ghda', '3cha', 'snack']::text[], '🥙', '1 batbout (180 g)', 180, 320, 34, 4, 24, 9, 5, 55, 'Le "sandwich" marocain sain : batbout à la farine complète, poulet grillé, crudités et un peu de fromage frais. Le fast-food du bled, sans la friture ni le pain blanc.', 'الساندويتش المغربي الصحي: بطبوط بالدقيق الكامل، دجاج مشوي، خضرة وشوية جبن طري. فاست فود ديال البلاد، بلا قلي وبلا خبز أبيض.', '["60 g farine de blé complète T150","30 ml eau tiède","2 g levure boulangère sèche","100 g blanc de poulet grillé, coupé en dés","30 g crudités variées (laitue, tomate, concombre)","15 g fromage frais 0% M.G.","5 g olives noires dénoyautées, hachées","2 ml huile d''olive extra vierge","Sel et poivre noir moulu au goût"]'::jsonb, '["60 غرام دقيق القمح الكامل T150","30 ملل ماء دافئ","2 غرام خميرة الخبز الجافة","100 غرام صدر دجاج مشوي، مقطع مكعبات","30 غرام خضروات مشكلة (خس، طماطم، خيار)","15 غرام جبن طري 0% دسم","5 غرام زيتون أسود بدون عظم، مفروم","2 ملل زيت الزيتون البكر الممتاز","ملح وفلفل أسود مطحون حسب الذوق"]'::jsonb, '["1. Dans un petit bol, mélanger 60 g de farine de blé complète T150 avec 2 g de levure boulangère sèche et une pincée de sel. Ajouter progressivement 30 ml d''eau tiède et pétrir pendant 5 minutes jusqu''à obtenir une pâte souple et non collante. Couvrir et laisser reposer 30 minutes dans un endroit chaud.","2. Pendant ce temps, préparer la garniture : dans un bol, mélanger 100 g de blanc de poulet grillé coupé en dés avec 30 g de crudités variées (laitue ciselée, tomate et concombre coupés en petits dés). Ajouter 5 g d''olives noires hachées, 15 g de fromage frais 0% M.G., 2 ml d''huile d''olive, du sel et du poivre noir moulu au goût. Bien mélanger pour enrober tous les ingrédients.","3. Après le repos, dégazer la pâte et la diviser en une boule unique. Sur un plan de travail légèrement fariné, étaler la pâte à l''aide d''un rouleau à pâtisserie pour obtenir un cercle d''environ 15 cm de diamètre et 0,5 cm d''épaisseur.","4. Faire chauffer une poêle antiadhésive à feu moyen-vif. Déposer délicatement le cercle de pâte dans la poêle chaude. Laisser cuire environ 2-3 minutes de chaque côté, jusqu''à ce que le batbout gonfle et prenne une belle couleur dorée. Le retourner une fois que des bulles apparaissent à la surface.","5. Retirer le batbout de la poêle et le laisser refroidir légèrement sur une grille. Une fois tiède, le couper en deux à l''aide d''un couteau, comme un pain pita, pour créer une poche.","6. Farcir généreusement la poche du batbout avec la préparation au poulet et aux crudités. S''assurer que la garniture est bien répartie à l''intérieur.","7. Servir immédiatement. Ce batbout complet farci est un repas équilibré et satisfaisant. 💡 Astuce diabète : Pour un meilleur contrôle de la glycémie, mangez d''abord les crudités et le poulet, puis le pain. La portion de 180 g est adaptée, mais accompagnez-la d''une grande salade verte sans féculents pour augmenter la satiété sans impacter le GI."]'::jsonb, '["1. فزلافة صغيرة، نخلطو 60 غرام ديال دقيق القمح الكامل T150 مع 2 غرام ديال خميرة الخبز الجافة وشوية ديال الملح. نزيدو بشوية بشوية 30 ملل ديال الماء دافئ وندلكو لمدة 5 دقائق حتى نحصلو على عجينة رطبة وما كتلصقش. نغطيوها ونخليوها ترتاح 30 دقيقة فمكان دافئ.","2. فهاذ الوقت، نوجدو الحشوة: فزلافة، نخلطو 100 غرام ديال صدر الدجاج المشوي مقطع مكعبات مع 30 غرام ديال الخضروات المشكلة (الخس مقطع رقيق، مطيشة والخيار مقطعين مكعبات صغار). نزيدو 5 غرام ديال الزيتون الأسود مفروم، 15 غرام ديال الجبن الطري 0% دسم، 2 ملل ديال زيت الزيتون، الملح والفلفل الأسود مطحون حسب الذوق. نخلطو مزيان باش يتجانسو المكونات.","3. من بعد ما ترتاح العجينة، نفرغو منها الهواء ونقسموها لكورة وحدة. فوق سطح عمل مرشوش بشوية ديال الدقيق، نسرحو العجينة بالمدلك باش نحصلو على دائرة بقطر حوالي 15 سم وسمك 0.5 سم.","4. نسخنو مقلاة غير لاصقة على نار متوسطة-مجهدة. نحطو دائرة العجينة بلطف فالمقلاة السخونة. نخليوها طيب حوالي 2-3 دقائق من كل جهة، حتى يتنفخ البطبوط وياخد لون ذهبي زوين. نقلبوه مرة وحدة ملي يبانو فقاعات على السطح.","5. نحيدو البطبوط من المقلاة ونخليوه يبرد شوية فوق شبكة. ملي يدفى، نقطعوه على جوج بالموس، بحال خبز البيتا، باش نصايبو جيب.","6. نعمرو الجيب ديال البطبوط مزيان بالحشوة ديال الدجاج والخضروات. نتأكدو أن الحشوة موزعة مزيان فالداخل.","7. نقدموه فالحين. هاد البطبوط الكامل المعمر وجبة متوازنة ومشبعة. 💡 نصيحة للسكري: باش تحكمو فمستوى السكر فالدم بشكل أفضل، كولو الخضروات والدجاج الأول عاد الخبز. الكمية ديال 180 غرام مناسبة، ولكن رافقوها بسلطة خضراء كبيرة بلا نشويات باش تزيدو من الشبع بلا ما تأثرو على المؤشر الجلايسيمي."]'::jsonb, null, ARRAY['sandwich batbout', 'بطبوط دجاج']::text[]),
  ('sardines-grillees', 'Sardines grillées', 'سردين مشوي', 'Grilled sardines', 'seafood', ARRAY['ghda', '3cha']::text[], '🐟', '4 sardines (200 g)', 200, 320, 2, 0, 38, 18, 0, 5, 'Le trésor marocain : oméga-3 au plus haut niveau, prix mini. Protège le cœur et les vaisseaux — exactement ce que le diabète attaque. 2×/semaine, grillées pas frites.', 'الكنز المغربي: أوميغا 3 فأعلى مستوى وبثمن رخيص. كيحمي القلب والشرايين — بالضبط اللي كيهاجم السكري. جوج مرات فالسيمانة، مشوي ماشي مقلي.', '["200 g de sardines fraîches (environ 4 pièces)","1 c. à soupe de persil frais haché","1 c. à soupe de coriandre fraîche hachée","1 gousse d''ail écrasée","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","1 pincée de piment fort (facultatif)","1 c. à soupe de jus de citron frais","1 c. à café d''huile d''olive extra vierge"]'::jsonb, '["200 غرام ديال السردين طري (تقريبا 4 حبات)","1 معلقة كبيرة ديال المعدنوس مقطع رقيق","1 معلقة كبيرة ديال القزبور مقطع رقيق","1 فص ديال الثومة محكوك","نص معلقة صغيرة ديال الكامون مطحون","ربع معلقة صغيرة ديال التحميرة الحلوة","رشة ديال الهريسة (اختياري)","1 معلقة كبيرة ديال عصير الحامض طري","1 معلقة صغيرة ديال زيت الزيتون بكر ممتاز"]'::jsonb, '["1. Nettoyer les sardines : Vider délicatement 200 g de sardines fraîches (environ 4 pièces) et les rincer sous l''eau froide. Ne pas enlever les écailles. Les égoutter et les sécher soigneusement avec du papier absorbant.","2. Préparer la chermoula : Dans un petit bol, mélanger 1 c. à soupe de persil haché, 1 c. à soupe de coriandre hachée, 1 gousse d''ail écrasée, 1/2 c. à café de cumin, 1/4 c. à café de paprika, et une pincée de piment fort (si désiré).","3. Ajouter le liquide à la chermoula : Incorporer 1 c. à soupe de jus de citron frais et 1 c. à café d''huile d''olive extra vierge à la chermoula. Bien mélanger pour obtenir une pâte homogène.","4. Farcir les sardines : Ouvrir chaque sardine en portefeuille (sans la séparer complètement) et étaler environ 1/2 c. à café de chermoula à l''intérieur. Refermer délicatement la sardine.","5. Préchauffer le grill : Faire chauffer un grill (barbecue ou grill électrique) à feu moyen-vif. S''assurer qu''il est bien chaud pour éviter que les sardines ne collent.","6. Griller les sardines : Déposer les sardines farcies sur le grill chaud. Faire griller 3 à 4 minutes de chaque côté, jusqu''à ce qu''elles soient bien dorées et que la chair se détache facilement de l''arête. Ne pas trop les manipuler pour qu''elles ne se cassent pas.","7. Servir : Servir les sardines grillées immédiatement, accompagnées d''une salade marocaine fraîche (tomate, concombre, oignon) sans ajout de sucre. Un filet de jus de citron frais peut être ajouté avant de servir.","💡 Astuce diabète : Le trésor marocain : oméga-3 au plus haut niveau, prix mini. Protège le cœur et les vaisseaux — exactement ce que le diabète attaque. 2×/semaine, grillées pas frites. Respectez la portion de 200 g de sardines par repas. Mangez-les avec une grande portion de légumes verts pour ralentir l''absorption des glucides."]'::jsonb, '["1. نقي السردين: حيد المصارن ديال 200 غرام ديال السردين طري (تقريبا 4 حبات) وغسلو مزيان بالماء بارد. ما تحيدش القشور. خليه يقطر ونشفو مزيان بورق المطبخ.","2. وجد الشرمولة: فزلافة صغيرة، خلط 1 معلقة كبيرة ديال المعدنوس مقطع، 1 معلقة كبيرة ديال القزبور مقطع، 1 فص ديال الثومة محكوك، نص معلقة صغيرة ديال الكامون، ربع معلقة صغيرة ديال التحميرة، ورشة ديال الهريسة (إلى بغيتي).","3. زيد السوائل للشرمولة: ضيف 1 معلقة كبيرة ديال عصير الحامض طري و 1 معلقة صغيرة ديال زيت الزيتون بكر ممتاز للشرمولة. خلط كلشي مزيان حتى تولي عندك عجينة متجانسة.","4. عمر السردين: حل كل سردينة بحال الكتاب (بلا ما تفصلها كاملة) ودير تقريبا نص معلقة صغيرة ديال الشرمولة لداخل. سد السردينة غير بشوية.","5. سخن الشواية: سخن الشواية (فحم أو كهربائية) على نار متوسطة-مجهدة. تأكد أنها سخونة مزيان باش السردين ما يلصقش.","6. شوي السردين: حط السردين المعمر فوق الشواية السخونة. خليه يتشوى 3 حتى لـ 4 دقايق من كل جهة، حتى يتحمر مزيان واللحم ديالو يتفصل بسهولة على الشوكة. ما تقلبوش بزاف باش ما يتهرسش.","7. قدم الطبق: قدم السردين المشوي مباشرة، معاه شلاضة مغربية طرية (مطيشة، خيار، بصلة) بلا سكر. ممكن تزيد شوية ديال عصير الحامض قبل التقديم.","💡 نصيحة للسكري: الكنز المغربي: أوميغا-3 بأعلى مستوى، وثمن رخيص. كيحمي القلب والشرايين — بالضبط داكشي لي كيهاجمو السكري. 2 مرات فالأسبوع، مشوي ماشي مقلي. احترم حصة 200 غرام ديال السردين فالوجبة. كولوه مع كمية كبيرة ديال الخضرة الخضراء باش تبطأ امتصاص الكربوهيدرات."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/c/c2/Grilled_Sardines_5.50%E2%82%AC_Marisqueira_O_Varino_Nazar%C3%A9_%283785526688%29.jpg', ARRAY['sardine', 'سردين']::text[]),
  ('sardines-chermoula-four', 'Sardines chermoula au four', 'سردين بالشرمولة فالفرن', 'Oven chermoula sardines', 'seafood', ARRAY['ghda', '3cha']::text[], '🔥', '1 portion (220 g)', 220, 300, 4, 1, 36, 16, 1, 10, 'La version "sans odeur de friture" : même oméga-3, moins de gras ajouté. En papillote, le poisson reste moelleux sans une goutte d’huile de friture.', 'النسخة بلا ريحة القلي: نفس الأوميغا 3 بدهون أقل. فالبابيوط، الحوت كيبقى رطب بلا قطرة زيت قلي.', '["220 g de sardines fraîches écaillées et vidées","1/2 botte de coriandre fraîche (environ 15 g)","1/2 botte de persil frais (environ 15 g)","2 gousses d''ail (environ 6 g)","1/2 c. à café de cumin moulu (environ 1 g)","1/4 c. à café de paprika doux (environ 0.5 g)","1 pincée de piment doux (facultatif, environ 0.2 g)","1 c. à soupe de jus de citron frais (environ 15 ml)","1 c. à café d''huile d''olive extra vierge (environ 5 ml)"]'::jsonb, '["220 غرام ديال السردين طري منقي ومحيد ليه المصارن","نص ربطة ديال القزبر طري (حوالي 15 غرام)","نص ربطة ديال المعدنوس طري (حوالي 15 غرام)","2 فصوص ديال الثومة (حوالي 6 غرام)","نص معلقة صغيرة ديال الكامون مطحون (حوالي 1 غرام)","ربع معلقة صغيرة ديال التحميرة الحلوة (حوالي 0.5 غرام)","رشيشة ديال السودانية الحلوة (اختياري، حوالي 0.2 غرام)","معلقة كبيرة ديال عصير الحامض طري (حوالي 15 مل)","معلقة صغيرة ديال زيت الزيتون البكر الممتاز (حوالي 5 مل)"]'::jsonb, '["Préchauffez votre four à 180°C (Thermostat 6). Préparez une plaque de cuisson recouverte de papier sulfurisé.","Rincez soigneusement les sardines nettoyées sous l''eau froide et égouttez-les bien. Séchez-les délicatement avec du papier absorbant pour enlever l''excès d''eau.","Dans un petit robot mixeur ou un mortier, hachez finement la coriandre et le persil. Ajoutez les gousses d''ail pelées et hachez-les également jusqu''à obtenir une pâte grossière.","Transférez le mélange d''herbes et d''ail dans un bol. Ajoutez le cumin moulu, le paprika doux, le piment doux (si utilisé), le jus de citron frais et l''huile d''olive extra vierge. Mélangez bien pour obtenir la chermoula.","Farcissez chaque sardine avec une petite quantité de chermoula (environ 1/2 c. à café par sardine), en la répartissant uniformément à l''intérieur. Vous pouvez aussi enduire légèrement l''extérieur des sardines avec le reste de la chermoula.","Disposez les sardines farcies sur la plaque de cuisson préparée, en veillant à ne pas les superposer. Enfournez pour 15 à 20 minutes, ou jusqu''à ce que les sardines soient bien dorées et cuites à cœur. Le temps de cuisson peut varier selon la taille des sardines et votre four. Elles doivent être tendres et se détacher facilement à la fourchette.","Servez immédiatement. Accompagnez d''une salade verte fraîche sans féculents pour un repas équilibré. 💡 Astuce diabète : Cette portion de 220 g de sardines au four est idéale. Pour maintenir une glycémie stable, consommez d''abord les protéines et les fibres (sardines et légumes) avant d''éventuels glucides complexes (si vous en ajoutez, choisissez des légumes secs ou du pain complet en très petite quantité)."]'::jsonb, '["سخن الفران ديالك على درجة حرارة 180°C (الدرجة 6). وجد لاطة ديال الفران مفرشة بورق الطبخ.","غسل السردين المنقي مزيان تحت الماء بارد وقطروه مزيان. نشفوه غير بشوية بورق النشاف باش تحيدو الماء الزائد.","فالهاشوار صغيرة ولا المهراز، قطعو القزبر والمعدنوس رقاق. زيدو عليهم الثومة مقشرة وقطعوها حتى هي حتى تولي بحال العجينة حرشة.","حطو خليط الربيع والثومة فزلافة. زيدو الكامون مطحون، التحميرة الحلوة، السودانية الحلوة (إلى استعملتوها)، عصير الحامض طري وزيت الزيتون البكر الممتاز. خلطو مزيان باش تحصلو على الشرمولة.","عمرو كل سردينة بكمية صغيرة ديال الشرمولة (حوالي نص معلقة صغيرة لكل سردينة)، وزعوها بالتساوي فالداخل. تقدرو دهنو حتى برا ديال السردين بالشرمولة اللي بقات.","ستفو السردين المعمر فاللاطة اللي وجدتوها، ردو البال ما تحطوش وحدة فوق وحدة. دخلوه للفران لمدة 15 حتى 20 دقيقة، ولا حتى يولي السردين مذهب ومطيب مزيان من الداخل. وقت الطياب يقدر يختلف على حسب حجم السردين والفران ديالك. خاصو يكون رطب ويتحل بسهولة بالفرشيطة.","قدموه مباشرة. رافقوه بشلاضة خضرا طرية بلا نشويات لوجبة متوازنة. 💡 نصيحة للسكري: هاد الحصة ديال 220 غرام ديال السردين فالفران مثالية. باش تحافظ على سكر الدم مستقر، كول البروتينات والألياف (السردين والخضراوات) هي الأولى قبل أي كربوهيدرات معقدة (إلى زدتو شي حاجة، اختارو القطاني أو الخبز الكامل بكمية قليلة جداً)."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/93/2006_sardines_plate_flash.jpg/1280px-2006_sardines_plate_flash.jpg', ARRAY['sardine four']::text[]),
  ('maquereau-grille', 'Maquereau grillé', 'الكابايلا المشوية', 'Grilled mackerel', 'seafood', ARRAY['ghda', '3cha']::text[], '🎣', '1 poisson (250 g)', 250, 340, 1, 0, 40, 20, 0, 5, 'Encore plus riche en oméga-3 que la sardine. Zéro glucide : la glycémie ne bouge pas. Vitamine D en bonus, souvent basse chez les diabétiques.', 'فيه أوميغا 3 أكثر من السردين. بلا نشويات: السكر ما كيتحركش. وفيتامين D زيادة، اللي غالباً ناقص عند السكري.', '["1 maquereau frais (environ 250 g), vidé et écaillé","1 c. à soupe de persil frais haché","1 c. à soupe de coriandre fraîche hachée","1 gousse d''ail, écrasée","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","1 pincée de piment fort (facultatif)","1 c. à soupe de jus de citron frais","1 c. à café d''huile d''olive extra vierge","Sel et poivre noir fraîchement moulu, au goût"]'::jsonb, '["1 كابايلا طرية (حوالي 250 غرام)، منقية ومحيدة المصارن","1 ملعقة كبيرة قزبر طري مفروم","1 ملعقة كبيرة معدنوس طري مفروم","1 فص ثوم، مدقوق","1/2 ملعقة صغيرة كامون مطحون","1/4 ملعقة صغيرة تحميرة حلوة","1 قريصة هريسة (اختياري)","1 ملعقة كبيرة عصير حامض طري","1 ملعقة صغيرة زيت الزيتون البكر الممتاز","ملح وإبزار مطحون طري، حسب الذوق"]'::jsonb, '["1. Préparez le maquereau : Rincez le poisson sous l''eau froide et séchez-le soigneusement avec du papier absorbant. Faites 2 à 3 incisions peu profondes sur chaque côté du poisson pour que la marinade pénètre bien.","2. Préparez la chermoula (marinade) : Dans un petit bol, mélangez le persil haché, la coriandre hachée, l''ail écrasé, le cumin, le paprika, le piment fort (si utilisé), le jus de citron, l''huile d''olive, le sel et le poivre. Mélangez bien pour obtenir une pâte homogène.","3. Marinez le poisson : Frottez généreusement la chermoula sur et dans le maquereau, en veillant à bien faire pénétrer la marinade dans les incisions. Laissez mariner au réfrigérateur pendant au moins 30 minutes, idéalement 1 heure pour plus de saveur.","4. Préchauffez le grill : Chauffez un grill (barbecue ou grill électrique) à feu moyen-vif. Si vous utilisez un barbecue, assurez-vous que les braises sont bien chaudes et recouvertes d''une fine couche de cendre.","5. Grillez le maquereau : Huilez légèrement la grille pour éviter que le poisson ne colle. Déposez le maquereau mariné sur la grille chaude. Laissez cuire pendant 5 à 7 minutes de chaque côté, ou jusqu''à ce que la chair soit opaque et se détache facilement à la fourchette.","6. Vérifiez la cuisson : Le poisson est cuit lorsque la peau est croustillante et légèrement carbonisée par endroits, et que la chair est blanche et feuilletée à l''intérieur. Évitez de trop le cuire pour qu''il reste juteux.","7. Servez immédiatement : Transférez le maquereau grillé sur une assiette. Vous pouvez le garnir d''une tranche de citron frais. Servez-le chaud, accompagné d''une salade marocaine de tomates et concombres sans pain. 💡 Astuce diabète : Ce maquereau grillé est un excellent choix avec zéro glucide. Pour un contrôle optimal de la glycémie, consommez d''abord la salade de légumes verts riches en fibres avant de déguster le poisson. La portion de 250g de poisson est idéale et ne nécessite pas de glucides ajoutés."]'::jsonb, '["1. وجدوا الكابايلا: شلوا الحوت تحت الماء بارد ومسحوه مزيان بورق المطبخ. ديروا 2 حتى 3 فليحات خفاف في كل جهة من الحوت باش تدخل فيه الشرمولة مزيان.","2. وجدوا الشرمولة: فزلافة صغيرة، خلطوا القزبر والمعدنوس مقطعين، الثومة مدقوقة، الكامون، التحميرة، الهريسة (إلى استعملتوها)، عصير الحامض، زيت الزيتون، الملحة والإبزار. خلطوا كلشي مزيان حتى تولي عندكم خلطة متجانسة.","3. شرملوا الحوت: دهنوا الكابايلا مزيان بالشرمولة من برا ومن الداخل، وتأكدوا أنها دخلات في الفليحات. خليوه يترقد فالثلاجة على الأقل 30 دقيقة، ومن الأحسن ساعة باش يجي بنين أكثر.","4. سخنوا الشواية: سخنوا الشواية (شواية الفاخر أو الشواية الكهربائية) على نار متوسطة مجهدة. إلى استعملتوا شواية الفاخر، تأكدوا أن الفاخر سخون مزيان ومغطى بطبقة رقيقة من الرماد.","5. شويوا الكابايلا: دهنوا الشواية بشوية الزيت باش ما يلصقش الحوت. حطوا الكابايلا مشرملة فوق الشواية السخونة. خليوها طيب 5 حتى 7 دقائق من كل جهة، أو حتى تولي اللحم بيضة وتتفتت بسهولة بالفرشيطة.","6. تأكدوا من الطياب: الحوت كيكون طايب ملي كيكون الجلده مقرمشة ومحمرة شوية فبعض البلايص، واللحم بيضة ومورقة من الداخل. تجنبوا طيبوه بزاف باش يبقى رطب.","7. قدموه فالحين: حطوا الكابايلا مشوية فطبسيل. ممكن تزينوه بشريحة حامض طري. قدموه سخون، مع سلطة مغربية ديال مطيشة والخيار بلا خبز. 💡 نصيحة للسكري: هاد الكابايلا المشوية اختيار ممتاز بدون كربوهيدرات. باش تتحكموا فمستوى السكر فالدم بشكل أفضل، كولوا سلطة الخضراوات الغنية بالألياف هي الأولى قبل ما تستمتعوا بالحوت. حصة 250 غرام من الحوت مثالية وما كتحتاجش كربوهيدرات إضافية."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/d/df/Grilled_horse-mackerel_%285171123164%29.jpg', ARRAY['maquereau', 'كابايلا']::text[]),
  ('crevettes-ail', 'Crevettes sautées à l''ail', 'القمرون المقلي بالثوم', 'Garlic sautéed shrimp', 'seafood', ARRAY['ghda', '3cha']::text[], '🦐', '1 portion (200 g)', 200, 200, 3, 0, 32, 7, 0, 5, 'Ultra-protéinées, ultra-légères : 200 kcal le plat. Prêtes en 5 minutes, elles dépannent les soirs pressés sans toucher à la glycémie.', 'بروتين عالي وخفاف بزاف: 200 كالوري فالطبق. واجدين ف5 دقايق، كيسدو الحاجة فليالي الزربة بلا ما يهزو السكر.', '["200 g de crevettes roses décortiquées (fraîches ou surgelées, décongelées)","2 gousses d''ail (environ 10 g)","1 cuillère à soupe d''huile d''olive extra vierge (15 ml)","1/4 cuillère à café de paprika doux (1 g)","1/4 cuillère à café de cumin moulu (1 g)","Une pincée de piment fort (facultatif, 0.5 g)","Jus d''un quart de citron (environ 10 ml)","Quelques brins de coriandre fraîche (5 g)","Sel et poivre noir fraîchement moulu (au goût)"]'::jsonb, '["200 غرام من القمرون الوردي مقشر (طري أو مجمد ومذوب)","2 فصوص ثوم (حوالي 10 غرام)","1 ملعقة كبيرة زيت الزيتون البكر الممتاز (15 مل)","1/4 ملعقة صغيرة تحميرة حلوة (بابريكا) (1 غرام)","1/4 ملعقة صغيرة كمون مطحون (1 غرام)","رشة فلفل حار (اختياري، 0.5 غرام)","عصير ربع حامضة (حوالي 10 مل)","بعض أغصان القزبور الطري (5 غرام)","ملح وفلفل أسود مطحون طازج (حسب الذوق)"]'::jsonb, '["Préparez les crevettes : Si elles sont surgelées, décongelez-les complètement et égouttez-les bien. Rincez-les rapidement à l''eau froide et séchez-les avec du papier absorbant. C''est crucial pour une bonne cuisson.","Préparez l''ail et les herbes : Pelez les 2 gousses d''ail et hachez-les très finement. Lavez les brins de coriandre fraîche, séchez-les et ciselez-les.","Assaisonnez les crevettes : Dans un bol, mélangez les 200 g de crevettes avec le paprika doux (1/4 c. à café), le cumin moulu (1/4 c. à café), la pincée de piment fort (si utilisé), le sel et le poivre noir fraîchement moulu. Mélangez bien pour que les épices enrobent chaque crevette.","Faites chauffer la poêle : Placez une poêle antiadhésive sur feu moyen-vif. Quand elle est bien chaude (une goutte d''eau s''évapore instantanément), ajoutez la cuillère à soupe d''huile d''olive extra vierge (15 ml).","Faites revenir l''ail : Dès que l''huile est chaude, ajoutez l''ail haché. Faites-le revenir pendant environ 30 secondes, juste assez pour qu''il libère son parfum sans brûler. L''ail brûlé devient amer.","Cuisson des crevettes : Ajoutez les crevettes assaisonnées dans la poêle. Faites-les sauter sur feu vif pendant 2 à 3 minutes maximum, en remuant constamment. Les crevettes sont cuites dès qu''elles deviennent roses et opaques. Ne les sur-cuisez pas, elles deviendraient caoutchouteuses.","Finitions et service : Retirez la poêle du feu. Arrosez les crevettes avec le jus d''un quart de citron (environ 10 ml) et parsemez-les de coriandre fraîche ciselée (5 g). Mélangez délicatement et servez immédiatement. Ce plat est excellent seul ou accompagné d''une grande salade verte. 💡 Astuce diabète : Cette portion de 200 g de crevettes est idéale pour un repas léger. Pour maintenir une glycémie stable, consommez-la en entrée ou comme plat principal avec une grande portion de légumes verts non-féculents (brocoli, épinards, haricots verts) qui ont un indice glycémique très bas et sont riches en fibres."]'::jsonb, '["وجد القمرون: إذا كان مجمد، ذوبو مزيان وصفيوه من الماء. شللوه دغيا بالماء بارد ونشفوه بورق المطبخ. هاد الخطوة مهمة باش يطيب مزيان.","وجد الثوم والقزبور: قشرو 2 فصوص ثوم وقطعوهم رقاق بزاف. غسلو القزبور طري، نشفوه وقطعوه رقيق.","تبل القمرون: فزلافة، خلطو 200 غرام ديال القمرون مع التحميرة الحلوة (1/4 م.ص)، الكمون مطحون (1/4 م.ص)، رشة الفلفل الحار (إذا استعملتوه)، الملح والفلفل الأسود مطحون طازج. خلطو مزيان باش يتلبس القمرون بالعطرية كلها.","سخن المقلاة: حطو مقلاة ماكتلصقش فوق نار متوسطة إلى مجهدة. ملي تسخن مزيان (قطرة ماء كتبخر دغيا)، زيدو ملعقة كبيرة زيت الزيتون البكر الممتاز (15 مل).","شحر الثوم: غير يسخن الزيت، زيدو الثوم مقطع. شحروه لمدة 30 ثانية تقريبا، غير يطلق الريحة ديالو بلا ما يتحرق. الثوم المحروق كيولي مر.","طيب القمرون: زيدو القمرون المتبل في المقلاة. شحروه فوق نار مجهدة لمدة 2 حتى 3 دقائق كحد أقصى، مع التحريك المستمر. القمرون كيطيب غير كيولي وردي وما بقاش شفاف. ماتطيبوهش بزاف باش مايجيش قاصح بحال الكاواتشو.","اللمسات الأخيرة والتقديم: حيدو المقلاة من فوق النار. رشو القمرون بعصير ربع حامضة (حوالي 10 مل) وزيدو عليه القزبور طري مقطع (5 غرام). خلطو بلطف وقدموه مباشرة. هاد الطبق كيجي رائع بوحدو أو مع سلطة خضراء كبيرة. 💡 نصيحة للسكري: هاد الكمية ديال 200 غرام من القمرون مثالية لوجبة خفيفة. باش تحافظو على مستوى السكر في الدم مستقر، كلوه كمقبلات أو طبق رئيسي مع كمية كبيرة من الخضروات الخضراء غير النشوية (بروكولي، سبانخ، لوبيا خضراء) اللي عندها مؤشر سكري منخفض جدا وغنية بالألياف."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/96/Crevettes_saut%C3%A9es_%C3%A0_l%27ail_et_frites.JPG/1280px-Crevettes_saut%C3%A9es_%C3%A0_l%27ail_et_frites.JPG', ARRAY['crevettes', 'قمرون']::text[]),
  ('thon-salade-complete', 'Assiette complète au thon', 'طبق كامل بالطون', 'Complete tuna plate', 'seafood', ARRAY['ghda', '3cha']::text[], '🥫', '1 assiette (300 g)', 300, 290, 12, 4, 34, 12, 5, 20, 'Le déjeuner de secours : une boîte de thon AU NATUREL, des légumes, un œuf dur. Zéro cuisine, zéro pic de glycémie au travail.', 'غدا الإنقاذ: علبة طون فالماء، خضرة، وبيضة مسلوقة. بلا طياب وبلا طلعة سكر فالخدمة.', '["100 g de thon au naturel, égoutté","1 œuf dur (environ 50 g)","50 g de laitue romaine, coupée","50 g de tomate, coupée en dés","50 g de concombre, coupé en dés","1 c. à soupe d''huile d''olive extra vierge (15 ml)","1 c. à café de vinaigre de cidre (5 ml)","Une pincée de sel de mer","Une pincée de poivre noir moulu"]'::jsonb, '["100 غرام طون طبيعي، مصفى","1 بيضة مسلوقة (حوالي 50 غرام)","50 غرام خس روماني، مقطع","50 غرام مطيشة، مقطعة مكعبات صغيرة","50 غرام خيار، مقطع مكعبات صغيرة","1 ملعقة كبيرة زيت الزيتون البكر الممتاز (15 مل)","1 ملعقة صغيرة خل التفاح (5 مل)","رشة ملح بحري","رشة إبزار أسود مطحون"]'::jsonb, '["1. Commencez par préparer les légumes frais. Lavez soigneusement 50 g de laitue romaine, 50 g de tomate et 50 g de concombre. Coupez la laitue en fines lanières, la tomate et le concombre en petits dés d''environ 1 cm.","2. Égouttez soigneusement 100 g de thon au naturel de son eau ou de son huile. Émiettez-le légèrement à l''aide d''une fourchette.","3. Préparez l''œuf dur. Si ce n''est pas déjà fait, faites bouillir un œuf dans de l''eau pendant environ 8-10 minutes pour obtenir un œuf dur. Laissez-le refroidir, écalez-le et coupez-le en quartiers ou en rondelles.","4. Dans un grand bol, mélangez délicatement la laitue coupée, les dés de tomate et les dés de concombre.","5. Ajoutez le thon émietté sur les légumes dans le bol.","6. Préparez la vinaigrette : Dans un petit récipient, mélangez 1 c. à soupe (15 ml) d''huile d''olive extra vierge, 1 c. à café (5 ml) de vinaigre de cidre, une pincée de sel de mer et une pincée de poivre noir moulu. Fouettez bien pour émulsionner.","7. Versez la vinaigrette sur la salade et mélangez délicatement pour bien enrober tous les ingrédients. Disposez l''œuf dur coupé sur le dessus de l''assiette avant de servir. Servez immédiatement.","💡 Astuce diabète : Cette assiette complète est idéale pour un déjeuner rapide. Pour maintenir une glycémie stable, consommez d''abord les légumes et le thon, riches en fibres et protéines, avant l''œuf. La portion de 300 g est contrôlée pour un apport calorique d''environ 290 kcal et un indice glycémique très bas de 20. Évitez d''ajouter du pain blanc ou des féculents raffinés."]'::jsonb, '["1. ابدأ بتحضير الخضروات الطازجة. اغسل بعناية 50 غرام من الخس الروماني، 50 غرام من الطماطم و 50 غرام من الخيار. قطع الخس شرائح رقيقة، والطماطم والخيار مكعبات صغيرة حوالي 1 سم.","2. صفي بعناية 100 غرام من الطون الطبيعي من الماء أو الزيت. فتته قليلاً باستخدام شوكة.","3. حضر البيضة المسلوقة. إذا لم تكن جاهزة، اسلق بيضة في الماء لمدة 8-10 دقائق للحصول على بيضة مسلوقة جيداً. اتركها تبرد، قشرها وقطعها إلى أرباع أو دوائر.","4. في وعاء كبير، اخلط بلطف الخس المقطع، مكعبات الطماطم ومكعبات الخيار.","5. أضف الطون المفتت فوق الخضروات في الوعاء.","6. حضر الصلصة: في وعاء صغير، اخلط 1 ملعقة كبيرة (15 مل) من زيت الزيتون البكر الممتاز، 1 ملعقة صغيرة (5 مل) من خل التفاح، رشة ملح بحري ورشة إبزار أسود مطحون. اخفق جيداً حتى تتجانس المكونات.","7. اسكب الصلصة فوق السلطة واخلط بلطف لتغطية جميع المكونات جيداً. رتب البيضة المسلوقة المقطعة فوق الطبق قبل التقديم. قدمها فوراً.","💡 نصيحة للسكري: هاد الطبق الكامل مثالي لوجبة غداء سريعة. باش تحافظ على مستوى سكر الدم مستقر، كل الخضروات والطون الأول، حيت غنيين بالألياف والبروتينات، عاد البيض. الكمية ديال 300 غرام محسوبة باش تعطي حوالي 290 سعرة حرارية ومؤشر سكري منخفض جداً (20). تجنب إضافة الخبز الأبيض أو النشويات المكررة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/2/27/Ensalada_en_M%C3%A1laga.jpg', ARRAY['thon']::text[]),
  ('tajine-kwar-sardine', 'Tajine de boulettes de sardines', 'طاجين كوار السردين', 'Sardine ball tagine', 'seafood', ARRAY['ghda', '3cha']::text[], '🍲', '1 assiette (300 g)', 300, 310, 12, 6, 30, 16, 3, 25, 'Le plat doukkali par excellence : les oméga-3 de la sardine dans une sauce tomate épicée, presque sans glucides. Un des meilleurs tajines possibles pour un diabétique.', 'الطبق الدكالي بامتياز: أوميغا 3 ديال السردين فصلصة طماطم حارة، تقريباً بلا نشويات. من أحسن الطواجن الممكنة للسكري.', '["150 g de sardines fraîches (nettoyées, sans arêtes ni peau)","100 g de tomates mûres (pelées, épépinées et concassées)","10 ml d''huile d''olive extra vierge","1/2 oignon rouge (petit, finement haché)","1 gousse d''ail (écrasée)","1/2 bouquet de coriandre fraîche (hachée)","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","Une pincée de piment fort (facultatif)"]'::jsonb, '["150 غرام سردين طازج (منقي، محيد الشوك والجلد)","100 غرام مطيشة طايبة (منقية، محيد الزريعة ومقطعة رقيقة)","10 مل زيت الزيتون البكر الممتاز","نص بصلة حمراء (صغيرة، مشلظة رقيقة)","ضرس ثومة (مدقوق)","نص ربطة قزبور طري (مقطع رقيق)","نص معلقة صغيرة كامون مطحون","ربع معلقة صغيرة تحميرة حلوة","قبيصة هريسة (اختياري)"]'::jsonb, '["1. Préparez les boulettes de sardines : Dans un bol, mélangez les sardines nettoyées et hachées finement avec la moitié de la coriandre hachée, la moitié de l''ail écrasé, la moitié du cumin et une pincée de sel et de poivre. Façonnez de petites boulettes d''environ 15 g chacune.","2. Préparez la sauce tomate : Dans un tajine ou une cocotte à fond épais, faites chauffer l''huile d''olive à feu moyen. Ajoutez l''oignon haché et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide.","3. Incorporez l''ail restant et le reste des épices (cumin, paprika, piment fort si utilisé). Remuez pendant 1 minute jusqu''à ce que les arômes se dégagent.","4. Ajoutez les tomates concassées et le reste de la coriandre hachée. Salez et poivrez légèrement. Laissez mijoter à feu doux pendant 10-12 minutes, en remuant de temps en temps, jusqu''à ce que la sauce épaississe légèrement.","5. Disposez délicatement les boulettes de sardines sur la sauce tomate. Couvrez le tajine et laissez cuire à feu très doux pendant 15-20 minutes. Les boulettes doivent être cuites à cœur et la sauce bien parfumée.","6. Vérifiez l''assaisonnement et ajustez si nécessaire. Servez immédiatement, directement dans le tajine ou dans une assiette creuse.","💡 Astuce diabète : Cette portion de 300 g est idéale pour un diabétique de type 2. Le faible indice glycémique (GI 25) et la richesse en oméga-3 en font un excellent choix. Pour une meilleure gestion de la glycémie, mangez d''abord les boulettes et la sauce, puis accompagnez d''une salade verte sans féculents."]'::jsonb, '["1. وجد كوار السردين: فزلافة، خلط السردين المنقي والمقطع رقيق مع نص القزبور مقطع، نص الثومة مدقوقة، نص الكامون وشوية الملحة والبزار. صاوب كويرات صغار كل وحدة فيها تقريبا 15 غرام.","2. وجد لاصوص مطيشة: ف طاجين أو كوكوط تقيلة، سخن زيت الزيتون على عافية متوسطة. زيد البصلة مشلظة وخليها تشحر 3-4 دقايق حتى تولي شفافة.","3. زيد الثومة اللي بقات والعطرية الأخرى (الكامون، التحميرة، الهريسة إذا استعملتيها). حرك لمدة دقيقة حتى تطلع الريحة ديال العطرية.","4. زيد مطيشة مقطعة والقزبور اللي بقى. دير شوية الملحة والبزار. خليها طيب على عافية مهيلة 10-12 دقيقة، وحرك مرة مرة، حتى تخثار لاصوص شوية.","5. حط كوار السردين فوق لاصوص مطيشة غير بشوية. غطي الطاجين وخليه يطيب على عافية مهيلة بزاف 15-20 دقيقة. خاص الكويرات يطيبو مزيان من الداخل ولاصوص تكون بنينة.","6. ذوق وشوف واش خاصها شي حاجة. قدمها سخونة مباشرة من الطاجين أو ف طبق غارق.","💡 نصيحة للسكري: هاد الكمية ديال 300 غرام مثالية لمريض السكري من النوع 2. المؤشر الجلايسيمي المنخفض (GI 25) والغنى بالأوميغا-3 كيخليوه اختيار ممتاز. باش تحكم فمستوى السكر ف الدم أحسن، كل الكويرات ولاصوص هي الأولى، ومن بعد رافقها بسلطة خضراء بلا نشويات."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/70/Tag%C3%ADn_de_sardiens_al_fron_%281%29.png/1280px-Tag%C3%ADn_de_sardiens_al_fron_%281%29.png', ARRAY['kwar sardine', 'boulettes sardine', 'كوار']::text[]),
  ('calamars-ail-persil', 'Calamars à l’ail et persil', 'الكالمار بالثوم والمعدنوس', 'Garlic-parsley calamari', 'seafood', ARRAY['ghda', '3cha']::text[], '🦑', '1 portion (200 g)', 200, 210, 6, 1, 30, 8, 0, 10, 'Le calamar est une protéine maigre presque sans glucides. Sauté à l’ail, au persil et au citron (pas pané, pas frit), c’est un plat côtier ultra-léger qui laisse la glycémie tranquille.', 'الكالمار بروتين مزوق تقريباً بلا نشويات. مقلي بالثوم والمعدنوس والحامض (ماشي مغطي بالدقيق ولا مقلي فالزيت)، طبق ساحلي خفيف بزاف كيخلي السكر هاني.', '["200 g de calamars frais (anneaux et tentacules)","2 c. à soupe d''huile d''olive extra vierge","4 gousses d''ail, hachées finement","3 c. à soupe de persil frais, haché","1/2 citron, le jus","1/4 c. à café de cumin moulu","1 pincée de piment doux (paprika)","Sel et poivre noir fraîchement moulu, au goût"]'::jsonb, '["200 غرام من الكالمار الطري (حلقات وأذرع)","2 ملاعق كبيرة من زيت الزيتون البكر الممتاز","4 فصوص ثوم، مفرومة رقيقاً","3 ملاعق كبيرة من المعدنوس الطري، مفروم","1/2 حامضة، العصير ديالها","1/4 ملعقة صغيرة من الكمون مطحون","رشة فلفل أحمر حلو (تحميرة)","ملح وإبزار أسود مطحون طري، حسب الذوق"]'::jsonb, '["1. Nettoyez soigneusement les calamars : retirez la plume transparente, la peau, les yeux et le bec. Lavez-les à l''eau froide et coupez les corps en anneaux d''environ 1 cm d''épaisseur. Laissez les tentacules entiers ou coupez les plus gros en deux. Égouttez-les et séchez-les bien avec du papier absorbant.","2. Dans une poêle antiadhésive à feu moyen-vif, ajoutez 1 cuillère à soupe d''huile d''olive. Une fois chaude, ajoutez les calamars. Faites-les sauter pendant 1 à 2 minutes seulement, jusqu''à ce qu''ils deviennent opaques et commencent à se recroqueviller. Ne les sur-cuisez pas, sinon ils deviendront caoutchouteux. Retirez les calamars de la poêle et réservez-les.","3. Réduisez le feu à moyen. Ajoutez la cuillère à soupe d''huile d''olive restante dans la même poêle. Ajoutez l''ail haché et faites-le revenir pendant environ 30 secondes, juste jusqu''à ce qu''il soit parfumé, sans le laisser dorer.","4. Incorporez le persil haché, le cumin et le piment doux. Mélangez bien et laissez cuire pendant 15 secondes, le temps que les arômes se développent.","5. Remettez les calamars dans la poêle avec la préparation à l''ail et au persil. Mélangez délicatement pour bien enrober les calamars.","6. Versez le jus d''un demi-citron sur les calamars. Salez et poivrez généreusement selon votre goût. Mélangez une dernière fois et retirez immédiatement du feu.","7. Servez les calamars chauds, accompagnés d''une salade verte simple ou de légumes vapeur non féculents. Ce plat est idéal en entrée ou en plat principal léger. \n💡 Astuce diabète : Pour une gestion optimale de la glycémie, cette portion de 200g de calamars est parfaite. Accompagnez-la toujours de légumes verts à faible indice glycémique (GI 10 pour ce plat) et consommez-les en premier. Évitez de servir avec du pain blanc ou du riz, préférez une petite portion de quinoa ou de boulgour complet si un féculent est désiré."]'::jsonb, '["1. نقي الكالمار مزيان: حيد ديك الريشة الشفافة، الجلده، العينين والفم. غسلو بالماء بارد وقطع الجسم ديالو حلقات بسمك 1 سنتيمتر تقريبا. خلي الأذرع صحاح ولا قطع الكبار على جوج. قطرهم ونشفهم مزيان بورق المطبخ.","2. فمقلاة ما كاتلصقش على نار متوسطة-مجهدة، زيد ملعقة كبيرة ديال زيت الزيتون. ملي تسخن، زيد الكالمار. شحرهم لمدة 1 حتى 2 دقائق فقط، حتى يولي اللون ديالهم أبيض ويبداو يتكمشوا. ما طيبهمش بزاف باش ما يوليوش قاصحين. حيد الكالمار من المقلاة وخليه على جنب.","3. نقص العافية لمتوسطة. زيد ملعقة الزيت الزيتون اللي بقات فنفس المقلاة. زيد الثوم مفروم وشحرو لمدة 30 ثانية تقريبا، غير حتى تطلع ريحتو، بلا ما يتحمر.","4. زيد المعدنوس مفروم، الكمون والفلفل الأحمر الحلو (التحميرة). خلط مزيان وخليه يطيب لمدة 15 ثانية، غير باش تخرج النكهات.","5. رجع الكالمار للمقلاة مع خليط الثوم والمعدنوس. خلط بلطف باش يتغطى الكالمار مزيان.","6. خوي عصير نصف حامضة فوق الكالمار. زيد الملح والإبزار بزايد حسب الذوق ديالك. خلط آخر مرة وحيدو من فوق العافية مباشرة.","7. قدم الكالمار سخون، مع سلطة خضراء بسيطة أو خضروات مفورة ماشي نشوية. هاد الطبق مثالي كمقبلات أو طبق رئيسي خفيف. \n💡 نصيحة للسكري: لهاد الكمية ديال 200 غرام ديال الكالمار مثالية للتحكم في مستوى السكر في الدم. ديما قدمها مع خضروات خضراء ذات مؤشر جلايسيمي منخفض (GI 10 لهاد الطبق) وكلها هي الأولى. تجنب تقدمها مع الخبز الأبيض أو الأرز، وفضل كمية صغيرة من الكينوا أو البرغل الكامل إذا كنت باغي نشويات."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f2/Calamari_Fritti_-_Tavola_Di_Famiglia_2026-02-27.jpg/1280px-Calamari_Fritti_-_Tavola_Di_Famiglia_2026-02-27.jpg', ARRAY['calamars', 'كالمار']::text[]),
  ('dorade-vapeur', 'Dorade vapeur aux herbes', 'الدورادة فالبخار بالأعشاب', 'Steamed sea bream with herbs', 'seafood', ARRAY['ghda', '3cha']::text[], '🐠', '1 poisson (300 g)', 300, 260, 2, 0, 40, 10, 0, 5, 'La cuisson vapeur préserve les oméga-3 sans une goutte de matière grasse ajoutée. Poisson entier, herbes, citron : le dîner le plus léger et le plus sûr pour la glycémie.', 'الطيب فالبخار كيحافظ على الأوميغا 3 بلا قطرة دهون مزيودة. حوت كامل، أعشاب، حامض: أخف وأأمن عشا للسكر.', '["1 dorade royale entière (environ 300 g), écaillée et vidée","1/2 bouquet de coriandre fraîche (environ 15 g), hachée","1/2 bouquet de persil frais (environ 15 g), haché","2 gousses d''ail (environ 6 g), écrasées","1/2 citron (environ 50 g), coupé en rondelles fines","1/4 de cuillère à café de cumin moulu (environ 0.5 g)","1/4 de cuillère à café de paprika doux (environ 0.5 g)","Une pincée de sel de mer (environ 1 g)","Une pincée de poivre noir fraîchement moulu (environ 0.5 g)"]'::jsonb, '["1 دورادة رويال كاملة (تقريبا 300 غرام)، منقية ومحيدة ليها المصارن","نص ربطة قزبور طري (تقريبا 15 غرام)، مقطع رقيق","نص ربطة معدنوس طري (تقريبا 15 غرام)، مقطع رقيق","2 فصوص ثومة (تقريبا 6 غرام)، مدقوقة","نص حامضة (تقريبا 50 غرام)، مقطعة دوائر رقاق","ربع معلقة صغيرة كامون مطحون (تقريبا 0.5 غرام)","ربع معلقة صغيرة تحميرة حلوة (تقريبا 0.5 غرام)","قبيصة ملح البحر (تقريبا 1 غرام)","قبيصة إبزار أسود مطحون جديد (تقريبا 0.5 غرام)"]'::jsonb, '["1. Rincez soigneusement la dorade sous l''eau froide, puis séchez-la avec du papier absorbant. Faites 2 à 3 entailles peu profondes sur chaque flanc du poisson pour que les saveurs pénètrent bien.","2. Dans un petit bol, mélangez la coriandre hachée, le persil haché, l''ail écrasé, le cumin moulu, le paprika doux, la pincée de sel de mer et la pincée de poivre noir. Cette chermoula légère est la base de notre assaisonnement.","3. Farcissez l''intérieur de la dorade avec une partie de la chermoula préparée. Ensuite, frottez l''extérieur du poisson avec le reste de la chermoula, en veillant à bien faire pénétrer les herbes et les épices dans les entailles.","4. Placez quelques rondelles de citron à l''intérieur de la dorade et d''autres sur le dessus du poisson. Cela ajoutera une fraîcheur et une acidité délicates pendant la cuisson.","5. Préparez votre couscoussier ou votre cuiseur vapeur. Versez environ 1 litre d''eau dans la partie inférieure et portez à ébullition à feu vif. L''eau doit frémir généreusement pour produire une vapeur constante.","6. Une fois l''eau bouillante, placez délicatement la dorade assaisonnée dans le panier vapeur. Couvrez hermétiquement et laissez cuire à la vapeur pendant 15 à 20 minutes à feu moyen. Le poisson est cuit lorsque la chair est opaque et se détache facilement à la fourchette.","7. Servez immédiatement la dorade vapeur aux herbes avec les rondelles de citron. Elle peut être accompagnée d''une salade verte simple ou de légumes vapeur non féculents. Ne pas ajouter d''huile d''olive après cuisson pour maintenir la légèreté. Chaque portion est d''environ 300g de poisson.","💡 Astuce diabète : Pour un contrôle optimal de la glycémie, consommez d''abord la moitié de votre poisson et les légumes non féculents. Le poisson (300g) apporte environ 260 kcal et 2g de glucides, avec un GI très bas. Évitez de le servir avec du pain blanc ou du riz, préférez une petite portion de boulgour complet si vous souhaitez un accompagnement céréalier."]'::jsonb, '["1. غسلوا الدورادة مزيان تحت الماء بارد، ومن بعد نشفوها بورق المطبخ. ديروا 2 حتى 3 فليحات خفاف فكل جنب ديال الحوتة باش تدخل فيها البنة مزيان.","2. فزلافة صغيرة، خلطوا القزبور مقطع، المعدنوس مقطع، الثومة مدقوقة، الكامون مطحون، التحميرة الحلوة، قبيصة ملح البحر وقبيصة إبزار أسود. هاد الشرمولة الخفيفة هي أساس التتبيلة ديالنا.","3. عمروا الداخل ديال الدورادة بشوية من الشرمولة اللي وجدتو. من بعد، دهنوا الحوتة من برا بالباقي ديال الشرمولة، وتأكدوا بلي الأعشاب والعطرية دخلات مزيان فالفليحات.","4. حطوا شي دوائر ديال الحامض لداخل ديال الدورادة وشي وحدين فوق الحوتة. هادشي غادي يزيد واحد النكهة منعشة وحموضة خفيفة أثناء الطياب.","5. وجدوا الكسكاس ديالكم أو الطنجرة ديال البخار. خويو تقريبا 1 لتر ديال الماء فالجزء التحتاني وخليوه يغلى على نار مجهدة. خاص الماء يكون كيغلي مزيان باش يعطي بخار مستمر.","6. ملي يغلى الماء، حطوا الدورادة مشرملة غير بشوية فالكسكاس. غطيوها مزيان وخليوها طيب على البخار لمدة 15 حتى 20 دقيقة على نار متوسطة. الحوتة كتكون طابت ملي كيولي اللحم ديالها أبيض ومكيشدش فالفورشيطة.","7. قدموا الدورادة فالبخار بالأعشاب مباشرة مع دوائر الحامض. ممكن تقدموها مع شلاضة خضرا بسيطة أو خضروات مبخرة ماشي نشوية. متزيدوش زيت الزيتون من بعد الطياب باش تبقى خفيفة. كل حصة هي تقريبا 300 غرام ديال الحوت.","💡 نصيحة للسكري: باش تحكموا فالسكري ديالكم مزيان، كولوا النص ديال الحوت والخضرة اللي ماشي نشوية هي الأولى. الحوت (300 غرام) كيعطي تقريبا 260 سعرة حرارية و 2 غرام ديال الكربوهيدرات، ومعامل سكري منخفض بزاف. تجنبوا تقدموه مع الخبز الأبيض أو الروز، فضّلوا كمية صغيرة من البرغل الكامل إذا بغيتوا شي حاجة من الحبوب."]'::jsonb, null, ARRAY['dorade', 'دورادة']::text[]),
  ('amandes', 'Poignée d''amandes', 'قبضة ديال اللوز', 'Handful of almonds', 'snack', ARRAY['snack']::text[], '🌰', '15 amandes (20 g)', 20, 120, 4, 1, 4, 10, 3, 15, 'LA collation du diabétique : coupe la faim sans toucher la glycémie, magnésium qui améliore la sensibilité à l’insuline. 15 amandes, pas le paquet !', 'السناك ديال السكري: كيقطع الجوع بلا ما يهز السكر، وفيه المغنيزيوم اللي كيحسن حساسية الأنسولين. 15 حبة، ماشي الكيس كامل!', '["20 g d''amandes entières non mondées","1 pincée de sel de mer fin","1/4 de cuillère à café de cumin moulu","1/8 de cuillère à café de paprika doux","1/2 cuillère à café d''eau de fleur d''oranger (facultatif)","1/4 de cuillère à café d''huile d''olive extra vierge"]'::jsonb, '["20 غرام ديال اللوز صحيح بالقشرة","قرصة ديال الملحة الرقيقة","ربع معلقة صغيرة ديال الكامون مطحون","تمن معلقة صغيرة ديال التحميرة الحلوة","نص معلقة صغيرة ديال ماء الزهر (اختياري)","ربع معلقة صغيرة ديال زيت الزيتون البكر الممتاز"]'::jsonb, '["Préchauffez votre four à 150°C (Th. 5). Pendant ce temps, tapissez une petite plaque de cuisson de papier sulfurisé.","Dans un petit bol, mélangez l''huile d''olive, le sel, le cumin moulu et le paprika doux. Si vous utilisez de l''eau de fleur d''oranger, ajoutez-la à ce mélange.","Ajoutez les 20 g d''amandes entières non mondées au bol et mélangez bien pour enrober chaque amande uniformément avec les épices et l''huile.","Étalez les amandes assaisonnées en une seule couche sur la plaque de cuisson préparée, en veillant à ce qu''elles ne se chevauchent pas.","Enfournez les amandes et faites-les rôtir pendant 10 à 12 minutes. Surveillez-les attentivement pour éviter qu''elles ne brûlent. Elles doivent être légèrement dorées et croustillantes.","Laissez les amandes refroidir complètement sur la plaque de cuisson. Elles deviendront plus croustillantes en refroidissant. Une fois froides, elles sont prêtes à être dégustées.","💡 Astuce diabète : Cette portion de 15 amandes (environ 20g) est idéale pour un snack sans impact majeur sur la glycémie. Le magnésium des amandes aide à améliorer la sensibilité à l''insuline. Évitez de les saler excessivement et ne dépassez pas la portion recommandée pour contrôler l''apport calorique."]'::jsonb, '["سخن الفران ديالك على درجة حرارة 150°C. فهاذ الوقت، فرّش لاطة صغيرة بورق الطهي.","فزلافة صغيرة، خلط زيت الزيتون، الملحة، الكامون مطحون والتحميرة الحلوة. إلا كنتي غتستعمل ماء الزهر، زيدو لهاد الخليط.","زيد 20 غرام ديال اللوز صحيح بالقشرة للزلافة وخلط مزيان باش كل لوزة تغلف بالتوابل والزيت بشكل متساوي.","فرّش اللوز المتبل فطبقة وحدة فوق اللاطة اللي وجدتي، وتأكد أنهم مايكونوش متراكبين.","دخل اللوز للفران وخليه يتحمر لمدة 10 حتى لـ 12 دقيقة. راقبو مزيان باش مايتحرقش. خاصو يولي مذهب شوية ومقرمش.","خلي اللوز يبرد تمامًا فوق اللاطة. غادي يولي مقرمش أكثر منين يبرد. منين يبرد، راه واجد باش يتكال.","💡 نصيحة للسكري: هاد الكمية ديال 15 لوزة (تقريبا 20 غرام) مثالية كوجبة خفيفة بدون تأثير كبير على مستوى السكر في الدم. المغنيسيوم اللي فاللوز كيساعد على تحسين حساسية الأنسولين. تجنب تمليحهم بزاف وماتجاوزش الكمية الموصى بها باش تحافظ على السعرات الحرارية."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/cf/Bowl_of_chopped_almonds.jpg/1280px-Bowl_of_chopped_almonds.jpg', ARRAY['amande', 'لوز']::text[]),
  ('pomme-beurre-cacahuete', 'Pomme & purée de cacahuètes', 'تفاحة مع زبدة الكاوكاو', 'Apple & peanut butter', 'snack', ARRAY['snack']::text[], '🍎', '1 pomme + 1 c.s. (170 g)', 170, 180, 25, 18, 4, 8, 4, 38, 'La pomme ENTIÈRE (jamais en jus !) a un IG bas grâce à ses fibres. La purée de cacahuète sans sucre ralentit encore l’absorption. Le goûter parfait.', 'التفاحة الكاملة (ماشي عصير!) عندها مؤشر منخفض بفضل الألياف. زبدة الكاوكاو بلا سكر كتبطئ الامتصاص أكثر. اللمجة المثالية.', '["1 pomme moyenne (environ 150-170 g)","1 cuillère à soupe (environ 15 g) de purée de cacahuètes naturelle (sans sucre ajouté)","1/4 cuillère à café de cannelle moulue","1 pincée de sel de mer fin"]'::jsonb, '["1 تفاحة متوسطة (حوالي 150-170 غرام)","1 ملعقة كبيرة (حوالي 15 غرام) زبدة الكاوكاو طبيعية (بدون سكر مضاف)","1/4 ملعقة صغيرة قرفة مطحونة","1 قبيصة ملح البحر الرقيق"]'::jsonb, '["Lavez soigneusement la pomme sous l''eau froide. Il est essentiel de garder la peau car elle contient la majorité des fibres, cruciales pour ralentir l''absorption du sucre.","Coupez la pomme en quartiers, puis retirez délicatement le trognon et les pépins. Vous pouvez ensuite couper chaque quartier en tranches plus fines, d''environ 0.5 cm d''épaisseur, pour faciliter la dégustation.","Dans un petit bol, mélangez la cuillère à soupe de purée de cacahuètes naturelle avec la cannelle moulue et une toute petite pincée de sel de mer. Le sel rehaussera les saveurs sans ajouter de sodium excessif.","Remuez bien le mélange jusqu''à obtenir une pâte homogène et facile à étaler. Si la purée de cacahuètes est trop épaisse, vous pouvez la réchauffer très légèrement au micro-ondes pendant 5 secondes pour la ramollir, mais évitez de la liquéfier.","Étalez uniformément la purée de cacahuètes assaisonnée sur chaque tranche de pomme. Assurez-vous que chaque morceau de pomme reçoit une fine couche de purée pour un équilibre parfait des saveurs et des textures.","Disposez les tranches de pomme garnies sur une petite assiette. Ce goûter est prêt à être dégusté immédiatement pour profiter de la fraîcheur de la pomme et du crémeux de la purée de cacahuètes.","💡 Astuce diabète : Pour ce goûter, respectez scrupuleusement la portion d''une pomme moyenne (environ 170g) et d''une cuillère à soupe de purée de cacahuètes naturelle. La pomme entière, grâce à ses fibres, a un indice glycémique bas (environ 38). Mangez toujours la pomme avec sa peau et la purée de cacahuètes pour maximiser l''effet de ralentissement de l''absorption du glucose. Évitez les jus de pomme qui n''ont pas les fibres et augmentent rapidement la glycémie."]'::jsonb, '["غسل التفاحة مزيان تحت الما بارد. ضروري تخليو القشرة حيت فيها بزاف ديال الألياف اللي كتعاون باش السكر ما يمتصش دغيا.","قطع التفاحة على أربعة، ومن بعد حيد ليها القلب والزريعة بشوية. تقدر تقطع كل ربع لشرائح رقيقة، تقريبا 0.5 سم في السمك، باش يسهال عليك تاكلها.","فزلافة صغيرة، خلط معلقة كبيرة ديال زبدة الكاوكاو الطبيعية مع القرفة مطحونة وواحد القبيصة صغيرة ديال ملح البحر. الملح كيزيد يبنن المذاق بلا ما يكون فيه بزاف ديال الصوديوم.","خلط الخليط مزيان حتى يولي متجانس وساهل باش يتدهن. إلا كانت زبدة الكاوكاو قاصحة بزاف، تقدر تسخنها شوية فالميكروويف لمدة 5 ثواني باش ترطاب، ولكن رد البال ما تخليهاش تولي سائلة.","دهن زبدة الكاوكاو اللي وجدتي بالتساوي على كل شريحة ديال التفاح. تأكد أن كل طرف ديال التفاح فيه طبقة رقيقة ديال زبدة الكاوكاو باش يكون المذاق والقوام متوازن.","حط شرائح التفاح اللي دهنتيها فطبسيل صغير. هاد الكوتي واجد باش يتكال دغيا باش تستمتع بالطراوة ديال التفاح والكريمة ديال زبدة الكاوكاو.","💡 نصيحة للسكري: بالنسبة لهاد الكوتي، التزم بالكمية ديال تفاحة متوسطة (حوالي 170 غرام) ومعلقة كبيرة ديال زبدة الكاوكاو الطبيعية. التفاحة كاملة، بفضل الألياف اللي فيها، عندها مؤشر سكري منخفض (حوالي 38). ديما كول التفاح بالقشرة ديالو ومع زبدة الكاوكاو باش تزيد من تأثير تبطيء امتصاص السكر. تجنب عصير التفاح اللي مافيهش الألياف وكيرفع السكر فالدم بسرعة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/cd/Apple_butter_and_peanut_butter%2C_heated_on_a_half_sandwich_of_toasted_potato_bread_-_Massachusetts.jpg/1280px-Apple_butter_and_peanut_butter%2C_heated_on_a_half_sandwich_of_toasted_potato_bread_-_Massachusetts.jpg', ARRAY['pomme']::text[]),
  ('hoummos-batonnets', 'Houmous & bâtonnets de légumes', 'حمص متحون مع عيدان الخضرة', 'Hummus & veggie sticks', 'snack', ARRAY['snack']::text[], '🥕', '3 c.s. + légumes (150 g)', 150, 160, 14, 4, 6, 9, 5, 25, 'Pois chiches mixés = IG 25. Trempez carottes et concombres dedans au lieu du pain : croquant, rassasiant, glycémie plate.', 'الحمص المطحون = مؤشر 25. غمس الخيزو والخيار فيه بلاصة الخبز: مقرمش، مشبع، والسكر مستقر.', '["100 g de pois chiches cuits (en conserve, rincés et égouttés)","15 ml (1 c. à soupe) de tahini","15 ml (1 c. à soupe) de jus de citron frais","1 petite gousse d''ail (environ 3 g), écrasée","30 ml (2 c. à soupe) d''eau froide","1.5 ml (1/4 c. à café) de cumin moulu","1 pincée de sel de mer","1 pincée de paprika doux (pour la garniture)","75 g de bâtonnets de carottes crues","75 g de bâtonnets de concombre cru"]'::jsonb, '["100 غرام حمص طايب (معلب، مغسول ومقطر)","15 مللتر (1 م.ك.) طحينة","15 مللتر (1 م.ك.) عصير حامض طري","ضرس ثومة صغير (حوالي 3 غرام)، مدقوق","30 مللتر (2 م.ك.) ماء بارد","1.5 مللتر (1/4 م.ص.) كمون مطحون","رشة ملحة بحرية","رشة تحميرة حلوة (للتزيين)","75 غرام خيزو مقطع عيدان","75 غرام خيار مقطع عيدان"]'::jsonb, '["1. Dans un mixeur, ajoutez les 100 g de pois chiches cuits et rincés, les 15 ml de tahini, les 15 ml de jus de citron frais, la petite gousse d''ail écrasée, les 30 ml d''eau froide, les 1.5 ml de cumin moulu et la pincée de sel de mer.","2. Mixez tous les ingrédients à haute vitesse pendant 2 à 3 minutes, en raclant les bords du mixeur si nécessaire, jusqu''à obtenir une consistance lisse et crémeuse. Si le houmous est trop épais, ajoutez une cuillère à café d''eau froide supplémentaire et mixez à nouveau.","3. Goûtez et ajustez l''assaisonnement si besoin. Le houmous doit avoir un équilibre entre l''acidité du citron et la saveur du tahini.","4. Transférez les 3 cuillères à soupe (environ 150 g) de houmous dans un petit bol de service. Réservez le reste pour une autre portion ou congelez-le.","5. Disposez les 75 g de bâtonnets de carottes et les 75 g de bâtonnets de concombre à côté du bol de houmous, prêts à être trempés.","6. Saupoudrez la pincée de paprika doux sur le houmous pour la couleur et une légère touche de saveur fumée.","💡 Astuce diabète : Cette portion de 150g de houmous avec 150g de légumes est un excellent snack à IG bas (25). Commencez toujours par les légumes pour maximiser la sensation de satiété et ralentir l''absorption des glucides. Évitez de le servir avec du pain blanc; privilégiez les légumes crus ou des crackers complets à faible IG si vous souhaitez une alternative."]'::jsonb, '["1. فخلاط كهربائي، دير 100 غرام ديال الحمص طايب ومغسول، 15 مللتر ديال الطحينة، 15 مللتر ديال عصير الحامض الطري، ضرس الثومة المدقوق الصغير، 30 مللتر ديال الماء البارد، 1.5 مللتر ديال الكمون مطحون ورشة الملحة البحرية.","2. طحن كاع المكونات مزيان لمدة 2 حتى 3 دقايق، وحرك الجناب ديال الخلاط إذا كان خاص، حتى يولي الخليط رطب وكريمي. إذا كان الحمص قاصح بزاف، زيد معلقة صغيرة ديال الماء بارد وطحن مرة أخرى.","3. ذوق وقاد المذاق إذا كان خاص. خاص الحمص يكون فيه توازن بين الحموضة ديال الحامض والبنة ديال الطحينة.","4. حط 3 المعالق كبار (حوالي 150 غرام) ديال الحمص فزلافة صغيرة ديال التقديم. خلي الباقي لوجبة أخرى أو ديرو فالمجمد.","5. ستف 75 غرام ديال عيدان خيزو و 75 غرام ديال عيدان الخيار حدا زلافة الحمص، واجدين للغماس.","6. رش رشة ديال التحميرة الحلوة فوق الحمص باش تعطيه لون ولمسة خفيفة ديال البنة.","💡 نصيحة للسكري: هاد الكمية ديال 150 غرام حمص مع 150 غرام خضرة هي وجبة خفيفة ممتازة بمؤشر سكري منخفض (25). ديما بدا بالخضرة باش تحس بالشبع مزيان وتقلل من امتصاص الكربوهيدرات. تجنب تقدمو مع الخبز الأبيض؛ من الأفضل تقدمو مع الخضرة خضرا أو بسكويت قمح كامل بمؤشر سكري منخفض إذا بغيتي بديل."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a0/HUMMUS_PLATE.JPG/1280px-HUMMUS_PLATE.JPG', ARRAY['houmous', 'حمص']::text[]),
  ('oeuf-dur-snack', 'Œuf dur (encas)', 'بيضة مسلوقة (لمجة)', 'Hard-boiled egg (snack)', 'snack', ARRAY['snack', 'ftour']::text[], '🥚', '1 œuf (50 g)', 50, 78, 0.5, 0.5, 6, 5, 0, 0, 'Zéro glucide, 78 kcal, rassasiant : l’encas de secours à toujours avoir au frigo. Aucune excuse pour les biscuits.', 'بلا نشويات، 78 كالوري، وكيشبع: لمجة الإنقاذ اللي خاصها تكون ديما فالتلاجة. ما بقاش عذر للبيسكوي.', '["1 pièce d''œuf de poule (environ 50 g)","250 ml d''eau filtrée","1 pincée de sel de mer (environ 0.5 g)","1 pincée de cumin moulu (environ 0.5 g)","1 pincée de paprika doux (environ 0.5 g)","Quelques brins de persil frais (pour la garniture, facultatif)"]'::jsonb, '["1 بيضة دجاج (تقريبا 50 غرام)","250 مل ماء مصفي","1 قبيصة ملح البحر (تقريبا 0.5 غرام)","1 قبيصة كمون مطحون (تقريبا 0.5 غرام)","1 قبيصة تحميرة حلوة (تقريبا 0.5 غرام)","شوية معدنوس طري (للتزيين، اختياري)"]'::jsonb, '["1. Prenez une petite casserole et versez-y 250 ml d''eau filtrée. Ajoutez délicatement 1 œuf de poule (environ 50 g) dans l''eau froide pour éviter qu''il ne se fende pendant la cuisson.","2. Placez la casserole sur un feu moyen. Portez l''eau à ébullition. Dès que l''eau commence à bouillir, réduisez le feu à doux-moyen pour maintenir un frémissement léger.","3. Laissez l''œuf cuire pendant exactement 9 à 10 minutes à partir du moment où l''eau bout. Cela garantira un jaune bien ferme et une cuisson parfaite pour un œuf dur.","4. Après 9 à 10 minutes, retirez la casserole du feu. Videz l''eau chaude avec précaution et remplissez immédiatement la casserole d''eau très froide, éventuellement avec quelques glaçons, pour arrêter la cuisson et faciliter l''écalage.","5. Laissez l''œuf refroidir dans l''eau froide pendant au moins 5 minutes. Une fois refroidi, écalez l''œuf sous un filet d''eau froide en tapotant doucement la coquille sur une surface dure et en la retirant délicatement.","6. Coupez l''œuf dur en deux dans le sens de la longueur ou en rondelles, selon votre préférence. Disposez-le sur une petite assiette.","7. Assaisonnez l''œuf avec 1 pincée de sel de mer, 1 pincée de cumin moulu et 1 pincée de paprika doux. Si vous le souhaitez, garnissez avec quelques brins de persil frais haché pour une touche de fraîcheur.","💡 Astuce diabète : Cet œuf dur est un excellent encas coupe-faim avec un GI de 0. Consommez-le tel quel pour un apport minimal en glucides (0.5 g) et seulement 78 kcal. Évitez de l''accompagner de pain ou de biscuits. Il peut être préparé à l''avance et conservé au réfrigérateur jusqu''à 3 jours pour un encas rapide et sain."]'::jsonb, '["1. خذ كاسرونة صغيرة وصب فيها 250 مل من الماء المصفي. حط بيضة دجاجة (تقريبا 50 غرام) بشوية في الماء البارد باش متطرطقش أثناء الطياب.","2. حط الكاسرونة فوق نار متوسطة. خلي الماء حتى يغلى. غير يبدا الماء يغلى، نقص النار لمهيلة-متوسطة باش يبقى يغلي بشوية.","3. خلي البيضة طيب لمدة 9 حتى 10 دقائق بالضبط من وقت ما بدا الماء يغلى. هاد المدة غتخلي الصفار قاصح ومطيب مزيان باش تكون بيضة مسلوقة مزيانة.","4. من بعد 9 حتى 10 دقائق، حيد الكاسرونة من فوق النار. خوي الماء السخون بحذر وعمر الكاسرونة فورا بماء بارد بزاف، تقدر تزيد شي مكعبات ثلج، باش توقف الطياب ويسهل عليك تقشيرها.","5. خلي البيضة تبرد في الماء البارد لمدة 5 دقائق على الأقل. منين تبرد، قشر البيضة تحت الروبيني ديال الماء البارد، خبط القشرة بشوية على شي سطح قاصح وحيدها بلطف.","6. قطع البيضة المسلوقة على جوج بالطول أو على شكل دوائر، على حسب شنو كتفضل. حطها في طبسيل صغير.","7. تبّل البيضة بقبيصة ملح البحر، قبيصة كمون مطحون وقبيصة تحميرة حلوة. إلا بغيتي، زينها بشوية معدنوس طري مقطع باش تعطيها لمسة ديال الطراوة.","💡 نصيحة للسكري: هاد البيضة المسلوقة وجبة خفيفة ممتازة كتشبع وكتنقص الجوع، ومؤشرها الجلايسيمي هو 0. كلها كيف ما هي باش تاخد أقل كمية من الكربوهيدرات (0.5 غرام) و 78 سعرة حرارية فقط. تجنب تاكلها مع الخبز أو البسكويت. تقدر توجدها من قبل وتحتفظ بها في الثلاجة حتى 3 أيام كوجبة خفيفة سريعة وصحية."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a4/Boiled_Egg_-_Crossection.jpg/1280px-Boiled_Egg_-_Crossection.jpg', ARRAY['oeuf dur']::text[]),
  ('fruits-rouges-yaourt', 'Fruits rouges & yaourt grec', 'التوت مع الياغورت اليوناني', 'Berries & Greek yogurt', 'snack', ARRAY['snack', 'dessert']::text[], '🫐', '100 g fruits + 100 g yaourt', 200, 150, 14, 10, 10, 6, 4, 25, 'Fraises, framboises, myrtilles : les fruits les MOINS sucrés qui existent. Avec le yaourt grec protéiné, le dessert-plaisir sans remords.', 'الفريز والتوت: الفواكه الأقل سكر اللي كاينين. مع الياغورت اليوناني الغني بالبروتين، حلوى بلا ندم.', '["100 g de fruits rouges frais (fraises, framboises, myrtilles)","100 g de yaourt grec nature 0% matière grasse","1/2 c. à café de graines de chia","1/4 c. à café d''extrait de vanille pure (facultatif)","Quelques feuilles de menthe fraîche pour la garniture (facultatif)"]'::jsonb, '["100 غرام من الفواكه الحمراء الطازجة (الفريز، التوت، العنب البري)","100 غرام من الياغورت اليوناني الطبيعي 0% دهون","1/2 ملعقة صغيرة من بذور الشيا","1/4 ملعقة صغيرة من خلاصة الفانيليا النقية (اختياري)","بعض وريقات النعناع الطازج للتزيين (اختياري)"]'::jsonb, '["Lavez délicatement les 100 g de fruits rouges sous l''eau froide. Égouttez-les soigneusement sur du papier absorbant. Si vous utilisez des fraises, équeutez-les et coupez les plus grosses en deux ou en quatre.","Dans un petit bol, versez les 100 g de yaourt grec nature 0% matière grasse.","Ajoutez 1/4 de cuillère à café d''extrait de vanille pure au yaourt grec si vous le souhaitez, pour rehausser la saveur. Mélangez doucement avec une petite cuillère.","Incorporez 1/2 cuillère à café de graines de chia au yaourt. Mélangez bien pour que les graines soient uniformément réparties. Laissez reposer 2-3 minutes pour qu''elles commencent à absorber l''humidité et épaississent légèrement le yaourt.","Disposez les fruits rouges préparés sur le yaourt grec dans le bol. Vous pouvez les mélanger légèrement ou les laisser joliment posés sur le dessus.","Pour une touche de fraîcheur et de couleur, garnissez avec quelques feuilles de menthe fraîche, si désiré.","Servez immédiatement pour profiter de la fraîcheur des fruits et de la texture crémeuse du yaourt.","💡 Astuce diabète : Ce snack de 200 g (100 g fruits + 100 g yaourt) est idéal pour les diabétiques de type 2. Les fruits rouges ont un indice glycémique très bas (GI 25) et le yaourt grec est riche en protéines, ce qui aide à stabiliser la glycémie. Consommez cette portion comme collation et évitez d''ajouter du sucre ou du miel. Mangez les fruits en premier pour bénéficier de leurs fibres avant les autres nutriments."]'::jsonb, '["غسل 100 غرام من الفواكه الحمراء بلطف تحت الماء البارد. صفيها بعناية على ورق المطبخ. إذا كنت تستخدم الفريز، أزل الأوراق وقطع الحبات الكبيرة إلى نصفين أو أربعة أجزاء.","في زلافة صغيرة، صب 100 غرام من الياغورت اليوناني الطبيعي 0% دهون.","أضف 1/4 ملعقة صغيرة من خلاصة الفانيليا النقية إلى الياغورت إذا أردت، لتعزيز النكهة. اخلط بلطف بملعقة صغيرة.","أضف 1/2 ملعقة صغيرة من بذور الشيا إلى الياغورت. اخلط جيدا حتى تتوزع البذور بالتساوي. اتركها ترتاح لمدة 2-3 دقائق لتبدأ في امتصاص الرطوبة وتكثيف الياغورت قليلا.","ضع الفواكه الحمراء المحضرة فوق الياغورت اليوناني في الزلافة. يمكنك خلطها قليلا أو تركها موضوعة بشكل جميل فوق الياغورت.","لإضافة لمسة من الانتعاش واللون، زين ببعض وريقات النعناع الطازج، إذا رغبت في ذلك.","قدم الطبق فورا للاستمتاع بانتعاش الفواكه وقوام الياغورت الكريمي.","💡 نصيحة للسكري: هاد الوجبة الخفيفة اللي فيها 200 غرام (100 غرام فواكه + 100 غرام ياغورت) مثالية لمرضى السكري من النوع 2. الفواكه الحمراء عندها مؤشر سكري منخفض بزاف (GI 25) والياغورت اليوناني غني بالبروتينات، وهذا كيساعد على استقرار نسبة السكر في الدم. تناول هاد الكمية كوجبة خفيفة وتجنب إضافة السكر أو العسل. كل الفواكه هي الأولى باش تستافد من الألياف ديالها قبل ما تاكل المكونات الأخرى."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/5/5b/Strawberry_Frozen_Yogurt_%282552806737%29.jpg', ARRAY['fruits rouges']::text[]),
  ('lben-verre', 'Verre de lben', 'كاس ديال اللبن', 'Glass of lben (buttermilk)', 'snack', ARRAY['snack', 'drink']::text[], '🥛', '1 verre (250 ml)', 250, 95, 12, 12, 8, 2, 0, 30, 'Le lben traditionnel est naturellement pauvre en gras et son lactose a un IG bas. Bien meilleur que n’importe quel jus ou soda avec le repas.', 'اللبن التقليدي قليل الدهون طبيعياً والسكر ديالو عندو مؤشر منخفض. أحسن بكثير من أي عصير ولا مونادا مع الماكلة.', '["250 ml de lben (babeurre traditionnel marocain)","1 pincée de sel de l''Himalaya (facultatif)","2-3 feuilles de menthe fraîche (pour la garniture, facultatif)"]'::jsonb, '["250 مل ديال اللبن البلدي","1 قبيصة ديال الملحة الوردية (اختياري)","2-3 وريقات ديال النعناع طري (للتزيين، اختياري)"]'::jsonb, '["Assurez-vous que votre lben est bien frais. Si vous le préparez à la maison, utilisez du lait entier fermenté naturellement pour un goût authentique et un IG bas.","Versez délicatement les 250 ml de lben dans un verre de 250 ml.","Si vous le souhaitez, ajoutez une très légère pincée de sel de l''Himalaya. Cela rehausse parfois le goût du lben sans ajouter de sodium excessif.","Mélangez doucement le lben avec une cuillère si vous avez ajouté du sel, juste pour le dissoudre.","Goûtez le lben pour vous assurer qu''il est à votre convenance. Le lben traditionnel a une légère acidité rafraîchissante.","Pour une touche de fraîcheur supplémentaire, garnissez le verre avec 2-3 feuilles de menthe fraîche. Cela ajoute un arôme agréable sans sucre ni calories.","Servez immédiatement, bien frais. Le lben est un excellent accompagnement pour un repas léger ou une collation rafraîchissante.","💡 Astuce diabète : Le verre de lben (250 ml) est une excellente collation ou boisson d''accompagnement. Son IG bas (environ 30) aide à maintenir une glycémie stable. Évitez d''y ajouter du sucre ou du miel. Il est préférable de le consommer avec un repas riche en fibres (légumes, légumineuses) pour ralentir davantage l''absorption des glucides."]'::jsonb, '["تأكدوا أن اللبن ديالكم بارد مزيان. إلا كنتو غادي تصايبوه فالدار، استعملو الحليب الكامل الدسم اللي تخمر طبيعي باش يجي بنين وصحي.","خويو 250 مل ديال اللبن بشوية فكاس ديال 250 مل.","إلى بغيتو، زيدو قبيصة صغيرة بزاف ديال الملحة الوردية. هادشي كيزيد يبنن اللبن بلا ما يزيد الملح بزاف.","خلطو اللبن غير بشوية بالمعلقة إلى زدتو الملحة، غير باش تذوب.","ذوقو اللبن باش تتأكدو أنه عجبكم. اللبن البلدي كيكون فيه حموضة خفيفة ومنعشة.","باش تزيدو ليه لمسة ديال الانتعاش، زوقو الكاس بـ 2-3 وريقات ديال النعناع طري. هادشي كيعطي ريحة زوينة بلا سكر ولا سعرات حرارية.","قدموه فالحين، وهو بارد مزيان. اللبن كيجي رائع مع شي وجبة خفيفة أو كوجبة خفيفة منعشة.","💡 نصيحة للسكري: كاس ديال اللبن (250 مل) وجبة خفيفة أو مشروب مرافق ممتاز. المؤشر الجلايسيمي ديالو منخفض (حوالي 30) كيساعد باش يبقى السكر ف الدم مستقر. تجنبو تزيدو ليه السكر أو العسل. من الأفضل تشربوه مع وجبة غنية بالألياف (خضروات، قطاني) باش تبطئو امتصاص الكربوهيدرات أكثر."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/23/Buttermilk-%28right%29-and-Milk-%28left%29.jpg/1280px-Buttermilk-%28right%29-and-Milk-%28left%29.jpg', ARRAY['lben', 'لبن', 'raib']::text[]),
  ('zitoun', 'Olives (poignée)', 'الزيتون (قبضة)', 'Olives (handful)', 'snack', ARRAY['snack']::text[], '🫒', '10 olives (40 g)', 40, 60, 2, 0, 0, 6, 1, 0, 'Zéro sucre, bonnes graisses méditerranéennes : l''apéritif marocain qui ne touche pas la glycémie. Attention seulement au sel si tension élevée.', 'بلا سكر، ودهون متوسطية صحية: المقبلات المغربية اللي ما كتقيسش السكر. رد البال غير من الملح إلا كانت التونسيو مرتفعة.', '["40 g d''olives violettes de Meknès (environ 10 pièces)","5 ml d''huile d''olive extra vierge (1 c. à café)","1 g de cumin moulu (1/4 c. à café)","1 g de paprika doux (1/4 c. à café)","0.5 g de piment doux moulu (1 pincée, facultatif)","1 petite gousse d''ail (environ 2 g), hachée finement","5 g de persil frais, haché finement","5 g de coriandre fraîche, hachée finement","2 ml de jus de citron frais (1/2 c. à café)"]'::jsonb, '["40 غرام زيتون بلدي بنفسجي من مكناس (تقريباً 10 حبات)","5 ملل زيت الزيتون البكر الممتاز (1 ملعقة صغيرة)","1 غرام كمون مطحون (1/4 ملعقة صغيرة)","1 غرام تحميرة حلوة (1/4 ملعقة صغيرة)","0.5 غرام فلفلة حارة مطحونة (رشة، اختياري)","1 فص ثوم صغير (تقريباً 2 غرام)، مفروم رقيق","5 غرام معدنوس طري، مفروم رقيق","5 غرام قزبر طري، مفروم رقيق","2 ملل عصير حامض طري (1/2 ملعقة صغيرة)"]'::jsonb, '["Commencez par rincer délicatement les 40 g d''olives violettes sous l''eau froide pour enlever l''excès de sel. Égouttez-les bien et mettez-les de côté dans un petit bol.","Dans un petit mortier (ou un petit bol), écrasez finement la petite gousse d''ail hachée avec une pincée de sel (si les olives ne sont pas trop salées) jusqu''à obtenir une pâte.","Ajoutez à la pâte d''ail le 1 g de cumin moulu, le 1 g de paprika doux, et le 0.5 g de piment doux moulu (si utilisé). Mélangez bien pour combiner les épices.","Incorporez le 5 g de persil frais haché et le 5 g de coriandre fraîche hachée au mélange d''épices et d''ail. Remuez pour créer une chermoula aromatique.","Versez le 5 ml d''huile d''olive extra vierge et le 2 ml de jus de citron frais sur la chermoula. Mélangez à nouveau pour bien émulsionner la sauce.","Ajoutez les olives rincées et égouttées dans le bol contenant la chermoula. Mélangez délicatement avec une cuillère ou vos mains propres pour que chaque olive soit bien enrobée de la sauce.","Laissez les olives mariner pendant au moins 15 minutes à température ambiante pour que les saveurs se développent. Vous pouvez les préparer à l''avance et les conserver au réfrigérateur, mais sortez-les 30 minutes avant de servir.","Servez les 10 olives préparées comme une collation saine et savoureuse.","💡 Astuce diabète : Cette portion de 10 olives (environ 40 g) est idéale pour un snack sans impact sur la glycémie (GI 0). Les bonnes graisses de l''huile d''olive et des olives aident à la satiété. Attention à ne pas dépasser cette portion pour contrôler l''apport en sel, surtout si vous avez de l''hypertension."]'::jsonb, '["أولاً، شلّل 40 غرام من الزيتون البنفسجي بلطف تحت الماء البارد باش تحيد الملح الزايد. صفّيه مزيان وحطّو على جنب فزلافة صغيرة.","فمهراز صغير (أو زلافة صغيرة)، دقّ فص الثوم الصغير المفروم رقيق مع رشة ملح (إلا كان الزيتون ماشي مالح بزاف) حتى يولي بحال العجينة.","زيد على عجينة الثوم 1 غرام كمون مطحون، 1 غرام تحميرة حلوة، و 0.5 غرام فلفلة حارة مطحونة (إلا كنتي ستعملها). خلط مزيان باش يتجانسو العطرية.","خلط 5 غرام معدنوس طري مفروم و 5 غرام قزبر طري مفروم مع خليط العطرية والثوم. حرّك باش تصاوب شرمولة بنينة.","خوي 5 ملل زيت الزيتون البكر الممتاز و 2 ملل عصير حامض طري على الشرمولة. خلط مرة أخرى باش تخلط الصلصة مزيان.","زيد الزيتون المشلل والمصفى فالزلافة اللي فيها الشرمولة. خلط بلطف بملعقة أو بيديك نقيين باش كل زيتونة تغطى بالصلصة مزيان.","خلي الزيتون يترقد على الأقل 15 دقيقة فدرجة حرارة الغرفة باش يتشرب النكهات. تقدر توجدهم من قبل وتحتفظ بهم فالثلاجة، ولكن خرجهم 30 دقيقة قبل التقديم.","قدم 10 حبات زيتون اللي وجدتي كوجبة خفيفة صحية ولذيذة.","💡 نصيحة للسكري: هاد الحصة ديال 10 حبات زيتون (تقريباً 40 غرام) مثالية كوجبة خفيفة ما كتاثرش على السكر فالدم (مؤشر سكري 0). الدهون الصحية اللي فالزيتون وزيت الزيتون كتعاون على الشبع. رد البال ما تفوتش هاد الحصة باش تحكم فكمية الملح، خصوصاً إلا كان عندك ارتفاع فضغط الدم."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/db/Fresh_green_olives_and_black_olives_served_at_a_food_display.jpg/1280px-Fresh_green_olives_and_black_olives_served_at_a_food_display.jpg', ARRAY['olives', 'زيتون']::text[]),
  ('noix-cerneaux', 'Poignée de noix (krekaa)', 'قبضة ديال الكركاع', 'Handful of walnuts', 'snack', ARRAY['snack']::text[], '🌰', '5 noix (25 g)', 25, 160, 3, 1, 4, 15, 2, 15, 'Les noix (krekaa) sont les reines des oméga-3 végétaux. Une petite poignée coupe la faim, protège le cœur et n’a aucun effet sur la glycémie. STOP à 5 cerneaux.', 'الكركاع ملكة الأوميغا 3 النباتية. قبضة صغيرة كتقطع الجوع، كتحمي القلب وما عندها حتى تأثير على السكر. حبس ف5 حبات.', '["25 g de cerneaux de noix (environ 5 noix entières)","1 pincée de sel de mer fin","1/4 de cuillère à café de cannelle moulue","1/2 cuillère à café d''eau de fleur d''oranger (facultatif)","1 feuille de papier sulfurisé"]'::jsonb, '["25 غرام ديال الكركاع (تقريباً 5 كركاعات كاملين)","1 قبيصة ديال الملحة الرقيقة","1/4 معلقة صغيرة ديال القرفة مطحونة","1/2 معلقة صغيرة ديال ماء الزهر (إختياري)","1 ورقة ديال ورق الطهي"]'::jsonb, '["1. Préchauffez votre four à 150°C (thermostat 5). Si vous n''avez pas de four, vous pouvez utiliser une poêle antiadhésive à feu très doux.","2. Étalez les 25 g de cerneaux de noix sur une feuille de papier sulfurisé posée sur une plaque de cuisson.","3. Enfournez les noix pour 5 à 7 minutes. Le but est de les torréfier légèrement pour exhausser leur saveur et les rendre plus croquantes, sans les brûler. Elles doivent dégager un léger parfum grillé.","4. Si vous utilisez une poêle, faites-les revenir à sec sur feu très doux pendant 3 à 5 minutes, en remuant constamment pour éviter qu''elles ne brûlent. Retirez-les dès qu''elles sont légèrement dorées et parfumées.","5. Une fois les noix torréfiées, retirez-les du four ou de la poêle et laissez-les refroidir complètement sur la plaque. Elles deviendront plus croquantes en refroidissant.","6. Dans un petit bol, mélangez la pincée de sel fin et la 1/4 de cuillère à café de cannelle moulue. Si vous utilisez l''eau de fleur d''oranger, ajoutez la 1/2 cuillère à café à ce mélange.","7. Saupoudrez ce mélange d''épices sur les noix refroidies. Mélangez délicatement pour bien enrober chaque cerneau. Servez immédiatement ou conservez dans une boîte hermétique.","💡 Astuce diabète : Une portion de 5 cerneaux de noix (environ 25 g) est idéale comme collation. Les noix ont un indice glycémique très bas (environ 15) et sont riches en oméga-3, ce qui est excellent pour la santé cardiovasculaire sans impacter la glycémie. Évitez de les associer à des fruits secs très sucrés ou du miel pour maintenir un bon contrôle glycémique."]'::jsonb, '["1. سخّن الفران ديالك على درجة حرارة 150°C. إلا ما عندكش الفران، تقدر تستعمل مقلة ما كاتلصقش على نار مهيلة بزاف.","2. فرّق 25 غرام ديال الكركاع فوق ورقة ديال الطهي محطوطة فوق لاطة ديال الفران.","3. دخل الكركاع للفران لمدة 5 حتى لـ 7 دقايق. الهدف هو يتحمر شوية باش يطلق البنة ديالو ويولي مقرمش، بلا ما يتحرق. خاص تكون فيه ريحة خفيفة ديال التحمار.","4. إلا كنتي كتستعمل مقلة، حمر الكركاع بلا زيت على نار مهيلة بزاف لمدة 3 حتى لـ 5 دقايق، مع التحريك المستمر باش ما يتحرقش. حيدو غير يبدا يذهب اللون ديالو وتشم الريحة ديالو.","5. ملي يتحمر الكركاع، حيدو من الفران أو المقلة وخليه يبرد تماماً فوق اللاطة. غادي يولي مقرمش أكثر ملي يبرد.","6. فزلافة صغيرة، خلط قبيصة ديال الملحة الرقيقة و 1/4 معلقة صغيرة ديال القرفة مطحونة. إلا كنتي غتستعمل ماء الزهر، زيد 1/2 معلقة صغيرة لهذا الخليط.","7. رش هذا الخليط ديال التوابل فوق الكركاع اللي برد. خلط بلطف باش يتلبس كل كركاعة مزيان. قدمو مباشرة أو احتفظ بيه فبواطة محكمة الإغلاق.","💡 نصيحة للسكري: حصة ديال 5 كركاعات (تقريباً 25 غرام) مثالية كوجبة خفيفة. الكركاع عندو مؤشر سكري منخفض بزاف (تقريباً 15) وغني بالأوميغا-3، وهادشي ممتاز لصحة القلب والشرايين بلا ما يأثر على مستوى السكر فالدم. تجنب تخلطو مع فواكه جافة حلوة بزاف أو العسل باش تحافظ على تحكم جيد فالسكر."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c9/Chopped_walnuts_on_board.jpg/1280px-Chopped_walnuts_on_board.jpg', ARRAY['noix', 'kerkaa', 'كركاع']::text[]),
  ('graines-courge-tournesol', 'Graines de courge & tournesol', 'زريعة القرع ودوار الشمس', 'Pumpkin & sunflower seeds', 'snack', ARRAY['snack']::text[], '🌻', '1 petite poignée (25 g)', 25, 145, 4, 1, 6, 12, 3, 15, 'Les graines (zriaa) grillées sans sel sont riches en magnésium et en zinc, deux minéraux qui aident l’insuline à travailler. À grignoter à la place des chips ou des biscuits.', 'الزريعة المحمرة بلا ملح عامرة بالمغنيزيوم والزنك، جوج معادن كيعاونو الأنسولين يخدم. تسناك بلاصة الشيبس والبيسكوي.', '["12.5 g de graines de courge crues, non salées","12.5 g de graines de tournesol crues, non salées","1 ml d''huile d''olive extra vierge (environ 1/4 de c. à café)","1 pincée de paprika doux (environ 0.2 g)","1 pincée de cumin moulu (environ 0.2 g)","1 pincée de curcuma moulu (environ 0.2 g)"]'::jsonb, '["12.5 غرام من زريعة القرع خضرا، بلا ملح","12.5 غرام من زريعة دوار الشمس خضرا، بلا ملح","1 مللتر من زيت الزيتون البكر الممتاز (تقريبا ربع ملعقة صغيرة)","رشة صغيرة ديال التحميرة الحلوة (تقريبا 0.2 غرام)","رشة صغيرة ديال الكامون مطحون (تقريبا 0.2 غرام)","رشة صغيرة ديال الخرقوم البلدي مطحون (تقريبا 0.2 غرام)"]'::jsonb, '["1. Préchauffez votre four à 150°C (Th. 5). Si vous n''avez pas de four, une poêle à fond épais fera l''affaire sur feu doux.","2. Dans un petit bol, mélangez les 12.5 g de graines de courge et les 12.5 g de graines de tournesol. Assurez-vous qu''elles soient bien sèches.","3. Ajoutez les 1 ml d''huile d''olive aux graines et mélangez bien pour enrober toutes les graines d''une fine couche d''huile. Cela aidera les épices à adhérer.","4. Incorporez la pincée de paprika doux, la pincée de cumin moulu et la pincée de curcuma moulu. Mélangez délicatement pour que les épices soient réparties uniformément sur toutes les graines.","5. Étalez les graines assaisonnées en une seule couche sur une petite plaque de cuisson recouverte de papier sulfurisé. Si vous utilisez une poêle, étalez-les sur la poêle froide.","6. Enfournez pendant 10 à 15 minutes, ou faites griller à sec dans une poêle sur feu doux pendant 8 à 12 minutes, en remuant fréquemment pour éviter qu''elles ne brûlent. Les graines doivent être légèrement dorées et croustillantes. Laissez-les refroidir complètement avant de les consommer pour qu''elles deviennent bien croquantes.","7. 💡 Astuce diabète : Pour un contrôle optimal de la glycémie, respectez la portion de 25 g (une petite poignée) de graines grillées. Leur faible indice glycémique (GI 15) en fait une excellente alternative saine aux snacks industriels. Évitez de les saler et servez-les seules ou avec une petite salade de légumes frais pour un apport supplémentaire en fibres."]'::jsonb, '["1. سخّن الفران ديالك على درجة حرارة 150°C. إلا ما عندكش الفران، مقلة ثقيلة غتخدم الغرض على نار مهيلة.","2. فزلافة صغيرة، خلط 12.5 غرام ديال زريعة القرع و 12.5 غرام ديال زريعة دوار الشمس. تأكد بلي راهم ناشفين مزيان.","3. زيد 1 مللتر ديال زيت الزيتون على الزريعة وخلط مزيان باش كل حبة تغلف بطبقة رقيقة ديال الزيت. هادشي كيعاون العطرية تلصق.","4. زيد الرشة ديال التحميرة الحلوة، الرشة ديال الكامون مطحون والرشة ديال الخرقوم البلدي مطحون. خلط بلطف باش العطرية توزع بالتساوي على الزريعة كاملة.","5. سرح الزريعة اللي تبلات فصينية صغيرة ديال الفران مفرشة بورق الطهي، طبقة وحدة. إلا كنتي كتستعمل المقلة، سرحها فالمقلة باردة.","6. دخلها للفران لمدة 10 حتى 15 دقيقة، أو حمرها فالمقلة على نار مهيلة لمدة 8 حتى 12 دقيقة، مع التحريك المستمر باش ما تحرقش. خاص الزريعة تولي مذهبة شوية ومقرمشة. خليها تبرد تماما قبل ما تاكلها باش تولي مقرمشة مزيان.","7. 💡 نصيحة للسكري: باش تتحكم فمستوى السكر فالدم ديالك مزيان، التزم بالكمية ديال 25 غرام (قبضة يد صغيرة) ديال الزريعة المحمرة. المؤشر الجلايسيمي المنخفض ديالها (GI 15) كيخليها بديل صحي وممتاز للوجبات الخفيفة المصنعة. تجنب تمليحها وقدمها بوحدها أو مع سلطة صغيرة ديال الخضرة طرية باش تزيد من الألياف."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/c/cb/Small_home_made_bread_with_pumpkin_and_sunflower_seeds.jpg', ARRAY['zriaa', 'graines', 'زريعة']::text[]),
  ('figue-de-barbarie', 'Figues de Barbarie (karmous hindi)', 'الكرموس الهندي', 'Prickly pears', 'snack', ARRAY['snack', 'dessert']::text[], '🌵', '2 fruits (200 g)', 200, 80, 18, 12, 2, 1, 6, 35, 'Le fruit de l’été marocain : très riche en fibres, IG bas (35), rassasiant pour peu de calories. Des études suggèrent même un léger effet sur la glycémie. 2 fruits, pas plus.', 'فاكهة الصيف المغربي: عامر بالألياف، مؤشر منخفض (35)، وكيشبع بقليل ديال الكالوري. بعض الدراسات كتقول أن عندو تأثير خفيف على السكر. جوج حبات، ماشي أكثر.', '["2 pièces de Figues de Barbarie (Karmous Hindi) (environ 200 g)","50 ml d''eau froide","1 c. à café de jus de citron frais","1 pincée de sel (facultatif)"]'::jsonb, '["2 حبات كرموس هندي (حوالي 200 غرام)","50 مل ماء بارد","1 ملعقة صغيرة عصير حامض طري","1 قريصة ملح (اختياري)"]'::jsonb, '["Préparez un bol d''eau froide avec une pincée de sel et le jus de citron. Ce mélange aidera à neutraliser l''acidité et à faciliter le nettoyage des fruits.","Tenez chaque figue de Barbarie avec une fourchette ou des gants épais pour éviter les épines fines. Coupez les deux extrémités du fruit avec un couteau bien aiguisé.","Faites une incision peu profonde sur la longueur de la peau du fruit, d''une extrémité à l''autre.","Avec la pointe du couteau ou vos doigts (toujours avec des gants), décollez délicatement la peau en commençant par l''incision. La peau devrait se retirer facilement, révélant la chair juteuse.","Plongez rapidement les fruits épluchés dans le bol d''eau froide citronnée pendant 30 secondes. Cela permet de rincer les éventuelles épines résiduelles et de rafraîchir le fruit.","Égouttez les figues de Barbarie et disposez-les sur une assiette. Elles sont prêtes à être dégustées immédiatement.","💡 Astuce diabète : Consommez 2 fruits (200 g) comme portion idéale pour un snack. Leur faible indice glycémique (35) et leur richesse en fibres aident à contrôler la glycémie. Mangez-les seuls ou avant un repas léger pour profiter de leur effet rassasiant."]'::jsonb, '["حضّر زلافة فيها ماء بارد مع قريصة ملح وعصير الحامض. هاد الخليط غادي يعاون باش يحيد الحموضة ويسهل تنظيف الفاكهة.","شد كل حبة كرموس هندي بفرشيطة أو قفازات غليظة باش تتجنب الشوك الرقيق. قطع الجوانب بجوج ديال الفاكهة بموس ماضي مزيان.","دير شق خفيف على طول القشرة ديال الفاكهة، من طرف لآخر.","بواسطة رأس الموس أو صبعانك (ديما بالقفازات)، حيد القشرة بلطف بدءًا من الشق. القشرة خاصها تحيد بسهولة و تبان اللب ديال الفاكهة.","غطس الكرموس المقشر بسرعة في الزلافة ديال الماء البارد والحامض لمدة 30 ثانية. هادشي كيساعد باش تشلل الشوك اللي ممكن يكون باقي وكتبرد الفاكهة.","صفي الكرموس الهندي وحطو في طبق. هو واجد باش يتكال مباشرة.","💡 نصيحة للسكري: تناول 2 حبات (200 غرام) كوجبة خفيفة مثالية. مؤشرها الجلايسيمي المنخفض (35) وغناها بالألياف كيساعد على التحكم في مستوى السكر في الدم. كلها بوحدها أو قبل وجبة خفيفة باش تستافد من إحساس الشبع."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9e/Prickly_pears.jpg/1280px-Prickly_pears.jpg', ARRAY['karmous', 'hindi', 'كرموس هندي']::text[]),
  ('the-menthe-sans-sucre', 'Thé à la menthe SANS sucre', 'أتاي بالنعناع بلا سكر', 'Mint tea WITHOUT sugar', 'drink', ARRAY['drink']::text[], '🍵', '1 verre (150 ml)', 150, 2, 0, 0, 0, 0, 0, 0, 'Le thé vert lui-même est un ALLIÉ (antioxydants). Le problème, c''est les 3 sucres par verre : 15 g de sucre pur. Sans sucre ou avec stevia, buvez-en toute la journée.', 'الأتاي الأخضر براسو صديق (مضادات الأكسدة). المشكل هو 3 قوالب سكر فالكاس: 15 غرام سكر صافي. بلا سكر ولا بستيفيا، شرب منو النهار كامل.', '["1 c. à café de thé vert chinois (Gunpowder)","150 ml d''eau filtrée","1 branche généreuse de menthe fraîche (environ 15 g)","2-3 feuilles de verveine (facultatif)","1-2 brins de sauge (facultatif)","Quelques pistils de safran (facultatif)"]'::jsonb, '["1 معلقة صغيرة ديال أتاي أخضر صيني (الشاي البارود)","150 مل ديال الما مصفي","1 ربطة كبيرة ديال النعناع طري (تقريبا 15 غرام)","2-3 وريقات ديال اللويزة (اختياري)","1-2 عريشات ديال السالمية (اختياري)","شوية ديال شعيرات الزعفران الحر (اختياري)"]'::jsonb, '["1. Dans une petite théière ou une casserole, mettez 1 c. à café de thé vert. Rincez-le une première fois avec 50 ml d''eau bouillante, remuez et jetez cette eau. Cela permet d''enlever l''amertume et la poussière.","2. Ajoutez les 150 ml d''eau filtrée fraîche à la théière avec le thé rincé. Portez à ébullition sur feu moyen. Laissez frémir doucement pendant 2-3 minutes pour que le thé infuse bien.","3. Pendant ce temps, lavez soigneusement 1 branche généreuse de menthe fraîche. Égouttez-la bien. Si vous utilisez, rincez également les 2-3 feuilles de verveine, les 1-2 brins de sauge et les quelques pistils de safran.","4. Retirez la théière du feu. Ajoutez la menthe fraîche, la verveine, la sauge et le safran directement dans la théière avec le thé chaud. Ne remettez pas sur le feu.","5. Laissez infuser le tout pendant 5 minutes, en couvrant la théière, pour que les arômes se mélangent bien et que la menthe libère ses saveurs sans devenir amère.","6. Servez le thé chaud dans un verre de 150 ml. Vous pouvez le filtrer si vous préférez ne pas avoir les feuilles de menthe, mais traditionnellement, elles restent dans le verre.","💡 Astuce diabète : Ce thé à la menthe sans sucre est une boisson idéale pour les personnes diabétiques (GI 0). Buvez-en à volonté tout au long de la journée. Évitez de le servir avec des pâtisseries sucrées. Accompagnez-le plutôt d''amandes non salées ou d''olives pour une collation saine."]'::jsonb, '["1. فبراد صغير ولا كاسرونة، حط 1 معلقة صغيرة ديال أتاي أخضر. شللو أول مرة بـ 50 مل ديال الما طايب، حركو و كب هاد الما. هاد الشي كيحيد المرورة و الغبرة.","2. زيد 150 مل ديال الما مصفي بارد للبراد مع أتاي اللي تشلل. حطو فوق البوطة على نار متوسطة حتى يغلى. خليه يطبخ غير بشوية لمدة 2-3 دقايق باش أتاي يطلق مزيان.","3. فهاذ الوقت، غسل مزيان 1 ربطة كبيرة ديال النعناع طري. قطرو مزيان. إلا كنتي غتستعمل اللويزة و السالمية و الزعفران، غسلهم حتى هما.","4. حيد البراد من فوق البوطة. زيد النعناع طري، اللويزة، السالمية و الزعفران مباشرة للبراد مع أتاي سخون. ما ترجعوش فوق البوطة.","5. خلي كلشي يرتاح لمدة 5 دقايق، غطي البراد، باش النكهات يتخلطو مزيان و النعناع يطلق البنة ديالو بلا ما يولي مر.","6. قدم أتاي سخون فكاس ديال 150 مل. تقدر تصفيه إلا كنتي ما كتبغيش وريقات النعناع، ولكن تقليديا كيبقاو فالكاس.","💡 نصيحة للسكري: أتاي بالنعناع بلا سكر هو مشروب مثالي لمرضى السكري (مؤشر سكري 0). شرب منو شحال ما بغيتي طول النهار. تجنب تقدمو مع حلويات حلوة. قدمو مع اللوز بلا ملح ولا الزيتون كوجبة خفيفة صحية."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/6/6c/The_menthe.jpg', ARRAY['atay', 'أتاي']::text[]),
  ('eau-citron-menthe', 'Eau citron-menthe', 'ماء بالحامض والنعناع', 'Lemon-mint water', 'drink', ARRAY['drink']::text[], '🍋', '1 grand verre (300 ml)', 300, 8, 2, 1, 0, 0, 0, 0, 'L’hydratation aide les reins à éliminer l’excès de sucre. Cette eau parfumée fait oublier les sodas — 0 calorie contre 35 g de sucre par canette.', 'الماء كيعاون الكلاوي يخرجو السكر الزايد. هاد الماء المعطر كينسيك فالمونادا — 0 كالوري مقابل 35 غرام سكر فالكانيط.', '["250 ml d''eau filtrée froide","50 ml d''eau de source (pour l''infusion)","1/4 de citron jaune bio (environ 30 g)","10 feuilles de menthe fraîche (environ 2 g)","1 fine tranche de gingembre frais (environ 1 g)","1 pincée de sel de l''Himalaya"]'::jsonb, '["250 مل ماء مصفى بارد","50 مل ماء معدني (للتنقيع)","1/4 حامضة بلدية بيو (حوالي 30 غرام)","10 وريقات نعناع طري (حوالي 2 غرام)","1 شريحة رقيقة سكينجبير طري (حوالي 1 غرام)","1 قبيصة ملح الهيمالايا"]'::jsonb, '["Lavez soigneusement le quart de citron bio et les feuilles de menthe sous l''eau froide. Brossez légèrement la peau du citron si nécessaire.","Coupez le quart de citron en très fines rondelles ou en petits dés, en retirant les pépins. Le but est d''exposer un maximum de surface pour l''infusion des saveurs.","Dans un petit verre ou une tasse, placez les rondelles de citron, les 10 feuilles de menthe légèrement froissées entre vos doigts pour libérer les arômes, et la fine tranche de gingembre frais.","Versez les 50 ml d''eau de source sur les ingrédients dans le petit verre. Laissez infuser à température ambiante pendant environ 15 minutes. Cela permet aux saveurs de se diffuser doucement sans amertume.","Après 15 minutes, filtrez cette infusion concentrée à l''aide d''une petite passoire fine directement dans votre grand verre de service (300 ml), en pressant légèrement les solides pour extraire le maximum de jus et d''arômes. Jetez les résidus (citron, menthe, gingembre).","Ajoutez les 250 ml d''eau filtrée froide dans le grand verre. Mélangez délicatement avec une cuillère. Ajoutez une pincée de sel de l''Himalaya pour rehausser les saveurs et apporter des minéraux.","💡 Astuce diabète : Cette eau citron-menthe est une excellente alternative aux boissons sucrées. Sa consommation régulière, à raison d''un grand verre (300 ml) par jour, aide à maintenir une bonne hydratation essentielle pour la régulation de la glycémie. Elle a un indice glycémique de 0 et ne contient pas de sucre ajouté, ce qui la rend parfaitement adaptée. Buvez-la avant ou entre les repas pour éviter les pics de glycémie liés aux boissons sucrées."]'::jsonb, '["غسل ربع الحامضة البيو و وريقات النعناع مزيان تحت الماء البارد. حك القشرة ديال الحامض شوية إذا كان ضروري.","قطع ربع الحامضة شرائح رقاق بزاف أو مكعبات صغار، وحيد العظم. الهدف هو تخرج النكهة ديالها مزيان.","فواحد الكاس صغير، حط الشرائح ديال الحامض، و 10 وريقات ديال النعناع اللي تكوني حكيتيها شوية بين يديك باش تطلق الريحة ديالها، و الشريحة الرقيقة ديال سكينجبير الطري.","خوي 50 مل ديال الماء المعدني فوق المكونات فالكاس الصغير. خليه يتنقع فدرجة حرارة الغرفة لمدة 15 دقيقة تقريبا. هادشي كيخلي النكهات تطلق بشوية بلا ما يجي مر.","من بعد 15 دقيقة، صفي هاد الخليط المركز باستعمال مصفاة رقيقة مباشرة فكاس التقديم الكبير ديالك (300 مل)، وعصر المكونات شوية باش تخرج أكبر قدر من العصير والنكهة. لوح البقايا (الحامض، النعناع، سكينجبير).","زيد 250 مل ديال الماء المصفى البارد فالكاس الكبير. خلط بلطف بملعقة. زيد قبيصة ملح الهيمالايا باش تزيد النكهة وتوفر معادن.","💡 نصيحة للسكري: هاد الماء بالحامض والنعناع بديل ممتاز للمشروبات السكرية. الشرب ديالو بانتظام، كاس كبير (300 مل) فاليوم، كيساعد فالحفاظ على ترطيب جيد ضروري لتنظيم السكر فالدم. المؤشر الغلايسيمي ديالو هو 0 ومافيهش سكر مضاف، داكشي علاش هو مناسب جدا. شربيه قبل أو بين الوجبات باش تجنبي ارتفاع السكر فالدم اللي كيكون بسبب المشروبات السكرية."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d1/Cold_water_with_lemon_and_mint.jpg/1280px-Cold_water_with_lemon_and_mint.jpg', ARRAY['eau citron']::text[]),
  ('infusion-cannelle', 'Infusion de cannelle', 'منقوع القرفة', 'Cinnamon infusion', 'drink', ARRAY['drink']::text[], '☕', '1 tasse (200 ml)', 200, 5, 1, 0, 0, 0, 0, 0, 'Des études suggèrent que la cannelle aide modestement à réguler la glycémie. Au minimum : une boisson chaude réconfortante à 0 sucre pour remplacer le thé sucré du soir.', 'دراسات كتقول أن القرفة كتعاون شوية فتنظيم السكر. على الأقل: مشروب سخون بلا سكر كيعوض أتاي الليل المسكر.', '["200 ml d''eau filtrée","1 bâton de cannelle de Ceylan (environ 3-4 cm, 2 g)","1 tranche fine de citron bio (environ 5 g)","1 pincée de gingembre frais râpé (environ 1 g)"]'::jsonb, '["200 مل ماء مصفى","1 عود قرفة سيلانية (حوالي 3-4 سم، 2 غرام)","1 شريحة رقيقة من الحامض البلدي (حوالي 5 غرام)","1 قبيصة سكينجبير طري محكوك (حوالي 1 غرام)"]'::jsonb, '["1. Dans une petite casserole propre, versez les 200 ml d''eau filtrée.","2. Ajoutez le bâton de cannelle de Ceylan et la pincée de gingembre frais râpé dans l''eau.","3. Placez la casserole sur feu moyen et portez l''eau à frémissement. Ne laissez pas bouillir à gros bouillons pour préserver les arômes délicats.","4. Dès que l''eau commence à frémir (petites bulles apparaissent sur les bords), réduisez le feu à doux.","5. Laissez infuser doucement pendant 5 à 7 minutes. L''eau prendra une légère teinte ambrée et une odeur agréable de cannelle se dégagera.","6. Retirez la casserole du feu. À l''aide d''une petite passoire fine, filtrez l''infusion directement dans une tasse de 200 ml, en vous assurant de retirer le bâton de cannelle et le gingembre râpé.","7. Ajoutez la tranche fine de citron bio dans la tasse. Servez immédiatement et savourez chaud.","💡 Astuce diabète : Cette infusion de cannelle est une excellente alternative aux boissons sucrées. Sa valeur calorique et son indice glycémique sont quasi nuls. Consommez une tasse (200 ml) le soir pour remplacer un thé sucré ou une boisson gazeuse. La cannelle peut aider à stabiliser la glycémie, mais ne remplace en aucun cas votre traitement médical. Évitez d''ajouter du miel ou du sucre, même en petite quantité."]'::jsonb, '["1. فكاسرونة صغيرة ونقية، خوي 200 مل ديال الماء المصفى.","2. زيد عود القرفة السيلانية والقبيصة ديال سكينجبير طري محكوك فالماء.","3. حط الكاسرونة فوق نار متوسطة وخلي الماء يبدا يغلى غير بشوية. ماتخليهش يغلى بزاف باش تبقى النكهات زوينة.","4. فاش يبدا الماء يغلى (يبانو فقاعات صغار فالجناب)، نقص النار لمهيلة.","5. خليها ترتاح وتطلق لمدة 5 حتى 7 دقايق. الماء غادي ياخد لون ذهبي خفيف وريحة القرفة زوينة غادي تطلع.","6. حيد الكاسرونة من فوق النار. باستعمال صفاية رقيقة، صفي المشروب مباشرة فكأس ديال 200 مل، وتأكد أنك حيدتي عود القرفة وسكينجبير محكوك.","7. زيد الشريحة الرقيقة ديال الحامض البلدي فالكأس. قدمها دغيا واستمتع بها سخونة.","💡 نصيحة للسكري: هاد منقوع القرفة بديل ممتاز للمشروبات اللي فيها السكر. السعرات الحرارية ومؤشر السكر ديالو شبه منعدمين. شرب كاس (200 مل) فالليل باش تعوض أتاي مسكر أو مشروب غازي. القرفة ممكن تساعد فتنظيم سكر الدم، ولكنها ماتعوضش العلاج الطبي ديالك بأي شكل من الأشكال. تجنب إضافة العسل أو السكر، حتى بكمية قليلة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/43/Cinnamon_tea.JPG/1280px-Cinnamon_tea.JPG', ARRAY['cannelle', 'قرفة']::text[]),
  ('smoothie-vert', 'Smoothie vert sans sucre', 'سموذي أخضر بلا سكر', 'Green smoothie (no sugar)', 'drink', ARRAY['drink', 'ftour']::text[], '🥬', '1 verre (250 ml)', 250, 90, 14, 9, 3, 3, 4, 30, 'Contrairement aux jus de fruits (du sucre liquide !), ce smoothie garde les FIBRES : concombre + épinards + ½ pomme verte + citron. Fraîcheur sans pic.', 'عكس عصير الفواكه (سكر سائل!)، هاد السموذي كيحتفظ بالألياف: خيار وسبانخ ونص تفاحة خضراء وحامض. انتعاش بلا طلعة سكر.', '["100 g de concombre frais, non pelé","50 g d''épinards frais (environ 1 tasse compacte)","50 g de pomme verte (environ ½ petite pomme), non pelée","50 ml d''eau filtrée très froide","15 ml de jus de citron frais (environ ½ citron)","2-3 feuilles de menthe fraîche","1 pincée de gingembre frais râpé (environ 1 g)","3-4 glaçons"]'::jsonb, '["100 غرام خيار طري، بلا ما تقشروه","50 غرام سبانخ طرية (تقريباً كاس عامر مزيان)","50 غرام تفاح أخضر (تقريباً نص تفاحة صغيرة)، بلا ما تقشروه","50 ملل ماء بارد بزاف ومصفي","15 ملل عصير حامض طري (تقريباً نص حامضة)","2-3 وريقات نعناع طري","قبيصة سكينجبير طري محكوك (تقريباً 1 غرام)","3-4 طوبات ديال الثلج"]'::jsonb, '["1. Lavez soigneusement le concombre, les épinards, la pomme verte et les feuilles de menthe sous l''eau froide. Il est important de bien nettoyer les fruits et légumes car nous allons les utiliser avec leur peau pour conserver toutes les fibres.","2. Coupez le concombre en morceaux d''environ 2-3 cm. Épépinez la demi-pomme verte et coupez-la également en petits morceaux (environ 2 cm). Laissez la peau sur le concombre et la pomme.","3. Dans un blender puissant, ajoutez les 100 g de concombre coupé, les 50 g d''épinards frais, les 50 g de pomme verte coupée, les 2-3 feuilles de menthe fraîche et la pincée de gingembre frais râpé (1 g).","4. Versez les 50 ml d''eau filtrée très froide et les 15 ml de jus de citron frais dans le blender. Le liquide aidera à mixer les ingrédients plus facilement.","5. Mixez le tout à haute vitesse pendant environ 1 à 2 minutes, ou jusqu''à obtenir une consistance parfaitement lisse et homogène. Il ne doit rester aucun morceau visible. Si nécessaire, arrêtez le blender et raclez les parois avec une spatule avant de mixer à nouveau.","6. Ajoutez les 3-4 glaçons dans le blender et mixez à nouveau pendant 15 à 30 secondes, juste assez pour les concasser et bien refroidir le smoothie. Cela donnera une texture encore plus rafraîchissante.","7. Versez immédiatement le smoothie dans un verre de 250 ml. Servez et consommez sans attendre pour profiter de toutes les vitamines et de la fraîcheur. Ce smoothie est une excellente boisson pour le petit-déjeuner ou une collation légère. Il est important de ne pas le filtrer pour conserver toutes les fibres.","💡 Astuce diabète : Ce smoothie de 250 ml (environ 250 g) apporte environ 14 g de glucides et un IG bas (30) grâce à ses fibres. Pour un meilleur contrôle de la glycémie, buvez-le lentement et idéalement avant un repas léger riche en protéines et en graisses saines, comme une petite portion d''œufs brouillés ou une poignée d''amandes. Évitez de le consommer avec d''autres aliments riches en glucides pour ne pas dépasser votre apport journalier."]'::jsonb, '["1. غسلوا الخيار، السبانخ، التفاح الأخضر ووريقات النعناع مزيان تحت الماء البارد. مهم بزاف نغسلوا الفواكه والخضر مزيان حيت غادي نستعملوهم بالقشور ديالهم باش نحافظوا على جميع الألياف.","2. قطعوا الخيار طراف صغار ديال 2-3 سم. حيدوا الزريعة من نص تفاحة خضرا وقطعوها حتى هي طراف صغار (تقريباً 2 سم). خليو القشرة على الخيار والتفاح.","3. في الخلاط الكهربائي القوي، حطوا 100 غرام ديال الخيار مقطع، 50 غرام ديال السبانخ الطرية، 50 غرام ديال التفاح الأخضر مقطع، 2-3 وريقات ديال النعناع الطري وقبيصة ديال سكينجبير طري محكوك (1 غرام).","4. خويو 50 ملل ديال الماء المصفي البارد بزاف و 15 ملل ديال عصير الحامض الطري في الخلاط. السائل غادي يعاون باش يتطحنوا المكونات بسهولة أكثر.","5. طحنوا كلشي بسرعة عالية لمدة 1 حتى 2 دقائق، أو حتى تحصلوا على خليط أملس ومتجانس تماماً. خاص ما يبقاش فيه حتى شي طريف باين. إذا كان ضروري، حبسوا الخلاط وحيدوا اللي لاصق في الجناب بالسباتولا عاد عاودوا طحنوا.","6. زيدوا 3-4 طوبات ديال الثلج في الخلاط وعاودوا طحنوا لمدة 15 حتى 30 ثانية، غير باش يتكسر الثلج ويبرد السموذي مزيان. هادشي غادي يعطيه قوام منعش أكثر.","7. خويو السموذي مباشرة في كاس ديال 250 ملل. قدموه وشربوه بلا ما تعطلوا باش تستافدوا من جميع الفيتامينات والانتعاش. هاد السموذي مشروب رائع للفطور أو كوجبة خفيفة. مهم بزاف ما تصفيوهش باش تحافظوا على جميع الألياف.","💡 نصيحة للسكري: هاد السموذي ديال 250 ملل (تقريباً 250 غرام) فيه حوالي 14 غرام ديال الكربوهيدرات ومؤشر سكري منخفض (30) بفضل الألياف اللي فيه. باش تحكموا في مستوى السكر في الدم أحسن، شربوه بشوية ومن الأفضل قبل وجبة خفيفة غنية بالبروتينات والدهون الصحية، بحال كمية صغيرة ديال البيض المخفوق أو حفنة ديال اللوز. تجنبوا تشربوه مع أطعمة أخرى غنية بالكربوهيدرات باش ما تفوتوش الكمية المسموحة لكم في اليوم."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/dc/Fresh_fruit_smoothie_preparation_with_assorted_fruits_on_a_table.jpg/1280px-Fresh_fruit_smoothie_preparation_with_assorted_fruits_on_a_table.jpg', ARRAY['smoothie']::text[]),
  ('louiza', 'Infusion de verveine (louiza)', 'اللويزة', 'Verbena infusion (louiza)', 'drink', ARRAY['drink']::text[], '🌿', '1 tasse (200 ml)', 200, 2, 0, 0, 0, 0, 0, 0, 'La louiza du soir : apaise, aide à digérer et à dormir — sans une goutte de sucre. Le stress et le mauvais sommeil font monter la glycémie ; la louiza travaille pour vous.', 'لويزة الليل: كتهدن، كتعاون على الهضم والنعاس — بلا قطرة سكر. الستريس والنعاس الخايب كيطلعو السكر؛ اللويزة كتخدم معاك.', '["200 ml d''eau filtrée","1.5 g de feuilles de verveine séchées (louiza)","1 tranche fine de citron bio (environ 5 g)","1 petite feuille de menthe fraîche (facultatif)"]'::jsonb, '["200 مل ديال الما مصفي","1.5 غرام ديال وراق اللويزة ناشفين","1 طريف رقيق ديال الحامض بيو (تقريبا 5 غرام)","1 وريقة صغيرة ديال النعناع طري (اختياري)"]'::jsonb, '["Dans une petite casserole, versez les 200 ml d''eau filtrée. Portez l''eau à frémissement sur feu moyen. Ne la laissez pas bouillir à gros bouillons, juste de petites bulles se formant sur les bords.","Une fois l''eau frémissante, retirez la casserole du feu immédiatement.","Ajoutez délicatement les 1.5 g de feuilles de verveine séchées directement dans l''eau chaude.","Couvrez la casserole avec un couvercle et laissez infuser pendant 5 à 7 minutes. Il est important de couvrir pour que les huiles essentielles ne s''échappent pas avec la vapeur.","Pendant ce temps, préparez votre tasse. Si vous le souhaitez, ajoutez la petite feuille de menthe fraîche au fond de la tasse pour une touche aromatique subtile.","Après le temps d''infusion, filtrez l''infusion à travers une petite passoire fine directement dans votre tasse pour retirer les feuilles de verveine.","Ajoutez la tranche fine de citron bio dans l''infusion chaude. Servez immédiatement et dégustez.","💡 Astuce diabète : Cette infusion est naturellement sans sucre et n''a aucun impact sur la glycémie. Elle peut être consommée le soir pour favoriser la détente et un meilleur sommeil, ce qui est bénéfique pour la gestion du diabète de type 2. Évitez d''ajouter du miel ou du sucre, même en petite quantité, pour maintenir son indice glycémique à zéro."]'::jsonb, '["فكسرونة صغيرة، خوي 200 مل ديال الما مصفي. خلي الما يسخن فوق عافية متوسطة حتى يبدا يغلي غير بشوية، ماشي يطبخ بزاف، غير تشوف فقاعات صغار كيتكونو فالجناب.","ملي يبدا الما يغلي، حيد الكسرونة من فوق العافية فالحين.","زيد 1.5 غرام ديال وراق اللويزة ناشفين غير بشوية مباشرة فالما سخون.","غطّي الكسرونة وخليها تطلق لمدة 5 حتى 7 دقائق. مهم تغطيها باش الزيوت الأساسية مايطيروش مع البخار.","فهاد الوقت، وجد الكاس ديالك. إلا بغيتي، زيد وريقة صغيرة ديال النعناع طري فالقاع ديال الكاس باش تعطي نكهة خفيفة.","من بعد ما تطلق اللويزة، صفيها بمصفاة رقيقة مباشرة فالكاس ديالك باش تحيد وراق اللويزة.","زيد الطريف الرقيق ديال الحامض بيو فاللويزة سخونة. قدمها فالحين واستمتع بها.","💡 نصيحة للسكري: هاد اللويزة طبيعية ومافيهاش السكر وماكتاثرش على نسبة السكر فالدم. تقدر تشربها فالليل باش تساعدك على الاسترخاء ونعاس حسن، وهادشي مزيان لتدبير داء السكري من النوع 2. تجنب تزيد العسل أو السكر، حتى بكمية قليلة، باش تحافظ على المؤشر الجلايسيمي ديالها صفر."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6f/Herbal_Tea_01.jpg/1280px-Herbal_Tea_01.jpg', ARRAY['verveine', 'لويزة']::text[]),
  ('cafe-cannelle', 'Café noir à la cannelle', 'قهوة كحلة بالقرفة', 'Black coffee with cinnamon', 'drink', ARRAY['drink', 'ftour']::text[], '☕', '1 tasse (150 ml)', 150, 5, 1, 0, 0, 0, 0, 0, 'Le café noir sans sucre n’a quasi aucun effet sur la glycémie et une pincée de cannelle le rend savoureux sans une calorie. Le vrai piège du diabétique, ce sont les 2 sucres habituels.', 'القهوة الكحلة بلا سكر ما عندها حتى تأثير على السكر، وشوية قرفة كتخليها بنينة بلا كالوري. الفخ الحقيقي ديال السكري هو جوج قوالب السكر المعتادين.', '["150 ml d''eau filtrée","1 c. à soupe de café moulu (torréfaction moyenne, 100% Arabica)","1/4 c. à café de cannelle moulue","1 pincée de sel (facultatif)"]'::jsonb, '["150 مل ماء مفلتر","1 م.ك. قهوة مطحونة (تحميص متوسط، 100% أرابيكا)","1/4 م.ص. قرفة مطحونة","1 قبيصة ملح (اختياري)"]'::jsonb, '["1. Dans une petite casserole ou une cafetière de type \"ibrik\" (djezva), versez les 150 ml d''eau filtrée.","2. Ajoutez délicatement la 1 c. à soupe de café moulu. Ne mélangez pas immédiatement pour permettre au café de s''imbiber progressivement.","3. Incorporez la 1/4 c. à café de cannelle moulue et la pincée de sel si vous l''utilisez. Le sel aide à rehausser les arômes du café.","4. Placez la casserole sur feu doux à moyen. Laissez chauffer doucement sans faire bouillir à gros bouillons. Surveillez attentivement.","5. Dès que vous voyez une mousse commencer à se former sur le dessus et que le café monte légèrement (avant l''ébullition complète), retirez la casserole du feu.","6. Laissez reposer quelques secondes pour que le marc se dépose au fond. Versez doucement le café dans une tasse de 150 ml, en évitant de verser le marc.","7. 💡 Astuce diabète : Cette boisson est idéale car elle ne contient ni sucre ni édulcorant artificiel. Pour un contrôle optimal de la glycémie, savourez-la telle quelle. Évitez d''ajouter du sucre ou du lait sucré, qui augmenteraient rapidement votre indice glycémique. Une portion de 150 ml est parfaite."]'::jsonb, '["1. فشي كاسرونة صغيرة ولا براد ديال القهوة (جذوة)، خوي 150 مل ديال الماء مفلتر.","2. زيد بشوية 1 م.ك. ديال القهوة مطحونة. متخلطش دغيا باش القهوة تشرب الماء بشوية.","3. زيد 1/4 م.ص. ديال القرفة مطحونة و قبيصة الملح إذا كنتي غتستعملها. الملح كيساعد باش يبانو النكهات ديال القهوة.","4. حط الكاسرونة فوق نار مهيلة حتى لمتوسطة. خليها تسخن بشوية بلا ما تخليها تغلى بزاف. راقبها مزيان.","5. فاش تبدا تشوف الرغوة كتكون الفوق و القهوة كطلع شوية (قبل ما تغلى كليا)، حيد الكاسرونة من فوق النار.","6. خليها ترتاح شي ثواني باش التفل يهبط لتحت. خوي القهوة بشوية فكاس ديال 150 مل، وحاول متخويش التفل.","7. 💡 نصيحة للسكري: هاد المشروب مثالي حيت مافيه لا سكر لا محليات اصطناعية. باش تحافظ على مستوى السكر فدمك مزيان، شربو كيفما هو. تجنب تزيد السكر ولا الحليب المحلى، لي غادي يرفعو مؤشر السكر فدمك بسرعة. حصة ديال 150 مل هي القياس المثالي."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/b/be/Coffee-and-cinnamon.jpg', ARRAY['café', 'قهوة']::text[]),
  ('karkade-sans-sucre', 'Karkadé (hibiscus) sans sucre', 'الكركديه بلا سكر', 'Hibiscus tea (no sugar)', 'drink', ARRAY['drink']::text[], '🌺', '1 grand verre (300 ml)', 300, 5, 1, 0, 0, 0, 0, 0, 'Infusion rouge riche en antioxydants, connue pour aider à faire baisser la tension — un plus quand le diabète menace le cœur. Servi frais et sans sucre, il remplace les sodas rouges.', 'منقوع أحمر عامر بمضادات الأكسدة، معروف باللي كيعاون على تنقيص التونسيو — زيادة مزيانة ملي السكري كيهدد القلب. مقدم بارد وبلا سكر، كيعوض المونادا الحمراء.', '["10 g de fleurs d''hibiscus séchées (karkadé)","300 ml d''eau filtrée","1 rondelle de citron vert (environ 5 g)","2 feuilles de menthe fraîche (environ 1 g)","1 pincée de cannelle en poudre (environ 0.5 g)"]'::jsonb, '["10 غرام من أزهار الكركديه المجففة","300 مل من الماء المصفى","1 شريحة ليمون أخضر (حوالي 5 غرام)","2 ورقات نعناع طازج (حوالي 1 غرام)","1 قريصة قرفة مطحونة (حوالي 0.5 غرام)"]'::jsonb, '["1. Dans une petite casserole, versez 300 ml d''eau filtrée. Portez l''eau à ébullition sur feu moyen-vif.","2. Une fois l''eau bouillante, retirez la casserole du feu. Ajoutez immédiatement les 10 g de fleurs d''hibiscus séchées dans l''eau chaude.","3. Couvrez la casserole et laissez infuser les fleurs d''hibiscus pendant 10 à 15 minutes. Plus l''infusion est longue, plus la couleur et le goût seront intenses. Surveillez la couleur rouge rubis foncée.","4. Après l''infusion, filtrez le liquide à travers une passoire fine pour retirer toutes les fleurs d''hibiscus. Pressez légèrement les fleurs pour extraire le maximum de saveur.","5. Laissez le karkadé refroidir complètement à température ambiante, puis placez-le au réfrigérateur pendant au moins 1 heure pour qu''il soit bien frais.","6. Au moment de servir, versez le karkadé frais dans un grand verre (300 ml). Ajoutez la rondelle de citron vert et les feuilles de menthe fraîche pour la décoration et une touche aromatique.","7. Saupoudrez une pincée de cannelle en poudre sur le dessus de la boisson juste avant de déguster. La cannelle ajoute une note chaleureuse et est connue pour ses bienfaits sur la glycémie.","💡 Astuce diabète : Ce karkadé sans sucre est une excellente alternative aux boissons sucrées. Sa portion de 300 ml est idéale. Il a un indice glycémique de 0. Servez-le toujours bien frais et évitez d''ajouter du miel ou d''autres édulcorants caloriques. Il peut être consommé à tout moment de la journée."]'::jsonb, '["1. فكاسرونة صغيرة، خوي 300 مل من الماء المصفى. خلي الماء يغلى على نار متوسطة مجهدة.","2. ملي يغلى الماء، حيد الكاسرونة من فوق النار. زيد مباشرة 10 غرام ديال أزهار الكركديه المجففة فالماء السخون.","3. غطي الكاسرونة وخلي الكركديه يترقد لمدة 10 حتى 15 دقيقة. كل ما ترقد كثر، كل ما اللون والمذاق غيكونوا أقوى. راقب اللون الأحمر الغامق ديال الياقوت.","4. من بعد ما يترقد، صفي السائل فمصفاة رقيقة باش تحيد جميع أزهار الكركديه. عصر الأزهار شوية باش تستخلص أكبر قدر من المذاق.","5. خلي الكركديه يبرد تمامًا فدرجة حرارة الغرفة، من بعد حطو فالثلاجة على الأقل ساعة باش يبرد مزيان.","6. فاش تبغي تقدمو، خوي الكركديه البارد فكاس كبير (300 مل). زيد شريحة الليمون الأخضر ووريقات النعناع الطازجة للتزيين ولمسة عطرية.","7. رش قريصة قرفة مطحونة فوق المشروب قبل ما تشربو مباشرة. القرفة كتزيد نكهة دافئة ومعروفة بفوائدها على مستوى السكر فالدم.","💡 نصيحة للسكري: هاد الكركديه بلا سكر بديل ممتاز للمشروبات اللي فيها السكر. الكمية ديال 300 مل مثالية. عندو مؤشر سكري 0. قدمو دايماً بارد مزيان وتجنب تزيد العسل أو أي محليات أخرى فيها سعرات حرارية. ممكن يتشرب فأي وقت من النهار."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/89/Chai_torsh_-_Hibiscus_tea.png/1280px-Chai_torsh_-_Hibiscus_tea.png', ARRAY['hibiscus', 'كركديه']::text[]),
  ('atay-siba', 'Thé aux herbes (atay siba, sans sucre)', 'أتاي بالأعشاب بلا سكر', 'Herbal tea (atay siba, no sugar)', 'drink', ARRAY['drink']::text[], '🌿', '1 verre (150 ml)', 150, 3, 0, 0, 0, 0, 0, 0, 'Le thé du bled aux herbes de montagne (chiba, zaïtra, fliyou, louiza) : réconfortant, digestif, à 0 sucre. Toute la chaleur du Maroc dans un verre qui ne touche pas la glycémie.', 'أتاي البلاد بأعشاب الجبل (الشيبة، الزعيترة، الفليو، اللويزة): مريح، كيعاون على الهضم، وبلا سكر. كل دفا المغرب فكاس ما كيمسش السكر.', '["1 sachet de thé vert marocain (type Gunpowder)","5 g de chiba (armoise)","3 g de zaïtra (thym sauvage)","3 g de fliyou (menthe pouliot)","2 g de louiza (verveine citronnelle)","150 ml d''eau filtrée"]'::jsonb, '["1 صاشي ديال أتاي أخضر مغربي (نوع بارود)","5 غرام ديال الشيبة","3 غرام ديال الزعتر","3 غرام ديال فليو","2 غرام ديال اللويزة","150 ملل ديال الماء مصفي"]'::jsonb, '["Dans une petite théière ou une casserole, rincez le sachet de thé vert avec une petite quantité d''eau bouillante (environ 30 ml) pendant quelques secondes, puis jetez cette première eau. Cette étape permet d''éliminer l''amertume et la poussière du thé.","Ajoutez le sachet de thé rincé dans la théière. Incorporez ensuite la chiba, la zaïtra, le fliyou et la louiza.","Faites bouillir les 150 ml d''eau filtrée dans une bouilloire ou une petite casserole jusqu''à ce qu''elle atteigne un frémissement intense.","Versez l''eau bouillante directement sur le mélange de thé et d''herbes dans la théière.","Laissez infuser le thé et les herbes pendant 5 à 7 minutes. Pour une saveur plus prononcée, vous pouvez laisser infuser un peu plus longtemps, mais ne dépassez pas 10 minutes pour éviter l''amertume.","Après l''infusion, remuez délicatement le thé avec une cuillère. Servez immédiatement dans un verre (150 ml).","💡 Astuce diabète : Ce thé aux herbes est une excellente boisson sans sucre, avec un GI de 0, idéale pour les personnes atteintes de diabète de type 2. Il peut être consommé à tout moment de la journée sans impact sur la glycémie. Évitez d''y ajouter du sucre ou des édulcorants artificiels. Accompagnez-le d''une poignée d''amandes ou de noix pour une collation saine et équilibrée si vous avez faim."]'::jsonb, '["فبراد صغير ولا كاسرونة، شلل صاشي ديال أتاي أخضر بشوية ديال الماء طايب (تقريبا 30 ملل) لشي ثواني، ومن بعد لوح هاد الما اللول. هاد الخطوة كتحيد المرورة والغبرة من أتاي.","زيد صاشي ديال أتاي اللي تشلل فالبراد. من بعد، زيد الشيبة، الزعتر، فليو واللويزة.","غلي 150 ملل ديال الماء مصفي فغلاي ولا كاسرونة صغيرة حتى يوصل لدرجة الغليان القوية.","خوي الماء طايب مباشرة فوق خليط أتاي والأعشاب فالبراد.","خلي أتاي والأعشاب يتشربو لمدة 5 حتى 7 دقايق. باش يجي المذاق أقوى، تقدر تخليه يتشرب شوية كثر، ولكن متفوتش 10 دقايق باش ميجيش مر.","من بعد ما يتشرب، حرك أتاي غير بشوية بالمعلقة. قدمو مباشرة فكاس (150 ملل).","💡 نصيحة للسكري: هاد أتاي بالأعشاب مشروب ممتاز بلا سكر، المؤشر الكلايسيمي ديالو 0، مثالي للناس اللي عندهم السكري من النوع 2. ممكن يتشرب فأي وقت فاليوم بلا ما يأثر على نسبة السكر فالدم. تجنب تزيد عليه السكر أو المحليات الصناعية. رافقو بشي قبصة ديال اللوز أو الكركاع كسناك صحي ومتوازن إلا حسيتي بالجوع."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3b/Krasnoyarsk_Stolby%2C_Herbal_tea%2C_Herbal_infusion%2C_Taiga_forest_tea%2C_Russia.jpg/1280px-Krasnoyarsk_Stolby%2C_Herbal_tea%2C_Herbal_infusion%2C_Taiga_forest_tea%2C_Russia.jpg', ARRAY['chiba', 'fliyou', 'أتاي أعشاب']::text[]),
  ('salade-fruits-cannelle', 'Salade de fruits frais à la cannelle', 'شلاضة الفواكه بالقرفة', 'Fresh fruit salad with cinnamon', 'dessert', ARRAY['dessert', 'snack']::text[], '🍓', '1 bol (180 g)', 180, 90, 20, 16, 1, 0, 4, 35, 'Fruits ENTIERS à IG bas (fraise, orange, pomme, kiwi) — jamais de sirop ni sucre ajouté. La cannelle donne le goût "dessert" sans une calorie.', 'فواكه كاملة بمؤشر منخفض (فريز، ليمون، تفاح، كيوي) — بلا سيرو وبلا سكر مزيود. القرفة كتعطي ذوق الحلوى بلا كالوري.', '["50 g fraises fraîches, équeutées et coupées en quatre","40 g orange, pelée à vif et coupée en dés (environ 1/4 d''orange moyenne)","40 g pomme rouge (type Gala ou Fuji), non pelée, coupée en dés","30 g kiwi, pelé et coupé en rondelles ou en dés","10 ml jus de citron frais (environ 1/2 citron)","1/2 c. à café cannelle moulue","1 pincée de menthe fraîche ciselée (pour la garniture, facultatif)"]'::jsonb, '["50 غرام فريز طري، محيد العرش ومقطع على أربعة","40 غرام ليمون (تشين)، مقشر مزيان ومقطع مربعات صغار (تقريبا ربع ليمونة متوسطة)","40 غرام تفاح أحمر (نوع كالا أو فوجي)، بلا ما تقشريه، مقطع مربعات صغار","30 غرام كيوي، مقشر ومقطع دوائر أو مربعات","10 ملل عصير حامض طري (تقريبا نص حامضة)","نص ملعقة صغيرة قرفة مطحونة","رشة نعناع طري مقطع رقيق (للتزيين، اختياري)"]'::jsonb, '["1. Préparer les fruits : Lavez soigneusement les fraises, l''orange, la pomme et le kiwi. Équeutez les fraises et coupez-les en quatre. Pelez l''orange à vif (retirez la peau blanche et les membranes) puis coupez la chair en petits dés. Coupez la pomme (avec la peau) en dés de taille similaire. Pelez le kiwi et coupez-le en rondelles ou en dés.","2. Dans un bol de taille moyenne, mélangez délicatement les fraises coupées (50 g), les dés d''orange (40 g), les dés de pomme (40 g) et les morceaux de kiwi (30 g).","3. Pressez le jus d''un demi-citron frais (environ 10 ml) et versez-le sur les fruits. Le jus de citron aide à prévenir l''oxydation de la pomme et ajoute une touche de fraîcheur.","4. Saupoudrez la demi-cuillère à café de cannelle moulue sur l''ensemble des fruits. La cannelle est l''ingrédient clé qui apporte une saveur douce et chaleureuse sans ajout de sucre.","5. Mélangez délicatement tous les ingrédients à l''aide d''une cuillère en bois ou d''une spatule, en veillant à ne pas écraser les fruits. Assurez-vous que la cannelle et le jus de citron sont bien répartis.","6. Laissez reposer la salade de fruits au réfrigérateur pendant au moins 15 à 20 minutes avant de servir. Cela permet aux saveurs de se mélanger et aux fruits de bien s''imprégner de la cannelle.","7. Servez la salade de fruits frais dans un petit bol individuel (environ 180 g par portion). Si désiré, garnissez d''une pincée de menthe fraîche ciselée juste avant de déguster pour une touche aromatique. 💡 Astuce diabète : Cette salade est conçue pour être une portion unique de 180 g, apportant environ 90 kcal et 20 g de glucides avec un IG bas (35). Consommez-la en fin de repas principal pour bénéficier des fibres qui ralentissent l''absorption du sucre, et évitez de la combiner avec d''autres desserts sucrés."]'::jsonb, '["1. وجدي الفواكه: غسلي الفريز، الليمون، التفاح والكيوي مزيان. حيدي العرش للفريز وقطعيه على أربعة. قشري الليمون مزيان (حيدي القشرة البيضاء والخيوط) وقطعيه مربعات صغار. قطعي التفاح (بالقشرة ديالو) مربعات بنفس الحجم. قشري الكيوي وقطعيه دوائر أو مربعات.","2. فزلافة متوسطة، خلطي بلطف الفريز المقطع (50 غرام)، مربعات الليمون (40 غرام)، مربعات التفاح (40 غرام) وقطع الكيوي (30 غرام).","3. عصري نص حامضة طرية (تقريبا 10 ملل) وكبيها فوق الفواكه. عصير الحامض كيعاون باش التفاح ما يكحالش وكيزيد لمسة ديال الانتعاش.","4. رشي نص ملعقة صغيرة ديال القرفة مطحونة فوق جميع الفواكه. القرفة هي المكون الأساسي اللي كيعطي مذاق حلو ودافئ بلا ما تزيدي السكر.","5. خلطي بلطف جميع المكونات بملعقة خشبية أو سباتول، ردي البال باش ما تعصريش الفواكه. تأكدي أن القرفة وعصير الحامض توزعو مزيان.","6. خلي شلاضة الفواكه ترتاح فالثلاجة على الأقل 15 حتى 20 دقيقة قبل التقديم. هادشي كيخلي النكهات يتخلطو والفواكه تشرب القرفة مزيان.","7. قدمي شلاضة الفواكه الطرية فزلافة صغيرة فردية (تقريبا 180 غرام لكل حصة). إذا بغيتي، زيني برشة ديال النعناع الطري مقطع رقيق قبل ما تاكليها مباشرة باش تزيدي لمسة عطرية. 💡 نصيحة للسكري: هاد الشلاضة مصممة باش تكون حصة وحدة ديال 180 غرام، كتعطي تقريبا 90 سعرة حرارية و 20 غرام ديال الكربوهيدرات بمؤشر سكري منخفض (35). كوليها فآخر الوجبة الرئيسية باش تستافدي من الألياف اللي كتبطئ امتصاص السكر، وتجنبي تجمعيها مع حلويات أخرى حلوة."]'::jsonb, null, ARRAY['salade fruits']::text[]),
  ('compote-sans-sucre', 'Compote de pommes sans sucre', 'كومبوت التفاح بلا سكر', 'No-sugar apple compote', 'dessert', ARRAY['dessert', 'snack']::text[], '🍏', '1 pot (120 g)', 120, 70, 16, 14, 0, 0, 2, 35, 'Cuite avec cannelle et zéro sucre ajouté, la compote calme l’envie de sucré à 70 kcal. À faire maison : la version industrielle "sans sucres ajoutés" reste la meilleure alternative aux pâtisseries.', 'مطيبة بالقرفة وبلا سكر مزيود، الكومبوت كتهدن الرغبة فالحلو ب70 كالوري برك. أحسن بديل للحلويات.', '["120 g de pommes (environ 1 petite pomme)","50 ml d''eau","1/2 bâton de cannelle","1/4 de cuillère à café de jus de citron frais","1 pincée de sel","1/4 de cuillère à café d''extrait de vanille (facultatif)"]'::jsonb, '["120 غرام ديال التفاح (تقريبا تفاحة صغيرة وحدة)","50 ملليلتر ديال الما","نص عود ديال القرفة","ربع معلقة صغيرة ديال عصير الحامض طري","قبيصة ديال الملحة","ربع معلقة صغيرة ديال خلاصة الفانيلا (اختياري)"]'::jsonb, '["1. Lavez soigneusement la pomme. Épluchez-la, retirez le trognon et coupez-la en petits dés d''environ 1 à 2 cm. Cette taille permet une cuisson plus rapide et homogène.","2. Dans une petite casserole à fond épais, mettez les dés de pomme, les 50 ml d''eau, le demi-bâton de cannelle et la pincée de sel. Le sel rehausse les saveurs naturelles de la pomme.","3. Couvrez la casserole et faites cuire à feu doux pendant environ 10 à 12 minutes. Remuez de temps en temps pour éviter que les pommes n''attachent au fond. Les pommes doivent devenir tendres et commencer à se défaire.","4. Une fois les pommes bien tendres, retirez le bâton de cannelle de la casserole. Si vous préférez une texture plus lisse, vous pouvez écraser les pommes à l''aide d''une fourchette ou d''un presse-purée directement dans la casserole. Pour une compote très lisse, passez-la au mixeur plongeant.","5. Ajoutez le quart de cuillère à café de jus de citron frais. Le citron aide à préserver la couleur de la compote et apporte une légère touche d''acidité qui équilibre le goût. Si vous utilisez l''extrait de vanille, ajoutez-le à ce moment.","6. Laissez la compote refroidir complètement à température ambiante. Une fois froide, transférez-la dans un petit pot ou un ramequin. La compote épaissira légèrement en refroidissant.","7. Servez la compote de pommes sans sucre comme dessert léger. Elle peut être consommée telle quelle ou accompagnée d''une petite portion de yaourt nature sans sucre. Conservez au réfrigérateur et consommez dans les 2-3 jours. Le pot de 120 g est la portion idéale.","💡 Astuce diabète : Cette compote de 120 g (environ 70 kcal, 16 g de glucides, GI 35) est un excellent choix pour calmer une envie de sucré. Pour optimiser la glycémie, consommez-la en fin de repas, après les légumes et les protéines, ou comme collation équilibrée. Évitez de l''associer à d''autres aliments sucrés ou à des féculents raffinés."]'::jsonb, '["1. غسل التفاح مزيان. قشروه، حيدو ليه القلب ديالو وقطعوه مكعبات صغار قياس 1 حتى 2 سنتيمتر. هاد الحجم كيخلي التفاح يطيب دغيا وبشكل متساوي.","2. فكاسرونة صغيرة وثقيلة، حطو مكعبات التفاح، 50 ملليلتر ديال الما، نص عود ديال القرفة وقبيصة الملحة. الملحة كتعزز النكهات الطبيعية ديال التفاح.","3. غطيو الكاسرونة وخليوها طيب على نار مهيلة لمدة 10 حتى 12 دقيقة. حركو مرة مرة باش التفاح ما يلصقش فالقاع. التفاح خاصو يولي رطب ويبدا يتفرتت.","4. ملي يولي التفاح رطب مزيان، حيدو عود القرفة من الكاسرونة. إذا كنتو كتفضلو قوام أملس، يمكن ليكم تهرسو التفاح بالفرشيطة أو بالهراسة مباشرة فالكاسرونة. باش تحصلو على كومبوت أملس بزاف، استعملو الخلاط اليدوي.","5. زيدو ربع معلقة صغيرة ديال عصير الحامض طري. الحامض كيساعد باش الكومبوت يحافظ على لونو وكيعطي واحد الحموضة خفيفة اللي كتوازن المذاق. إذا كنتو غتستعملو خلاصة الفانيلا، زيدوها فهاد المرحلة.","6. خليو الكومبوت يبرد تماما فدرجة حرارة الغرفة. ملي يبرد، حطوه فشي زلافة صغيرة أو طاس. الكومبوت كيتقال شوية ملي كيبرد.","7. قدمو كومبوت التفاح بلا سكر كتحلية خفيفة. يمكن تاكلوه بوحدو أو مع شوية ديال ياغورت طبيعي بلا سكر. احتفظو بيه فالثلاجة وتاكلوه فظرف 2-3 أيام. الطاس ديال 120 غرام هو الحصة المثالية.","💡 نصيحة للسكري: هاد الكومبوت ديال 120 غرام (تقريبا 70 سعرة حرارية، 16 غرام كربوهيدرات، مؤشر سكري 35) اختيار ممتاز باش تهدأ شهوة الحلاوة. باش تحافظو على مستوى السكر فالدم، كلوه فآخر الوجبة، من بعد الخضراوات والبروتينات، أو كوجبة خفيفة متوازنة. تجنبو تاكلوه مع أطعمة أخرى حلوة أو نشويات مكررة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/92/Apfelkompott.jpg/1280px-Apfelkompott.jpg', ARRAY['compote']::text[]),
  ('oranges-cannelle', 'Oranges à la cannelle (dessert fassi)', 'الليمون بالقرفة', 'Cinnamon oranges (Fassi dessert)', 'dessert', ARRAY['dessert']::text[], '🍊', '1 orange (150 g)', 150, 70, 17, 14, 1, 0, 3, 40, 'Le dessert marocain traditionnel le PLUS adapté au diabète : l’orange entière garde ses fibres (contrairement au jus), la cannelle et la fleur d’oranger font le reste.', 'الحلوى المغربية التقليدية الأنسب للسكري: الليمونة الكاملة كتحتفظ بأليافها (عكس العصير)، والقرفة وماء الزهر كيكملو.', '["1 orange (environ 150 g)","1/2 cuillère à café de cannelle moulue","1 cuillère à café d''eau de fleur d''oranger","1/4 cuillère à café de stévia en poudre (facultatif)","1 feuille de menthe fraîche (pour la décoration)"]'::jsonb, '["1 ليمونة (حوالي 150 غرام)","1/2 معلقة صغيرة قرفة مطحونة","1 معلقة صغيرة ماء الزهر","1/4 معلقة صغيرة ستيفيا بودرة (اختياري)","1 ورقة نعناع طري (للتزيين)"]'::jsonb, '["1. Lavez soigneusement l''orange sous l''eau froide. À l''aide d''un couteau bien aiguisé, pelez l''orange à vif en retirant toute la peau blanche et amère, ne laissant que la chair juteuse. Travaillez au-dessus d''une assiette pour récupérer le jus.","2. Coupez l''orange en rondelles d''environ 0,5 cm d''épaisseur. Disposez délicatement les rondelles sur une assiette de présentation, en les chevauchant légèrement pour un bel effet visuel.","3. Dans un petit bol, mélangez la 1/2 cuillère à café de cannelle moulue avec la 1 cuillère à café d''eau de fleur d''oranger. Si vous utilisez la stévia, ajoutez la 1/4 cuillère à café de stévia en poudre à ce mélange et remuez bien pour dissoudre.","4. Versez uniformément le mélange de cannelle et de fleur d''oranger sur les rondelles d''orange. Assurez-vous que chaque tranche est légèrement enrobée.","5. Laissez reposer le dessert au réfrigérateur pendant au moins 15 à 20 minutes. Cela permet aux saveurs de bien se mélanger et à l''orange de s''imprégner des arômes.","6. Juste avant de servir, décorez chaque portion avec une feuille de menthe fraîche au centre de l''assiette pour une touche de couleur et de fraîcheur.","7. Servez frais. Ce dessert est idéal en fin de repas léger. \n💡 Astuce diabète : Consommez une portion d''une seule orange (environ 150g) pour contrôler l''apport en glucides (environ 17g). Le GI de l''orange entière est modéré (environ 40). Mangez ce dessert après un repas riche en fibres et en protéines pour ralentir l''absorption du sucre."]'::jsonb, '["1. غسل الليمونة مزيان تحت الما بارد. باستعمال موس ماضي، قشر الليمونة مزيان وحيد ليها القشرة البيضاء المرة كاملة، خلي غير اللب ديالها. خدم فوق طبسيل باش تجمع العصير اللي يطيح.","2. قطع الليمونة دوائر بسمك حوالي 0.5 سم. ستف الدوائر بلطف فوق طبسيل التقديم، خليها متراكبة شوية باش يجي المنظر زوين.","3. فزلافة صغيرة، خلط 1/2 معلقة صغيرة ديال القرفة مطحونة مع 1 معلقة صغيرة ديال ماء الزهر. إلا كنتي غتستعمل ستيفيا، زيد 1/4 معلقة صغيرة ديال ستيفيا بودرة لهاد الخليط وخلط مزيان باش تذوب.","4. خوي خليط القرفة وماء الزهر بالتساوي فوق دوائر الليمون. تأكد أن كل دائرة تغطات شوية.","5. خلي التحلية ترتاح فالثلاجة على الأقل 15 حتى لـ 20 دقيقة. هادشي كيخلي النكهات يتخلطو مزيان والليمون يتشرب الروائح.","6. قبل التقديم مباشرة، زين كل حصة بورقة نعناع طري فوسط الطبسيل باش تعطي لمسة ديال اللون والانتعاش.","7. قدمها باردة. هاد التحلية مثالية فآخر وجبة خفيفة. \n💡 نصيحة للسكري: تناول حصة واحدة فقط من الليمون (حوالي 150 غرام) للتحكم في كمية الكربوهيدرات (حوالي 17 غرام). المؤشر الجلايسيمي للبرتقال الكامل معتدل (حوالي 40). تناول هذه التحلية بعد وجبة غنية بالألياف والبروتين لإبطاء امتصاص السكر."]'::jsonb, null, ARRAY['orange cannelle']::text[]),
  ('dattes-noix', '2 dattes fourrées aux noix', 'جوج تمرات معمرين بالكركاع', '2 dates stuffed with walnuts', 'dessert', ARRAY['dessert', 'snack']::text[], '🌴', '2 dattes + noix (30 g)', 30, 110, 20, 17, 2, 3, 2, 45, 'Les dattes sont sucrées, oui — mais DEUX dattes avec des noix (les graisses ralentissent le sucre) restent un plaisir gérable. La règle absolue : 2, pas 10.', 'التمر مسكر، صحيح — ولكن جوج تمرات بالكركاع (الدهون كتبطئ السكر) كيبقاو متعة ممكنة. القاعدة: جوج، ماشي عشرة.', '["2 pièces de dattes Medjool (environ 25g)","5 g de cerneaux de noix (environ 2-3 moitiés)","1 pincée de cannelle moulue","1/4 de cuillère à café d''eau de fleur d''oranger","1/2 cuillère à café de graines de sésame grillées (pour la garniture)"]'::jsonb, '["2 حبات تمر مجهول (حوالي 25 غرام)","5 غرام كركاع (حوالي 2-3 نصاص)","قبيصة قرفة مطحونة","1/4 معلقة صغيرة ماء الزهر","1/2 معلقة صغيرة زنجلان محمر (للتزيين)"]'::jsonb, '["Commencez par préparer les dattes. À l''aide d''un petit couteau pointu, faites une incision longitudinale sur un côté de chaque datte et retirez délicatement le noyau. Veillez à ne pas couper la datte complètement en deux pour qu''elle puisse être farcie.","Dans un petit bol, mélangez les 5 g de cerneaux de noix concassés grossièrement avec la pincée de cannelle moulue et le 1/4 de cuillère à café d''eau de fleur d''oranger. Malaxez bien pour que les saveurs se mélangent.","Prenez une datte dénoyautée et, à l''aide d''une petite cuillère ou de vos doigts, farcissez l''intérieur avec la moitié du mélange de noix préparé. Appuyez légèrement pour que la farce tienne bien.","Répétez l''opération avec la deuxième datte et le reste du mélange de noix.","Une fois les deux dattes farcies, disposez-les délicatement sur une petite assiette de service.","Saupoudrez chaque datte farcie avec 1/4 de cuillère à café de graines de sésame grillées pour ajouter une touche de croquant et de saveur.","💡 Astuce diabète : Savourez ces deux dattes farcies comme une petite douceur après un repas équilibré. Les noix ralentissent l''absorption du sucre des dattes, mais la clé est la portion : ne dépassez jamais les deux dattes. Le GI de cette portion est modéré (environ 45). Pour un meilleur contrôle, mangez-les après un repas riche en fibres et protéines, jamais à jeun."]'::jsonb, '["أول حاجة، وجد التمر. باستعمال موس صغير ومضي، حل التمرة من الجنب بالطول وحيد العظم بشوية. رد البال ما تقطعش التمرة كاملة باش تقدر تعمرها.","فزلافة صغيرة، خلط 5 غرام ديال الكركاع مهرمش غليظ مع قبيصة القرفة مطحونة و 1/4 معلقة صغيرة ديال ماء الزهر. خلط مزيان باش يتجانسو النكهات.","شد تمرة محيدة ليها العظم، وبمعلقة صغيرة ولا بصبعانك، عمرها بنص خليط الكركاع اللي وجدتي. ضغط عليها شوية باش تبقى الحشوة ثابتة.","عاود نفس العملية مع التمرة الثانية وباقي خليط الكركاع.","ملي تعمر التمرات بجوج، حطهم غير بشوية فطبسيل صغير ديال التقديم.","رش كل تمرة معمرة بـ 1/4 معلقة صغيرة ديال الزنجلان محمر باش تزيد قرمشة وبنة.","💡 نصيحة للسكري: استمتع بهاد جوج تمرات معمرين كحلوى خفيفة من بعد وجبة متوازنة. الكركاع كيقلل من امتصاص السكر ديال التمر، ولكن السر هو الكمية: ما تفوتش جوج تمرات. المؤشر الجلايسيمي لهاد الكمية متوسط (حوالي 45). باش تتحكم أحسن، كلها من بعد وجبة غنية بالألياف والبروتينات، وعمرك تاكلها على معدة خاوية."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8e/Date_and_walnut.JPG/1280px-Date_and_walnut.JPG', ARRAY['dattes']::text[]),
  ('pomme-cuite-cannelle', 'Pomme au four à la cannelle', 'تفاحة فالفرن بالقرفة', 'Baked cinnamon apple', 'dessert', ARRAY['dessert', 'snack']::text[], '🍎', '1 pomme (150 g)', 150, 95, 22, 17, 1, 1, 4, 35, 'La pomme cuite entière garde toutes ses fibres, et la cuisson douce à la cannelle en fait un dessert chaud et parfumé qui remplace la pâtisserie. Zéro sucre ajouté nécessaire.', 'التفاحة المطيبة كاملة كتحتفظ بكل الألياف، والطيب الهادئ بالقرفة كيخليها حلوى سخونة ومعطرة كتعوض الحلويات. بلا حاجة لسكر مزيود.', '["1 pomme moyenne (environ 150 g)","1/2 c. à café de cannelle moulue","1/4 c. à café de gingembre moulu (facultatif)","1 pincée de noix de muscade râpée (facultatif)","1 c. à café d''eau de fleur d''oranger (facultatif)","50 ml d''eau"]'::jsonb, '["1 تفاحة متوسطة (حوالي 150 غرام)","1/2 معلقة صغيرة قرفة مطحونة","1/4 معلقة صغيرة سكينجبير مطحون (اختياري)","1 قريصة كوزة محكوكة (اختياري)","1 معلقة صغيرة ماء الزهر (اختياري)","50 ملل ماء"]'::jsonb, '["Préchauffez votre four à 180°C (Thermostat 6). Lavez soigneusement la pomme et retirez le trognon à l''aide d''un vide-pomme, en veillant à ne pas percer le fond. Vous pouvez aussi la couper en deux et retirer le trognon avec une petite cuillère.","Dans un petit bol, mélangez la 1/2 c. à café de cannelle moulue, la 1/4 c. à café de gingembre moulu (si utilisé) et la pincée de noix de muscade râpée (si utilisée).","Remplissez le centre évidé de la pomme avec le mélange d''épices. Si vous utilisez l''eau de fleur d''oranger, versez la 1 c. à café délicatement sur les épices.","Déposez la pomme dans un petit plat allant au four. Versez les 50 ml d''eau au fond du plat pour créer de la vapeur et éviter que la pomme ne sèche.","Enfournez pour 25 à 35 minutes. Le temps de cuisson peut varier selon la taille et la variété de la pomme. La pomme doit être tendre quand vous la piquez avec la pointe d''un couteau, mais pas en purée.","Sortez la pomme du four et laissez-la tiédir quelques minutes avant de servir. Elle peut être dégustée telle quelle ou avec une touche de yaourt nature sans sucre si désiré.","💡 Astuce diabète : Cette portion d''une pomme de 150g est idéale pour un dessert. Son indice glycémique (IG 35) est bas. Pour une meilleure gestion de la glycémie, consommez-la après un repas riche en fibres et protéines, et évitez de l''accompagner de sucres rapides. Surveillez toujours votre portion."]'::jsonb, '["سخن الفران ديالك على درجة حرارة 180°C (الدرجة 6). غسل التفاحة مزيان وحيد ليها القلب ديالها بآلة خاصة، رد البال ما تقبش التحت ديالها. تقدر تقسمها على جوج وتحيد القلب بمعلقة صغيرة.","فزلافة صغيرة، خلط 1/2 معلقة صغيرة ديال القرفة مطحونة، 1/4 معلقة صغيرة ديال سكينجبير مطحون (إلى استعملتيه) وقريصة ديال الكوزة محكوكة (إلى استعملتيها).","عمر الوسط ديال التفاحة اللي خويتي بالخليط ديال العطرية. إلى استعملتي ماء الزهر، خوي 1 معلقة صغيرة غير بشوية فوق العطرية.","حط التفاحة فطبسيل صغير كيدخل للفران. خوي 50 ملل ديال الماء فالقاع ديال الطبسيل باش يدير البخار وما تنشفش التفاحة.","دخلها للفران لمدة 25 حتى ل 35 دقيقة. وقت الطياب يقدر يختلف على حسب حجم ونوع التفاح. التفاحة خاصها تكون رطبة ملي تقيسها بالراس ديال الموس، ولكن ماشي تولي بحال البوري.","خرج التفاحة من الفران وخليها تدفى شوية قبل ما تقدمها. تقدر تاكلها هكاك ولا مع شوية ديال ياغورت طبيعي بلا سكر إلى بغيتي.","💡 نصيحة للسكري: هاد الحصة ديال تفاحة وحدة بوزن 150 غرام مثالية كتحلية. المؤشر الجلايسيمي ديالها (IG 35) منخفض. باش تحافظ على مستوى السكر فالدم، كلها من بعد وجبة غنية بالألياف والبروتينات، وتجنب تاكل معاها سكريات سريعة. ديما راقب الحصة ديالك."]'::jsonb, null, ARRAY['pomme cuite', 'تفاحة فرن']::text[]),
  ('chocolat-noir-85', 'Carré de chocolat noir 85 %', 'قطعة شوكولا كحلة 85%', 'Dark chocolate square (85%)', 'dessert', ARRAY['dessert', 'snack']::text[], '🍫', '2 carrés (20 g)', 20, 120, 8, 3, 2, 9, 3, 25, 'Le chocolat NOIR à 85 % contient très peu de sucre et des flavonoïdes bons pour les vaisseaux. 2 carrés suffisent à calmer l’envie — rien à voir avec le chocolat au lait sucré.', 'الشوكولا الكحلة 85% فيها سكر قليل بزاف وفلافونويد مزيان للشرايين. جوج قطع كافيين باش تهدن الرغبة — والو مقارنة مع الشوكولا بالحليب المسكرة.', '["20 g de chocolat noir 85% de cacao (environ 2 carrés)","1 pincée de fleur de sel","1/4 de cuillère à café d''extrait de vanille pure (facultatif)","1 petite feuille de menthe fraîche pour la garniture (facultatif)"]'::jsonb, '["20 غرام شوكولا كحلة 85% كاكاو (تقريبا 2 مربعات)","1 قريصة ملح البحر (ملح خشن)","1/4 معلقة صغيرة خلاصة الفانيلا النقية (اختياري)","1 ورقة صغيرة ديال النعناع طري للتزيين (اختياري)"]'::jsonb, '["Préparez un bain-marie : remplissez une petite casserole d''eau sur un tiers et portez-la à frémissement à feu doux. Placez un bol résistant à la chaleur au-dessus, en vous assurant que le fond du bol ne touche pas l''eau.","Cassez les 20 g de chocolat noir 85% en petits morceaux et déposez-les dans le bol du bain-marie. Laissez fondre doucement, en remuant occasionnellement avec une spatule en silicone propre, jusqu''à obtenir une texture lisse et brillante. Évitez toute surchauffe qui pourrait rendre le chocolat granuleux.","Une fois le chocolat fondu, retirez le bol du bain-marie. Ajoutez la pincée de fleur de sel et l''extrait de vanille (si utilisé). Mélangez délicatement pour bien incorporer les saveurs.","Préparez une petite surface recouverte de papier sulfurisé ou un petit moule en silicone pour chocolat. Versez le chocolat fondu sur le papier sulfurisé ou dans le moule, en l''étalant légèrement si nécessaire pour former deux petits carrés distincts ou une petite tablette.","Laissez le chocolat refroidir à température ambiante pendant environ 15-20 minutes, puis placez-le au réfrigérateur pendant au moins 30 minutes, ou jusqu''à ce qu''il soit complètement durci et cassant.","Une fois durci, cassez ou coupez le chocolat en deux carrés de 10 g chacun. Si désiré, garnissez d''une petite feuille de menthe fraîche juste avant de servir pour une touche aromatique.","💡 Astuce diabète : Ce dessert est parfait en fin de repas. Limitez-vous à la portion recommandée de 2 carrés (20 g) pour un apport contrôlé en glucides (8 g) et en sucre (3 g). Le chocolat noir 85% a un IG bas (25) et ses flavonoïdes sont bénéfiques pour la santé vasculaire. Évitez de le consommer avec d''autres aliments sucrés."]'::jsonb, '["وجدو حمام مريم: عمرو كاسرونة صغيرة بالماء حتى الثلث ديالها و خليوها تسخن على نار مهيلة حتى تبدا تغلي. حطو زلافة ديال الزاج كتحمل الحرارة فوق الكاسرونة، و تأكدو أن القاع ديال الزلافة ما كيقيسش الماء.","هرسو 20 غرام ديال الشوكولا الكحلة 85% لقطع صغار و حطوها في الزلافة فوق حمام مريم. خليوها تذوب بشوية، و حركو مرة مرة بملعقة سيليكون نقية، حتى تولي رطبة و لامعة. تجنبو تسخينها بزاف باش ما توليش حرشة.","ملي تذوب الشوكولا، حيدو الزلافة من فوق حمام مريم. زيدو قريصة ديال ملح البحر و خلاصة الفانيلا (إذا استعملتوها). خلطو غير بشوية باش يتخلطو المكونات مزيان.","وجدو بلاصة صغيرة مغطية بورق الطهي (papier sulfurisé) أو قالب سيليكون صغير خاص بالشوكولا. خويو الشوكولا الذائبة فوق ورق الطهي أو في القالب، و سرحوها غير بشوية إذا كان خاص باش تشكل جوج مربعات صغار أو لوحة صغيرة.","خليو الشوكولا تبرد في درجة حرارة الغرفة لمدة 15-20 دقيقة تقريبا، من بعد دخلوها للثلاجة لمدة 30 دقيقة على الأقل، أو حتى تقصاح و تولي قاصحة مزيان.","ملي تقصاح، هرسو أو قطعو الشوكولا لجوج مربعات كل واحد فيه 10 غرام. إذا بغيتو، زينوها بورقة صغيرة ديال النعناع طري قبل التقديم مباشرة باش تعطيوها لمسة عطرية.","💡 نصيحة للسكري: هاد الديسير ممتاز في آخر الوجبة. التزمو بالكمية الموصى بها ديال 2 مربعات (20 غرام) باش تحكمو في الكربوهيدرات (8 غرام) و السكر (3 غرام). الشوكولا الكحلة 85% عندها مؤشر سكري منخفض (25) و الفلافونويدات اللي فيها مزيانة لصحة الأوعية الدموية. تجنبو تاكلوها مع أطعمة أخرى حلوة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/ee/Ghirardelli_Dark_Chocolate_with_White_Mint_Square_%2816584035835%29.jpg/1280px-Ghirardelli_Dark_Chocolate_with_White_Mint_Square_%2816584035835%29.jpg', ARRAY['chocolat noir', 'شوكولا كحلة']::text[]),
  ('mhalbi-light', 'Mhalbi léger (crème sans sucre)', 'مهلبية خفيفة (بلا سكر)', 'Light mhalbi (sugar-free cream)', 'dessert', ARRAY['dessert']::text[], '🍮', '1 ramequin (120 g)', 120, 110, 14, 8, 5, 3, 1, 35, 'La crème à la fleur d’oranger version saine : lait demi-écrémé, très peu de maïzena, stevia à la place du sucre, cannelle en surface. Le dessert des fêtes sans la montée de glycémie.', 'كريمة ماء الزهر بالنسخة الصحية: حليب نص دسم، شوية ديال المايزينا، ستيفيا بلاصة السكر، وقرفة فوق. حلوى الأعراس بلا طلعة السكر.', '["120 ml de lait demi-écrémé","5 g de maïzena (environ 1 cuillère à café)","1 cuillère à café d''eau de fleur d''oranger","1/2 cuillère à café d''édulcorant stevia en poudre","1 pincée de cannelle moulue pour la décoration"]'::jsonb, '["120 مل حليب نص دسم","5 غرام مايزينا (تقريبا 1 معلقة صغيرة)","1 معلقة صغيرة ماء الزهر","1/2 معلقة صغيرة ستيڤيا بودرة","رشة قرفة مطحونة للتزيين"]'::jsonb, '["1. Dans une petite casserole, mélangez la maïzena avec 2 cuillères à soupe de lait froid pour dissoudre complètement les grumeaux. Assurez-vous d''obtenir une pâte lisse.","2. Ajoutez le reste du lait demi-écrémé (environ 100 ml) et l''édulcorant stevia en poudre à la préparation de maïzena dans la casserole.","3. Placez la casserole sur feu doux à moyen. Remuez constamment avec un fouet pour éviter que le mélange n''attache au fond et pour qu''il épaississe uniformément.","4. Continuez de remuer pendant environ 5 à 7 minutes, jusqu''à ce que la crème commence à épaissir et à napper la cuillère. La consistance doit être celle d''une crème anglaise légère.","5. Retirez la casserole du feu et incorporez l''eau de fleur d''oranger. Mélangez bien pour parfumer la crème de manière homogène.","6. Versez immédiatement la crème chaude dans un ramequin de 120 g. Laissez refroidir à température ambiante pendant environ 15-20 minutes, puis placez au réfrigérateur pendant au moins 2 heures pour qu''elle prenne et soit bien fraîche.","7. Avant de servir, saupoudrez une pincée de cannelle moulue sur la surface de la mhalbi légère. Servez frais. 💡 Astuce diabète : Ce dessert est conçu pour être consommé en portion unique de 120 g (environ 110 kcal, 14 g de glucides, GI 35). Pour une meilleure gestion de la glycémie, consommez-le en fin de repas équilibré et évitez de le combiner avec d''autres desserts sucrés."]'::jsonb, '["1. فكاسرونة صغيرة، خلطو المايزينا مع 2 معالق كبار ديال الحليب بارد باش تذوب مزيان وميبقاوش الحبيبات. خاص الخليط يولي أملس.","2. زيدو باقي الحليب نص دسم (تقريبا 100 مل) و ستيڤيا بودرة على خليط المايزينا فالكاسرونة.","3. حطو الكاسرونة فوق نار مهيلة حتى المتوسطة. بقاو تحركو باستمرار بالطراب اليدوي باش ما يلصقش الخليط فالقاع ويتقال بالتساوي.","4. بقاو تحركو لمدة 5 حتى 7 دقايق تقريبا، حتى تبدا الكريمة تتقال وتغطي المعلقة. خاص القوام يكون بحال كريمة إنجليزية خفيفة.","5. حيدو الكاسرونة من فوق النار وزيدو ماء الزهر. خلطو مزيان باش الكريمة تتنسم كلها بنفس الطريقة.","6. خويو الكريمة سخونة مباشرة فزلافة صغيرة (رامكان) ديال 120 غرام. خليوها تبرد فدرجة حرارة الغرفة لمدة 15-20 دقيقة، عاد دخلوها للثلاجة على الأقل ساعتين باش تشد راسها وتبرد مزيان.","7. قبل التقديم، رشو شوية القرفة مطحونة فوق المهلبية الخفيفة. قدموها باردة. 💡 نصيحة للسكري: هاد الديسير مصمم باش يتكال كحصة فردية ديال 120 غرام (تقريبا 110 سعرة حرارية، 14 غرام كاربوهيدرات، مؤشر سكري 35). باش تحكمو فمستوى السكر فالدم أحسن، كلوه فآخر وجبة متوازنة وتجنبو تاكلو معاه شي ديسير آخر حلو."]'::jsonb, null, ARRAY['mhalbi', 'مهلبية']::text[]),
  ('tajine-jelbana-qoq', 'Tajine de petits pois & artichauts', 'طاجين الجلبانة والقوق', 'Peas & artichoke tagine', 'main', ARRAY['ghda', '3cha']::text[], '🫛', '1 assiette (320 g)', 320, 250, 24, 8, 14, 10, 9, 35, 'Le tajine du printemps (jelbana o qoq) : petits pois et artichauts, riches en fibres et à IG bas. Un peu de viande maigre ou de poulet suffit — le plat est déjà rassasiant et léger.', 'طاجين الربيع (الجلبانة والقوق): جلبانة وقوق، عامرين بالألياف وبمؤشر منخفض. شوية ديال اللحم المزوق ولا الدجاج كافي — الطبق كيشبع وخفيف.', '["120 g de petits pois frais écossés","100 g de fonds d''artichauts frais (environ 2 petits artichauts)","60 g de viande de veau maigre ou de blanc de poulet, coupé en dés","1/4 d''oignon moyen, haché finement","1/2 tomate moyenne, pelée, épépinée et coupée en petits dés","1/2 gousse d''ail, écrasée","1 c. à café d''huile d''olive extra vierge","1/4 c. à café de curcuma moulu","1/4 c. à café de gingembre moulu","Une pincée de safran (facultatif)"]'::jsonb, '["120 غرام جلبانة طرية منقية","100 غرام قوق منقي (حوالي 2 قوقات صغار)","60 غرام لحم عجل بلا شحمة أو صدر دجاج، مقطع مكعبات","1/4 بصلة متوسطة، مشلضة رقيقة","1/2 مطيشة متوسطة، مقشرة ومحيدة الزريعة ومقطعة مكعبات صغار","1/2 فص ثوم، مدقوق","1 ملعقة صغيرة زيت الزيتون البكر الممتاز","1/4 ملعقة صغيرة خرقوم بلدي مطحون","1/4 ملعقة صغيرة سكينجبير مطحون","شوية زعفران شعرة (اختياري)"]'::jsonb, '["1. Dans un tajine ou une cocotte à fond épais, faites chauffer 1 c. à café d''huile d''olive à feu moyen. Ajoutez 1/4 d''oignon haché finement et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide, sans le laisser dorer.","2. Incorporez 60 g de viande de veau ou de poulet coupée en dés. Faites dorer la viande de tous les côtés pendant environ 5 minutes. Ajoutez 1/2 gousse d''ail écrasée, 1/4 c. à café de curcuma, 1/4 c. à café de gingembre, une pincée de safran (si utilisé), du sel et du poivre. Mélangez bien pour enrober la viande des épices.","3. Ajoutez 1/2 tomate coupée en petits dés. Laissez mijoter à feu doux pendant 5 minutes, en remuant de temps en temps, jusqu''à ce que la tomate commence à se défaire et à libérer son jus.","4. Versez environ 50 ml d''eau chaude (juste assez pour couvrir à moitié la viande) dans le tajine. Couvrez et laissez mijoter à feu très doux pendant 20-25 minutes pour que la viande devienne tendre. Si vous utilisez du poulet, 15 minutes suffiront.","5. Après ce temps, ajoutez 100 g de fonds d''artichauts coupés en quartiers ou en deux (selon leur taille) et 120 g de petits pois frais écossés. Mélangez délicatement pour que les légumes soient légèrement immergés dans la sauce.","6. Couvrez à nouveau le tajine et laissez cuire à feu doux pendant 15-20 minutes, ou jusqu''à ce que les petits pois et les artichauts soient tendres. Vérifiez la cuisson des légumes avec la pointe d''un couteau. La sauce doit être réduite et légèrement épaisse.","7. Servez le tajine chaud, garni de coriandre fraîche ciselée. Accompagnez d''une petite portion de pain complet (environ 30g) si désiré. 💡 Astuce diabète : Cette portion de 320 g est équilibrée pour un diabétique de type 2 (environ 250 kcal, 24 g de glucides, GI 35). Pour optimiser le contrôle glycémique, commencez toujours par manger les légumes et la viande avant le pain. Évitez de tremper excessivement le pain dans la sauce."]'::jsonb, '["1. فواحد الطاجين أو كوكوط تقيلة، سخني 1 ملعقة صغيرة ديال زيت الزيتون على عافية متوسطة. زيدي 1/4 بصلة مشلضة رقيقة وخليها تشحر لمدة 3-4 دقايق حتى تولي شفافة، بلا ما تحمر بزاف.","2. زيدي 60 غرام ديال اللحم العجل أو الدجاج مقطع مكعبات. حمر اللحم من جميع الجوانب لمدة 5 دقايق تقريبا. زيدي 1/2 فص ثوم مدقوق، 1/4 ملعقة صغيرة خرقوم، 1/4 ملعقة صغيرة سكينجبير، شوية زعفران (إذا استعملتيه)، ملح وإبزار. خلطي مزيان باش اللحم يتشرب العطرية.","3. زيدي 1/2 مطيشة مقطعة مكعبات صغار. خليها طيب على عافية مهيلة لمدة 5 دقايق، مع التحريك مرة مرة، حتى تبدا المطيشة تذوب وتطلق الماء ديالها.","4. خوي حوالي 50 مللتر ديال الماء سخون (غير القياس اللي يغطي نص اللحم) فالطاجين. غطي الطاجين وخليه يطيب على عافية مهيلة بزاف لمدة 20-25 دقيقة باش اللحم يولي رطب. إذا استعملتي الدجاج، 15 دقيقة كافية.","5. من بعد هاد المدة، زيدي 100 غرام ديال القوق مقطع على أربعة أو على جوج (حسب الحجم ديالو) و 120 غرام ديال الجلبانة الطرية. خلطي بلطف باش الخضرة تغطس شوية فالمرقة.","6. غطي الطاجين مرة أخرى وخليه يطيب على عافية مهيلة لمدة 15-20 دقيقة، أو حتى تولي الجلبانة والقوق رطبين. تأكدي من طياب الخضرة بالراس ديال الموس. المرقة خاصها تكون خاترة شوية.","7. قدمي الطاجين سخون، مزين بالقزبر طري مقطع رقيق. تقدري تقدميه مع شوية ديال الخبز الكامل (حوالي 30 غرام) إذا بغيتي. 💡 نصيحة للسكري: هاد الكمية ديال 320 غرام متوازنة لمريض السكري من النوع 2 (حوالي 250 سعرة حرارية، 24 غرام كربوهيدرات، مؤشر سكري 35). باش تحافظ على مستوى السكر في الدم، ديما بداي تاكلي الخضرة واللحم قبل الخبز. تجنبي تغماس الخبز بزاف فالمرقة."]'::jsonb, null, ARRAY['jelbana', 'qoq', 'جلبانة قوق']::text[]),
  ('tajine-navets-viande', 'Tajine de navets à la viande maigre', 'طاجين اللفت باللحم المزوق', 'Turnip & lean meat tagine', 'main', ARRAY['ghda', '3cha']::text[], '🍲', '1 assiette (330 g)', 330, 280, 16, 8, 26, 12, 6, 30, 'Le navet (left) est un légume d’hiver à très basse charge glycémique. Mijoté avec de la viande maigre et des épices, il fait un tajine chaud et rassasiant sans faire grimper le sucre.', 'اللفت خضرة ديال الشتا بحمولة سكرية منخفضة بزاف. مطيب مع اللحم المزوق والعطرية، كيدير طاجين سخون وكيشبع بلا ما يطلع السكر.', '["120 g de navets (environ 2 petits), pelés et coupés en quartiers","80 g de viande de bœuf maigre (épaule ou gîte), coupée en dés de 3 cm","30 g d''oignon, haché finement","10 ml d''huile d''olive extra vierge","50 ml d''eau","1/4 c. à café de curcuma moulu","1/4 c. à café de gingembre moulu","1/4 c. à café de sel de mer","Une pincée de poivre noir fraîchement moulu"]'::jsonb, '["120 غرام ديال اللفت (حوالي 2 صغار)، مقشر ومقطع على أربعة","80 غرام ديال اللحم البقري الهبرة (الكتف أو الفخد)، مقطع مكعبات ديال 3 سم","30 غرام ديال البصل، مشلض رقيق","10 ملليلتر ديال زيت الزيتون البكر الممتاز","50 ملليلتر ديال الماء","1/4 معلقة صغيرة ديال الخرقوم البلدي مطحون","1/4 معلقة صغيرة ديال سكينجبير مطحون","1/4 معلقة صغيرة ديال الملحة البحرية","قبيصة ديال البزار الكحل مطحون طري"]'::jsonb, '["Dans un tajine ou une cocotte à fond épais, versez 10 ml d''huile d''olive et faites chauffer à feu moyen.","Ajoutez 30 g d''oignon haché et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide, sans le laisser dorer.","Incorporez 80 g de viande de bœuf coupée en dés. Faites-la dorer de tous les côtés pendant environ 5 minutes, en remuant de temps en temps.","Ajoutez 1/4 c. à café de curcuma, 1/4 c. à café de gingembre, 1/4 c. à café de sel et une pincée de poivre noir. Mélangez bien pour enrober la viande et les oignons des épices. Laissez mijoter 1 minute pour que les saveurs se développent.","Versez 50 ml d''eau dans le tajine. Couvrez et laissez mijoter à feu doux pendant 45 minutes à 1 heure, ou jusqu''à ce que la viande soit presque tendre. Vérifiez de temps en temps et ajoutez un peu d''eau si nécessaire pour éviter que ça n''attache.","Ajoutez les 120 g de navets coupés en quartiers autour de la viande. Couvrez à nouveau et poursuivez la cuisson à feu doux pendant 20 à 30 minutes, ou jusqu''à ce que les navets soient tendres et que la sauce ait légèrement épaissi. La sauce doit être réduite et onctueuse.","Servez le tajine chaud directement dans l''assiette. 💡 Astuce diabète : Cette portion de 330 g est idéale. Pour un meilleur contrôle glycémique, commencez toujours votre repas par les légumes (navets) avant de consommer la viande et la sauce. Accompagnez ce plat d''une salade verte fraîche sans féculents."]'::jsonb, '["فطاجين أو كوكوط تقيلة، دير 10 ملليلتر ديال زيت الزيتون وسخنها على نار متوسطة.","زيد 30 غرام ديال البصل مشلض وخليه يتشحر لمدة 3-4 دقايق حتى يولي شفاف، بلا ما يتحمر.","ضيف 80 غرام ديال اللحم البقري مقطع مكعبات. خليه يتحمر من جميع الجوانب لمدة 5 دقايق تقريبا، مع التحريك مرة مرة.","زيد 1/4 معلقة صغيرة ديال الخرقوم، 1/4 معلقة صغيرة ديال سكينجبير، 1/4 معلقة صغيرة ديال الملحة وقبيصة ديال البزار الكحل. خلط مزيان باش يتلبس اللحم والبصل بالعطرية. خليه يتشحر دقيقة باش تطلق النكهات.","صب 50 ملليلتر ديال الماء فالطاجين. غطيه وخليه يطيب على نار مهيلة لمدة 45 دقيقة حتى لساعة، أو حتى يقرب اللحم يطيب. قلب مرة مرة وزيد شوية ديال الماء إذا لزم الأمر باش ما يلصقش.","زيد 120 غرام ديال اللفت مقطع على أربعة حول اللحم. غطيه مرة أخرى وكمل الطياب على نار مهيلة لمدة 20 حتى ل 30 دقيقة، أو حتى يولي اللفت رطب وتكون المرق ختارت شوية. المرق خاصها تكون قليلة وخاترة.","قدم الطاجين سخون مباشرة فالطبسيل. 💡 نصيحة للسكري: هاد الكمية ديال 330 غرام مثالية. باش تتحكم فمستوى السكر فدمك بشكل أفضل، ديما بدا الوجبة ديالك بالخضرة (اللفت) قبل ما تاكل اللحم والمرقة. رافق هاد الطبق بسلطة خضرا طرية بلا نشويات."]'::jsonb, null, ARRAY['left', 'navets', 'لفت']::text[]),
  ('berkoukech-complet', 'Berkoukech d''orge aux légumes', 'البركوكش بالشعير والخضرة', 'Barley berkoukech with vegetables', 'main', ARRAY['ghda', '3cha']::text[], '🍜', '1 assiette (300 g)', 300, 360, 52, 6, 12, 8, 8, 50, 'Le berkoukech (grosses billes de semoule) en version orge : IG plus bas et 2× plus de fibres que la semoule blanche. Beaucoup de bouillon et de légumes, peu de billes — un dîner du bled réconfortant.', 'البركوكش (كرات السميدة الكبار) بالشعير: مؤشر أقل وضعف الألياف ديال السميدة البيضاء. مرقة وخضرة بزاف، وشوية ديال الكرات — عشا البلاد المريح.', '["50 g berkoukech d''orge","100 g légumes variés (carotte, courgette, potiron)","50 g tomate concassée","1/2 oignon (environ 30 g)","1 c. à café d''huile d''olive","1/2 c. à café de ras el hanout","1/4 c. à café de curcuma","1/4 c. à café de gingembre moulu","200 ml bouillon de légumes (sans sel ajouté)"]'::jsonb, '["50 غ بركوكش بالشعير","100 غ خضرة مشكلة (خيزو، كرعة خضرا، كرعة حمرا)","50 غ مطيشة محكوكة","1/2 بصلة (تقريبا 30 غ)","1 م. ص. زيت الزيتون","1/2 م. ص. راس الحانوت","1/4 م. ص. خرقوم","1/4 م. ص. سكينجبير","200 مل مرقة الخضرة (بلا ملحة زايدة)"]'::jsonb, '["1. Dans une marmite à fond épais, faites chauffer 1 c. à café d''huile d''olive à feu moyen. Ajoutez 1/2 oignon haché finement et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide.","2. Incorporez 50 g de tomate concassée, 1/2 c. à café de ras el hanout, 1/4 c. à café de curcuma et 1/4 c. à café de gingembre moulu. Laissez mijoter 5 minutes à feu doux, en remuant de temps en temps, jusqu''à ce que la sauce épaississe légèrement et que les arômes se développent.","3. Ajoutez 100 g de légumes coupés en petits dés (carotte, courgette, potiron). Mélangez bien pour enrober les légumes de sauce.","4. Versez 200 ml de bouillon de légumes (sans sel ajouté) dans la marmite. Portez à ébullition, puis réduisez le feu à doux, couvrez et laissez mijoter pendant 10 minutes pour que les légumes commencent à s''attendrir.","5. Ajoutez 50 g de berkoukech d''orge dans la marmite. Remuez délicatement pour éviter que les billes ne collent entre elles. Assurez-vous que le berkoukech est bien immergé dans le bouillon.","6. Laissez cuire à feu doux, à couvert, pendant 15-20 minutes, ou jusqu''à ce que le berkoukech soit tendre et ait absorbé la majeure partie du bouillon. Remuez occasionnellement pour éviter que le fond n''attache. Le plat doit rester légèrement crémeux, pas sec.","7. Servez immédiatement dans une assiette creuse. Le plat doit être chaud et réconfortant. Garnissez si désiré d''une pincée de persil frais haché (non inclus dans les quantités pour la simplicité).","💡 Astuce diabète : Pour maintenir un bon contrôle glycémique, savourez votre assiette de 300 g en commençant par les légumes et le bouillon. Cela aide à ralentir l''absorption des glucides du berkoukech d''orge, malgré son IG déjà plus bas. Évitez d''ajouter du pain ou d''autres sources de glucides."]'::jsonb, '["1. فكوكوط تقيلة، سخّن 1 م. ص. زيت الزيتون على عافية متوسطة. زيد 1/2 بصلة مشلّضة رقيقة وشحّرها لمدة 3-4 دقايق حتى تولي شفافة.","2. زيد 50 غ مطيشة محكوكة، 1/2 م. ص. راس الحانوت، 1/4 م. ص. خرقوم و 1/4 م. ص. سكينجبير. خليها تشحر 5 دقايق على عافية مهيلة، وحرّك مرة مرة، حتى تبدا لاصوص تعقاد شوية وتطلع الريحة ديال العطرية.","3. زيد 100 غ ديال الخضرة مقطعة مكعبات صغار (خيزو، كرعة خضرا، كرعة حمرا). خلط مزيان باش الخضرة تتغطى بصوص.","4. خوي 200 مل ديال مرقة الخضرة (بلا ملحة زايدة) فالكوكوط. خليها حتى تغلى، من بعد نقص العافية لمهيلة، غطيها وخليها طيب 10 دقايق باش الخضرة تبدا ترطاب.","5. زيد 50 غ ديال البركوكش بالشعير فالكوكوط. حرّك بشوية باش الحبات ما يتلصقوش. تأكد أن البركوكش مغمور مزيان فالمرقة.","6. خليها طيب على عافية مهيلة، مغطية، لمدة 15-20 دقيقة، أو حتى يرطاب البركوكش ويشرب معظم المرقة. حرّك مرة مرة باش ما يلصقش فالقاع. الطبق خاص يبقى شوية كريمي، ماشي ناشف.","7. قدّم الطبق مباشرة فزلافة عميقة. خاصو يكون سخون ومريح. ممكن تزينو بشوية معدنوس مقطع رقيق (ما داخلش فالمقادير للتبسيط).","💡 نصيحة للسكري: باش تحافظ على مستوى السكر فدمك مزيان، كل الطبق ديالك (300 غ) وبدا بالخضرة والمرقة هي اللولة. هادشي كيساعد باش يتباطأ امتصاص الكربوهيدرات من البركوكش بالشعير، واخا هو أصلا عندو مؤشر سكري أقل. تجنب تزيد الخبز أو أي مصادر أخرى للكربوهيدرات."]'::jsonb, null, ARRAY['berkoukech', 'بركوكش']::text[]),
  ('couscous-tfaya-light', 'Couscous tfaya de dinde (sans sucre)', 'كسكس التفاية بالبيبي (بلا سكر)', 'Turkey tfaya couscous (sugar-free)', 'main', ARRAY['ghda']::text[], '🥘', '1 assiette moyenne (300 g)', 300, 390, 50, 10, 20, 11, 8, 50, 'Le couscous tfaya revisité : semoule d’orge, dinde maigre, oignons fondus à la cannelle SANS sucre (la cannelle et l’oignon donnent le sucré naturel). Le vendredi sauvé, la glycémie aussi.', 'كسكس التفاية بطريقة جديدة: سميدة الشعير، بيبي مزوق، بصلة ذايبة بالقرفة بلا سكر (القرفة والبصلة كيعطيو الحلاوة الطبيعية). الجمعة تسالمات، والسكر تسالم.', '["100 g de semoule d''orge (belboula)","150 g de filet de dinde, coupé en dés","200 g d''oignons, émincés finement","1 c. à soupe d''huile d''olive","1/2 c. à café de cannelle moulue","1/4 c. à café de gingembre moulu","1/4 c. à café de curcuma moulu","Quelques brins de safran (ou une pincée de colorant alimentaire)","Sel et poivre noir au goût"]'::jsonb, '["100 غرام ديال بلبولة الشعير","150 غرام ديال صدر الديك الرومي (البيبي) مقطع مكعبات","200 غرام ديال البصل، مقطع رقيق بزاف","1 معلقة كبيرة ديال زيت الزيتون","1/2 معلقة صغيرة ديال القرفة مطحونة","1/4 معلقة صغيرة ديال سكينجبير مطحون","1/4 معلقة صغيرة ديال الخرقوم مطحون","شوية ديال الزعفران شعرة (أو شوية ملون غذائي)","الملح والإبزار حسب الذوق"]'::jsonb, '["Préparez la semoule d''orge : Rincez 100 g de semoule d''orge et laissez-la tremper dans de l''eau tiède pendant 15 minutes. Égouttez bien, puis étalez-la sur un plateau pour qu''elle sèche légèrement.","Dans le bas d''un couscoussier, faites chauffer 1 c. à soupe d''huile d''olive à feu moyen. Ajoutez les dés de 150 g de dinde et faites-les dorer de tous les côtés pendant environ 5 minutes. Salez et poivrez.","Ajoutez 200 g d''oignons émincés, 1/4 c. à café de gingembre, 1/4 c. à café de curcuma et les brins de safran (ou le colorant) à la dinde. Remuez bien et laissez mijoter à feu doux pendant 10 minutes, jusqu''à ce que les oignons commencent à ramollir.","Versez environ 500 ml d''eau chaude dans le bas du couscoussier, juste assez pour couvrir la dinde. Portez à ébullition, puis réduisez le feu à doux. Couvrez et laissez mijoter pendant 20 minutes.","Pendant ce temps, préparez la tfaya : Dans une petite casserole séparée, prenez 2 cuillères à soupe des oignons et du jus de cuisson de la dinde. Ajoutez 1/2 c. à café de cannelle. Laissez mijoter à feu très doux, en remuant de temps en temps, jusqu''à ce que les oignons soient très fondants et caramélisés naturellement (environ 15-20 minutes). Si nécessaire, ajoutez une cuillère à soupe d''eau pour éviter que ça n''attache.","Placez la semoule d''orge égouttée dans le haut du couscoussier. Une fois que la dinde a mijoté pendant 20 minutes, placez le haut du couscoussier sur le bas. Laissez cuire à la vapeur pendant 20 minutes. Retirez la semoule, aérez-la avec une fourchette, salez légèrement et arrosez d''une cuillère à soupe d''eau froide. Laissez reposer 5 minutes, puis remettez à cuire à la vapeur pour une deuxième fois pendant 15 minutes.","Servez le couscous chaud en formant un dôme de semoule d''orge dans une assiette moyenne (environ 300 g). Disposez la dinde et sa sauce au centre, puis garnissez généreusement avec la tfaya d''oignons à la cannelle. 💡 Astuce diabète : Pour un meilleur contrôle de la glycémie, commencez votre repas par une petite salade verte sans féculents. Consommez une portion de 300 g de ce couscous, riche en fibres grâce à la semoule d''orge, qui a un indice glycémique plus bas que la semoule de blé. Évitez d''ajouter des légumes sucrés comme les carottes ou les courges à la sauce principale pour maintenir un faible apport en sucre."]'::jsonb, '["وجد البلبولة: شلل 100 غرام ديال بلبولة الشعير وخليها ترقد في ماء دافي لمدة 15 دقيقة. صفيها مزيان، ومن بعد سرحها فوق شي لاطة باش تنشف شوية.","في الكسكاس التحتاني، سخن 1 معلقة كبيرة ديال زيت الزيتون على نار متوسطة. زيد مكعبات 150 غرام ديال البيبي وحمرهم من جميع الجوانب لمدة تقريبا 5 دقائق. زيد الملح والإبزار.","زيد 200 غرام ديال البصل المشلض رقيق، 1/4 معلقة صغيرة ديال سكينجبير، 1/4 معلقة صغيرة ديال الخرقوم وشعيرات الزعفران (أو الملون) على البيبي. خلط مزيان وخليهم يتشحروا على نار مهيلة لمدة 10 دقائق، حتى يبدا البصل يدبال.","صب تقريبا 500 ملل ديال الماء سخون في الكسكاس التحتاني، غير القياس اللي يغطي البيبي. خليه حتى يغلى، ومن بعد نقص النار لمهيلة. غطي الكسكاس وخليه يطيب لمدة 20 دقيقة.","في هاد الوقت، وجد التفاية: في كاسرونة صغيرة بوحدها، خذ 2 معالق كبار من البصل ومرقة البيبي. زيد 1/2 معلقة صغيرة ديال القرفة. خليها طيب على نار مهيلة بزاف، مع التحريك مرة مرة، حتى يولي البصل معسل ودايب طبيعيا (تقريبا 15-20 دقيقة). إذا لزم الأمر، زيد معلقة كبيرة ديال الماء باش ما تلصقش.","حط البلبولة المصفاة في الكسكاس الفوقاني. من بعد ما يطيب البيبي لمدة 20 دقيقة، حط الكسكاس الفوقاني فوق التحتاني. خليها تفور لمدة 20 دقيقة. حيد البلبولة، فركها بفرشيطة، زيد شوية الملح ورشها بمعلقة كبيرة ديال الماء بارد. خليها ترتاح 5 دقائق، ومن بعد رجعها تفور مرة ثانية لمدة 15 دقيقة.","قدم الكسكس سخون على شكل قبة من البلبولة في طبق متوسط (تقريبا 300 غرام). حط البيبي والمرقة ديالو في الوسط، ومن بعد زين مزيان بالتفاية ديال البصل والقرفة. 💡 نصيحة للسكري: باش تحكم في مستوى السكر في الدم بشكل أفضل، ابدأ وجبتك بسلطة خضراء صغيرة بدون نشويات. تناول حصة 300 غرام من هذا الكسكس، اللي غني بالألياف بفضل بلبولة الشعير، واللي عندها مؤشر سكري أقل من سميدة القمح. تجنب إضافة الخضروات الحلوة بحال خيزو أو القرعة للصلصة الرئيسية باش تحافظ على نسبة سكر منخفضة."]'::jsonb, null, ARRAY['tfaya', 'كسكس تفاية']::text[]),
  ('djaj-mchermel-vapeur', 'Poulet mchermel à la vapeur', 'دجاج مشرمل فالبخار', 'Steamed chermoula chicken', 'main', ARRAY['ghda', '3cha']::text[], '🍗', '1 portion (300 g)', 300, 300, 6, 2, 40, 13, 1, 10, 'La cuisson vapeur (comme le poulet du couscous) sans peau ni friture : la chermoula parfume, la vapeur garde le moelleux. Quasi zéro glucide, idéal quand la glycémie du jour est haute.', 'الطيب فالبخار (بحال دجاج الكسكس) بلا جلدة وبلا قلي: الشرمولة كتعطر، والبخار كيخلي الطراوة. تقريباً بلا نشويات، مثالي ملي السكر ديال النهار طالع.', '["200 g de blanc de poulet (sans peau ni os)","1 c. à soupe de coriandre fraîche hachée","1 c. à soupe de persil frais haché","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","1 petite gousse d''ail écrasée","1/2 citron confit (pulpe seulement, rincée et hachée finement)","1 c. à café d''huile d''olive extra vierge","Sel et poivre noir fraîchement moulu (au goût)"]'::jsonb, '["200 غرام صدر دجاج (بلا جلد وعظم)","1 ملعقة كبيرة قزبر طري مفروم","1 ملعقة كبيرة معدنوس طري مفروم","1/2 ملعقة صغيرة كامون بلدي مطحون","1/4 ملعقة صغيرة تحميرة حلوة","1 فص ثوم صغير مدقوق","1/2 حامضة مصيرة (اللب فقط، مغسول ومقطع رقيق)","1 ملعقة صغيرة زيت الزيتون البكر الممتاز","ملح وإبزار أسود مطحون طري (حسب الذوق)"]'::jsonb, '["1. Dans un grand bol, préparez la chermoula : mélangez la coriandre hachée, le persil haché, le cumin moulu, le paprika doux, l''ail écrasé, la pulpe de citron confit hachée, l''huile d''olive, le sel et le poivre. Assurez-vous que tous les ingrédients sont bien combinés pour former une pâte aromatique.","2. Coupez le blanc de poulet en morceaux de taille moyenne, d''environ 3-4 cm. Ajoutez les morceaux de poulet à la chermoula dans le bol. Mélangez bien avec vos mains pour que chaque morceau de poulet soit entièrement enrobé de la marinade.","3. Laissez mariner le poulet au réfrigérateur pendant au moins 30 minutes. Idéalement, laissez-le mariner pendant 1 à 2 heures pour que les saveurs pénètrent bien la viande. Cela rendra le poulet plus savoureux et moelleux.","4. Préparez votre cuiseur vapeur. Versez environ 500 ml d''eau dans la partie inférieure du cuiseur vapeur et portez à ébullition à feu vif. L''eau ne doit pas toucher le fond du panier vapeur.","5. Une fois l''eau bouillante, placez délicatement les morceaux de poulet marinés dans le panier vapeur, en veillant à ne pas les superposer trop pour permettre une cuisson homogène. Couvrez le cuiseur vapeur avec son couvercle hermétique.","6. Réduisez le feu à moyen et laissez cuire le poulet à la vapeur pendant 20 à 25 minutes. Le poulet est cuit lorsqu''il est blanc opaque à l''intérieur et qu''il se défait facilement à la fourchette. Vérifiez la cuisson d''un morceau au centre du panier.","7. Servez immédiatement. Le poulet mchermel à la vapeur est délicieux seul ou accompagné d''une salade de légumes frais non féculents. Il est important de ne pas ajouter de sauces riches ou de féculents pour maintenir le faible indice glycémique du plat. Le poulet doit être tendre et juteux, imprégné des saveurs de la chermoula.","💡 Astuce diabète : Cette portion de 300g de poulet mchermel à la vapeur est idéale pour un repas principal. Son très faible indice glycémique (GI 10) et sa quasi-absence de glucides en font un excellent choix, surtout si votre glycémie est élevée. Pour un contrôle optimal, mangez-le avec une grande portion de légumes verts à feuilles ou une salade sans féculents. Évitez de le servir avec du pain, du riz ou des pommes de terre pour maintenir un apport en glucides minimal."]'::jsonb, '["1. فزلافة كبيرة، وجد الشرمولة: خلط القزبر والمعدنوس مقطعين، الكامون، التحميرة، الثومة مدقوقة، لب الحامض المصير مقطع رقيق، زيت الزيتون، الملح والإبزار. تأكد أن كلشي تخلط مزيان باش تحصل على شرمولة منسمة.","2. قطع صدر الدجاج طراف متوسطين، تقريبا 3-4 سنتيم. زيد طراف الدجاج على الشرمولة فزلافة. خلط مزيان بيديك باش كل طرف دجاج يتغطى كامل بالشرمولة.","3. خلي الدجاج يترقد فالثلاجة على الأقل 30 دقيقة. من الأحسن تخليه يترقد 1 حتى ل 2 سوايع باش تشرب اللحم النسمة مزيان. هادشي غايخلي الدجاج بنين ورطب أكثر.","4. وجد الكسكاس ديالك. خوي تقريبا 500 ملل ديال الماء فالبرمة التحتانية وخليها تغلى على نار مجهدة. الماء خاصو مايقيسش القاع ديال الكسكاس.","5. ملي يغلى الماء، حط طراف الدجاج المشرمولين غير بشوية فالكسكاس، رد البال ماتحطش بزاف فوق بعضياتهم باش يطيبو مزيان. غطي الكسكاس بالغطاء ديالو محكم الإغلاق.","6. نقص العافية لمتوسطة وخلي الدجاج يطيب فالكسكاس لمدة 20 حتى ل 25 دقيقة. الدجاج كيكون طايب ملي كيولي لونو أبيض من الداخل وكيتحل بسهولة بالفرشيطة. تأكد من طياب طرف فالوسط ديال الكسكاس.","7. قدم الطبق سخون فالحين. دجاج مشرمل فالبخار بنين بوحدو أو مع شلاضة ديال خضرا طرية ماشي نشوية. مهم ماتزيدش عليه صلصات ثقيلة أو نشويات باش تحافظ على المؤشر الكلايسيمي المنخفض ديال الطبق. الدجاج خاصو يكون رطب ولذيذ، ومشرب بالنسمة ديال الشرمولة.","💡 نصيحة للسكري: هاد الحصة ديال 300 غرام ديال دجاج مشرمل فالبخار مثالية لوجبة رئيسية. المؤشر الكلايسيمي ديالو قليل بزاف (GI 10) ومفيهش تقريبا الكاربوهيدرات، كيجعلو اختيار ممتاز، خصوصا إلا كان السكر ديالك طالع. باش تتحكم مزيان، كولوه مع كمية كبيرة ديال الخضرا الخضرا الورقية أو شلاضة بلا نشويات. تجنب تقدموه مع الخبز، الروز أو البطاطا باش تحافظ على أقل كمية ديال الكاربوهيدرات."]'::jsonb, null, ARRAY['djaj mchermel', 'دجاج مشرمل']::text[]),
  ('kefta-maticha-oeuf', 'Kefta maticha aux œufs (bœuf maigre)', 'كفتة مطيشة بالبيض (لحم مزوق)', 'Kefta with tomato & eggs (lean beef)', 'main', ARRAY['ghda', '3cha']::text[], '🍳', '1 assiette (320 g)', 320, 350, 12, 7, 30, 20, 3, 25, 'Le grand classique kefta-maticha en version maigre : bœuf 5 % de MG, sauce tomate maison, 2 œufs. Protéines et lycopène, peu de glucides — un plat de partage qui reste raisonnable.', 'الكلاسيك كفتة مطيشة بالنسخة المزوقة: لحم بقري 5% دهون، صلصة مطيشة ديال الدار، وجوج بيضات. بروتين وليكوبين، نشويات قليلة — طبق ديال التشارك ويبقى معقول.', '["150 g de viande de bœuf hachée maigre (5% MG)","200 g de tomates fraîches mûres","1/2 oignon moyen (environ 60 g)","1 gousse d''ail","2 œufs de poule","1 cuillère à soupe d''huile d''olive extra vierge","1/2 cuillère à café de cumin moulu","1/4 cuillère à café de paprika doux","Sel et poivre noir fraîchement moulu (au goût)"]'::jsonb, '["150 غرام لحم بقري مفروم قليل الدهن (5% دهون)","200 غرام طماطم طازجة وناضجة","1/2 بصلة متوسطة (حوالي 60 غرام)","1 فص ثوم","2 بيضات","1 ملعقة كبيرة زيت زيتون بكر ممتاز","1/2 ملعقة صغيرة كمون مطحون","1/4 ملعقة صغيرة فلفل أحمر حلو (تحميرة)","ملح وفلفل أسود مطحون طازج (حسب الذوق)"]'::jsonb, '["Dans un saladier, mélangez la viande hachée maigre avec 1/4 de l''oignon finement haché, la moitié du cumin, la moitié du paprika, du sel et du poivre. Façonnez de petites boulettes (environ 15-20 g chacune).","Lavez les tomates, retirez le pédoncule et râpez-les grossièrement. Hachez finement le reste de l''oignon et la gousse d''ail.","Dans une poêle antiadhésive à bords hauts, faites chauffer l''huile d''olive à feu moyen. Ajoutez l''oignon haché et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide. Ajoutez ensuite l''ail haché et faites revenir 1 minute de plus sans le laisser dorer.","Incorporez les tomates râpées dans la poêle. Ajoutez le reste du cumin et du paprika, salez et poivrez. Laissez mijoter à feu doux pendant 10-12 minutes, en remuant de temps en temps, jusqu''à ce que la sauce épaississe légèrement et que l''eau des tomates s''évapore.","Déposez délicatement les boulettes de kefta dans la sauce tomate. Couvrez la poêle et laissez cuire à feu doux pendant 8-10 minutes, ou jusqu''à ce que les boulettes soient bien cuites, en les retournant une fois à mi-cuisson.","Faites deux petits puits dans la sauce entre les boulettes et cassez un œuf dans chaque puits. Salez et poivrez légèrement les œufs. Couvrez à nouveau la poêle et laissez cuire 3-5 minutes, ou jusqu''à ce que les blancs soient pris et que les jaunes soient à votre convenance (coulants pour un maximum de saveur).","Servez immédiatement dans une assiette creuse. Accompagnez d''une petite salade verte sans féculents. 💡 Astuce diabète : Cette portion de 320 g est idéale pour un repas équilibré. Pour maintenir un indice glycémique bas, évitez le pain blanc et privilégiez une petite portion de pain complet (max 30g) si nécessaire, ou mieux, une salade de légumes frais. Mangez d''abord les protéines et les légumes pour ralentir l''absorption des glucides."]'::jsonb, '["فزلافة، خلطو اللحم المفروم قليل الدهن مع ربع البصلة مقطعة رقيقة بزاف، نص الكمون، نص التحميرة، الملحة والإبزار. صايبو كويرات صغار (حوالي 15-20 غرام لكل وحدة).","غسلو مطيشة، حيدو ليها الراس وحكوها غليظة. قطعو البصلة اللي بقات والثومة رقيق بزاف.","فمقلاة ما كاتلصقش و عندها الجناب طالعين، سخنو زيت الزيتون على نار متوسطة. زيدو البصلة المقطعة وخليوها تشحر 3-4 دقايق حتى تولي شفافة. من بعد زيدو الثومة مقطعة وخليوها تشحر دقيقة أخرى بلا ما تحمر.","ديرو مطيشة محكوكة فالمقلاة. زيدو الكمون والتحميرة اللي بقاو، الملحة والإبزار. خليوها طيب على نار مهيلة 10-12 دقيقة، وحركو مرة مرة، حتى تعقاد لاصوص شوية وينشف الماء ديال مطيشة.","حطو كويرات الكفتة غير بشوية فصوص مطيشة. غطيو المقلاة وخليوها طيب على نار مهيلة 8-10 دقايق، ولا حتى طيب الكفتة مزيان، وقلبوها مرة فوسط الطياب.","صايبو جوج حفرات صغار فصوص بين الكويرات وهرسو بيضة فكل حفرة. رشو شوية الملحة والإبزار فوق البيض. غطيو المقلاة مرة أخرى وخليوها طيب 3-5 دقايق، ولا حتى يطيب البيض الأبيض ويبقى البيض الأصفر كيف بغيتو (سايح باش يجي بنين بزاف).","قدموها سخونة فطبسيل غارق. رافقوها بشلاضة خضرا صغيرة بلا نشويات. 💡 نصيحة للسكري: هاد الكمية ديال 320 غرام مثالية لوجبة متوازنة. باش تحافظو على مؤشر سكري منخفض، تجنبو الخبز الأبيض وفضلو كمية قليلة ديال الخبز الكامل (أقصى حد 30 غرام) إذا كان ضروري، أو من الأفضل شلاضة ديال الخضرة طرية. كولو البروتينات والخضرة هي اللولة باش تبطئو امتصاص الكربوهيدرات."]'::jsonb, null, ARRAY['kefta maticha', 'كفتة مطيشة']::text[]),
  ('tajine-poulet-coing', 'Tajine de poulet aux coings', 'طاجين الدجاج بالسفرجل', 'Chicken tagine with quince', 'main', ARRAY['ghda']::text[], '🍗', '1 assiette (330 g)', 330, 330, 20, 12, 34, 12, 4, 35, 'Le coing (sfarjel) est un fruit ferme à IG modéré et riche en fibres. Cuit avec le poulet SANS sucre ajouté, il apporte une douceur naturelle acidulée — bien plus sage que le tajine aux pruneaux sucré.', 'السفرجل فاكهة قاسحة بمؤشر معتدل وعامرة بالألياف. مطيب مع الدجاج بلا سكر مزيود، كيعطي حلاوة طبيعية حامضة — أعقل بكثير من طاجين البرقوق المسكر.', '["150 g de cuisse de poulet désossée et sans peau","150 g de coing frais, pelé, épépiné et coupé en quartiers","30 g d''oignon rouge, finement haché","5 ml d''huile d''olive extra vierge","50 ml d''eau","1/4 c. à café de curcuma moulu","1/4 c. à café de gingembre moulu","1 pincée de safran en filaments (ou 1 petite pincée de colorant alimentaire)","Sel et poivre noir fraîchement moulu, au goût"]'::jsonb, '["150 غرام من فخذ الدجاج بدون عظم وجلد","150 غرام من السفرجل الطازج، مقشر، منزوع البذور ومقطع أرباع","30 غرام من البصل الأحمر، مفروم ناعم","5 مللتر من زيت الزيتون البكر الممتاز","50 مللتر من الماء","1/4 ملعقة صغيرة من الكركم المطحون","1/4 ملعقة صغيرة من الزنجبيل المطحون","رشة صغيرة من شعيرات الزعفران (أو رشة صغيرة من الملون الغذائي)","ملح وفلفل أسود مطحون طازج، حسب الذوق"]'::jsonb, '["Dans un tajine ou une cocotte à fond épais, faites chauffer 5 ml d''huile d''olive à feu doux. Ajoutez 30 g d''oignon rouge haché et faites-le revenir doucement pendant 3-4 minutes jusqu''à ce qu''il devienne translucide, sans le laisser dorer.","Ajoutez 150 g de cuisse de poulet. Saupoudrez avec 1/4 c. à café de curcuma, 1/4 c. à café de gingembre, une pincée de safran (ou colorant), du sel et du poivre. Faites dorer le poulet de tous les côtés pendant environ 5 minutes, en le retournant régulièrement.","Versez 50 ml d''eau dans le tajine. Couvrez et laissez mijoter à feu très doux pendant 20 minutes. Le poulet doit commencer à devenir tendre.","Pendant ce temps, préparez le coing : lavez 150 g de coing, pelez-le, retirez le cœur et coupez-le en quartiers. Vous pouvez le blanchir 5 minutes dans de l''eau bouillante si vous souhaitez qu''il cuise plus rapidement, mais ce n''est pas obligatoire.","Après 20 minutes de cuisson du poulet, disposez les quartiers de coing autour et sur le poulet dans le tajine. Assurez-vous qu''ils soient légèrement immergés dans la sauce.","Couvrez à nouveau le tajine et laissez mijoter à feu très doux pendant 25-30 minutes supplémentaires, ou jusqu''à ce que le coing soit très tendre et que le poulet soit parfaitement cuit et se détache facilement. La sauce doit avoir légèrement réduit et épaissi.","Servez immédiatement ce tajine de poulet aux coings chaud. 💡 Astuce diabète : Pour cette portion de 330 g (environ 330 kcal, 20 g de glucides), accompagnez-le d''une grande salade verte sans féculents. Mangez d''abord les légumes et le poulet pour ralentir l''absorption des glucides du coing et maintenir une glycémie stable."]'::jsonb, '["في طاجين أو طنجرة ثقيلة، سخّن 5 مللتر من زيت الزيتون على نار مهيلة. أضف 30 غرام من البصل الأحمر المفروم وقلبه بلطف لمدة 3-4 دقائق حتى يصبح شفافًا دون أن يتحمر.","أضف 150 غرام من فخذ الدجاج. رش فوقه 1/4 ملعقة صغيرة كركم، 1/4 ملعقة صغيرة زنجبيل، رشة زعفران (أو ملون غذائي)، ملح وفلفل. حمر الدجاج من جميع الجوانب لمدة 5 دقائق تقريبًا، مع التقليب بانتظام.","صب 50 مللتر من الماء في الطاجين. غطِ الطاجين واتركه يتشرب على نار هادئة جدًا لمدة 20 دقيقة. يجب أن يبدأ الدجاج في أن يصبح طريًا.","في هذه الأثناء، حضّر السفرجل: اغسل 150 غرام من السفرجل، قشره، أزل اللب وقطعه أرباع. يمكنك سلقه لمدة 5 دقائق في ماء مغلي إذا أردت أن ينضج بسرعة أكبر، لكن هذا ليس إلزاميًا.","بعد 20 دقيقة من طهي الدجاج، رتب قطع السفرجل حول الدجاج وفوقه في الطاجين. تأكد من أنها مغمورة قليلًا في الصلصة.","غطِ الطاجين مرة أخرى واتركه يتشرب على نار هادئة جدًا لمدة 25-30 دقيقة إضافية، أو حتى يصبح السفرجل طريًا جدًا والدجاج مطبوخًا تمامًا وينفصل بسهولة. يجب أن تكون الصلصة قد خثرت وتكثفت قليلًا.","قدم طاجين الدجاج بالسفرجل ساخنًا فورًا. 💡 نصيحة للسكري: لهذه الحصة التي تزن 330 غرام (حوالي 330 سعرة حرارية، 20 غرام كربوهيدرات)، قدمها مع سلطة خضراء كبيرة بدون نشويات. تناول الخضروات والدجاج أولاً لإبطاء امتصاص الكربوهيدرات من السفرجل والحفاظ على مستوى سكر الدم مستقرًا."]'::jsonb, null, ARRAY['coing', 'sfarjel', 'سفرجل']::text[]),
  ('sbanekh-mchermla', 'Épinards mchermel (selq)', 'السبانخ المشرملة', 'Chermoula spinach', 'salad', ARRAY['ghda', '3cha']::text[], '🌿', '1 portion (200 g)', 200, 100, 8, 2, 5, 6, 5, 15, 'Épinards ou blettes (selq) sautés à l’ail, cumin et citron confit : fer, fibres, presque zéro glucide. L’accompagnement vert qui remplace féculents et frites à côté de toute grillade.', 'السبانخ ولا السلق مقلي بالثوم والكامون والحامض المصير: حديد، ألياف، تقريباً بلا نشويات. المرافق الأخضر اللي كيعوض النشويات والفريت مع أي مشوي.', '["200 g d''épinards frais (ou blettes)","1 c. à soupe d''huile d''olive extra vierge","2 gousses d''ail, hachées finement","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","1/8 c. à café de piment fort (facultatif)","1/4 de citron confit, la pulpe retirée et la peau coupée en petits dés","Jus d''1/4 de citron frais","Sel et poivre noir fraîchement moulu, au goût"]'::jsonb, '["200 غرام سبانخ طرية (أو سلق)","1 ملعقة كبيرة زيت الزيتون البكر الممتاز","2 فصوص ثوم مفروم ناعم","1/2 ملعقة صغيرة كمون مطحون","1/4 ملعقة صغيرة فلفل أحمر حلو (تحميرة)","1/8 ملعقة صغيرة هريسة (اختياري)","1/4 حامضة مصيرة، اللب محيد والجلدة مقطعة مكعبات صغيرة","عصير 1/4 حامضة طرية","ملح وفلفل أسود مطحون طازج، حسب الذوق"]'::jsonb, '["1. Lavez soigneusement les épinards frais. Si vous utilisez des blettes, retirez les côtes dures. Hachez grossièrement les feuilles. Faites-les cuire à la vapeur pendant 5 à 7 minutes, ou jusqu''à ce qu''elles soient tendres mais encore d''un vert vif. Égouttez-les très bien en pressant pour retirer l''excès d''eau.","2. Dans une poêle antiadhésive, faites chauffer 1 c. à soupe d''huile d''olive à feu moyen. Ajoutez les 2 gousses d''ail hachées et faites-les revenir pendant 1 minute, jusqu''à ce qu''elles soient parfumées mais sans coloration.","3. Incorporez 1/2 c. à café de cumin moulu, 1/4 c. à café de paprika doux et 1/8 c. à café de piment fort (si utilisé). Mélangez bien et laissez cuire 30 secondes, en veillant à ne pas brûler les épices.","4. Ajoutez les épinards égouttés et pressés dans la poêle. Mélangez bien pour enrober les épinards des épices et de l''ail. Laissez mijoter à feu doux pendant 5 minutes, en remuant de temps en temps.","5. Incorporez les dés de peau de 1/4 de citron confit et le jus d''1/4 de citron frais. Mélangez délicatement. Le citron confit apportera une saveur salée et acidulée unique.","6. Goûtez et ajustez l''assaisonnement avec du sel et du poivre noir fraîchement moulu si nécessaire. Le citron confit est déjà salé, soyez donc prudent avec le sel ajouté.","7. Servez chaud ou tiède en accompagnement. Ce plat peut être préparé à l''avance et se conserve bien au réfrigérateur.","💡 Astuce diabète : Cette portion de 200 g d''épinards mchermel est idéale pour un diabétique de type 2, avec son faible indice glycémique (GI 15) et sa richesse en fibres. Servez-le comme accompagnement principal pour remplacer les féculents ou les frites à côté d''une protéine maigre grillée (poulet, poisson). Mangez cette salade verte en début de repas pour aider à stabiliser la glycémie."]'::jsonb, '["1. غسل السبانخ الطرية مزيان. إذا كنتي تستعملي السلق، حيدي العواد القاصحين. قطعي الأوراق غليظة. فوريهم لمدة 5 حتى 7 دقائق، أو حتى يوليوا رطبين ولكن اللون ديالهم يبقى أخضر زاهي. قطريهم مزيان وعصريهم باش تحيدي الماء الزائد.","2. في مقلاة ما كاتلصقش، سخني 1 ملعقة كبيرة زيت الزيتون على نار متوسطة. زيدي 2 فصوص ثوم مفروم وقليهم لمدة دقيقة، حتى تطلع ريحتهم ولكن ما يتحمروش.","3. زيدي 1/2 ملعقة صغيرة كمون مطحون، 1/4 ملعقة صغيرة تحميرة و 1/8 ملعقة صغيرة هريسة (إذا كنتي تستعمليها). خلطي مزيان وخليهم يطيبوا 30 ثانية، ردي البال باش ما يتحرقوش العطرية.","4. زيدي السبانخ اللي قطرتي وعصرتي للمقلاة. خلطي مزيان باش يتشرب السبانخ العطرية والثوم. خليه يتشحر على نار مهيلة لمدة 5 دقائق، مع التحريك مرة مرة.","5. زيدي مكعبات جلدة 1/4 حامضة مصيرة وعصير 1/4 حامضة طرية. خلطي بلطف. الحامض المصير غادي يعطي واحد المذاق مالح وحامض فريد.","6. ذوقي وقادي المذاق بالملح والفلفل الأسود المطحون طازج إذا لزم الأمر. الحامض المصير مالح أصلاً، لذا كوني حذرة مع الملح الإضافي.","7. قدميه سخون أو دافئ كمرافق. هاد الطبق ممكن يتوجد قبل الوقت وكيبقى مزيان في الثلاجة.","💡 نصيحة للسكري: هاد الحصة ديال 200 غرام ديال السبانخ المشرملة مثالية لمريض السكري من النوع الثاني، حيت المؤشر الجلايسيمي ديالها منخفض (GI 15) وغنية بالألياف. قدميها كطبق جانبي رئيسي باش تعوضي النشويات أو البطاطس المقلية مع بروتين قليل الدهن مشوي (دجاج، سمك). كولي هاد السلطة الخضراء في بداية الوجبة باش تساعدي في استقرار نسبة السكر في الدم."]'::jsonb, null, ARRAY['epinards', 'selq', 'سبانخ', 'سلق']::text[]),
  ('matbucha', 'Matbucha (tomates-poivrons mijotés)', 'المطبوشة', 'Matbucha (slow-cooked tomato & pepper)', 'salad', ARRAY['ghda', '3cha']::text[], '🍅', '1 portion (180 g)', 180, 110, 12, 8, 2, 6, 4, 30, 'Tomates et poivrons longuement mijotés : concentré de lycopène et de fibres, très peu de calories. Une entrée marocaine à volonté qui aide à couper la faim avant le plat.', 'مطيشة وفلفلة مطيبين بشوية بشوية: مركز ديال الليكوبين والألياف، وكالوري قليلة بزاف. مقبلات مغربية بلا حساب كتعاون على قطع الجوع قبل الطبق.', '["200 g de tomates mûres (environ 2 petites)","100 g de poivron rouge (environ 1/2 poivron moyen)","1 gousse d''ail","1 c. à café d''huile d''olive extra vierge","1/4 c. à café de paprika doux","1/8 c. à café de cumin moulu","Une pincée de sel","Une pincée de poivre noir","5 g de coriandre fraîche ciselée (environ 1 c. à soupe)"]'::jsonb, '["200 غرام من الطماطم الناضجة (حبتان صغيرتان تقريبا)","100 غرام من الفلفل الأحمر (نصف فلفلة متوسطة تقريبا)","1 فص ثوم","1 ملعقة صغيرة من زيت الزيتون البكر الممتاز","1/4 ملعقة صغيرة من التحميرة (بابريكا حلوة)","1/8 ملعقة صغيرة من الكمون المطحون","رشة ملح","رشة فلفل أسود","5 غرام من القزبر الطري المقطع (ملعقة كبيرة تقريبا)"]'::jsonb, '["1. Lavez les tomates et les poivrons. Coupez les tomates en petits dés après les avoir monder et épépinées si désiré (pour une texture plus lisse, sinon laissez la peau et les graines pour plus de fibres). Épépinez le poivron rouge et coupez-le également en petits dés.","2. Épluchez la gousse d''ail et hachez-la finement.","3. Dans une petite casserole à fond épais, versez 1 c. à café d''huile d''olive. Faites chauffer à feu doux. Ajoutez l''ail haché et faites-le revenir pendant 30 secondes sans le laisser dorer.","4. Ajoutez les dés de tomates et de poivrons dans la casserole. Remuez bien. Incorporez 1/4 c. à café de paprika doux, 1/8 c. à café de cumin moulu, une pincée de sel et une pincée de poivre noir.","5. Couvrez la casserole et laissez mijoter à feu très doux pendant au moins 45 minutes, voire 1 heure, en remuant de temps en temps. Les légumes doivent compoter et l''eau doit s''évaporer progressivement. La matbucha est prête quand elle a une consistance épaisse et onctueuse, presque une purée grossière.","6. Une fois la matbucha cuite, retirez-la du feu. Incorporez 5 g de coriandre fraîche ciselée. Mélangez bien et laissez reposer quelques minutes avant de servir.","💡 Astuce diabète : Cette portion de 180 g de matbucha a un IG bas (30) et est riche en fibres. Servez-la en entrée pour aider à réguler la glycémie avant le plat principal. Évitez de l''accompagner de pain blanc ; préférez une petite portion de pain complet ou de crudités."]'::jsonb, '["1. غسل الطماطم والفلفل. تقطيع الطماطم إلى مكعبات صغيرة بعد تقشيرها وإزالة البذور إذا أردت (للحصول على قوام أنعم، وإلا اترك القشر والبذور لمزيد من الألياف). إزالة بذور الفلفل الأحمر وتقطيعه أيضاً إلى مكعبات صغيرة.","2. تقشير فص الثوم وفرمه فرماً ناعماً.","3. في كسرولة صغيرة ذات قاع سميك، صب 1 ملعقة صغيرة من زيت الزيتون. سخّن على نار هادئة. أضف الثوم المفروم وقلبه لمدة 30 ثانية دون أن يتحمر.","4. أضف مكعبات الطماطم والفلفل إلى الكسرولة. حرك جيداً. أضف 1/4 ملعقة صغيرة من التحميرة، 1/8 ملعقة صغيرة من الكمون المطحون، رشة ملح ورشة فلفل أسود.","5. غطِ الكسرولة واتركها تتسبك على نار هادئة جداً لمدة 45 دقيقة على الأقل، أو حتى ساعة، مع التحريك من حين لآخر. يجب أن تتفتت الخضروات وتتبخر الماء تدريجياً. المطبوشة جاهزة عندما يصبح قوامها سميكاً وكريمياً، شبه هريس خشن.","6. بمجرد أن تنضج المطبوشة، أزلها من على النار. أضف 5 غرام من القزبر الطري المقطع. اخلط جيداً واتركها ترتاح لبضع دقائق قبل التقديم.","💡 نصيحة للسكري: هذه الحصة من المطبوشة بوزن 180 غرام لها مؤشر سكري منخفض (30) وغنية بالألياف. قدمها كمقبلات للمساعدة في تنظيم سكر الدم قبل الطبق الرئيسي. تجنب تقديمها مع الخبز الأبيض؛ فضل قطعة صغيرة من الخبز الكامل أو الخضروات النيئة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f7/2008_04_23_-_Laurel_-_Sauce.JPG/1280px-2008_04_23_-_Laurel_-_Sauce.JPG', ARRAY['matbucha', 'مطبوشة']::text[]),
  ('artichauts-vapeur', 'Artichauts vapeur (qoq)', 'القوق فالبخار', 'Steamed artichokes', 'salad', ARRAY['ghda', '3cha']::text[], '🌱', '2 artichauts (200 g)', 200, 90, 14, 2, 4, 2, 8, 20, 'L’artichaut (qoq) est champion des fibres (8 g) et contient de l’inuline, une fibre qui aide à réguler la glycémie. En entrée vapeur avec un filet de citron, il cale sans presque aucun sucre.', 'القوق بطل الألياف (8 غ) وفيه الإنولين، ألياف كتعاون على تنظيم السكر. كمقبلات مبخرة مع خيط ديال الحامض، كيشبع بلا تقريباً حتى سكر.', '["2 pièces d''artichauts frais (environ 200 g)","1/2 citron (pour le jus et la cuisson)","1/4 c. à café de sel fin","1/8 c. à café de cumin moulu","1 c. à café d''huile d''olive extra vierge","2 brins de persil frais (pour la garniture)"]'::jsonb, '["2 حبات قوق طري (حوالي 200 غ)","1/2 حامضة (للعصير و الطياب)","1/4 م.ص ملح رقيق","1/8 م.ص كمون مطحون","1 م.ص زيت الزيتون البكر الممتاز","2 عريش معدنوس طري (للتزيين)"]'::jsonb, '["1. Préparation des artichauts : Remplissez un grand bol d''eau froide et ajoutez le jus d''un quart de citron. Coupez la tige des artichauts à ras et retirez les feuilles extérieures les plus dures. Coupez le haut des feuilles (environ 2 cm) et frottez immédiatement les parties coupées avec le quart de citron restant pour éviter l''oxydation. Plongez les artichauts dans l''eau citronnée.","2. Cuisson à la vapeur : Dans le bas d''un couscoussier ou d''une grande marmite, versez environ 1 litre d''eau. Ajoutez une rondelle de citron à l''eau. Placez les artichauts égouttés dans le panier vapeur (le haut du couscoussier).","3. Démarrage de la cuisson : Couvrez le couscoussier et portez l''eau à ébullition sur feu vif. Une fois que la vapeur s''échappe bien, réduisez le feu à moyen-doux.","4. Temps de cuisson : Laissez cuire à la vapeur pendant 25 à 40 minutes. Le temps de cuisson varie selon la taille et la fraîcheur des artichauts. Vérifiez la cuisson en tirant sur une feuille : elle doit se détacher facilement. La base de l''artichaut doit être tendre quand on la pique avec un couteau.","5. Préparation de la vinaigrette simple : Pendant que les artichauts cuisent, dans un petit bol, mélangez 1 c. à café d''huile d''olive, 1/4 c. à café de sel fin, 1/8 c. à café de cumin moulu et le jus d''un quart de citron frais.","6. Service : Une fois cuits, retirez délicatement les artichauts du panier vapeur et disposez-les sur une assiette. Arrosez chaque artichaut avec la vinaigrette préparée. Ciselez finement les 2 brins de persil frais et parsemez-les sur les artichauts pour la garniture.","7. Dégustation : Servez les artichauts tièdes. Pour les manger, détachez les feuilles une par une, grattez la chair tendre à la base avec les dents. Une fois toutes les feuilles consommées, retirez le foin (barbe) au centre pour déguster le cœur tendre de l''artichaut. 💡 Astuce diabète : Consommez cette portion de 2 artichauts (environ 200g) en entrée pour profiter de ses fibres (8g) et de son inuline, qui aident à stabiliser la glycémie avant le plat principal. Son indice glycémique est très bas (environ 20). Évitez d''ajouter des sauces riches ou du pain blanc pour accompagner."]'::jsonb, '["1. تحضير القوق: عمروا زلافة كبيرة بالماء بارد و زيدوا عليها عصير ربع حامضة. قطعوا العود ديال القوق من التحت و حيدوا الوريقات القاصحين اللي على برا. قطعوا الفوق ديال الوريقات (حوالي 2 سم) و حكوا البلايص اللي قطعتوا بالحامضة اللي بقات باش ما يكحالش. غطسوا القوق في الماء و الحامض.","2. الطياب فالكوكوط: في التحت ديال الكسكاس أو طنجرة كبيرة، خويوا حوالي 1 لتر ديال الماء. زيدوا طريف ديال الحامض فالماء. حطوا القوق اللي صفيناه من الماء في الكسكاس (الفوق ديال الكوكوط).","3. بداية الطياب: غطوا الكسكاس و خليوا الماء يغلى على نار مجهدة. ملي يبدا البخار يطلع مزيان، نقصوا العافية لمتوسطة حتى لمهيلة.","4. مدة الطياب: خليوه يطيب على البخار لمدة 25 حتى ل 40 دقيقة. وقت الطياب كيختلف على حسب حجم القوق و طراوته. قلبوا الطياب بجر وريقة: خاصها تحيد بسهولة. خاص القاعدة ديال القوق تكون رطبة ملي تقيسوها بالموس.","5. تحضير الشرمولة البسيطة: فاش يكون القوق كيطيب، في زلافة صغيرة، خلطوا 1 م.ص زيت الزيتون، 1/4 م.ص ملح رقيق، 1/8 م.ص كمون مطحون و عصير ربع حامضة طرية.","6. التقديم: ملي يطيب، حيدوا القوق بلطف من الكسكاس و حطوه في طبق التقديم. سقيوا كل حبة قوق بالشرمولة اللي وجدتوها. قطعوا المعدنوس طريفات صغار و رشوه فوق القوق للتزيين.","7. التذوق: قدموا القوق دافئ. باش تاكلوه، حيدوا الوريقات وحدة بوحدة، و حكوا اللب الرطب اللي في القاعدة بالأسنان. ملي تكملوا كاع الوريقات، حيدوا الشوك (الشعر) اللي فالوسط باش تاكلوا القلب الرطب ديال القوق. 💡 نصيحة للسكري: تناولوا هاد الحصة ديال 2 حبات قوق (حوالي 200 غ) كمقبلات للاستفادة من الألياف (8 غ) و الإينولين اللي فيه، اللي كيعاونوا على تنظيم السكر في الدم قبل الطبق الرئيسي. المؤشر الجلايسيمي ديالو منخفض بزاف (حوالي 20). تجنبوا إضافة صلصات غنية أو خبز أبيض للمرافقة."]'::jsonb, null, ARRAY['artichaut', 'qoq', 'قوق']::text[]),
  ('briouat-legumes-four', 'Briouates de légumes au four', 'بريوات الخضرة فالفرن', 'Baked vegetable briouats', 'snack', ARRAY['snack', 'ghda', '3cha']::text[], '🥟', '3 pièces (120 g)', 120, 200, 22, 3, 8, 9, 4, 45, 'Les briouates AU FOUR (jamais frites) et farcies de légumes ou de fromage frais : le croustillant du bled sans le bain d’huile. En entrée ou en collation, 3 pièces maximum.', 'البريوات فالفرن (ماشي مقلية) ومعمرة بالخضرة ولا الجبن الطري: القرمشة ديال البلاد بلا حمام الزيت. كمقبلات ولا لمجة، 3 حبات على الأكثر.', '["120 g de feuilles de brick (3 pièces)","50 g de carottes râpées","50 g de courgettes râpées","30 g de poivron rouge coupé en petits dés","1 petite gousse d''ail hachée","1 c. à café d''huile d''olive","1/4 c. à café de cumin en poudre","1/4 c. à café de paprika doux","Sel et poivre noir au goût"]'::jsonb, '["120 غرام ورقة البسطيلة (3 وريقات)","50 غرام خيزو محكوك","50 غرام كرعة خضرا محكوكة","30 غرام فلفلة حمرا مقطعة مكعبات صغار","1 ضريس صغير ديال الثومة محكوك","1 معلقة صغيرة زيت الزيتون","1/4 معلقة صغيرة كامون بلدي","1/4 معلقة صغيرة تحميرة حلوة","ملح و إبزار حسب الذوق"]'::jsonb, '["1. Dans une poêle antiadhésive, faites chauffer 1 c. à café d''huile d''olive à feu moyen. Ajoutez la gousse d''ail hachée et faites revenir pendant 30 secondes jusqu''à ce qu''elle soit parfumée, sans la laisser dorer.","2. Incorporez les carottes râpées, les courgettes râpées et les dés de poivron rouge. Faites cuire les légumes à feu moyen pendant environ 5 à 7 minutes, en remuant de temps en temps, jusqu''à ce qu''ils soient tendres mais encore légèrement croquants.","3. Assaisonnez les légumes avec 1/4 c. à café de cumin, 1/4 c. à café de paprika doux, du sel et du poivre noir selon votre goût. Mélangez bien et retirez du feu. Laissez la farce refroidir complètement pour éviter de déchirer les feuilles de brick.","4. Préchauffez votre four à 180°C (Th. 6). Préparez une plaque de cuisson recouverte de papier sulfurisé.","5. Prenez une feuille de brick et coupez-la en deux pour obtenir deux demi-cercles. Pliez chaque demi-cercle en deux dans le sens de la longueur pour obtenir une bande. Déposez environ 40 g de farce aux légumes à une extrémité de la bande.","6. Pliez la feuille de brick en forme de triangle, en rabattant un coin sur la farce, puis en continuant à plier en triangle jusqu''à l''autre extrémité. Répétez l''opération pour les deux autres feuilles de brick, afin d''obtenir 3 briouates au total.","7. Disposez les briouates sur la plaque de cuisson. Enfournez pendant 15 à 20 minutes, ou jusqu''à ce qu''elles soient dorées et croustillantes. Surveillez la cuisson pour éviter qu''elles ne brûlent.","💡 Astuce diabète : Une portion de 3 briouates (environ 120 g) apporte environ 200 kcal et 22 g de glucides. Pour une meilleure gestion de la glycémie, consommez-les en collation ou en entrée, accompagnées d''une grande salade verte riche en fibres pour ralentir l''absorption des sucres."]'::jsonb, '["1. فمقلاة ما كتلصقش، سخّن 1 معلقة صغيرة ديال زيت الزيتون على نار متوسطة. زيد ضريس الثومة محكوك و قلّيه لمدة 30 ثانية حتى تطلع ريحتو، بلا ما يتحمر.","2. زيد خيزو محكوك، كرعة خضرا محكوكة و مكعبات الفلفلة الحمرا. طيّب الخضرة على نار متوسطة لمدة 5 حتى 7 دقائق تقريبا، و حرك مرة مرة، حتى تولي رطبة و لكن باقا شوية مقرمشة.","3. نكّه الخضرة بـ 1/4 معلقة صغيرة كامون، 1/4 معلقة صغيرة تحميرة حلوة، ملح و إبزار حسب الذوق. خلط مزيان و حيدها من فوق العافية. خلي الحشوة تبرد تماما باش ما تقطعش ورقة البسطيلة.","4. سخّن الفران على درجة حرارة 180°C. وجد لاطة ديال الفران مفرشة بورق الطهي.","5. خد ورقة البسطيلة و قطعها على جوج باش تحصل على نصفي دائرة. طوي كل نصف دائرة على جوج بالطول باش تحصل على شريط. حط تقريبا 40 غرام من حشوة الخضرة فطرف واحد من الشريط.","6. طوي ورقة البسطيلة على شكل مثلث، و رجع القنت على الحشوة، و كمل الطي على شكل مثلث حتى للطرف الآخر. عاود نفس العملية للوريقات الآخرين، باش تحصل على 3 بريوات فالمجموع.","7. ستّف البريوات فاللاطة. دخلهم للفران لمدة 15 حتى 20 دقيقة، أو حتى يذهبو و يولّيو مقرمشين. راقب الطياب باش ما يتحرقوش.","💡 نصيحة للسكري: حصة ديال 3 بريوات (تقريبا 120 غرام) فيها حوالي 200 سعرة حرارية و 22 غرام ديال الكربوهيدرات. باش تحافظ على مستوى السكر فالدم، كلّهم كوجبة خفيفة أو كمقبلات، مع سلطة خضرا كبيرة غنية بالألياف باش تبطّئ امتصاص السكر."]'::jsonb, null, ARRAY['briouat', 'بريوات']::text[]),
  ('makouda-four', 'Maakouda au four (galette de pommes de terre)', 'المعقودة فالفرن', 'Baked potato patties', 'snack', ARRAY['snack', 'ghda']::text[], '🥔', '2 galettes (120 g)', 120, 180, 26, 2, 5, 6, 3, 55, 'La maakouda de rue, cuite AU FOUR au lieu de la friture : même goût, 3× moins de gras. La pomme de terre reste un féculent, donc petite portion (2 galettes) et pas de pain à côté.', 'المعقودة ديال الزنقة، مطيبة فالفرن بلاصة القلي: نفس الذوق، ب3 مرات أقل دهون. البطاطا تبقى نشويات، إذن كمية صغيرة (جوج معقودات) وبلا خبز معاها.', '["120 g de pommes de terre (environ 1 petite)","1 c. à soupe de persil frais haché","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","1 petite pincée de piment fort (facultatif)","1/4 c. à café de sel fin","1/8 c. à café de poivre noir moulu","1 c. à café d''huile d''olive","1/2 œuf battu (environ 25 g)"]'::jsonb, '["120 غ بطاطا (حبة صغيرة تقريبا)","1 م.ك قزبر ومعدنوس مقطعين رقاق","1/2 م.ص كمون مطحون","1/4 م.ص تحميرة حلوة","قبيصة صغيرة هريسة (اختياري)","1/4 م.ص ملح رقيق","1/8 م.ص إبزار مطحون","1 م.ص زيت الزيتون","1/2 بيضة مخفوقة (حوالي 25 غ)"]'::jsonb, '["1. Lavez soigneusement la pomme de terre. Faites-la cuire avec sa peau dans de l''eau bouillante salée pendant environ 20-25 minutes, ou jusqu''à ce qu''elle soit très tendre quand vous la piquez avec une fourchette.","2. Égouttez la pomme de terre et laissez-la tiédir légèrement. Épluchez-la délicatement pendant qu''elle est encore chaude et écrasez-la finement à l''aide d''une fourchette ou d''un presse-purée jusqu''à obtenir une purée sans grumeaux.","3. Dans un bol, mélangez la purée de pomme de terre avec le persil haché, le cumin, le paprika, le piment fort (si utilisé), le sel et le poivre. Mélangez bien pour que les épices soient uniformément réparties.","4. Ajoutez la moitié de l''œuf battu à la préparation de pomme de terre. Mélangez à nouveau jusqu''à ce que l''œuf soit complètement incorporé et que la pâte soit homogène et légèrement collante.","5. Préchauffez votre four à 180°C (Th. 6). Chemisez une plaque de cuisson de papier sulfurisé et badigeonnez-le légèrement avec la moitié de l''huile d''olive (1/2 c. à café).","6. Divisez la pâte de pomme de terre en deux portions égales. Façonnez chaque portion en une galette ronde et plate d''environ 1 cm d''épaisseur. Déposez les galettes sur la plaque de cuisson préparée. Badigeonnez le dessus des galettes avec le reste de l''huile d''olive (1/2 c. à café).","7. Enfournez pour 15 à 20 minutes, ou jusqu''à ce que les maakoudas soient dorées et croustillantes sur les bords. Retournez-les à mi-cuisson si nécessaire pour une coloration uniforme. Servez chaud.","💡 Astuce diabète : Cette portion de 2 galettes (120g) est un snack équilibré pour un diabétique. Pour maintenir un indice glycémique bas (GI 55), évitez de la consommer avec du pain. Accompagnez-la plutôt d''une petite salade de crudités pour augmenter l''apport en fibres et ralentir l''absorption des glucides."]'::jsonb, '["1. غسل البطاطا مزيان. سلقها بقشرتها في ماء مملح طايب لمدة 20-25 دقيقة، أو حتى تولي رطبة بزاف فاش تقيسها بالفرشيطة.","2. صفي البطاطا وخليها تبرد شوية. قشرها غير بشوية وهي باقا سخونة، ومعكها مزيان بالفرشيطة أو بالمعاكة ديال البطاطا حتى تولي بوري ما فيهاش كويرات.","3. في زلافة، خلط البوري ديال البطاطا مع القزبر والمعدنوس، الكمون، التحميرة، الهريسة (إلى استعملتيها)، الملحة والإبزار. خلط مزيان باش العطرية تدخل في البطاطا كلها.","4. زيد نص البيضة المخفوقة على خليط البطاطا. خلط مرة أخرى حتى تدخل البيضة كلها ويولي الخليط متجانس وشاد فراسو شوية.","5. سخن الفران على 180 درجة مئوية. فرش لاطة ديال الفران بورق الطبخ ودهنو غير شوية بنص معلقة صغيرة ديال زيت الزيتون.","6. قسم خليط البطاطا على جوج كويرات متساويين. شكل كل كويرة على شكل غليطة دائرية ومسطحة بسمك 1 سم تقريبا. حط الغليطات في اللاطة اللي وجدتي. دهن وجه الغليطات بالزيت الزيتون اللي بقا (نص م.ص).","7. دخل اللاطة للفران لمدة 15 حتى 20 دقيقة، أو حتى يولي وجه المعقودة مذهب ومقرمش من الجناب. قلبهم في نص الطياب إلى كان خاص باش يتحمروا من الجهتين. قدمها سخونة.","💡 نصيحة للسكري: هاد الحصة ديال 2 غليطات (120غ) هي وجبة خفيفة متوازنة لمرضى السكري. باش تحافظ على مؤشر سكري منخفض (GI 55)، تجنب تاكلها مع الخبز. من الأفضل تقدمها مع سلطة صغيرة ديال الخضرة خضرا باش تزيد من الألياف وتبطئ امتصاص الكربوهيدرات."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/83/Chicken_patties_again_%28111422187%29.jpg/1280px-Chicken_patties_again_%28111422187%29.jpg', ARRAY['maakouda', 'معقودة']::text[]),
  ('batata-hlwa-four', 'Patate douce rôtie', 'البطاطا الحلوة فالفرن', 'Roasted sweet potato', 'main', ARRAY['ghda', '3cha', 'snack']::text[], '🍠', '1 portion (180 g)', 180, 160, 32, 9, 3, 2, 5, 50, 'La patate douce a un IG plus bas que la pomme de terre classique et beaucoup plus de fibres et de béta-carotène. Rôtie au four avec un filet d’huile d’olive, une portion raisonnable remplace le pain.', 'البطاطا الحلوة عندها مؤشر أقل من البطاطا العادية وألياف وبيتا كاروتين بزاف. محمرة فالفرن بخيط زيت زيتون، كمية معقولة كتعوض الخبز.', '["180 g de patate douce (environ 1 petite)","5 ml (1 c. à café) d''huile d''olive extra vierge","2 g (1/2 c. à café) de cumin moulu","1 g (1/4 c. à café) de paprika doux","1 pincée de sel de mer","1 pincée de poivre noir fraîchement moulu","5 g de persil frais, haché (pour la garniture)"]'::jsonb, '["180 غرام بطاطا حلوة (حبة صغيرة تقريبا)","5 مل (1 معلقة صغيرة) زيت الزيتون البكر الممتاز","2 غرام (1/2 معلقة صغيرة) كمون مطحون","1 غرام (1/4 معلقة صغيرة) تحميرة حلوة","رشة ملح بحري","رشة إبزار أسود مطحون طري","5 غرام معدنوس طري، مفروم (للتزيين)"]'::jsonb, '["1. Préchauffez votre four à 200°C (Thermostat 6-7). Tapissez une plaque de cuisson de papier sulfurisé.","2. Lavez soigneusement la patate douce et brossez la peau. Coupez-la en dés d''environ 2 cm ou en bâtonnets de taille similaire. Il n''est pas nécessaire de l''éplucher, car la peau contient des fibres précieuses.","3. Dans un grand bol, mélangez les dés de patate douce avec 5 ml d''huile d''olive. Assurez-vous que tous les morceaux sont bien enrobés.","4. Ajoutez 2 g de cumin moulu, 1 g de paprika doux, une pincée de sel de mer et une pincée de poivre noir. Mélangez à nouveau pour que les épices adhèrent uniformément à la patate douce.","5. Étalez les morceaux de patate douce en une seule couche sur la plaque de cuisson préparée, en veillant à ne pas les superposer pour une cuisson uniforme.","6. Enfournez et faites rôtir pendant 20 à 25 minutes, en retournant les morceaux à mi-cuisson (après environ 10-12 minutes), jusqu''à ce qu''ils soient tendres à l''intérieur et légèrement dorés et croustillants à l''extérieur.","7. Retirez du four, transférez dans une assiette et garnissez avec 5 g de persil frais haché avant de servir immédiatement.","💡 Astuce diabète : Cette portion de 180 g de patate douce rôtie (environ 160 kcal, 32 g de glucides, IG 50) est une excellente alternative au pain ou au riz. Pour mieux gérer votre glycémie, consommez-la avec une source de protéines maigres (poulet grillé, poisson) et des légumes verts non amylacés (salade, haricots verts) pour un repas équilibré. Évitez de la servir avec d''autres féculents."]'::jsonb, '["1. سخّن الفران ديالك على درجة حرارة 200°C (الدرجة 6-7). فرّش لاطة ديال الفران بورق الطهي.","2. غسل البطاطا الحلوة مزيان وحكها بالقشرة ديالها. قطعها مكعبات صغار ديال 2 سنتيمتر تقريبا أو أصابع بنفس الحجم. ماشي ضروري تقشرها حيت القشرة فيها ألياف مهمة.","3. فزلافة كبيرة، خلط مكعبات البطاطا الحلوة مع 5 مل ديال زيت الزيتون. تأكد أن جميع الطراف تغطاو بالزيت مزيان.","4. زيد 2 غرام ديال الكمون مطحون، 1 غرام ديال التحميرة الحلوة، رشة ملح بحري ورشة إبزار أسود. خلط عاوتاني باش العطرية تلصق على البطاطا الحلوة بالتساوي.","5. سرح طراف البطاطا الحلوة فطبقة وحدة فوق اللاطة اللي وجدتي، رد البال ما تحطش وحدة فوق وحدة باش طيب مزيان.","6. دخلها للفران وخليها طيب لمدة 20 حتى لـ 25 دقيقة، قلب الطراف فالنص ديال الطياب (من بعد شي 10-12 دقيقة)، حتى تولي رطبة من الداخل ومذهبة ومقرمشة شوية من برا.","7. خرجها من الفران، حطها فطبسيل وزينها بـ 5 غرام ديال المعدنوس طري مفروم قبل ما تقدمها مباشرة.","💡 نصيحة للسكري: هاد الكمية ديال 180 غرام ديال البطاطا الحلوة فالفران (تقريبا 160 سعرة حرارية، 32 غرام كربوهيدرات، مؤشر سكري 50) هي بديل ممتاز للخبز أو الروز. باش تحافظ على مستوى السكر فالدم ديالك، كلها مع مصدر بروتين قليل الدهون (دجاج مشوي، حوت) وخضروات خضراء غير نشوية (شلاضة، لوبيا خضرا) لوجبة متوازنة. تجنب تقدمها مع نشويات أخرى."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5d/Gungoguma_%28roasted_sweet_potatoes%29_2.jpg/1280px-Gungoguma_%28roasted_sweet_potatoes%29_2.jpg', ARRAY['patate douce', 'batata hlwa', 'بطاطا حلوة']::text[]),
  ('felfla-mcharmla', 'Salade de poivrons grillés à l’ail', 'الفلفلة المشرملة', 'Grilled pepper & garlic salad', 'salad', ARRAY['ghda', '3cha']::text[], '🫑', '1 portion (180 g)', 180, 100, 9, 6, 2, 7, 4, 30, 'Poivrons grillés, ail, cumin et huile d’olive : une entrée fraîche riche en vitamine C et en fibres, presque sans glucides. Parfaite à côté de sardines ou de brochettes.', 'فلفلة مشوية، ثوم، كامون وزيت زيتون: مقبلات منعشة عامرة بفيتامين C والألياف، تقريباً بلا نشويات. مثالية مع السردين ولا القطبان.', '["180 g de poivrons de couleurs variées (rouges, verts, jaunes)","1 c. à café d''huile d''olive extra vierge","2 gousses d''ail","1/4 c. à café de cumin moulu","1 pincée de paprika doux","1 pincée de sel","1 pincée de poivre noir moulu","1 c. à café de persil frais ciselé"]'::jsonb, '["180 غرام فلفلة ألوان (حمراء، خضراء، صفراء)","1 معلقة صغيرة زيت الزيتون البكر الممتاز","2 فصوص ثوم","ربع معلقة صغيرة كامون مطحون","شوية تحميرة حلوة","شوية ملح","شوية إبزار مطحون","1 معلقة صغيرة معدنوس مقطع رقيق"]'::jsonb, '["1. Préchauffez votre four à 200°C (Thermostat 6-7) ou un grill. Lavez soigneusement les 180 g de poivrons et placez-les entiers sur une plaque de cuisson recouverte de papier sulfurisé ou directement sur la grille du four/grill.","2. Faites griller les poivrons pendant environ 20 à 30 minutes, en les retournant toutes les 7-10 minutes, jusqu''à ce que leur peau soit noircie et cloquée de tous les côtés. Ils doivent être bien tendres.","3. Une fois grillés, retirez les poivrons du four/grill et placez-les immédiatement dans un sac en plastique fermé ou un saladier couvert d''un film alimentaire pendant 10 à 15 minutes. Cela facilitera l''épluchage.","4. Après ce temps de repos, retirez délicatement la peau noircie des poivrons. Ouvrez-les, retirez les graines et les membranes blanches à l''intérieur. Coupez la chair des poivrons en lanières d''environ 1 cm de large.","5. Dans un petit bol, écrasez les 2 gousses d''ail. Ajoutez la 1 c. à café d''huile d''olive, le 1/4 c. à café de cumin, la pincée de paprika, la pincée de sel et la pincée de poivre noir. Mélangez bien pour obtenir la charmoula.","6. Dans un saladier, mélangez les lanières de poivrons grillés avec la charmoula préparée. Ajoutez la 1 c. à café de persil frais ciselé et mélangez délicatement pour bien enrober tous les poivrons.","7. Servez la salade de poivrons grillés tiède ou froide. Elle peut être préparée à l''avance et conservée au réfrigérateur. Pour une portion de 180 g, vous obtenez environ 100 kcal. 💡 Astuce diabète : Cette salade est excellente pour stabiliser la glycémie grâce à ses fibres et son faible indice glycémique (GI 30). Consommez votre portion de 180 g en début de repas, avant les protéines ou les glucides, pour ralentir l''absorption du sucre. Accompagnez-la de poisson grillé ou de brochettes de poulet pour un repas équilibré."]'::jsonb, '["1. سخّن الفران ديالك على درجة حرارة 200°C (الدرجة 6-7) أو الشواية. غسل الفلفلة ديالك (180 غرام) مزيان وحطها كاملة فوق لاطة مغطية بورق الطهي أو مباشرة فوق الشواية ديال الفران/الشواية.","2. شْوِي الفلفلة لمدة 20 حتى 30 دقيقة تقريبا، وقلبها كل 7-10 دقائق، حتى تولي القشرة ديالها كحلة ومنفوخة من جميع الجوانب. خاصها تكون رطبة مزيان.","3. منين تشوى الفلفلة، حيدها من الفران/الشواية وحطها مباشرة فميكة مسدودة أو زلافة مغطية بالبلاستيك الغذائي لمدة 10 حتى 15 دقيقة. هادشي غيساعدك باش تقشرها بسهولة.","4. من بعد ما ترتاح، حيد القشرة الكحلة ديال الفلفلة غير بشوية. حلها، حيد الزريعة والجلدة البيضاء اللي لداخل. قطع الفلفلة شرائح بسمك 1 سم تقريبا.","5. فزلافة صغيرة، دق 2 فصوص ديال الثوم. زيد 1 معلقة صغيرة ديال زيت الزيتون، ربع معلقة صغيرة ديال الكامون، شوية ديال التحميرة، شوية ديال الملح وشوية ديال الإبزار. خلط مزيان باش تحصل على الشرمولة.","6. فزلافة كبيرة، خلط شرائح الفلفلة المشوية مع الشرمولة اللي وجدتي. زيد 1 معلقة صغيرة ديال المعدنوس مقطع رقيق وخلط غير بشوية باش الفلفلة كلها تغطى بالشرمولة.","7. قدم سلطة الفلفلة المشوية دافئة أو باردة. يمكن تحضيرها مسبقًا والاحتفاظ بها في الثلاجة. لكل حصة 180 غرام، كتحصل على حوالي 100 سعرة حرارية. 💡 نصيحة للسكري: هاد السلطة ممتازة لتثبيت مستوى السكر في الدم بفضل الألياف ديالها ومؤشرها الجلايسيمي المنخفض (GI 30). تناول حصتك ديال 180 غرام في بداية الوجبة، قبل البروتينات أو الكربوهيدرات، باش تبطئ امتصاص السكر. رافقها مع الحوت مشوي أو قطبان الدجاج لوجبة متوازنة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/db/Grilled_Salad.jpg/1280px-Grilled_Salad.jpg', ARRAY['felfla', 'poivrons grillés', 'فلفلة مشرملة']::text[]),
  ('salade-chou-carotte', 'Salade chou-carotte (sans mayo)', 'شلاضة الكرومب والخيزو', 'Cabbage-carrot slaw (no mayo)', 'salad', ARRAY['ghda', '3cha']::text[], '🥬', '1 assiette (180 g)', 180, 90, 12, 7, 2, 4, 5, 25, 'Le coleslaw version saine : chou et carotte crus, vinaigrette citron-huile d’olive au lieu de la mayonnaise sucrée. Croquant, riche en fibres, très peu de calories.', 'الكولسلو بالنسخة الصحية: كرومب وخيزو نيان، تتبيلة حامض-زيت زيتون بلاصة المايونيز المسكر. مقرمش، عامر بالألياف، وكالوري قليلة.', '["120 g de chou blanc frais","60 g de carottes fraîches","1 c. à soupe de jus de citron frais (environ 15 ml)","1 c. à café d''huile d''olive extra vierge (environ 5 ml)","1/4 c. à café de cumin moulu","Une pincée de sel fin","Une pincée de poivre noir moulu"]'::jsonb, '["120 غرام ديال الكرومب الأبيض طري","60 غرام ديال خيزو طري","1 معلقة كبيرة ديال عصير الحامض طري (تقريبا 15 مل)","1 معلقة صغيرة ديال زيت الزيتون البكر الممتاز (تقريبا 5 مل)","1/4 معلقة صغيرة ديال الكامون مطحون","رشيشة ديال الملحة رقيقة","رشيشة ديال البزار كحل مطحون"]'::jsonb, '["1. Lavez soigneusement le chou blanc et les carottes à l''eau froide. Égouttez-les bien.","2. Coupez le chou blanc en très fines lanières. Vous pouvez utiliser une mandoline pour obtenir une texture uniforme et très fine, ou un couteau bien aiguisé.","3. Râpez les carottes à l''aide d''une râpe à gros trous pour obtenir des juliennes épaisses. Évitez de les râper trop finement pour conserver leur croquant.","4. Dans un grand saladier, mélangez le chou blanc émincé et les carottes râpées. Assurez-vous que les légumes sont bien séparés et aérés.","5. Dans un petit bol, préparez la vinaigrette : versez 1 c. à soupe de jus de citron frais, 1 c. à café d''huile d''olive extra vierge, 1/4 c. à café de cumin moulu, une pincée de sel fin et une pincée de poivre noir moulu. Mélangez énergiquement avec une fourchette jusqu''à obtenir une émulsion légère.","6. Versez la vinaigrette sur les légumes dans le saladier. Mélangez délicatement mais fermement avec deux cuillères ou vos mains propres pour bien enrober tous les légumes de la vinaigrette. Laissez reposer 5 minutes pour que les saveurs se mélangent.","7. Servez immédiatement cette salade fraîche et croquante. Pour une meilleure saveur, vous pouvez la laisser reposer au frais pendant 15 à 20 minutes avant de servir, mais pas plus pour éviter que les légumes ne ramollissent trop.","💡 Astuce diabète : Cette salade est excellente pour un diabétique de type 2. Une portion de 180 g est idéale. Son indice glycémique très bas (GI 25) et sa richesse en fibres aident à stabiliser la glycémie. Consommez-la en début de repas pour profiter de ses fibres qui ralentiront l''absorption des glucides des autres aliments."]'::jsonb, '["1. غسلوا الكرومب الأبيض وخيزو مزيان بالماء بارد. قطرُوهم مزيان.","2. قطعوا الكرومب الأبيض شرائح رقاق بزاف. ممكن تستعملوا آلة التقطيع باش يجي رقيق وموحد، أو موس ماضي مزيان.","3. حكوا خيزو بالحكاكة الغليظة باش يجي على شكل خيوط غلاظ. تجنبوا تحكوه رقيق بزاف باش يبقى قاصح ومقرمش.","4. فشي إناء كبير، خلطوا الكرومب مقطع وخيزو محكوك. تأكدوا أن الخضرة مفرقة ومتهوية مزيان.","5. فزلافة صغيرة، وجدوا لاصوص: خويو 1 معلقة كبيرة ديال عصير الحامض طري، 1 معلقة صغيرة ديال زيت الزيتون البكر الممتاز، 1/4 معلقة صغيرة ديال الكامون مطحون، رشيشة ديال الملحة رقيقة ورشيشة ديال البزار كحل مطحون. خلطوا مزيان بالفرشيطة حتى يتجانسو المكونات.","6. خويو لاصوص فوق الخضرة فالإناء. خلطوا غير بشوية ولكن مزيان بجوج معالق أو بيديكم نقيين باش يتلبس كلشي بالصوص. خليوها ترتاح 5 دقايق باش تطلق البنة.","7. قدموا هاد الشلاضة باردة ومقرمشة دغيا. باش تجي بنينة كثر، ممكن تخليوها ترتاح فالثلاجة 15 حتى لـ 20 دقيقة قبل التقديم، ولكن ماشي كثر باش ما ترطابش الخضرة بزاف.","💡 نصيحة للسكري: هاد الشلاضة ممتازة لمريض السكري من النوع الثاني. حصة ديال 180 غرام مثالية. المؤشر الجلايسيمي ديالها قليل بزاف (GI 25) وغنية بالألياف لي كتعاون فاستقرار نسبة السكر فالدم. كولوها فبداية الوجبة باش تستافدوا من الألياف ديالها لي كتبطئ امتصاص الكربوهيدرات من المأكولات الأخرى."]'::jsonb, null, ARRAY['coleslaw', 'chou carotte', 'كرومب خيزو']::text[]),
  ('grenade', 'Grenade (rmman)', 'الرمان', 'Pomegranate', 'snack', ARRAY['snack', 'dessert']::text[], '🔴', '½ grenade (120 g)', 120, 85, 18, 14, 2, 1, 5, 35, 'La grenade (rmman) est bourrée d’antioxydants (punicalagines) et de fibres, avec un IG bas. Ses graines entières rassasient et protègent les vaisseaux — ½ grenade, pas en jus.', 'الرمان عامر بمضادات الأكسدة والألياف، وبمؤشر منخفض. الحبوب الكاملة كتشبع وكتحمي الشرايين — نص رمانة، ماشي عصير.', '["1/2 grenade fraîche (environ 120 g)","1 c. à café de jus de citron frais (5 ml)","1/4 c. à café de cannelle moulue (1 g)","1 pincée de sel fin (0.5 g)","1 c. à soupe de feuilles de menthe fraîche ciselées (5 g)"]'::jsonb, '["نص رمانة طرية (حوالي 120 غرام)","1 معلقة صغيرة عصير حامض طري (5 مل)","1/4 معلقة صغيرة قرفة مطحونة (1 غرام)","قبيصة ملح رقيق (0.5 غرام)","1 معلقة كبيرة وريقات نعناع طري مقطعين رقاق (5 غرام)"]'::jsonb, '["Lavez soigneusement la grenade sous l''eau froide. Placez-la sur une planche à découper stable.","Coupez la grenade en deux moitiés égales à l''aide d''un couteau bien aiguisé. Vous utiliserez une seule moitié pour cette portion.","Pour extraire les graines facilement, tenez la moitié de grenade coupée vers le bas au-dessus d''un grand bol. Tapez fermement le dos de la grenade avec une cuillère en bois ou le dos d''une louche. Les graines tomberont dans le bol.","Vérifiez les graines et retirez toute membrane blanche ou morceau de peau qui aurait pu tomber, car ils peuvent être amers.","Dans le bol contenant les graines de grenade (environ 120 g), ajoutez 1 c. à café de jus de citron frais. Le citron rehaussera la saveur sans ajouter de sucre.","Saupoudrez les graines avec 1/4 c. à café de cannelle moulue et une pincée de sel fin. Mélangez délicatement pour bien enrober toutes les graines.","Incorporez 1 c. à soupe de feuilles de menthe fraîche ciselées. Servez immédiatement pour profiter de la fraîcheur.","💡 Astuce diabète : Consommez cette portion de ½ grenade (120 g) comme collation. Mangez les graines entières pour bénéficier de leurs fibres et de leur faible indice glycémique (GI 35). Évitez les jus de grenade, même sans sucre ajouté, car ils concentrent le sucre et éliminent les fibres essentielles."]'::jsonb, '["غسل الرمانة مزيان تحت الما بارد. حطها فوق لوحة التقطيع ثابتة.","قطع الرمانة على جوج نصاص متساويين بموس ماضي. غتستعمل نص واحد لهاد الحصة.","باش تخرج الحبوب بسهولة، شد نص الرمانة مقطوع لتحت فوق زلافة كبيرة. ضرب بقوة على ظهر الرمانة بمعلقة خشبية أو ظهر مغرفة. الحبوب غيطيحو فالزلافة.","قلب الحبوب وحيد أي غشاء أبيض أو طريف ديال القشرة لي طاح، حيت كيكونو مرين.","فالزلافة لي فيها حبوب الرمان (حوالي 120 غرام)، زيد 1 معلقة صغيرة ديال عصير الحامض طري. الحامض كيزيد فالبنة بلا ما يزيد السكر.","رش الحبوب بـ 1/4 معلقة صغيرة ديال القرفة مطحونة وقبيصة ديال الملح الرقيق. خلط غير بشوية باش يتلبسو الحبوب كاملين.","زيد 1 معلقة كبيرة ديال وريقات النعناع طري مقطعين رقاق. قدمها فالحين باش تستمتع بالطراوة ديالها.","💡 نصيحة للسكري: تناول هاد الحصة ديال نص رمانة (120 غرام) كوجبة خفيفة. كل الحبوب كاملين باش تستافد من الألياف ديالهم ومؤشر السكر المنخفض (GI 35). تجنب عصير الرمان، حتى لو كان بلا سكر مضاف، حيت كيركز السكر وكيزول الألياف الضرورية."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/fa/Pomegranate_fruit_-_whole_and_piece_with_arils.jpg/1280px-Pomegranate_fruit_-_whole_and_piece_with_arils.jpg', ARRAY['rmman', 'grenade', 'رمان']::text[]),
  ('yaourt-graines-lin', 'Yaourt nature aux graines de lin', 'دانون طبيعي بزريعة الكتان', 'Plain yogurt with flaxseed', 'snack', ARRAY['snack', 'ftour']::text[], '🥛', '1 yaourt + 1 c.s. (140 g)', 140, 140, 10, 8, 8, 7, 3, 25, 'Yaourt nature + graines de lin moulues : les fibres solubles du lin forment un gel qui ralentit le sucre, et ses oméga-3 protègent le cœur. Un encas ou un ftour rassasiant à IG bas.', 'دانون طبيعي + زريعة الكتان المطحونة: الألياف ديال الكتان كتكون جيل كيبطئ السكر، والأوميغا 3 كيحمي القلب. لمجة ولا فطور كيشبع بمؤشر منخفض.', '["140 g de yaourt nature entier (sans sucre ajouté)","1 cuillère à soupe (environ 10 g) de graines de lin moulues","1/2 cuillère à café de cannelle en poudre (facultatif)","Quelques gouttes d''extrait de vanille naturelle (facultatif)"]'::jsonb, '["140 غرام ياغورت طبيعي كامل الدسم (بدون سكر)","1 ملعقة كبيرة (تقريبا 10 غرام) زريعة الكتان مطحونة","1/2 ملعقة صغيرة قرفة مطحونة (اختياري)","قطرات من خلاصة الفانيليا الطبيعية (اختياري)"]'::jsonb, '["Prenez un bol de taille moyenne et assurez-vous qu''il est propre et sec.","Ouvrez le pot de yaourt nature entier (140 g) et versez-le délicatement dans le bol. Évitez de le mélanger excessivement à ce stade pour conserver sa texture crémeuse.","Mesurez précisément 1 cuillère à soupe (environ 10 g) de graines de lin moulues. Il est important d''utiliser des graines de lin moulues car le corps absorbe mieux leurs nutriments sous cette forme.","Ajoutez les graines de lin moulues au yaourt dans le bol. Si vous le souhaitez, incorporez également 1/2 cuillère à café de cannelle en poudre et quelques gouttes d''extrait de vanille naturelle pour rehausser la saveur.","Mélangez doucement tous les ingrédients à l''aide d''une petite cuillère ou d''une spatule jusqu''à ce que les graines de lin soient bien incorporées et que le mélange soit homogène. Ne mélangez pas trop vigoureusement pour ne pas rendre le yaourt trop liquide.","Laissez reposer le yaourt mélangé pendant environ 5 minutes. Ce temps permet aux fibres solubles des graines de lin de commencer à former un gel, ce qui contribue à ralentir l''absorption du sucre.","Servez immédiatement votre yaourt nature aux graines de lin. C''est un excellent encas ou un composant de votre ftour. \n💡 Astuce diabète : Consommez une portion de 140 g de ce yaourt, qui a un indice glycémique bas (environ 25). Les fibres du lin ralentissent l''absorption des glucides, aidant à stabiliser la glycémie. Évitez d''ajouter du miel ou d''autres sucres."]'::jsonb, '["خذ زلافة متوسطة الحجم وتأكد أنها نقية وناشفة.","حل علبة الياغورت الطبيعي الكامل الدسم (140 غرام) وخويه بشوية في الزلافة. حاول ما تخلطوش بزاف فهاد المرحلة باش يبقى محافظ على القوام الكريمي ديالو.","عبر بالضبط 1 ملعقة كبيرة (تقريبا 10 غرام) من زريعة الكتان مطحونة. مهم تستعمل زريعة الكتان مطحونة حيت الجسم كيمتص المغذيات ديالها أحسن فهاد الشكل.","زيد زريعة الكتان مطحونة على الياغورت في الزلافة. إلا بغيتي، زيد حتى 1/2 ملعقة صغيرة قرفة مطحونة وقطرات من خلاصة الفانيليا الطبيعية باش تزيد البنة.","خلط المكونات كلها بشوية بملعقة صغيرة أو سباتولا حتى تندمج زريعة الكتان مزيان ويولي الخليط متجانس. ما تخلطش بزاف باش ما يوليش الياغورت سائل بزاف.","خلي الياغورت المخلوط يرتاح لمدة 5 دقائق تقريبا. هاد الوقت كيخلي الألياف الذائبة في زريعة الكتان تبدا تكون واحد الجيل، وهادشي كيساعد على إبطاء امتصاص السكر.","قدم الياغورت الطبيعي بزريعة الكتان ديالك مباشرة. هادي وجبة خفيفة ممتازة أو جزء من فطورك. \n💡 نصيحة للسكري: تناول حصة 140 غرام من هذا الياغورت، اللي عندو مؤشر سكري منخفض (حوالي 25). الألياف ديال الكتان كتبطئ امتصاص الكربوهيدرات، وكتساعد على استقرار سكر الدم. تجنب إضافة العسل أو أي سكريات أخرى."]'::jsonb, null, ARRAY['graines de lin', 'lin', 'زريعة الكتان']::text[]),
  ('jus-tomate-maison', 'Jus de tomate maison', 'عصير المطيشة ديال الدار', 'Homemade tomato juice', 'drink', ARRAY['drink']::text[], '🍅', '1 verre (250 ml)', 250, 45, 9, 6, 2, 0, 2, 30, 'À la place des jus de fruits sucrés : un jus de tomate maison, salé au cumin. Peu de sucre, riche en lycopène, désaltérant. Le "cocktail" apéritif du diabétique.', 'بلاصة عصير الفواكه المسكر: عصير المطيشة ديال الدار، مملّح بالكامون. سكر قليل، عامر بالليكوبين، وكيقطع العطش. "الكوكتيل" ديال السكري.', '["200 g de tomates fraîches bien mûres (environ 2 petites tomates)","50 ml d''eau filtrée","1/4 de cuillère à café de cumin moulu","1 pincée de sel fin","1 petite feuille de menthe fraîche (pour la garniture, facultatif)","Quelques gouttes de jus de citron frais (facultatif)"]'::jsonb, '["200 غرام ديال مطيشة طايبة مزيان (تقريبا 2 مطيشات صغار)","50 مللتر ديال الماء مغلي ومبرد","1/4 معلقة صغيرة ديال الكامون مطحون","رشيشة صغيرة ديال الملحة الرقيقة","وريقة صغيرة ديال النعناع طري (للتزيين، اختياري)","قطرات قليلة ديال عصير الحامض طري (اختياري)"]'::jsonb, '["1. Lavez soigneusement les 200 g de tomates fraîches. Pour faciliter le mixage et obtenir une texture plus lisse, vous pouvez les monder : faites une petite incision en croix sur le dessus de chaque tomate, plongez-les 30 secondes dans de l''eau bouillante, puis transférez-les immédiatement dans un bol d''eau glacée. La peau se retirera très facilement.","2. Coupez les tomates mondées (ou non mondées si vous préférez une texture avec la peau) en morceaux grossiers et retirez le pédoncule.","3. Placez les morceaux de tomates dans le bol d''un mixeur ou d''un blender. Ajoutez les 50 ml d''eau filtrée. L''eau aide à obtenir une consistance de jus sans être trop épaisse.","4. Mixez le tout à pleine puissance pendant 1 à 2 minutes, jusqu''à obtenir une consistance lisse et homogène. Si vous préférez un jus sans pépins ni résidus de peau, passez le mélange à travers une passoire fine à l''aide d''une spatule pour extraire le maximum de jus.","5. Versez le jus de tomate obtenu dans un verre de 250 ml. Ajoutez 1/4 de cuillère à café de cumin moulu et une pincée de sel fin. Mélangez bien avec une petite cuillère pour que les épices se dispersent uniformément.","6. Goûtez et ajustez l''assaisonnement si nécessaire, en ajoutant quelques gouttes de jus de citron frais si vous souhaitez une note plus acidulée. Pour une touche de fraîcheur, garnissez avec une petite feuille de menthe fraîche.","7. Servez immédiatement pour profiter de toutes ses saveurs et de ses bienfaits. Ce jus est délicieux frais, mais évitez d''ajouter des glaçons qui dilueraient son goût. 💡 Astuce diabète : Ce jus de tomate maison est une excellente alternative aux boissons sucrées. Sa portion de 250 ml apporte environ 45 kcal et 9 g de glucides, avec un indice glycémique bas (environ 30). Consommez-le en début de repas ou comme boisson désaltérante entre les repas, sans sucre ajouté. Évitez de le servir avec des aliments riches en glucides simples."]'::jsonb, '["1. غسل 200 غرام ديال مطيشة طرية مزيان. باش يجي العصير رطب وساهل في الطحين، ممكن تقشروها: ديرو شريطة صغيرة على شكل زائد الفوق ديال كل مطيشة، حطوها 30 ثانية في ماء طايب، ومن بعد دغيا حولوها لزلافة فيها ماء بارد بزاف. القشرة غتحيد بسهولة.","2. قطعوا مطيشة اللي قشرتوها (أو خليتوها بقشرتها إذا كنتو كتبغيوها هكاك) طراف كبار وحيدو ليها العود الفوقاني.","3. حطو طراف مطيشة في الخلاط الكهربائي. زيدو عليهم 50 مللتر ديال الماء مغلي ومبرد. الماء كيساعد باش يجي العصير خفيف وماشي ثقيل بزاف.","4. طحنوا كلشي مزيان لمدة دقيقة حتى لجوج دقائق، حتى يولي الخليط رطب ومتجانس. إذا كنتو كتبغيو العصير بلا زريعة ولا قشور، صفيوه في صفاية رقيقة بمعلقة باش تحيدو كاع الشوائب.","5. خويو عصير مطيشة اللي وجدتو في كاس ديال 250 مللتر. زيدو 1/4 معلقة صغيرة ديال الكامون مطحون ورشيشة صغيرة ديال الملحة الرقيقة. خلطو مزيان بمعلقة صغيرة باش يتوزع الكامون والملحة بالتساوي.","6. ذوقو العصير وعدلو المذاق إذا كان خاص، ممكن تزيدو قطرات قليلة ديال عصير الحامض طري إذا كنتو كتبغيو شوية الحموضة. باش تزيدو لمسة ديال الانتعاش، زينو العصير بورقة صغيرة ديال النعناع طري.","7. قدموه دغيا باش تستمتعو بكامل النكهات والفوائد ديالو. هاد العصير كيجي بنين وهو بارد، ولكن تفاداو تزيدو فيه الثلج باش مايخففش المذاق ديالو. 💡 نصيحة للسكري: هاد عصير المطيشة ديال الدار بديل ممتاز للمشروبات اللي فيها السكر. الكاس ديال 250 مللتر فيه تقريبا 45 سعرة حرارية و 9 غرام ديال الكربوهيدرات، ومؤشر سكري منخفض (تقريبا 30). شربوه في بداية الوجبة أو كمشروب منعش بين الوجبات، بلا سكر إضافي. تفاداو تقدموه مع المأكولات اللي فيها كربوهيدرات بسيطة بزاف."]'::jsonb, null, ARRAY['jus tomate', 'عصير مطيشة']::text[]),
  ('lait-amande-maison', 'Lait d’amande maison (sans sucre)', 'حليب اللوز ديال الدار (بلا سكر)', 'Homemade almond milk (no sugar)', 'drink', ARRAY['drink', 'ftour']::text[], '🥛', '1 verre (250 ml)', 250, 70, 4, 2, 3, 5, 1, 25, 'Le lait d’amande maison sans sucre est pauvre en glucides et riche en bonnes graisses et vitamine E. Bien plus sage que le jus d’avocat sucré — à boire nature ou dans les smoothies.', 'حليب اللوز ديال الدار بلا سكر قليل النشويات وعامر بالدهون الصحية وفيتامين E. أعقل بكثير من عصير الأفوكادو المسكر — شربو نية ولا فالسموذي.', '["60 g d''amandes entières non mondées","250 ml d''eau filtrée (pour le trempage)","250 ml d''eau filtrée (pour le mixage)","1 pincée de sel de l''Himalaya","1/4 de cuillère à café d''extrait de vanille naturelle (facultatif)"]'::jsonb, '["60 غرام لوز صحيح بالقشرة","250 مل ماء مفلتر (للتنقيع)","250 مل ماء مفلتر (للطحن)","1 قريصة ملح الهيمالايا","1/4 ملعقة صغيرة خلاصة الفانيليا الطبيعية (اختياري)"]'::jsonb, '["1. La veille au soir (ou au moins 8 heures avant), placez les 60 g d''amandes entières non mondées dans un bol. Versez 250 ml d''eau filtrée dessus, de manière à bien les recouvrir. Laissez-les tremper à température ambiante pendant toute la nuit. Ce trempage facilite la digestion et l''extraction du lait.","2. Le lendemain matin, égouttez les amandes et rincez-les soigneusement sous l''eau froide. Frottez-les légèrement pour retirer la peau si vous préférez un lait plus blanc, mais la peau contient des fibres bénéfiques, donc ce n''est pas obligatoire.","3. Mettez les amandes rincées dans un mixeur puissant. Ajoutez 250 ml d''eau filtrée fraîche et la pincée de sel de l''Himalaya. Si vous utilisez l''extrait de vanille, ajoutez les 1/4 de cuillère à café maintenant.","4. Mixez à vitesse élevée pendant 1 à 2 minutes, jusqu''à obtenir un liquide laiteux et une consistance crémeuse. Le mélange doit être homogène et les amandes finement broyées.","5. Placez une étamine fine (ou un sac à lait végétal) sur un grand bol ou une carafe. Versez délicatement le mélange d''amandes mixé dans l''étamine.","6. Pressez fermement l''étamine pour extraire tout le lait d''amande. Continuez à presser jusqu''à ce qu''il ne reste plus qu''une pâte sèche (l''okara d''amande) dans l''étamine. Jetez l''okara ou réutilisez-le dans d''autres recettes (par exemple, des crackers).","7. Versez le lait d''amande maison sans sucre dans une bouteille en verre hermétique. Conservez-le au réfrigérateur et consommez-le dans les 3 à 4 jours. Avant chaque consommation, secouez bien la bouteille car le lait peut se séparer. Servez un verre de 250 ml bien frais.","💡 Astuce diabète : Ce lait d''amande maison sans sucre est une excellente boisson pour les diabétiques de type 2, avec un faible indice glycémique (GI 25) et seulement 4 g de glucides par portion de 250 ml. Il est idéal nature ou comme base pour des smoothies avec des fruits à faible IG (comme les baies) et des légumes verts. Évitez de le sucrer ou de l''associer à des aliments à IG élevé."]'::jsonb, '["1. الليلة اللي قبل (أو على الأقل 8 سوايع قبل)، حط 60 غرام ديال اللوز الصحيح بالقشرة فزلافة. خوي عليه 250 مل ديال الماء مفلتر حتى يتغطى مزيان. خليه يترقد فحرارة الغرفة طول الليل. هاد الترقد كيساعد على الهضم واستخراج الحليب.","2. فالصباح الموالي، صفي اللوز وغسلو مزيان تحت الماء بارد. حكو شوية باش تحيد القشرة إلا كنتي باغي حليب أبيض كتر، ولكن القشرة فيها ألياف مفيدة، لذا ماشي ضروري تحيدها.","3. حط اللوز اللي غسلتيه فخلاط كهربائي قوي. زيد عليه 250 مل ديال الماء مفلتر بارد وقريصة ملح الهيمالايا. إلا كنتي ستعمل خلاصة الفانيليا، زيد 1/4 ملعقة صغيرة دابا.","4. طحن بسرعة عالية لمدة 1 حتى 2 دقايق، حتى تحصل على سائل حليبي وقوام كريمي. الخليط خاصو يكون متجانس واللوز مطحون مزيان.","5. حط زيف حياتي رقيق (أو كيس حليب نباتي) فوق زلافة كبيرة أو قرعة. خوي الخليط ديال اللوز المطحون بشوية فالزيف.","6. عصر الزيف مزيان باش تخرج كاع حليب اللوز. كمل العصر حتى يبقى غير عجينة ناشفة (أوكارا اللوز) فالزيف. لوح الأوكارا أو استعملها فشي وصفات أخرى (بحال بسكويت مالح).","7. خوي حليب اللوز ديال الدار بلا سكر فقرعة زجاجية كتسد مزيان. خليه فالثلاجة واستهلكو فمدة 3 حتى 4 أيام. قبل كل استعمال، رج القرعة مزيان حيت الحليب ممكن يتفصل. قدم كاس ديال 250 مل بارد مزيان.","💡 نصيحة للسكري: حليب اللوز ديال الدار بلا سكر مشروب ممتاز لمرضى السكري من النوع 2، عندو مؤشر سكري منخفض (GI 25) وفيه غير 4 غرام ديال الكربوهيدرات فكل حصة ديال 250 مل. مثالي بوحدو أو كقاعدة للعصائر مع فواكه بمؤشر سكري منخفض (بحال التوت) والخضروات الخضراء. تجنب تحليته أو تقديمه مع أطعمة بمؤشر سكري عالي."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/de/Home-made_almond_milk%2C_November_2012.jpg/500px-Home-made_almond_milk%2C_November_2012.jpg', ARRAY['lait amande', 'حليب لوز']::text[]),
  ('the-gingembre-citron', 'Thé gingembre-citron', 'أتاي السكينجبير والحامض', 'Ginger-lemon tea', 'drink', ARRAY['drink']::text[], '🫚', '1 tasse (250 ml)', 250, 10, 2, 1, 0, 0, 0, 0, 'Le gingembre (skinjbir) est étudié pour un léger effet bénéfique sur la glycémie et l’inflammation. Chaud avec du citron et sans sucre, c’est la boisson réconfortante de l’hiver.', 'السكينجبير مدروس على تأثير خفيف مزيان على السكر والالتهاب. سخون بالحامض وبلا سكر، هو المشروب المريح ديال الشتا.', '["250 ml d''eau filtrée","10 g de gingembre frais (environ 2 cm de racine)","15 ml de jus de citron frais (environ 1/2 citron)","1 bâton de cannelle (environ 3 cm)","2-3 feuilles de menthe fraîche (pour la garniture)"]'::jsonb, '["250 مل ماء مفلتر","10 غرام سكينجبير طري (حوالي 2 سنتيمتر من الجذر)","15 مل عصير حامض طري (حوالي نصف حامضة)","1 عود قرفة (حوالي 3 سنتيمتر)","2-3 وريقات نعناع طري (للتزيين)"]'::jsonb, '["1. Rincez soigneusement 10 g de gingembre frais sous l''eau froide. À l''aide d''une petite cuillère ou d''un économe, pelez délicatement la peau fine du gingembre. Coupez le gingembre pelé en fines rondelles ou râpez-le finement pour maximiser l''extraction des saveurs.","2. Dans une petite casserole, versez 250 ml d''eau filtrée. Ajoutez les rondelles ou le gingembre râpé et le bâton de cannelle de 3 cm.","3. Portez l''eau à ébullition sur feu moyen. Une fois que l''eau bout, réduisez le feu à doux-moyen et laissez mijoter pendant 5 à 7 minutes. Le liquide doit frémir doucement, permettant aux arômes du gingembre et de la cannelle de bien infuser.","4. Pendant que le thé mijote, pressez 1/2 citron frais pour obtenir environ 15 ml de jus. Filtrez le jus si vous préférez éviter la pulpe.","5. Après 5 à 7 minutes de mijotage, retirez la casserole du feu. Laissez reposer le mélange pendant 1 à 2 minutes pour que les saveurs se développent davantage.","6. Filtrez le thé à travers une passoire fine directement dans une tasse de 250 ml, en vous assurant de retirer tous les morceaux de gingembre et le bâton de cannelle. Ajoutez immédiatement les 15 ml de jus de citron frais.","7. Garnissez le thé avec 2-3 feuilles de menthe fraîche pour une touche aromatique. Servez chaud et dégustez.","💡 Astuce diabète : Ce thé est une excellente boisson sans sucre ajouté, idéale pour les personnes atteintes de diabète de type 2. Sa portion de 250 ml est parfaite. Le gingembre a un indice glycémique (IG) de 0 et peut aider à la digestion. Évitez d''ajouter du miel ou du sucre, même en petite quantité, pour maintenir la boisson à 0 sucre."]'::jsonb, '["1. شلل 10 غرام ديال سكينجبير طري مزيان تحت الما بارد. قشر السكينجبير غير بشوية باستعمال معلقة صغيرة أو مقشرة. قطع السكينجبير اللي قشرتي لدوائر رقاق أو حكو مزيان باش تخرج النكهة ديالو كاملة.","2. فكاسرونة صغيرة، خوي 250 مل ديال الما مفلتر. زيد عليه دوائر السكينجبير أو السكينجبير المحكوك وعود القرفة ديال 3 سنتيمتر.","3. حط الكاسرونة فوق عافية متوسطة حتى يغلى الما. ملي يبدا يغلى، نقص العافية لمهيلة-متوسطة وخليه يطيب على نار هادئة لمدة 5 حتى 7 دقايق. خاص السائل يبقى يغلي غير بشوية باش النكهات ديال السكينجبير والقرفة يتشربو مزيان.","4. فاش يكون أتاي كيطيب، عصر نص حامضة طرية باش تحصل على حوالي 15 مل ديال العصير. صفي العصير إلى كنتي مابغيتيش اللب ديال الحامض.","5. من بعد 5 حتى 7 دقايق ديال الطياب، حيد الكاسرونة من فوق العافية. خلي الخليط يرتاح لمدة دقيقة حتى جوج دقايق باش تزيد النكهات تطلق مزيان.","6. صفي أتاي باستعمال مصفاة رقيقة مباشرة فكاس ديال 250 مل، وتأكد أنك حيدتي جميع الطراف ديال السكينجبير وعود القرفة. زيد مباشرة 15 مل ديال عصير الحامض الطري.","7. زين أتاي بـ 2-3 وريقات ديال النعناع الطري باش تعطيه لمسة عطرية. قدمو سخون وبالصحة والراحة.","💡 نصيحة للسكري: هاد أتاي مشروب ممتاز بلا سكر مضاف، مثالي للناس اللي عندهم السكري من النوع 2. الكمية ديال 250 مل هي مثالية. السكينجبير عندو مؤشر سكري (IG) ديال 0 وممكن يساعد على الهضم. تجنب إضافة العسل أو السكر، ولو بكميات قليلة، باش يبقى المشروب بلا سكر."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3d/Lemon_and_ginger_tea_%2CTanzania.jpg/1280px-Lemon_and_ginger_tea_%2CTanzania.jpg', ARRAY['gingembre', 'skinjbir', 'سكينجبير']::text[]),
  ('poire-pochee-cannelle', 'Poire pochée à la cannelle', 'الإجاصة المطيبة بالقرفة', 'Cinnamon poached pear', 'dessert', ARRAY['dessert']::text[], '🍐', '1 poire (150 g)', 150, 95, 24, 16, 1, 0, 5, 38, 'La poire entière garde ses fibres et a un IG bas (38). Pochée dans de l’eau à la cannelle et à l’anis (sans sirop sucré), elle devient un dessert chaud et parfumé sans excès de sucre.', 'الإجاصة الكاملة كتحتفظ بالألياف وعندها مؤشر منخفض (38). مطيبة فالماء بالقرفة والنافع (بلا سيرو مسكر)، كتولي حلوى سخونة ومعطرة بلا سكر زايد.', '["1 poire ferme (type Conférence ou Williams) de 150 g","500 ml d''eau","1 bâton de cannelle (environ 5 cm)","1 étoile de badiane (anis étoilé)","1/4 de cuillère à café d''extrait de vanille pure (sans sucre)","Quelques brins de safran (facultatif)","1/2 cuillère à café de jus de citron frais"]'::jsonb, '["1 إجاصة قاصحة (نوع كونفيرونس أو ويليامز) بوزن 150 غرام","500 مللتر ديال الماء","1 عود ديال القرفة (تقريبا 5 سنتيمتر)","1 نجمة ديال الباديان (يانسون نجمي)","1/4 معلقة صغيرة ديال خلاصة الفانيلا النقية (بلا سكر)","شوية ديال شعيرات الزعفران الحر (اختياري)","1/2 معلقة صغيرة ديال عصير الحامض طري"]'::jsonb, '["1. Lavez la poire délicatement. Pelez-la entièrement en laissant la queue intacte pour une meilleure présentation. Vous pouvez aussi la laisser avec la peau pour un apport en fibres maximal, mais assurez-vous de bien la brosser.","2. Dans une casserole de taille moyenne, versez les 500 ml d''eau. Ajoutez le bâton de cannelle, l''étoile de badiane, l''extrait de vanille et les brins de safran (si utilisés).","3. Portez l''eau à frémissement sur feu moyen. Une fois que l''eau commence à frémir, réduisez le feu à doux.","4. Plongez délicatement la poire pelée dans l''eau parfumée. Assurez-vous qu''elle soit bien immergée. Si nécessaire, ajoutez un peu d''eau pour la couvrir.","5. Laissez pocher la poire à feu doux pendant environ 20 à 30 minutes. Le temps de cuisson peut varier en fonction de la fermeté de la poire. Elle doit devenir tendre sans être molle. Vérifiez la cuisson en piquant la poire avec la pointe d''un couteau.","6. Une fois la poire cuite à votre goût, retirez-la délicatement de la casserole à l''aide d''une écumoire. Laissez-la égoutter et refroidir légèrement. Avant de servir, arrosez-la d''une demi-cuillère à café de jus de citron frais pour rehausser les saveurs.","7. Servez la poire tiède ou froide, seule ou accompagnée d''une toute petite cuillère de yaourt nature sans sucre. Vous pouvez verser une cuillère à soupe du liquide de pochage aromatisé sur la poire avant de déguster. \n💡 Astuce diabète : Cette poire pochée est un excellent dessert pour les diabétiques de type 2. Une portion de 150 g de poire entière (avec ou sans peau) a un indice glycémique bas (38) et apporte environ 24 g de glucides et 95 kcal. Pour une meilleure gestion de la glycémie, consommez ce dessert en fin de repas, après avoir mangé des légumes et des protéines, et évitez de le servir avec d''autres aliments sucrés."]'::jsonb, '["1. غسل الإجاصة مزيان. قشرها كلها وخلي العود ديالها باش تجي زوينة في التقديم. ممكن تخليها بقشرتها باش تستافد من الألياف أكثر، ولكن تأكد من أنك غسلتيها مزيان بالحلفة.","2. في كاسرونة متوسطة، صب 500 مللتر ديال الماء. زيد عليها عود القرفة، نجمة الباديان، خلاصة الفانيلا وشعيرات الزعفران (إلى كنتي غتستعملهم).","3. خلي الماء يغلى على نار متوسطة. ملي يبدا الماء يغلي، نقص العافية وخليها مهيلة.","4. حط الإجاصة المقشرة بشوية في الماء المعطر. تأكد أنها مغمورة مزيان. إلى خاص، زيد شوية ديال الماء باش تغطيها.","5. خلي الإجاصة طيب على نار مهيلة لمدة 20 حتى 30 دقيقة تقريبا. وقت الطياب يقدر يختلف على حسب قساوة الإجاصة. خاصها تولي رطبة ولكن ماشي مرخية. تأكد من الطياب بتخشية رأس الموس فيها.","6. ملي طيب الإجاصة كيف بغيتي، حيدها بشوية من الكاسرونة باستعمال مغرفة مثقوبة. خليها تقطر وتبرد شوية. قبل ما تقدمها، رش عليها نص معلقة صغيرة ديال عصير الحامض طري باش تزيد تبننها.","7. قدم الإجاصة دافئة أو باردة، بوحدها أو مع معلقة صغيرة ديال ياغورت طبيعي بلا سكر. ممكن تصب معلقة كبيرة من الماء اللي طابت فيه الإجاصة فوقها قبل ما تاكلها. \n💡 نصيحة للسكري: هاد الإجاصة المطيبة بالقرفة حلوة بزاف لمرضى السكري من النوع 2. حصة ديال 150 غرام من الإجاصة الكاملة (بالقشرة أو بلا قشرة) عندها مؤشر سكري منخفض (38) وكتعطي تقريبا 24 غرام ديال الكربوهيدرات و 95 سعرة حرارية. باش تحافظ على مستوى السكر في الدم، كل هاد التحلية في آخر الوجبة، من بعد ما تكون كليتي الخضرة والبروتينات، وتجنب تقدمها مع أطعمة أخرى حلوة."]'::jsonb, null, ARRAY['poire', 'إجاصة']::text[]),
  ('gelee-agar-citron', 'Gelée d’agar au citron (sans sucre)', 'جيلي أكار بالحامض (بلا سكر)', 'Lemon agar jelly (sugar-free)', 'dessert', ARRAY['dessert', 'snack']::text[], '🍮', '1 ramequin (120 g)', 120, 25, 5, 3, 0, 0, 1, 20, 'L’agar-agar (algue) est une fibre qui fige sans sucre ni gélatine animale. Aromatisée au citron et à la stevia, cette gelée fraîche à 25 kcal calme l’envie de dessert sans toucher la glycémie.', 'الأكار أكار (طحلب) ألياف كتجمّد بلا سكر وبلا جيلاتين حيواني. معطرة بالحامض والستيفيا، هاد الجيلي البارد ب25 كالوري كيهدن الرغبة فالحلو بلا ما يمس السكر.', '["250 ml d''eau filtrée","1/2 cuillère à café (1 g) d''agar-agar en poudre","Jus d''1/2 citron frais (environ 20 ml)","Zeste finement râpé d''1/4 de citron bio","1/4 de cuillère à café d''extrait de vanille pure","8-10 gouttes de stevia liquide (ou l''équivalent d''1/2 c. à café de stevia en poudre)","1 pincée de curcuma (pour la couleur, facultatif)"]'::jsonb, '["250 مل ماء مفلتر","1/2 ملعقة صغيرة (1 غرام) أجار-أجار بودرة","عصير 1/2 حامضة طرية (حوالي 20 مل)","قشور 1/4 حامضة بيو محكوكة رقيقة","1/4 ملعقة صغيرة خلاصة فانيليا طبيعية","8-10 قطرات ستيفيا سائلة (أو ما يعادل 1/2 ملعقة صغيرة ستيفيا بودرة)","رشة خرقوم (للون، اختياري)"]'::jsonb, '["Dans une petite casserole, versez les 250 ml d''eau filtrée. Saupoudrez l''agar-agar en poudre sur l''eau froide et mélangez bien avec un fouet pour éviter les grumeaux. Laissez reposer 5 minutes pour hydrater l''agar-agar.","Placez la casserole sur feu moyen. Portez le mélange à ébullition douce, en remuant constamment pendant 2 minutes. L''agar-agar doit être complètement dissous et le liquide légèrement épaissi.","Retirez la casserole du feu. Incorporez immédiatement le jus d''1/2 citron frais, le zeste finement râpé d''1/4 de citron bio, l''extrait de vanille pure et la pincée de curcuma (si utilisé) pour une belle couleur jaune pâle.","Ajoutez les 8-10 gouttes de stevia liquide (ou l''équivalent en poudre) et mélangez bien. Goûtez et ajustez la quantité de stevia si nécessaire, en gardant à l''esprit que le goût sucré s''atténue légèrement en refroidissant.","Versez délicatement la préparation chaude dans un ramequin de 120 g. Laissez refroidir à température ambiante pendant environ 15-20 minutes jusqu''à ce que la gelée commence à prendre.","Placez le ramequin au réfrigérateur pendant au moins 2 heures, ou jusqu''à ce que la gelée soit complètement ferme et bien froide. La gelée d''agar-agar se démoule facilement si vous le souhaitez, en passant une fine lame de couteau sur les bords.","💡 Astuce diabète : Cette gelée est un excellent choix de dessert avec seulement 25 kcal et 5 g de glucides par portion de 120 g. Pour une meilleure gestion de la glycémie, consommez-la après un repas équilibré riche en fibres et en protéines. Évitez de la servir avec d''autres desserts sucrés."]'::jsonb, '["فوق كاسرونة صغيرة، صب 250 مل ديال الماء مفلتر. رش الأجار-أجار بودرة فوق الماء البارد وخلط مزيان بالطراب اليدوي باش ما يتكورش. خليه يرتاح 5 دقائق باش يتشرب الأجار-أجار الماء.","حط الكاسرونة فوق نار متوسطة. خلي الخليط يغلى شوية، مع التحريك المستمر لمدة 2 دقائق. خاص الأجار-أجار يذوب كامل والخليط يولي خاتر شوية.","حيد الكاسرونة من فوق النار. زيد مباشرة عصير 1/2 حامضة طرية، قشور 1/4 حامضة بيو محكوكة رقيقة، خلاصة الفانيليا الطبيعية ورشة الخرقوم (إلى استعملتيه) باش يعطي لون أصفر فاتح زوين.","زيد 8-10 قطرات ديال ستيفيا سائلة (أو ما يعادلها بودرة) وخلط مزيان. ذوق وقاد كمية الستيفيا إلى خاص، مع الأخذ بعين الاعتبار أن المذاق الحلو كينقص شوية منين كيبرد.","صب الخليط الساخن غير بشوية في رامكان ديال 120 غرام. خليه يبرد فدرجة حرارة الغرفة لمدة 15-20 دقيقة تقريبا حتى يبدا الجيلي يشد راسو.","حط الرامكان فالثلاجة لمدة ساعتين على الأقل، أو حتى يولي الجيلي شاد راسو مزيان وبارد. جيلي الأجار-أجار كيتفك بسهولة من القالب إلى بغيتي، غير دوز موس رقيق على الجناب.","💡 نصيحة للسكري: هاد الجيلي اختيار ممتاز للتحلية فيه غير 25 سعرة حرارية و 5 غرام كربوهيدرات لكل حصة ديال 120 غرام. باش تحافظ على مستوى السكر فالدم، كولها من بعد وجبة متوازنة غنية بالألياف والبروتينات. تجنب تقدمها مع تحليات أخرى حلوة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/07/Berries%2C_lemon_sorbet_and_agar_jelly._A_beautiful_and_delicious_dessert_at_Otto%21_%285042970449%29.jpg/1280px-Berries%2C_lemon_sorbet_and_agar_jelly._A_beautiful_and_delicious_dessert_at_Otto%21_%285042970449%29.jpg', ARRAY['agar', 'jelly', 'جيلي']::text[]),
  ('oeufs-brouilles-khodra', 'Œufs brouillés aux légumes', 'بيض مخلط بالخضرة', 'Scrambled eggs with vegetables', 'breakfast', ARRAY['ftour', '3cha']::text[], '🍳', '2 œufs + légumes (200 g)', 200, 220, 7, 4, 15, 15, 3, 15, 'Œufs brouillés doux avec courgette, poivron et tomate : protéines et légumes, presque zéro glucide. Un ftour ou un dîner express (8 min) qui ne bouge pas la glycémie.', 'بيض مخلط هادي مع القرعة والفلفلة والمطيشة: بروتين وخضرة، تقريباً بلا نشويات. فطور ولا عشا سريع (8 دقايق) ما كيحركش السكر.', '["2 œufs moyens","100 g de courgette (environ 1/2 petite)","50 g de poivron vert (environ 1/4 de poivron)","50 g de tomate (environ 1/2 petite)","1 c. à café d''huile d''olive extra vierge","1 pincée de sel fin","1 pincée de cumin moulu","1 pincée de paprika doux","Quelques brins de coriandre fraîche ciselée"]'::jsonb, '["2 بيضات متوسطة","100 غرام من الكورجيت (حوالي نص حبة صغيرة)","50 غرام من الفلفلة خضرا (حوالي ربع فلفلة)","50 غرام من مطيشة (حوالي نص حبة صغيرة)","1 معلقة صغيرة ديال زيت الزيتون البكر الممتاز","1 قبيصة ديال الملحة رقيقة","1 قبيصة ديال الكمون مطحون","1 قبيصة ديال التحميرة الحلوة","شوية ديال القزبور طري مقطع رقيق"]'::jsonb, '["1. Lavez et préparez les légumes : coupez la courgette en petits dés de 0.5 cm, le poivron vert en dés similaires et la tomate en petits dés, en retirant les pépins pour éviter l''excès d''eau.","2. Dans une petite poêle antiadhésive, faites chauffer 1 c. à café d''huile d''olive à feu moyen-doux.","3. Ajoutez les dés de courgette et de poivron. Faites-les revenir pendant 4 à 5 minutes, en remuant de temps en temps, jusqu''à ce qu''ils commencent à ramollir légèrement.","4. Incorporez les dés de tomate. Poursuivez la cuisson pendant 2 minutes supplémentaires, juste le temps que la tomate libère un peu de son jus sans se défaire complètement.","5. Pendant ce temps, cassez les 2 œufs dans un bol, salez avec 1 pincée de sel, ajoutez 1 pincée de cumin et 1 pincée de paprika. Battez-les légèrement à la fourchette.","6. Versez les œufs battus sur les légumes dans la poêle. Laissez cuire sans remuer pendant 30 secondes, puis mélangez délicatement avec une spatule en bois pour obtenir des œufs brouillés crémeux. La cuisson doit durer environ 1 à 2 minutes, jusqu''à ce que les œufs soient juste pris mais encore moelleux.","7. Retirez du feu, parsemez de coriandre fraîche ciselée et servez immédiatement. Ce plat est idéal pour un petit-déjeuner ou un dîner léger.","💡 Astuce diabète : Cette portion de 220g (2 œufs + 200g de légumes) est parfaitement adaptée. Son faible indice glycémique (GI 15) et sa richesse en protéines et fibres stabilisent la glycémie. Pour un repas équilibré, accompagnez-le d''une petite portion de pain complet (30g maximum) ou d''une salade verte."]'::jsonb, '["1. غسل الخضرة ووجدها: قطع الكورجيت مكعبات صغار ديال 0.5 سم، والفلفلة خضرا حتى هي مكعبات بحالها، ومطيشة قطعها مكعبات صغار وحيد ليها الزريعة باش ما تطلقش الماء بزاف.","2. فمقيلة صغيرة ما كاتلصقش، سخّن 1 معلقة صغيرة ديال زيت الزيتون على نار مهيلة حتى لمتوسطة.","3. زيد مكعبات الكورجيت والفلفلة. شحرهم لمدة 4 حتى لـ 5 دقائق، وحرك مرة مرة، حتى يبداو يرطابو شوية.","4. زيد مكعبات مطيشة. كمل الطياب لمدة 2 دقائق أخرى، غير الوقت اللي مطيشة تطلق شوية من الماء ديالها بلا ما تذوب كاملة.","5. فهاذ الوقت، هرّس 2 بيضات فزلافة، زيد عليهم 1 قبيصة ديال الملحة، 1 قبيصة ديال الكمون و1 قبيصة ديال التحميرة. خلطهم شوية بالفرشيطة.","6. خوي البيض المخلط فوق الخضرة فالمقلاة. خليه يطيب بلا ما تحرك لمدة 30 ثانية، من بعد خلط بلطف بملعقة خشبية باش يجيك البيض مخلط كريمي. الطياب خاصو يكون حوالي 1 حتى لـ 2 دقائق، حتى يشد البيض راسو ولكن يبقى رطب.","7. حيد من فوق النار، رش عليه القزبور طري مقطع رقيق وقدمو فالحين. هاد الطبق مثالي للفطور أو عشاء خفيف.","💡 نصيحة للسكري: هاد الكمية ديال 220 غرام (2 بيضات + 200 غرام خضرة) مناسبة بزاف. المؤشر الكلايسيمي ديالها قليل (GI 15) وغنية بالبروتينات والألياف اللي كيحافظو على مستوى السكر فالدم. لوجبة متوازنة، تقدر ترافقها بكمية صغيرة ديال خبز القمح الكامل (30 غرام كحد أقصى) أو سلطة خضرا."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3a/Scrambled_eggs_with_cucumbers.jpg/1280px-Scrambled_eggs_with_cucumbers.jpg', ARRAY['oeufs brouillés', 'بيض مخلط']::text[]),
  ('herbel-belboula-lben', 'Bouillie d''orge au lben (herbel)', 'الهربل بالشعير واللبن', 'Barley porridge with lben (herbel)', 'breakfast', ARRAY['ftour']::text[], '🥣', '1 bol (250 g)', 250, 210, 34, 6, 8, 4, 6, 45, 'L''herbel, bouillie d''orge concassée traditionnelle, servie avec du lben au lieu du lait sucré : l''orge à IG bas et les fibres calent tout la matinée. Sans sucre, avec un peu de cannelle.', 'الهربل، حساء الشعير المرضوض التقليدي، مقدم باللبن بلاصة الحليب المسكر: الشعير بمؤشر منخفض والألياف كيشبعو الصباح كامل. بلا سكر، مع شوية قرفة.', '["50 g d''orge concassée (herbel)","250 ml d''eau","1 pincée de sel","1 bâton de cannelle (facultatif)","150 ml de lben (babeurre)","1/2 c. à café de cannelle en poudre (pour la garniture)"]'::jsonb, '["50 غرام من الهربل (الشعير المدشش)","250 ملل من الماء","1 قبيصة ملح","1 عود قرفة (اختياري)","150 ملل من اللبن","1/2 ملعقة صغيرة قرفة مطحونة (للتزيين)"]'::jsonb, '["Rincez soigneusement 50 g d''orge concassée (herbel) à l''eau froide pour enlever les impuretés et l''excès d''amidon. Égouttez bien.","Dans une petite casserole, versez 250 ml d''eau et ajoutez l''orge concassée rincée. Ajoutez une pincée de sel et le bâton de cannelle si vous l''utilisez.","Portez à ébullition sur feu moyen. Une fois que l''eau bout, réduisez le feu à doux, couvrez la casserole et laissez mijoter pendant 25 à 30 minutes.","Remuez de temps en temps pour éviter que l''orge n''attache au fond de la casserole. L''orge doit devenir tendre et avoir absorbé la majeure partie de l''eau, formant une bouillie épaisse.","Retirez le bâton de cannelle (si utilisé). Laissez la bouillie d''orge refroidir légèrement, à température ambiante ou tiède.","Versez la bouillie d''orge refroidie dans un bol de service. Ajoutez délicatement 150 ml de lben frais par-dessus.","Saupoudrez la bouillie avec 1/2 cuillère à café de cannelle en poudre pour la garniture. Servez immédiatement.","💡 Astuce diabète : Cette bouillie d''orge au lben est un excellent choix pour le petit-déjeuner. Respectez la portion de 250 g pour maintenir l''apport en glucides contrôlé (environ 34 g). L''orge a un IG bas (45) et ses fibres vous aideront à vous sentir rassasié plus longtemps. Évitez d''ajouter du sucre ou du miel, la cannelle apporte une saveur suffisante."]'::jsonb, '["غسل 50 غرام من الهربل (الشعير المدشش) مزيان بالماء بارد باش تحيد الشوائب والنشا الزايد. صفيه مزيان.","فطنجرة صغيرة، خوي 250 ملل من الماء وزيد الهربل المغسول. زيد قبيصة ملح وعود القرفة إذا كنتي غتستعمليه.","خلي الماء يغلى على نار متوسطة. ملي يبدا يغلى، نقصي النار لمهيلة، غطي الطنجرة وخليه يطيب على خاطرو لمدة 25 حتى 30 دقيقة.","حركي مرة مرة باش الهربل ما يلصقش فالقاع ديال الطنجرة. خاص الهربل يولي رطب ويكون شرب أغلب الماء، ويولي بحال عصيدة خاثرة.","حيدي عود القرفة (إذا استعملتيه). خلي العصيدة ديال الهربل تبرد شوية، لدرجة حرارة الغرفة أو دافية.","خوي عصيدة الهربل الباردة فزلافة ديال التقديم. زيدي عليها 150 ملل من اللبن البارد بشوية.","رشي العصيدة بنصف ملعقة صغيرة ديال القرفة مطحونة للتزيين. قدميها مباشرة.","💡 نصيحة للسكري: هاد الهربل باللبن اختيار ممتاز للفطور. احترم الكمية ديال 250 غرام باش تحافظ على الكربوهيدرات مضبوطة (حوالي 34 غرام). الشعير عندو مؤشر سكري منخفض (45) والألياف ديالو غتخليك شبعان مدة أطول. تجنب إضافة السكر أو العسل، القرفة كتعطي نكهة كافية."]'::jsonb, null, ARRAY['herbel', 'هربل']::text[]),
  ('thon-grille-frais', 'Steak de thon grillé', 'ستيك الطون الطري المشوي', 'Grilled fresh tuna steak', 'seafood', ARRAY['ghda', '3cha']::text[], '🐟', '1 pavé (180 g)', 180, 260, 1, 0, 40, 10, 0, 5, 'Le thon frais grillé est une protéine maigre exceptionnelle, riche en oméga-3 et sans glucides. Mariné à la chermoula et juste saisi, il laisse la glycémie parfaitement stable.', 'الطون الطري المشوي بروتين مزوق ممتاز، عامر بالأوميغا 3 وبلا نشويات. مشرمل ومشوي شوية، كيخلي السكر مستقر تماماً.', '["1 pavé de thon frais (environ 180 g)","1 c. à soupe de coriandre fraîche hachée","1 c. à soupe de persil frais haché","1 gousse d''ail écrasée","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","1 pincée de piment doux (facultatif)","1 c. à café de jus de citron frais","1 c. à café d''huile d''olive extra vierge"]'::jsonb, '["1 طريف ديال الطون الطري (تقريباً 180 غرام)","1 م. كبيرة قزبر طري مكرض","1 م. كبيرة معدنوس طري مكرض","1 فص ثوم محكوك","1/2 م. صغيرة كامون بلدي","1/4 م. صغيرة تحميرة حلوة","شوية هريسة (اختياري)","1 م. صغيرة عصير حامض طري","1 م. صغيرة زيت الزيتون البكر الممتاز"]'::jsonb, '["1. Rincez le pavé de thon à l''eau froide et séchez-le soigneusement avec du papier absorbant. C''est essentiel pour une bonne saisie.","2. Dans un petit bol, préparez la chermoula : mélangez la coriandre hachée, le persil haché, l''ail écrasé, le cumin moulu, le paprika doux et le piment doux (si utilisé).","3. Ajoutez le jus de citron frais et l''huile d''olive à la chermoula. Mélangez bien pour obtenir une pâte homogène.","4. Badigeonnez généreusement le pavé de thon avec la chermoula sur toutes les faces. Laissez mariner pendant au moins 15 minutes à température ambiante, ou jusqu''à 30 minutes au réfrigérateur pour des saveurs plus intenses.","5. Préchauffez une poêle-grill ou un barbecue à feu vif. La surface doit être très chaude pour bien saisir le poisson sans le dessécher.","6. Une fois la poêle bien chaude, déposez le pavé de thon mariné. Faites-le griller pendant 2 à 3 minutes de chaque côté pour une cuisson rosée à cœur. Si vous préférez une cuisson plus ferme, prolongez d''une minute par face, mais attention à ne pas trop le cuire pour qu''il reste moelleux.","7. Servez immédiatement. Vous pouvez accompagner ce steak de thon grillé d''une salade marocaine de tomates et concombres sans ajout de sucre, ou de légumes verts vapeur. 💡 Astuce diabète : Le thon est une excellente source de protéines sans glucides. Pour maintenir une glycémie stable, veillez à ne pas dépasser la portion de 180 g et accompagnez-le toujours de légumes à faible indice glycémique (IG bas) comme des brocolis ou des haricots verts, consommés en premier pour ralentir l''absorption des glucides si vous en mangez."]'::jsonb, '["1. غسلوا طريف الطون بالماء بارد ونشفوه مزيان بورق المطبخ. هاد الخطوة مهمة باش يتشوى مزيان.","2. فزلافة صغيرة، وجدوا الشرمولة: خلطوا القزبر والمعدنوس مكرضين، الثومة محكوكة، الكامون، التحميرة، والهريسة (إلى استعملتوها).","3. زيدوا عصير الحامض وزيت الزيتون على الشرمولة. خلطوا كلشي مزيان حتى تولي عندكم عجينة متجانسة.","4. دهنوا طريف الطون مزيان بالشرمولة من جميع الجوانب. خليوه يترقد على الأقل 15 دقيقة فحرارة الغرفة، أو حتى 30 دقيقة فالثلاجة باش يتشرب البنة أكثر.","5. سخنوا مقلة الشواء أو الشواية على نار مجهدة. خاص السطح يكون سخون بزاف باش يتشوى الحوت بلا ما ينشف.","6. ملي تسخن المقلة مزيان، حطوا طريف الطون المرقد. شويوه لمدة 2 حتى 3 دقائق من كل جهة باش يجي محمر من برا وطري من الداخل. إلى بغيتوه طايب أكثر، زيدوا دقيقة لكل جهة، ولكن ردوا البال باش ما يطيبش بزاف ويجي قاصح.","7. قدموه فالحين. تقدروا ترافقوا ستيك الطون المشوي بسلطة مغربية ديال مطيشة والخيار بلا سكر، أو خضرة مفورة. 💡 نصيحة للسكري: الطون مصدر ممتاز للبروتين ومافيهش كاع السكريات. باش تحافظوا على مستوى السكر فالدم مستقر، ردوا البال ما تفوتوش حصة 180 غرام وديما رافقوه بخضرة عندها مؤشر سكري منخفض بحال البروكولي أو اللوبيا الخضرا، وكلوها هي الأولى باش تبطأ امتصاص السكريات إلى كليتو شي حاجة أخرى."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/d/da/Time_for_another_food_photo_%285120543638%29.jpg', ARRAY['thon frais', 'steak thon', 'طون طري']::text[]),
  ('mloukhiya', 'Mloukhiya (corète)', 'الملوخية', 'Mloukhiya (jute leaves)', 'main', ARRAY['ghda', '3cha']::text[], '🌿', '1 assiette (320 g)', 320, 260, 12, 3, 26, 12, 6, 20, 'La mloukhiya (feuilles de corète) est un légume-feuille très riche en fibres et en fer, à IG très bas. Avec un peu de viande maigre, un plat mijoté qui rassasie sans faire monter le sucre.', 'الملوخية خضرة ورقية عامرة بالألياف والحديد، وبمؤشر منخفض بزاف. مع شوية ديال اللحم المزوق، طبق مطيب كيشبع بلا ما يطلع السكر.', '["120 g de feuilles de corète fraîche (mloukhiya)","80 g de viande de bœuf maigre (jarret ou gîte) coupée en petits dés","1 petite tomate (environ 60 g) râpée","1/2 oignon (environ 40 g) finement haché","1 gousse d''ail (environ 5 g) écrasée","1 cuillère à soupe d''huile d''olive extra vierge","1/2 cuillère à café de cumin moulu","1/4 cuillère à café de paprika doux","1 pincée de sel (environ 1 g), poivre noir fraîchement moulu au goût","150 ml d''eau"]'::jsonb, '["120 غرام من أوراق الملوخية الطازجة","80 غرام من لحم البقر الهبرة (الجلدة أو الفخذ) مقطع مكعبات صغيرة","1 حبة طماطم صغيرة (حوالي 60 غرام) محكوكة","1/2 بصلة صغيرة (حوالي 40 غرام) مفرومة رقيق","1 فص ثوم (حوالي 5 غرام) مدقوق","1 ملعقة كبيرة زيت الزيتون البكر الممتاز","1/2 ملعقة صغيرة كمون مطحون","1/4 ملعقة صغيرة تحميرة حلوة","1 رشة ملح (حوالي 1 غرام)، فلفل أسود مطحون طازج حسب الذوق","150 ملل ماء"]'::jsonb, '["1. Lavez soigneusement les feuilles de corète fraîche. Hachez-les finement à la main ou au robot culinaire jusqu''à obtenir une texture pâteuse et légèrement filandreuse. Mettez de côté.","2. Dans une cocotte ou une marmite à fond épais, faites chauffer 1 cuillère à soupe d''huile d''olive à feu moyen. Ajoutez l''oignon haché et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide, en remuant régulièrement.","3. Incorporez les dés de viande de bœuf. Faites-les dorer de tous les côtés pendant environ 5 minutes. Ajoutez ensuite l''ail écrasé, la tomate râpée, 1/2 cuillère à café de cumin, 1/4 cuillère à café de paprika, le sel et le poivre. Mélangez bien et laissez mijoter 5 minutes à feu doux, jusqu''à ce que la tomate ait rendu son jus.","4. Ajoutez les 150 ml d''eau à la préparation. Portez à ébullition, puis réduisez le feu à doux. Couvrez et laissez cuire pendant 45-60 minutes, ou jusqu''à ce que la viande soit très tendre. Vérifiez de temps en temps et ajoutez un filet d''eau si nécessaire pour éviter que le fond n''attache.","5. Une fois la viande tendre, incorporez délicatement la mloukhiya hachée à la sauce. Mélangez doucement pour bien l''intégrer. La mloukhiya va épaissir la sauce et prendre une couleur vert foncé.","6. Laissez mijoter la mloukhiya à feu très doux, à découvert, pendant 20-30 minutes supplémentaires, en remuant occasionnellement pour éviter qu''elle n''attache au fond. La sauce doit devenir onctueuse et la mloukhiya bien cuite, sans amertume.","7. Servez la mloukhiya chaude dans une assiette creuse. Accompagnez d''un quartier de citron pour ceux qui aiment. 💡 Astuce diabète : Une portion de 320 g de mloukhiya est idéale pour un plat principal. Son IG très bas (20) et sa richesse en fibres aident à stabiliser la glycémie. Pour maximiser les bénéfices, mangez-la avec une salade verte fraîche sans féculents, et évitez de l''accompagner de pain blanc ou de riz. Privilégiez plutôt une petite portion de pain complet si vous en ressentez le besoin."]'::jsonb, '["1. غسل أوراق الملوخية الطازجة بعناية. فرمها رقيق باليد أو في الخلاط الكهربائي حتى تصبح عجينة لزجة قليلاً. توضع جانباً.","2. في طنجرة أو قدر ثقيل القاعدة، سخن 1 ملعقة كبيرة من زيت الزيتون على نار متوسطة. أضف البصل المفروم وقلبه لمدة 3-4 دقائق حتى يصبح شفافاً، مع التحريك بانتظام.","3. أضف مكعبات لحم البقر. حمرها من جميع الجوانب لمدة 5 دقائق تقريباً. ثم أضف الثوم المدقوق، الطماطم المحكوكة، 1/2 ملعقة صغيرة كمون، 1/4 ملعقة صغيرة تحميرة، الملح والفلفل. اخلط جيداً واتركه يتشحر لمدة 5 دقائق على نار هادئة، حتى تطلق الطماطم ماءها.","4. أضف 150 ملل من الماء إلى التحضير. اتركه يغلي، ثم خفض النار إلى هادئة. غطِ القدر واتركه يطهى لمدة 45-60 دقيقة، أو حتى يصبح اللحم طرياً جداً. تحقق من وقت لآخر وأضف القليل من الماء إذا لزم الأمر لتجنب الالتصاق.","5. بمجرد أن يصبح اللحم طرياً، أضف الملوخية المفرومة بلطف إلى الصلصة. اخلط برفق لدمجها جيداً. ستكثف الملوخية الصلصة وتأخذ لوناً أخضر داكناً.","6. اترك الملوخية تتشحر على نار هادئة جداً، بدون غطاء، لمدة 20-30 دقيقة إضافية، مع التحريك من حين لآخر لتجنب الالتصاق بالقاع. يجب أن تصبح الصلصة كريمية والملوخية مطهوة جيداً، بدون مرارة.","7. قدم الملوخية ساخنة في طبق عميق. يمكن تقديمها مع قطعة ليمون لمن يحب. 💡 نصيحة للسكري: حصة 320 غرام من الملوخية مثالية كطبق رئيسي. مؤشرها الجلايسيمي المنخفض جداً (20) وغناها بالألياف يساعدان على استقرار نسبة السكر في الدم. لتحقيق أقصى فائدة، تناولها مع سلطة خضراء طازجة بدون نشويات، وتجنب تقديمها مع الخبز الأبيض أو الأرز. الأفضل تناول قطعة صغيرة من الخبز الكامل إذا شعرت بالحاجة لذلك."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/96/Molokheya_hi_res.JPG/1280px-Molokheya_hi_res.JPG', ARRAY['mloukhia', 'ملوخية']::text[]),
  ('tajine-gnaoua-gombo', 'Tajine de gombo (gnaouiya)', 'طاجين الملوخية الخضراء (القناوية)', 'Okra tagine', 'main', ARRAY['ghda', '3cha']::text[], '🫒', '1 assiette (320 g)', 320, 230, 16, 6, 20, 10, 6, 25, 'Le gombo (gnaoua) est pauvre en glucides et riche en fibres solubles qui ralentissent l’absorption du sucre. Mijoté en tajine avec de la viande maigre, un plat sudiste léger et sûr pour la glycémie.', 'القناوية (الملوخية الخضراء) قليلة النشويات وعامرة بالألياف اللي كتبطئ امتصاص السكر. مطيبة فطاجين مع لحم مزوق، طبق جنوبي خفيف وآمن للسكر.', '["120 g de gombo frais (gnaouiya)","80 g de viande de veau maigre (épaule ou noix), coupée en dés de 2-3 cm","1/2 tomate moyenne (environ 60 g), râpée","1/4 oignon moyen (environ 30 g), finement haché","1 gousse d''ail, écrasée","1 cuillère à café d''huile d''olive extra vierge","1/4 cuillère à café de paprika doux","1/8 cuillère à café de cumin moulu","Une pincée de sel et de poivre noir"]'::jsonb, '["120 غرام قناوية طرية","80 غرام لحم عجل بلا شحمة (كتف أو فخد)، مقطع مكعبات 2-3 سم","نص مطيشة متوسطة (حوالي 60 غرام)، محكوكة","ربع بصلة متوسطة (حوالي 30 غرام)، مشلضة رقيقة","ضرس ثومة، مدقوق","1 معلقة صغيرة زيت الزيتون البكر الممتاز","ربع معلقة صغيرة تحميرة حلوة","ثمن معلقة صغيرة كامون مطحون","رشيشة ملح وإبزار"]'::jsonb, '["1. Préparer le gombo : Laver soigneusement 120 g de gombo frais. Couper les deux extrémités (chapeau et pointe) et, si les gousses sont grandes, les couper en deux dans la longueur. Réserver.","2. Préparer la base du tajine : Dans un tajine ou une cocotte à fond épais, faire chauffer 1 cuillère à café d''huile d''olive à feu moyen. Ajouter 30 g d''oignon haché et faire revenir pendant 2-3 minutes jusqu''à ce qu''il devienne translucide.","3. Ajouter la viande et les épices : Incorporer 80 g de dés de veau maigre et la gousse d''ail écrasée. Faire dorer la viande de tous les côtés pendant environ 5 minutes. Ajouter 1/4 cuillère à café de paprika, 1/8 cuillère à café de cumin, une pincée de sel et de poivre noir. Bien mélanger pour enrober la viande.","4. Mijoter la sauce : Ajouter 60 g de tomate râpée. Mélanger et laisser mijoter à feu doux pendant 10 minutes, en remuant de temps en temps, jusqu''à ce que la sauce épaississe légèrement et que les saveurs se mélangent.","5. Ajouter le gombo et l''eau : Disposer le gombo préparé sur la viande et la sauce. Ajouter environ 50 ml d''eau chaude (juste assez pour couvrir à moitié le gombo et la viande).","6. Cuisson lente : Couvrir le tajine et laisser mijoter à feu très doux pendant 45 à 60 minutes, ou jusqu''à ce que la viande soit très tendre et que le gombo soit cuit mais encore légèrement ferme. Vérifier le liquide de temps en temps et ajouter un peu d''eau chaude si nécessaire pour éviter que le tajine ne sèche. La sauce doit être réduite et savoureuse.","7. Servir : Servir le tajine de gombo chaud directement du plat. 💡 Astuce diabète : Pour une portion de 320 g, ce plat a un indice glycémique bas (environ 25). Accompagnez-le d''une petite salade verte sans féculents. Mangez les légumes en premier pour aider à stabiliser la glycémie. Évitez le pain blanc ou les féculents raffinés avec ce plat."]'::jsonb, '["1. تحضير القناوية: غسل 120 غرام من القناوية الطرية مزيان. قطعو ليها الرويسات بجوج (الفوقاني والتحتاني)، وإيلا كانت الحبات كبار، قسموهم على جوج بالطول. خليوها على جنب.","2. تحضير قاعدة الطاجين: ف طاجين أو كوكوط تقيلة، سخنو 1 معلقة صغيرة زيت الزيتون على نار متوسطة. زيدو 30 غرام بصلة مشلضة وخليوها تشحر 2-3 دقايق حتى تولي شفافة.","3. إضافة اللحم والعطرية: زيدو 80 غرام مكعبات لحم العجل بلا شحمة و ضرس الثومة المدقوق. خليو اللحم يتحمر من جميع الجوانب لمدة 5 دقايق تقريبا. زيدو ربع معلقة صغيرة تحميرة، ثمن معلقة صغيرة كامون، رشيشة ملح وإبزار. خلطو مزيان باش اللحم يتغلف بالعطرية.","4. طياب لاصوص: زيدو 60 غرام مطيشة محكوكة. خلطو وخليوها طيب على نار مهيلة لمدة 10 دقايق، مع التحريك مرة مرة، حتى لاصوص تبدا تعقاد شوية والمذاقات يتخلطو.","5. إضافة القناوية والماء: ستفو القناوية اللي وجدتو فوق اللحم ولاصوص. زيدو تقريبا 50 مللتر ماء سخون (غير القياس اللي يغطي نص القناوية واللحم).","6. الطياب على نار مهيلة: غطيو الطاجين وخليوه يطيب على نار مهيلة بزاف لمدة 45 حتى 60 دقيقة، أو حتى يولي اللحم رطب بزاف والقناوية طايبة ولكن باقا شادة فراسها شوية. مرة مرة شوفو واش خاصو الماء وزيدو شوية ماء سخون إيلا نشف الطاجين. لاصوص خاصها تكون خاترة وبنينة.","7. التقديم: قدمو طاجين القناوية سخون مباشرة من الطاجين. 💡 نصيحة للسكري: بالنسبة لحصة ديال 320 غرام، هاد الطبق عندو مؤشر سكري منخفض (حوالي 25). قدموه مع سلطة خضراء صغيرة بلا نشويات. كولو الخضرة هي الأولى باش تساعدو على استقرار مستوى السكر في الدم. تجنبو الخبز الأبيض أو النشويات المكررة مع هاد الطبق."]'::jsonb, null, ARRAY['gombo', 'gnaoua', 'قناوية']::text[]),
  ('besbas-mchermel', 'Salade de fenouil (besbas)', 'شلاضة البسباس', 'Fennel salad', 'salad', ARRAY['ghda', '3cha']::text[], '🥬', '1 portion (180 g)', 180, 80, 9, 5, 2, 4, 4, 15, 'Le fenouil (besbas) cru est croquant, très pauvre en calories et à IG bas. Une entrée fraîche et digestive, parfaite avant un plat, qui n’a quasiment aucun effet sur la glycémie.', 'البسباس ني مقرمش، قليل الكالوري بزاف وبمؤشر منخفض. مقبلات منعشة وكتعاون على الهضم، مثالية قبل الطبق، وما عندها تقريباً حتى تأثير على السكر.', '["150 g de fenouil frais (environ 1 petit bulbe)","1/4 de concombre (environ 40 g)","1/2 tomate moyenne (environ 60 g)","1/4 d''oignon rouge (environ 20 g)","1 cuillère à soupe de jus de citron frais (15 ml)","1/2 cuillère à café d''huile d''olive extra vierge (2.5 ml)","Une pincée de sel de mer (environ 1 g)","Une pincée de poivre noir fraîchement moulu (environ 0.5 g)","Quelques feuilles de coriandre fraîche pour la garniture"]'::jsonb, '["150 غرام من البسباس الطازج (حبة صغيرة تقريبا)","1/4 خيارة (حوالي 40 غرام)","1/2 مطيشة متوسطة (حوالي 60 غرام)","1/4 بصلة حمراء (حوالي 20 غرام)","1 معلقة كبيرة عصير حامض طري (15 مل)","1/2 معلقة صغيرة زيت الزيتون البكر الممتاز (2.5 مل)","رشيشة ملح البحر (حوالي 1 غرام)","رشيشة إبزار أسود مطحون طري (حوالي 0.5 غرام)","وريقات قزبر طري للتزيين"]'::jsonb, '["1. Lavez soigneusement le fenouil, le concombre, la tomate et la coriandre sous l''eau froide. Égouttez-les bien.","2. Préparez le fenouil : retirez les tiges extérieures dures et la base. Coupez le bulbe de fenouil en très fines lamelles ou en petits dés. Vous devriez obtenir environ 150 g de fenouil coupé.","3. Coupez le quart de concombre en petits dés d''environ 0.5 cm. Coupez la demi-tomate en petits dés, en retirant si possible l''excès de graines et de jus pour éviter que la salade ne soit trop aqueuse.","4. Épluchez le quart d''oignon rouge et émincez-le très finement. Si vous trouvez l''oignon trop fort, vous pouvez le rincer rapidement sous l''eau froide après l''avoir coupé pour adoucir son goût.","5. Dans un petit saladier, mélangez délicatement le fenouil, le concombre, la tomate et l''oignon rouge émincé.","6. Dans un petit bol séparé, préparez la vinaigrette : mélangez 1 cuillère à soupe de jus de citron frais, 1/2 cuillère à café d''huile d''olive extra vierge, une pincée de sel de mer et une pincée de poivre noir fraîchement moulu. Fouettez bien pour émulsionner.","7. Versez la vinaigrette sur la salade et mélangez délicatement pour bien enrober tous les ingrédients. Goûtez et ajustez l''assaisonnement si nécessaire. Garnissez de quelques feuilles de coriandre fraîche avant de servir.","💡 Astuce diabète : Cette salade de fenouil (180 g) est une excellente entrée à IG bas (environ 15) qui aide à stabiliser la glycémie. Consommez-la en début de repas pour profiter de ses fibres qui ralentiront l''absorption des glucides du plat principal. Évitez d''ajouter des croûtons ou du pain avec cette salade pour maintenir un faible apport en glucides."]'::jsonb, '["1. غسلوا البسباس، الخيار، مطيشة والقزبر مزيان تحت الماء البارد. قطرهم مزيان.","2. وجدوا البسباس: حيدوا العواد القاصحين والراس التحتاني. قطعوا البسباس شرائح رقيقة بزاف أو مكعبات صغار. خاص تكون عندكم تقريبا 150 غرام ديال البسباس مقطع.","3. قطعوا ربع الخيارة مكعبات صغار ديال حوالي 0.5 سم. قطعوا نص مطيشة مكعبات صغار، وحاولوا تحيدوا الزريعة والماء الزايد باش ما تجيش الشلاضة ميهة.","4. قشروا ربع البصلة الحمراء وقطعوها رقيقة بزاف. إلا بانت ليكم البصلة قوية بزاف، ممكن تشللوها دغيا تحت الماء البارد من بعد ما تقطعوها باش تخففوا من المذاق ديالها.","5. فزلافة صغيرة، خلطوا بلطف البسباس، الخيار، مطيشة والبصلة الحمراء المقطعة.","6. فزلافة أخرى صغيرة، وجدوا لاصوص: خلطوا 1 معلقة كبيرة ديال عصير الحامض الطري، 1/2 معلقة صغيرة ديال زيت الزيتون البكر الممتاز، رشيشة ملح البحر ورشيشة إبزار أسود مطحون طري. خلطوا مزيان باش يتجانسوا.","7. خويوا لاصوص فوق الشلاضة وخلطوا بلطف باش يتغطاو كاع المكونات. ذوقوا وقادوا المذاق إلا كان خاص. زينوا بشي وريقات ديال القزبر الطري قبل ما تقدموها.","💡 نصيحة للسكري: شلاضة البسباس هادي (180 غرام) هي مقبلة ممتازة بمؤشر سكري منخفض (حوالي 15) وكتساعد باش تحافظ على مستوى السكر في الدم. كولوها في أول الوجبة باش تستافدوا من الألياف ديالها اللي كاتباطئ امتصاص الكربوهيدرات من الطبق الرئيسي. تجنبوا تزيدوا الخبز المحمص أو الخبز مع هاد الشلاضة باش تحافظوا على كمية قليلة من الكربوهيدرات."]'::jsonb, null, ARRAY['fenouil', 'besbas', 'بسباس']::text[]),
  ('brochettes-kebda', 'Brochettes de foie (boulfaf léger)', 'قطبان الكبدة (بولفاف خفيف)', 'Liver skewers (light boulfaf)', 'main', ARRAY['ghda', '3cha', 'snack']::text[], '🍢', '2 brochettes (150 g)', 150, 220, 5, 1, 30, 9, 1, 10, 'Le boulfaf de l’Aïd, version légère : foie grillé (sans l’envelopper de gras de mouton), cumin et citron. Bombe de fer et de B12, presque zéro glucide. Grillé, jamais frit.', 'بولفاف العيد، بالنسخة الخفيفة: كبدة مشوية (بلا ما نلفوها بالشحمة)، كامون وحامض. قنبلة ديال الحديد وB12، تقريباً بلا نشويات. مشوي، عمرو مقلي.', '["150 g de foie de veau ou d''agneau frais (coupé en dés de 2-3 cm)","1/2 c. à café de cumin moulu","1/4 c. à café de paprika doux","1/8 c. à café de piment doux (facultatif)","1 pincée de sel fin","1/2 c. à café d''huile d''olive extra vierge","1/2 citron (pour le jus et les quartiers)","2 petites brochettes en bois ou en métal"]'::jsonb, '["150 غرام كبدة عجل أو غنم طرية (مقطعة مكعبات 2-3 سم)","1/2 ملعقة صغيرة كمون مطحون","1/4 ملعقة صغيرة تحميرة حلوة","1/8 ملعقة صغيرة فلفل حار (اختياري)","رشة ملح رقيق","1/2 ملعقة صغيرة زيت الزيتون البكر الممتاز","1/2 حامضة (للعصير وقطع التقديم)","2 قطبان صغار من الخشب أو المعدن"]'::jsonb, '["1. Dans un bol, mélangez les dés de foie avec 1/2 c. à café de cumin moulu, 1/4 c. à café de paprika doux, 1/8 c. à café de piment doux (si utilisé), et une pincée de sel fin. Ajoutez 1/2 c. à café d''huile d''olive et le jus d''un quart de citron. Mélangez bien pour enrober tous les morceaux de foie.","2. Laissez mariner le foie pendant au moins 15 minutes à température ambiante, ou jusqu''à 30 minutes au réfrigérateur pour que les saveurs se développent.","3. Pendant ce temps, préchauffez votre grill (barbecue au charbon, grill électrique ou poêle-grill en fonte) à feu moyen-vif. Assurez-vous qu''il soit bien chaud avant de commencer la cuisson.","4. Enfilez les dés de foie marinés sur les deux brochettes, en veillant à ne pas trop les serrer pour une cuisson uniforme. Chaque brochette devrait contenir environ 75 g de foie.","5. Placez les brochettes sur le grill chaud. Faites-les cuire pendant 2 à 3 minutes de chaque côté, en les retournant régulièrement, jusqu''à ce que le foie soit bien doré à l''extérieur et légèrement rosé à l''intérieur. Le foie doit rester tendre et juteux.","6. Retirez les brochettes du grill et laissez-les reposer 1 minute avant de servir. Servez immédiatement avec les quartiers de citron restants pour presser un filet de jus frais sur le foie.","💡 Astuce diabète : Cette portion de 2 brochettes (environ 150 g) est parfaite pour un repas principal, avec seulement 5 g de glucides et un IG très bas de 10. Pour un repas équilibré, accompagnez-les d''une grande salade verte sans féculents et de légumes grillés non-amidonnés. Évitez le pain ou les frites pour maintenir un faible apport en glucides."]'::jsonb, '["1. فزلافة، خلطي مكعبات الكبدة مع 1/2 ملعقة صغيرة كمون مطحون، 1/4 ملعقة صغيرة تحميرة حلوة، 1/8 ملعقة صغيرة فلفل حار (إيلا استعملتيه)، ورشة ملح رقيق. زيدي 1/2 ملعقة صغيرة زيت الزيتون وعصير ربع حامضة. خلطي مزيان باش الكبدة كلها تلبس بالعطرية.","2. خلي الكبدة ترقد على الأقل 15 دقيقة فحرارة الغرفة، أو حتى 30 دقيقة فالثلاجة باش تشرب العطرية مزيان.","3. فهاذ الوقت، سخني الشواية ديالك (فحم، كهربائية أو مقلاة الشواء) على نار متوسطة إلى مجهدة. تأكدي أنها سخونة مزيان قبل ما تبداي الطياب.","4. ركبي مكعبات الكبدة المرقدة فالقطبان بجوج، ردي البال ما تزيريهمش بزاف باش يطيبو مقادين. كل قطيب خاص تكون فيه تقريبا 75 غرام ديال الكبدة.","5. حطي القطبان فوق الشواية السخونة. شوفيها لمدة 2 حتى 3 دقائق من كل جهة، وقلبيهم مرة مرة، حتى تتحمر الكبدة من برا وتبقى شوية وردية من الداخل. الكبدة خاصها تبقى رطبة ومعلكة.","6. حيدي القطبان من الشواية وخليهم يرتاحو دقيقة قبل التقديم. قدميهم فالحال مع قطع الحامض اللي بقاو باش تعصري شوية عصير طري فوق الكبدة.","💡 نصيحة للسكري: هاد الكمية ديال 2 قطبان (تقريبا 150 غرام) مثالية لوجبة رئيسية، فيها غير 5 غرام ديال الكربوهيدرات ومؤشر سكري منخفض جداً (10). لوجبة متوازنة، قدميها مع سلطة خضراء كبيرة بلا نشويات وخضروات مشوية غير نشوية. تجنبي الخبز أو البطاطس المقلية باش تحافظي على نسبة كربوهيدرات منخفضة."]'::jsonb, null, ARRAY['boulfaf', 'kebda mechwiya', 'بولفاف']::text[]),
  ('soupe-lentilles-corail', 'Soupe de lentilles corail au cumin', 'شوربة العدس الأحمر بالكامون', 'Red lentil cumin soup', 'soup', ARRAY['3cha', 'ghda']::text[], '🍲', '1 bol (320 ml)', 320, 200, 30, 4, 12, 4, 8, 30, 'Les lentilles corail cuisent vite et gardent un IG bas. Cette soupe veloutée, protéinée et riche en fibres, est un dîner d’hiver rassasiant qui stabilise la glycémie toute la nuit.', 'العدس الأحمر كيطيب بزربة وكيبقى بمؤشر منخفض. هاد الشوربة الدسمة، الغنية بالبروتين والألياف، عشا ديال الشتا كيشبع وكيثبت السكر الليل كامل.', '["80 g de lentilles corail rincées","1/2 oignon moyen (environ 60 g), haché finement","1 petite carotte (environ 40 g), coupée en petits dés","1/2 gousse d''ail (environ 2 g), écrasée","1/2 cuillère à café de cumin moulu","1/4 cuillère à café de curcuma moulu","250 ml d''eau ou de bouillon de légumes faible en sodium","1 cuillère à café d''huile d''olive extra vierge","Une pincée de sel de l''Himalaya et de poivre noir fraîchement moulu"]'::jsonb, '["80 غرام عدس أحمر مغسول","1/2 بصلة متوسطة (حوالي 60 غرام)، مفرومة رقيق","1 جزرة صغيرة (حوالي 40 غرام)، مقطعة مكعبات صغيرة","1/2 فص ثوم (حوالي 2 غرام)، مدقوق","1/2 ملعقة صغيرة كامون مطحون","1/4 ملعقة صغيرة خرقوم بلدي مطحون","250 مل ماء أو مرق خضار قليل الصوديوم","1 ملعقة صغيرة زيت الزيتون البكر الممتاز","رشة ملح الهيمالايا وفلفل أسود مطحون طازج"]'::jsonb, '["Dans une casserole à fond épais, faites chauffer 1 cuillère à café d''huile d''olive à feu moyen. Ajoutez 1/2 oignon haché et 1 petite carotte coupée en dés. Faites revenir pendant 5 minutes, en remuant de temps en temps, jusqu''à ce que les légumes ramollissent légèrement.","Ajoutez 1/2 gousse d''ail écrasée, 1/2 cuillère à café de cumin moulu et 1/4 cuillère à café de curcuma moulu. Mélangez bien et laissez cuire 1 minute de plus, jusqu''à ce que les épices libèrent leur parfum.","Incorporez 80 g de lentilles corail rincées et 250 ml d''eau ou de bouillon de légumes faible en sodium. Portez à ébullition à feu vif.","Une fois que la soupe bout, réduisez le feu à doux, couvrez et laissez mijoter pendant 15 à 20 minutes, ou jusqu''à ce que les lentilles soient très tendres et aient absorbé la majeure partie du liquide. Remuez de temps en temps pour éviter que ça n''accroche au fond.","Retirez la casserole du feu. À l''aide d''un mixeur plongeant, mixez la soupe jusqu''à obtenir une consistance veloutée et homogène. Si la soupe est trop épaisse, vous pouvez ajouter une petite quantité d''eau chaude (environ 20-30 ml) pour ajuster la texture désirée.","Assaisonnez avec une pincée de sel de l''Himalaya et de poivre noir fraîchement moulu selon votre goût. Mélangez bien et servez immédiatement dans un bol de 320 ml.","💡 Astuce diabète : Cette soupe de lentilles corail (320 g, IG 30) est un excellent choix pour stabiliser la glycémie. Pour un repas équilibré, accompagnez-la d''une petite salade verte sans féculents et d''une source de protéines maigres (comme 60-80g de poulet grillé). Évitez le pain blanc ou les croutons qui augmenteraient l''IG global du repas."]'::jsonb, '["فوق نار متوسطة، سخني 1 ملعقة صغيرة زيت الزيتون في طنجرة ثقيلة. ضيفي 1/2 بصلة مفرومة و 1 جزرة صغيرة مقطعة مكعبات. خليها تشحر لمدة 5 دقائق، مع التحريك مرة مرة، حتى تبدا الخضرة ترطاب شوية.","ضيفي 1/2 فص ثوم مدقوق، 1/2 ملعقة صغيرة كامون مطحون و 1/4 ملعقة صغيرة خرقوم بلدي مطحون. خلطي مزيان و خليها طيب دقيقة أخرى، حتى تطلع ريحة العطرية.","زيدي 80 غرام عدس أحمر مغسول و 250 مل ماء أو مرق خضار قليل الصوديوم. خليها تغلى فوق نار مجهدة.","ملي تبدا الشوربة تغلى، نقصي النار لمهيلة، غطي الطنجرة و خليها طيب على خاطرها لمدة 15 حتى 20 دقيقة، أو حتى يولي العدس رطب بزاف و يشرب أغلب السائل. حركي مرة مرة باش ما تلصقش في القاع.","حيدي الطنجرة من فوق النار. استعملي خلاط يدوي باش تطحني الشوربة حتى تولي خفيفة و ملساء. إذا كانت الشوربة ثقيلة بزاف، تقدري تزيدي شوية ماء سخون (حوالي 20-30 مل) باش تقادي القوام اللي بغيتي.","تبلي الشوربة برشة ملح الهيمالايا و فلفل أسود مطحون طازج حسب الذوق. خلطي مزيان و قدميها مباشرة في زلافة ديال 320 مل.","💡 نصيحة للسكري: هاد شوربة العدس الأحمر (320 غرام، مؤشر سكري 30) اختيار ممتاز لتثبيت مستوى السكر في الدم. لوجبة متوازنة، قدميها مع سلطة خضراء صغيرة بدون نشويات و مصدر بروتين قليل الدهن (بحال 60-80 غرام دجاج مشوي). تجنبي الخبز الأبيض أو الخبز المحمص اللي غادي يزيد من المؤشر السكري الإجمالي للوجبة."]'::jsonb, null, ARRAY['lentilles corail', 'عدس أحمر']::text[]),
  ('tajine-poulet-champignons', 'Tajine de poulet aux champignons', 'طاجين الدجاج بالفطر', 'Chicken & mushroom tagine', 'main', ARRAY['ghda', '3cha']::text[], '🍄', '1 assiette (320 g)', 320, 300, 8, 4, 36, 14, 3, 15, 'Les champignons sont presque sans glucides et riches en fibres. Mijotés avec du poulet sans peau, olives et citron confit, ils font un tajine savoureux et très léger pour la glycémie.', 'الفطر تقريباً بلا نشويات وعامر بالألياف. مطيب مع دجاج بلا جلدة وزيتون وحامض مصير، كيدير طاجين بنين وخفيف بزاف على السكر.', '["150 g de blanc de poulet, sans peau","100 g de champignons de Paris frais","1/4 d''oignon rouge (environ 30 g), haché finement","1/2 gousse d''ail (environ 2 g), écrasée","1/4 de citron confit (environ 10 g), rincé et coupé en dés","3 olives violettes (environ 10 g), dénoyautées","1 c. à café d''huile d''olive extra vierge","1/4 c. à café de curcuma moulu","Une pincée de safran en pistils","Sel et poivre noir fraîchement moulu, au goût"]'::jsonb, '["150 غرام صدر دجاج، بلا جلد","100 غرام فطر طري (شومبينيون)","1/4 بصلة حمراء (حوالي 30 غرام)، مشلضة رقيقة","1/2 فص ثوم (حوالي 2 غرام)، مدقوق","1/4 حامضة مصيرة (حوالي 10 غرام)، مغسولة ومقطعة مكعبات صغار","3 زيتونات كحلين (حوالي 10 غرام)، محيد العظم","1 م. ص. زيت الزيتون بكر ممتاز","1/4 م. ص. خرقوم بلدي مطحون","شوية زعفران شعرة","ملح وإبزار مطحون طري، حسب الذوق"]'::jsonb, '["Coupez le blanc de poulet en morceaux de taille moyenne. Dans un petit bol, mélangez le poulet avec le curcuma, le safran, une pincée de sel et de poivre. Laissez mariner 10 minutes.","Nettoyez les champignons de Paris avec un chiffon humide et coupez-les en quatre. Rincez le citron confit pour enlever l''excès de sel et coupez-le en petits dés. Dénoyautez les olives.","Dans un petit tajine ou une cocotte à fond épais, faites chauffer 1 c. à café d''huile d''olive à feu doux. Ajoutez l''oignon haché et faites-le revenir pendant 3-4 minutes jusqu''à ce qu''il devienne translucide, sans le laisser dorer.","Ajoutez l''ail écrasé et les morceaux de poulet mariné. Faites dorer le poulet de tous les côtés pendant environ 5-7 minutes à feu moyen, en remuant de temps en temps.","Incorporez les champignons coupés, les dés de citron confit et les olives. Ajoutez environ 50 ml d''eau chaude (juste assez pour couvrir le fond du tajine et éviter que ça ne colle).","Couvrez le tajine et laissez mijoter à feu très doux pendant 20-25 minutes, ou jusqu''à ce que le poulet soit bien cuit et tendre et que les champignons aient rendu leur eau et soient fondants. Vérifiez l''assaisonnement et ajustez si nécessaire.","Servez le tajine de poulet aux champignons chaud, parsemé de coriandre fraîche ciselée. 💡 Astuce diabète : Cette portion de 320g est idéale pour contrôler votre glycémie. Pour un repas équilibré, accompagnez ce tajine d''une salade verte fraîche sans féculents. Mangez toujours les légumes et les protéines en premier pour ralentir l''absorption des glucides."]'::jsonb, '["قطعوا صدر الدجاج طريفات متوسطين. فزلافة صغيرة، خلطوا الدجاج مع الخرقوم، الزعفران، شوية ملح وإبزار. خليوه يترقد 10 دقايق.","نظفوا الفطر (الشومبينيون) بفوطة فازكة وقطعوه على أربعة. شللوا الحامض المصير باش تحيدوا الملحة الزايدة وقطعوه مكعبات صغار. حيدوا العظم من الزيتون.","فطاجين صغير ولا كوكوط ثقيلة، سخنوا 1 م. ص. زيت الزيتون على نار مهيلة. زيدوا البصلة مشلضة وخليوها تشحر 3-4 دقايق حتى تولي شفافة، بلا ما تحمر.","زيدوا الثوم مدقوق وطريفات الدجاج المرقد. خليو الدجاج يتحمر من جميع الجوانب لمدة 5-7 دقايق على نار متوسطة، مع التحريك مرة مرة.","زيدوا الفطر مقطع، مكعبات الحامض المصير والزيتون. زيدوا تقريبا 50 مل ماء سخون (غير القياس اللي يغطي قاع الطاجين باش ما يلصقش).","غطيو الطاجين وخليوه يطيب على نار مهيلة بزاف لمدة 20-25 دقيقة، ولا حتى يطيب الدجاج مزيان ويولي رطب والفطر يطلق الماء ديالو ويولي طايب مزيان. ذوقوا الملح والإبزار وقادوا إذا خاص.","قدموا طاجين الدجاج بالفطر سخون، مرشوش بالقزبر طري مقطع رقيق. 💡 نصيحة للسكري: هاد الكمية ديال 320 غرام مثالية باش تحافظوا على مستوى السكر في الدم. لوجبة متوازنة، قدموا الطاجين مع شلاضة خضرا طرية بلا نشويات. ديما كلوا الخضرة والبروتينات هما الأولين باش تبطئوا امتصاص الكربوهيدرات."]'::jsonb, null, ARRAY['champignons', 'فطر']::text[]),
  ('poisson-charmoula-grille', 'Poisson entier grillé à la chermoula', 'حوت كامل مشوي بالشرمولة', 'Whole grilled chermoula fish', 'seafood', ARRAY['ghda', '3cha']::text[], '🐟', '1 poisson (300 g)', 300, 290, 2, 0, 42, 12, 0, 5, 'Un poisson blanc entier (loup, dorade), mariné à la chermoula et grillé : protéines pures, oméga-3, zéro glucide. Le plat côtier le plus sûr pour la glycémie, meilleur que toute viande.', 'حوت أبيض كامل (لوب، دورادة)، مشرمل ومشوي: بروتين صافي، أوميغا 3، بلا نشويات. أأمن طبق ساحلي للسكر، أحسن من أي لحم.', '["1 poisson blanc entier (loup, dorade) de 300 g, écaillé et vidé","2 gousses d''ail, hachées finement","1/2 bouquet de coriandre fraîche (environ 15 g), hachée","1/2 bouquet de persil frais (environ 15 g), haché","1/2 citron confit (environ 20 g), rincé et haché finement","1 c. à café de cumin moulu","1/2 c. à café de paprika doux","2 c. à soupe d''huile d''olive extra vierge","Sel et poivre noir fraîchement moulu, au goût"]'::jsonb, '["1 حوت أبيض كامل (دربان، دوراد) 300 غ، منقي ومحيد ليه المصارن","2 فصوص ثوم، مفرومين رقاق","1/2 ربطة قزبر طري (حوالي 15 غ)، مفروم","1/2 ربطة معدنوس طري (حوالي 15 غ)، مفروم","1/2 حامضة مصيرة (حوالي 20 غ)، مغسولة ومقطعة رقيق بزاف","1 م. ص. كمون مطحون","1/2 م. ص. تحميرة حلوة","2 م. ك. زيت الزيتون البكر الممتاز","ملح وإبزار أسود مطحون طري، حسب الذوق"]'::jsonb, '["1. Rincez soigneusement le poisson sous l''eau froide et séchez-le avec du papier absorbant. Faites 3 à 4 incisions diagonales profondes de chaque côté du poisson pour que la marinade pénètre bien.","2. Dans un bol, préparez la chermoula : mélangez l''ail haché, la coriandre hachée, le persil haché, le citron confit haché, le cumin moulu, le paprika doux, 1 cuillère à soupe d''huile d''olive, le sel et le poivre. Mélangez bien jusqu''à obtenir une pâte homogène.","3. Farcissez l''intérieur du poisson avec une partie généreuse de la chermoula. Ensuite, enduisez l''extérieur du poisson avec le reste de la marinade, en veillant à bien faire pénétrer la chermoula dans les incisions.","4. Laissez mariner le poisson au réfrigérateur pendant au moins 30 minutes, idéalement 1 à 2 heures pour que les saveurs se développent pleinement.","5. Préchauffez votre grill (barbecue ou grill de four) à feu moyen-vif. Badigeonnez légèrement la grille avec la cuillère à soupe d''huile d''olive restante pour éviter que le poisson ne colle.","6. Placez le poisson mariné sur le grill chaud. Faites-le griller pendant environ 7 à 9 minutes de chaque côté, ou jusqu''à ce que la chair soit opaque et se détache facilement à la fourchette. Le temps de cuisson peut varier selon l''épaisseur du poisson. Surveillez attentivement pour éviter de le dessécher.","7. Servez le poisson entier grillé immédiatement. Vous pouvez l''accompagner d''une salade de crudités simples (tomates, concombres) sans féculents. Il est délicieux tel quel, avec un filet de jus de citron frais si désiré.","💡 Astuce diabète : Ce plat est idéal pour les diabétiques de type 2. La portion de 300 g de poisson est riche en protéines et oméga-3, avec un indice glycémique (IG) quasi nul. Pour une meilleure gestion de la glycémie, mangez toujours les protéines et les légumes verts en début de repas. Évitez de le servir avec du pain blanc ou des frites ; préférez une salade verte ou des légumes vapeur."]'::jsonb, '["1. غسلوا الحوت مزيان تحت الماء بارد ونشفوه بورق المطبخ. ديروا 3 حتى 4 فليحات مايلين وعميقين في كل جهة من الحوت باش تدخل الشرمولة مزيان.","2. في زلافة، حضروا الشرمولة: خلطوا الثوم مفروم، القزبر مفروم، المعدنوس مفروم، الحامض مصير مفروم، الكمون، التحميرة، 1 م. ك. زيت الزيتون، الملح والإبزار. خلطوا مزيان حتى تحصلوا على خليط متجانس.","3. عمروا داخل الحوت بجزء كبير من الشرمولة. من بعد، دهنوا الحوت من برا بالباقي ديال الشرمولة، وتأكدوا أن الشرمولة دخلات مزيان في الفليحات.","4. خليوا الحوت يترقد في الثلاجة لمدة 30 دقيقة على الأقل، ومن الأفضل من ساعة حتى لساعتين باش يتشرب النكهات مزيان.","5. سخنوا الشواية ديالكم (شواية الفحم أو شواية الفرن) على نار متوسطة إلى مجهدة. دهنوا الشواية بشوية من م. ك. زيت الزيتون اللي بقات باش ما يلصقش الحوت.","6. حطوا الحوت المرقد فوق الشواية السخونة. شواوه لمدة 7 حتى 9 دقائق من كل جهة، أو حتى يولي اللحم أبيض ويتفتت بسهولة بالشوكة. وقت الطياب يقدر يختلف على حسب سمك الحوت. راقبوه مزيان باش ما ينشفش.","7. قدموا الحوت المشوي كامل مباشرة. تقدروا ترافقوه بسلطة خضرا بسيطة (مطيشة، خيار) بلا نشويات. كيجي بنين هكاك، مع شوية عصير حامض طري إذا بغيتوا.","💡 نصيحة للسكري: هاد الطبق مثالي لمرضى السكري من النوع 2. الحصة ديال 300 غرام ديال الحوت غنية بالبروتينات وأوميغا 3، ومؤشرها الجلايسيمي (IG) شبه منعدم. باش تتحكموا في مستوى السكر في الدم بشكل أفضل، ديما كلوا البروتينات والخضروات الخضراء في بداية الوجبة. تجنبوا تقدموه مع الخبز الأبيض أو البطاطس المقلية؛ فضلوا سلطة خضراء أو خضروات مبخرة."]'::jsonb, null, ARRAY['poisson grillé', 'حوت مشوي']::text[]),
  ('salade-pois-chiches', 'Salade de pois chiches', 'شلاضة الحمص', 'Chickpea salad', 'salad', ARRAY['ghda', '3cha', 'snack']::text[], '🫛', '1 assiette (220 g)', 220, 240, 30, 4, 12, 8, 9, 30, 'Pois chiches (IG 30) + crudités + huile d’olive : une salade-repas complète, riche en protéines végétales et en fibres, qui rassasie longtemps sans pic de glycémie.', 'الحمص (مؤشر 30) + خضرة نية + زيت زيتون: شلاضة-ماكلة كاملة، غنية بالبروتين النباتي والألياف، كتشبع مدة طويلة بلا طلعة سكر.', '["120 g de pois chiches cuits (en conserve, rincés et égouttés)","50 g de concombre (environ 1/4 de pièce moyenne), coupé en dés","30 g de tomate (environ 1/4 de pièce moyenne), coupée en dés","10 g d''oignon rouge (environ 1/8 de pièce moyenne), finement haché","5 g de persil frais, haché","1 c. à soupe (15 ml) d''huile d''olive extra vierge","1 c. à café (5 ml) de jus de citron frais","Une pincée de cumin moulu","Sel et poivre noir fraîchement moulu, au goût"]'::jsonb, '["120 غرام حمص طايب (معلب، مغسول ومقطر)","50 غرام خيار (تقريبا ربع خيارة متوسطة)، مقطع مكعبات","30 غرام مطيشة (تقريبا ربع مطيشة متوسطة)، مقطعة مكعبات","10 غرام بصل أحمر (تقريبا ثمن بصلة متوسطة)، مشلض رقيق","5 غرام معدنوس طري، مقطع رقيق","1 معلقة كبيرة (15 مل) زيت الزيتون البكر الممتاز","1 معلقة صغيرة (5 مل) عصير الحامض طري","رشة كمون مطحون","ملح وإبزار مطحون طري، حسب الذوق"]'::jsonb, '["1. Rincez soigneusement les 120 g de pois chiches en conserve sous l''eau froide et égouttez-les bien. Cela aide à réduire le sodium.","2. Lavez le concombre et la tomate. Coupez 50 g de concombre et 30 g de tomate en petits dés d''environ 0.5 cm. Hachez finement 10 g d''oignon rouge et 5 g de persil frais.","3. Dans un grand bol, mélangez les pois chiches égouttés avec les dés de concombre, de tomate, l''oignon rouge haché et le persil frais.","4. Dans un petit récipient séparé, préparez la vinaigrette. Versez 1 c. à soupe (15 ml) d''huile d''olive extra vierge et 1 c. à café (5 ml) de jus de citron frais.","5. Ajoutez une pincée de cumin moulu à la vinaigrette, puis salez et poivrez au goût. Mélangez bien la vinaigrette avec une petite cuillère ou une fourchette jusqu''à ce qu''elle soit émulsionnée.","6. Versez la vinaigrette sur le mélange de pois chiches et de légumes dans le grand bol. Mélangez délicatement pour que tous les ingrédients soient bien enrobés. Goûtez et ajustez l''assaisonnement si nécessaire.","7. Servez immédiatement ou laissez reposer au frais pendant 15-20 minutes pour que les saveurs se mélangent. Cette salade est meilleure fraîche. Garnissez d''une feuille de persil si désiré.","💡 Astuce diabète : Cette salade de pois chiches (220 g) est une excellente option avec un IG de 30. Pour une meilleure gestion de la glycémie, consommez-la en début de repas ou comme plat principal léger. Évitez de l''accompagner de pain blanc ou de féculents raffinés; préférez une petite portion de pain complet si nécessaire, ou savourez-la telle quelle pour maximiser les bienfaits des fibres."]'::jsonb, '["1. غسل 120 غرام ديال الحمص المعلب مزيان تحت الماء بارد وقطروه مزيان. هادشي كيعاون باش ينقص الصوديوم.","2. غسل الخيار ومطيشة. قطع 50 غرام خيار و 30 غرام مطيشة مكعبات صغار تقريبا 0.5 سم. شلض 10 غرام بصل أحمر و 5 غرام معدنوس طري رقيق.","3. فزلافة كبيرة، خلط الحمص اللي قطرتوه مع مكعبات الخيار، مطيشة، البصل الأحمر المشلض والمعدنوس الطري.","4. فزلافة صغيرة بوحدها، وجد الصلصة. خوي 1 معلقة كبيرة (15 مل) زيت الزيتون البكر الممتاز و 1 معلقة صغيرة (5 مل) عصير الحامض طري.","5. زيد رشة كمون مطحون على الصلصة، من بعد ملح وإبزار حسب الذوق. خلط الصلصة مزيان بمعلقة صغيرة ولا فرشيطة حتى تتجانس.","6. خوي الصلصة فوق خليط الحمص والخضرة فالزلافة الكبيرة. خلط بلطف باش يتغطاو كاع المكونات مزيان. ذوق وقاد الملح والإبزار إذا خاص.","7. قدمها مباشرة ولا خليها تبرد فالثلاجة لمدة 15-20 دقيقة باش تطلق النكهات. هاد الشلاضة كتجي بنينة وهي باردة. زينها بورقة معدنوس إذا بغيتي.","💡 نصيحة للسكري: هاد شلاضة الحمص (220 غرام) اختيار ممتاز بمؤشر سكري 30. باش تتحكم فمستوى السكر فالدم أحسن، كلها فبداية الوجبة ولا كوجبة رئيسية خفيفة. تجنب تاكلها مع الخبز الأبيض ولا النشويات المكررة؛ فضل كمية صغيرة من الخبز الكامل إذا ضروري، ولا كلها هاكا باش تستافد من الألياف لأقصى درجة."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/fe/Hummus_salad.jpg/1280px-Hummus_salad.jpg', ARRAY['pois chiches salade', 'شلاضة حمص']::text[]),
  ('jus-betterave-carotte', 'Jus betterave-carotte-gingembre', 'عصير البربة والخيزو والسكينجبير', 'Beet-carrot-ginger juice', 'drink', ARRAY['drink', 'ftour']::text[], '🥤', '1 verre (250 ml)', 250, 90, 18, 13, 2, 0, 4, 40, 'Contrairement aux jus de fruits sucrés, ce jus de légumes (betterave + carotte + gingembre) garde plus de fibres si non filtré, et apporte des nitrates bons pour la circulation. Petit verre, non filtré, sans sucre.', 'عكس عصير الفواكه المسكر، هاد عصير الخضرة (بربة + خيزو + سكينجبير) كيحتفظ بألياف أكثر إلا ما صفيتيهش، وفيه نترات مزيانة للدورة الدموية. كاس صغير، بلا تصفية، بلا سكر.', '["100 g de betterave crue (environ 1 petite betterave)","100 g de carotte crue (environ 1 carotte moyenne)","5 g de gingembre frais (environ 1 cm de racine)","50 ml d''eau filtrée","1/2 c. à café de jus de citron frais","1 pincée de sel de l''Himalaya (facultatif)"]'::jsonb, '["100 غرام ديال الباربا خضرا (حبة صغيرة تقريبا)","100 غرام ديال خيزو خضر (حبة متوسطة تقريبا)","5 غرام ديال سكينجبير طري (طرف صغير ديال 1 سنتيمتر)","50 مللتر ديال الماء مغلي ومبرد","نص معلقة صغيرة ديال عصير الحامض طري","رشيشة ديال الملحة الحية (اختياري)"]'::jsonb, '["1. Lavez soigneusement la betterave et la carotte. Brossez la peau si nécessaire pour retirer toute trace de terre. Épluchez-les si vous préférez, mais pour conserver un maximum de fibres et de nutriments, il est conseillé de les laisser avec leur peau fine.","2. Coupez la betterave et la carotte en petits dés ou en rondelles fines pour faciliter le mixage.","3. Épluchez le gingembre frais et coupez-le en petits morceaux.","4. Dans un mixeur puissant, placez les dés de betterave, les morceaux de carotte et le gingembre.","5. Ajoutez les 50 ml d''eau filtrée et le jus de citron frais. Si vous le souhaitez, ajoutez la pincée de sel de l''Himalaya pour rehausser les saveurs.","6. Mixez le tout à vitesse élevée pendant 1 à 2 minutes, jusqu''à obtenir une consistance lisse mais légèrement épaisse, en conservant toutes les fibres. Ne filtrez pas le jus pour maximiser l''apport en fibres.","7. Versez le jus dans un verre de 250 ml et consommez-le immédiatement pour profiter de tous ses bienfaits. Ce jus ne se conserve pas bien et doit être bu frais.","💡 Astuce diabète : Consommez ce jus de 250 g (1 verre) en début de repas ou en collation légère, sans le filtrer pour bénéficier de toutes les fibres qui aident à ralentir l''absorption du sucre. Son indice glycémique est modéré (environ 40), mais il est important de ne pas dépasser la portion recommandée et d''éviter d''ajouter du sucre ou du miel."]'::jsonb, '["1. غسلوا الباربا وخيزو مزيان. حكوا القشرة بالشيتا إلى كانت فيها شي تراب. تقدروا تقشروهم إلى بغيتوا، ولكن من الأحسن تخليوهم بقشرتهم الرقيقة باش تستافدوا من الألياف والفيتامينات.","2. قطعوا الباربا وخيزو مربعات صغار أو دوائر رقاق باش يسهل يتطحنوا.","3. قشروا سكينجبير طري وقطعوه طريفات صغار.","4. في الخلاط الكهربائي، حطوا الباربا وخيزو وسكينجبير اللي قطعتوهم.","5. زيدوا عليهم 50 مللتر ديال الماء مغلي ومبرد وعصير الحامض طري. إلى بغيتوا، زيدوا رشيشة ديال الملحة الحية باش تزيدوا البنة.","6. طحنوا كلشي على سرعة عالية لمدة دقيقة حتى جوج دقائق، حتى يولي الخليط أملس ولكن شوية خاتر، وخليو فيه جميع الألياف. متصفيوش العصير باش تستافدوا من الألياف كاملة.","7. خويوا العصير في كاس ديال 250 مللتر وشربوه مباشرة باش تستافدوا من جميع الفوائد ديالو. هذا العصير مكيصبرش بزاف وخصو يتشرب بارد.","💡 نصيحة للسكري: شربوا هذا العصير ديال 250 غرام (كاس واحد) في بداية الوجبة أو كوجبة خفيفة، ومتصفيوهش باش تستافدوا من الألياف اللي كتعاون باش السكر ميطلعش دغيا. المؤشر الجلايسيمي ديالو متوسط (حوالي 40)، ولكن من المهم متجاوزوش الكمية الموصى بها ومضيفوش السكر أو العسل."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6d/Juice_af_%C3%A6bler%2C_r%C3%B8dbede%2C_guler%C3%B8dder%2C_grape_og_ingef%C3%A6r_%285022924772%29.jpg/1280px-Juice_af_%C3%A6bler%2C_r%C3%B8dbede%2C_guler%C3%B8dder%2C_grape_og_ingef%C3%A6r_%285022924772%29.jpg', ARRAY['jus betterave', 'عصير بربة']::text[]),
  ('jben-tmatem-zit', 'Jben, tomate & huile d’olive', 'جبن بلدي بالمطيشة وزيت الزيتون', 'Fresh cheese, tomato & olive oil', 'breakfast', ARRAY['ftour', '3cha']::text[], '🍅', '1 assiette (200 g)', 200, 210, 8, 6, 13, 14, 2, 20, 'Un ftour salé à la marocaine : jben baladi, tomate en tranches, huile d’olive et zaatar. Protéines et bonnes graisses, presque pas de glucides — idéal quand la glycémie du matin est déjà haute.', 'فطور مالح على الطريقة المغربية: جبن بلدي، مطيشة شرائح، زيت زيتون وزعتر. بروتين ودهون صحية، تقريباً بلا نشويات — مثالي ملي السكر ديال الصباح مرتفع.', '["100 g de jben baladi (fromage frais de chèvre ou vache)","1 tomate moyenne (environ 80 g)","1 c. à soupe d''huile d''olive extra vierge (15 ml)","1/2 c. à café de zaatar (mélange d''épices)","1 pincée de sel de mer","1 pincée de poivre noir fraîchement moulu"]'::jsonb, '["100 غرام جبن بلدي (جبن طري من الماعز أو البقر)","1 حبة طماطم متوسطة (حوالي 80 غرام)","1 ملعقة كبيرة زيت الزيتون البكر الممتاز (15 مل)","1/2 ملعقة صغيرة زعتر (خليط توابل)","1 رشة ملح بحر","1 رشة فلفل أسود مطحون طازجاً"]'::jsonb, '["Lavez soigneusement la tomate moyenne sous l''eau froide. Séchez-la délicatement avec un torchon propre.","Sur une planche à découper, tranchez la tomate en rondelles fines d''environ 3-4 mm d''épaisseur. Disposez les rondelles de tomate en cercle ou en éventail sur une assiette de service.","Prenez les 100 g de jben baladi et émiettez-le grossièrement à la main ou coupez-le en petits morceaux. Répartissez le jben émietté au centre des rondelles de tomate sur l''assiette.","Versez délicatement la cuillère à soupe d''huile d''olive extra vierge sur le jben et les tomates, en veillant à bien napper l''ensemble du plat.","Saupoudrez uniformément la demi-cuillère à café de zaatar sur le jben et les tomates. Le zaatar apportera une saveur aromatique caractéristique.","Ajoutez une petite pincée de sel de mer et une pincée de poivre noir fraîchement moulu selon votre goût. Ne salez pas excessivement, le jben peut déjà être légèrement salé.","Servez immédiatement ce ftour frais et savoureux. Il est idéal accompagné d''un verre de thé vert sans sucre.","💡 Astuce diabète : Ce plat est excellent pour stabiliser la glycémie matinale grâce à sa richesse en protéines et bonnes graisses et sa faible teneur en glucides. Pour une portion de 200 g, il apporte environ 210 kcal et seulement 8 g de glucides. Mangez lentement et savourez chaque bouchée. Évitez de le servir avec du pain blanc ou des viennoiseries ; préférez une petite tranche de pain complet aux céréales (environ 30g) si vous avez besoin d''un apport glucidique supplémentaire, en tenant compte de votre glycémie."]'::jsonb, '["غسل الطماطم المتوسطة بعناية تحت الماء البارد. نشفها بلطف بمنشفة نظيفة.","فوق لوحة التقطيع، قطع الطماطم إلى دوائر رقيقة بسمك حوالي 3-4 ملم. رتب دوائر الطماطم في شكل دائري أو مروحي على طبق التقديم.","خذ 100 غرام من الجبن البلدي وفتته بشكل خشن باليد أو قطعه إلى قطع صغيرة. وزع الجبن المفتت في وسط دوائر الطماطم على الطبق.","صب ملعقة كبيرة من زيت الزيتون البكر الممتاز بلطف فوق الجبن والطماطم، مع التأكد من تغطية الطبق بالكامل.","رش نصف ملعقة صغيرة من الزعتر بالتساوي فوق الجبن والطماطم. الزعتر سيعطي نكهة عطرية مميزة.","أضف رشة صغيرة من ملح البحر ورشة من الفلفل الأسود المطحون طازجاً حسب ذوقك. لا تبالغ في إضافة الملح، فالجبن قد يكون مالحاً قليلاً بالفعل.","قدم هذا الفطور الطازج واللذيذ فوراً. إنه مثالي مصحوباً بكأس من الشاي الأخضر بدون سكر.","💡 نصيحة للسكري: هذا الطبق ممتاز لتثبيت سكر الدم في الصباح بفضل غناه بالبروتينات والدهون الصحية ومحتواه المنخفض من الكربوهيدرات. لحصة 200 غرام، يوفر حوالي 210 سعرة حرارية و 8 غرامات فقط من الكربوهيدرات. تناول ببطء واستمتع بكل لقمة. تجنب تقديمه مع الخبز الأبيض أو المعجنات؛ فضل قطعة صغيرة من الخبز الكامل بالحبوب (حوالي 30 غرام) إذا كنت بحاجة إلى كربوهيدرات إضافية، مع الأخذ في الاعتبار مستوى سكر الدم لديك."]'::jsonb, 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/0f/%D0%9A%D0%B0%D0%BF%D1%80%D0%B5%D0%B7%D0%B5_%D1%81%D0%B0%D0%BB%D0%B0%D1%82%D0%B0_%281%29.jpg/1280px-%D0%9A%D0%B0%D0%BF%D1%80%D0%B5%D0%B7%D0%B5_%D1%81%D0%B0%D0%BB%D0%B0%D1%82%D0%B0_%281%29.jpg', ARRAY['jben tomate', 'جبن بلدي']::text[])
